# ── Optional FAISS / sentence-transformers for memory_search vector mode ──
# NOTE: sentence_transformers imports torch (~700MB RSS). We do NOT import
# at module level to avoid loading 700MB in every process that touches
# persistent_agents (e.g. nexus_app).  Instead we check lazily.
_VECTOR_SEARCH_CHECKED = False
VECTOR_SEARCH_AVAILABLE = False

_shared_encoders: Dict = {}

def _check_vector_search() -> bool:
    """Lazily check if vector search deps are installed (without loading torch)."""
    global _VECTOR_SEARCH_CHECKED, VECTOR_SEARCH_AVAILABLE
    if _VECTOR_SEARCH_CHECKED:
        return VECTOR_SEARCH_AVAILABLE
    _VECTOR_SEARCH_CHECKED = True
    try:
        import importlib.util
        VECTOR_SEARCH_AVAILABLE = (
            importlib.util.find_spec("sentence_transformers") is not None
            and importlib.util.find_spec("faiss") is not None
        )
    except (ImportError, ModuleNotFoundError):
        VECTOR_SEARCH_AVAILABLE = False
    return VECTOR_SEARCH_AVAILABLE

def get_shared_sentence_transformer(model_name: str = 'all-MiniLM-L6-v2'):
    """Return a cached SentenceTransformer encoder (or None if unavailable)."""
    if not _check_vector_search():
        return None
    if model_name not in _shared_encoders:
        try:
            from sentence_transformers import SentenceTransformer as _ST
            _shared_encoders[model_name] = _ST(model_name)
        except (ImportError, ModuleNotFoundError):
            _shared_encoders[model_name] = None
    return _shared_encoders[model_name]

