# ── Hardware probes (run once at startup, cached) ──
def _probe_camera() -> bool:
    """Check if any camera is accessible on this machine.

    Existence-only probe: looks for /dev/video* nodes on Linux without
    opening them. The camera_broker is the only legitimate opener — see
    repryntt/hardware/camera_broker.py.
    """
    import sys as _sys
    if _sys.platform.startswith("linux"):
        import glob as _glob
        return bool(_glob.glob("/dev/video*"))
    # On macOS/Windows, presence is hard to check without opening; assume
    # available and let the broker's lazy init surface real failures.
    return True


def _probe_microphone() -> bool:
    """Check if a recording device is available."""
    import sys as _sys
    if _sys.platform == "linux":
        import shutil
        return shutil.which("arecord") is not None
    try:
        import sounddevice as sd
        devs = sd.query_devices(kind='input')
        return devs is not None
    except (ImportError, ModuleNotFoundError):
        return False


def _probe_speaker() -> bool:
    """Check if an audio output device is available."""
    import sys as _sys
    if _sys.platform == "linux":
        import shutil
        return shutil.which("aplay") is not None
    if _sys.platform == "darwin":
        return True  # macOS always has 'say'
    try:
        import pyttsx3
        return True
    except ImportError:
        return False

# ── Unified Workspace ──
# All agent work products go here — organized by purpose, not by agent UUID.
# This is the single source of truth for all agent output.
#   workspace/
#   ├── projects/       ← shared work products (research, reports, sims)
#   ├── reports/        ← finished deliverables
#   ├── data/           ← datasets, charts, simulation outputs
#   ├── agents/
#   │   ├── operator/   ← Jarvis/Artemis private state (memory, soul, deep_work)
#   │   └── marketplace/ ← spawned persistent + ephemeral agents
#   │       ├── AG-001/
#   │       ├── CC-001/
#   │       └── ephemeral_*/
#   └── archive/        ← old/completed project material
WORKSPACE_ROOT = BRAIN_DIR.parent / "workspace"
WORKSPACE_PROJECTS = WORKSPACE_ROOT / "projects"
WORKSPACE_REPORTS = WORKSPACE_ROOT / "reports"
WORKSPACE_DATA = WORKSPACE_ROOT / "data"
WORKSPACE_AGENTS = WORKSPACE_ROOT / "agents"
WORKSPACE_ARCHIVE = WORKSPACE_ROOT / "archive"
WORKSPACE_OPERATOR = WORKSPACE_AGENTS / "operator"      # Jarvis / main operator
WORKSPACE_MARKETPLACE = WORKSPACE_AGENTS / "marketplace"  # Spawned persistent + ephemeral agents

def _ensure_workspace():
    """Create the unified workspace directory structure."""
    for d in (WORKSPACE_ROOT, WORKSPACE_PROJECTS, WORKSPACE_REPORTS,
              WORKSPACE_DATA, WORKSPACE_AGENTS, WORKSPACE_ARCHIVE,
              WORKSPACE_OPERATOR, WORKSPACE_MARKETPLACE):
        d.mkdir(parents=True, exist_ok=True)

_ensure_workspace()


def _migrate_workspace_layout():
    """One-time migration: move legacy flat agent dirs into operator/ and marketplace/.
    
    Old layout:  agents/JARVIS/, agents/jarvis_autonomous/, agents/AG-001/, agents/ephemeral_*/
    New layout:  agents/operator/ (Jarvis data), agents/marketplace/<name>/ (spawned agents)
    """
    import shutil
    marker = WORKSPACE_AGENTS / ".migrated_v2"
    if marker.exists():
        return  # already migrated

    jarvis_variants = {"JARVIS", "jarvis", "jarvis_autonomous", "Jarvis"}

    for child in WORKSPACE_AGENTS.iterdir():
        if not child.is_dir():
            continue
        name = child.name
        # Skip the new structural dirs
        if name in ("operator", "marketplace"):
            continue
        if name in jarvis_variants:
            # Merge into operator/
            dst = WORKSPACE_OPERATOR
            dst.mkdir(parents=True, exist_ok=True)
            for item in child.iterdir():
                target = dst / item.name
                if target.exists():
                    # Don't overwrite — keep newer (operator/ already has it)
                    continue
                shutil.move(str(item), str(target))
            # Remove the now-empty legacy dir
            try:
                shutil.rmtree(str(child))
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)
        else:
            # Spawned agent or ephemeral — move entire dir into marketplace/
            dst = WORKSPACE_MARKETPLACE / name
            if dst.exists():
                continue  # already migrated somehow
            try:
                shutil.move(str(child), str(dst))
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

    # Write marker so we don't re-run
    try:
        marker.write_text("migrated\n")
    except Exception:
        logger.debug("Suppressed exception", exc_info=True)

_migrate_workspace_layout()


def _extract_doubt_block(text: str) -> str:
    """Pull `<doubt_block>...</doubt_block>` content from Andrew's report.

    The critic gate requires Andrew to enumerate his own concerns (≥150 words,
    referencing at least one specific identifier from the artifact) before a
    task can be marked complete. The doubt_block is parsed here from his
    free-form report text.
    """
    if not text:
        return ""
    import re as _re_db
    m = _re_db.search(r"<doubt_block>(.*?)</doubt_block>", text,
                       _re_db.IGNORECASE | _re_db.DOTALL)
    return m.group(1).strip() if m else ""


def _agent_workspace_dir(agent) -> str:
    """Get the unified workspace directory for an agent.
    
    Operator (Jarvis) → agents/operator/
    Spawned agents → agents/marketplace/<display_name>/
    """
    # Accept either an AutonomousAgentState object or a string agent_id
    if isinstance(agent, str):
        name = agent
    else:
        name = agent.display_name or agent.name or agent.agent_id
    # Normalize all Jarvis variants to the operator directory
    if name in ("JARVIS", "jarvis", "jarvis_autonomous", "Jarvis"):
        workspace = str(WORKSPACE_OPERATOR)
        os.makedirs(workspace, exist_ok=True)
        return workspace
    # Sanitize: replace spaces/special chars with underscores
    import re as _re
    safe_name = _re.sub(r'[^\w\-]', '_', name)
    workspace = str(WORKSPACE_MARKETPLACE / safe_name)
    os.makedirs(workspace, exist_ok=True)
    return workspace


# ── Cost-awareness helpers ────────────────────────────────────────────
# Per-million-token USD pricing for each provider. Used to compute the
# per-heartbeat burn that we inject into Andrew's prompt so the
# model can see what it's spending and self-throttle. Numbers may drift
# over time — operator can edit. "cached_in" is the discounted rate for
# cache-hit input tokens (xai caches prefixes automatically; Anthropic
# via explicit cache_control blocks). When per-call usage details are
# available we price uncached input / cached input / output separately;
# otherwise we fall back to the old worst-case average estimate.
_PROVIDER_PRICING_USD_PER_M = {
    "xai":       {"in": 1.25,  "out": 2.50,  "cached_in": 0.31},
    "anthropic": {"in": 15.00, "out": 75.00, "cached_in": 1.50},
    "openai":    {"in": 2.50,  "out": 10.00, "cached_in": 1.25},
    "openrouter":{"in": 3.00,  "out": 15.00, "cached_in": 1.50},  # varies by underlying model
    "nvidia":    {"in": 0.00,  "out": 0.00,  "cached_in": 0.00},  # free tier
    "local":     {"in": 0.00,  "out": 0.00,  "cached_in": 0.00},
    "custom":    {"in": 0.00,  "out": 0.00,  "cached_in": 0.00},
}


def _estimate_token_cost_usd(provider: str, total_tokens: int) -> float:
    """Rough USD estimate from total token count. Uses the average of
    input + output rates since we don't split the count finely here.
    Returns 0.0 for free tiers / unknown providers."""
    p = _PROVIDER_PRICING_USD_PER_M.get(provider or "", None)
    if not p:
        return 0.0
    avg = (p["in"] + p["out"]) / 2.0
    return round(total_tokens * avg / 1_000_000.0, 4)


def _estimate_split_cost_usd(provider: str, in_uncached: int,
                             in_cached: int, out: int) -> float:
    """USD estimate from real usage buckets (cache-aware). Returns 0.0
    for free tiers / unknown providers."""
    p = _PROVIDER_PRICING_USD_PER_M.get(provider or "", None)
    if not p:
        return 0.0
    cached_rate = p.get("cached_in", p["in"] * 0.25)
    usd = (in_uncached * p["in"] + in_cached * cached_rate
           + out * p["out"]) / 1_000_000.0
    return round(usd, 4)


def _record_llm_usage(agent, usage, fallback_tokens: int = 0) -> None:
    """Accumulate real token buckets from an API usage object onto the agent.

    Handles both shapes:
      - Anthropic: input_tokens / output_tokens / cache_read_input_tokens /
        cache_creation_input_tokens (input_tokens EXCLUDES cache activity)
      - OpenAI-compat (xai, openai, openrouter, nvidia): prompt_tokens /
        completion_tokens / prompt_tokens_details.cached_tokens

    When the provider returned no usage, `fallback_tokens` is counted as
    uncached input (keeps the old rough behavior). Also maintains the
    legacy `total_tokens` counter so nothing downstream changes.
    """
    usage = usage or {}
    try:
        if "input_tokens" in usage or "output_tokens" in usage:
            in_uncached = int(usage.get("input_tokens", 0) or 0)
            cache_read = int(usage.get("cache_read_input_tokens", 0) or 0)
            # Cache writes bill at a premium (~1.25x input); counting them
            # as plain uncached input keeps the estimate slightly conservative.
            cache_write = int(usage.get("cache_creation_input_tokens", 0) or 0)
            out = int(usage.get("output_tokens", 0) or 0)
            total = in_uncached + cache_read + cache_write + out
            if total <= 0:
                agent.input_tokens_uncached += fallback_tokens
                agent.total_tokens += fallback_tokens
                return
            agent.input_tokens_uncached += in_uncached + cache_write
            agent.input_tokens_cached += cache_read
            agent.output_tokens_total += out
            agent.total_tokens += total
            return

        prompt = int(usage.get("prompt_tokens", 0) or 0)
        completion = int(usage.get("completion_tokens", 0) or 0)
        total = int(usage.get("total_tokens", 0) or 0)
        details = usage.get("prompt_tokens_details") or {}
        cached = int(details.get("cached_tokens", 0) or 0) if isinstance(details, dict) else 0
        if not (prompt or completion or total):
            agent.input_tokens_uncached += fallback_tokens
            agent.total_tokens += fallback_tokens
            return
        if not (prompt or completion):
            prompt = total  # only total known — treat it all as input
        cached = min(cached, prompt)
        agent.input_tokens_uncached += prompt - cached
        agent.input_tokens_cached += cached
        agent.output_tokens_total += completion
        agent.total_tokens += (prompt + completion) or total
    except Exception:
        # Never let accounting break an API call path
        agent.total_tokens += fallback_tokens


# ── Tool-result cache (per-heartbeat) ────────────────────────────────
# TTL keeps stale results from leaking across heartbeats. For file-based
# tools (read_file, list_dir, read_bootstrap_file) we additionally check
# the path's mtime — if it changed, we treat the cache as cold.
_TOOL_CACHE_TTL_SEC = 600.0
_FILE_READ_TOOLS = ("read_file", "read_bootstrap_file", "list_dir")
_CACHEABLE_TOOLS = set(_FILE_READ_TOOLS) | {
    "grep_search",
    "knowledge_search",
}


def _tool_args_signature(tool_name: str, args: Any) -> str:
    """Compact signature for cache lookup. Args may be a dict or a JSON
    string depending on how the tool was parsed."""
    try:
        if isinstance(args, str):
            return f"{tool_name}::{args.strip()[:400]}"
        if isinstance(args, dict):
            import json as _json
            return f"{tool_name}::{_json.dumps(args, sort_keys=True)[:400]}"
        return f"{tool_name}::{str(args)[:400]}"
    except Exception:
        return f"{tool_name}::<unhashable>"


def _extract_path_from_args(args: Any) -> Optional[str]:
    """Pull the likely path argument from a tool-call's args. Returns None
    when no path-like key is present — caller falls back to TTL-only."""
    if not args:
        return None
    if isinstance(args, str):
        try:
            import json as _json
            args = _json.loads(args)
        except Exception:
            return None
    if not isinstance(args, dict):
        return None
    for k in ("path", "file_path", "filename", "filepath", "directory",
              "dir_path", "filenames"):
        v = args.get(k)
        if isinstance(v, str) and v:
            return v
    return None


def _path_mtime_safe(path: str) -> Optional[float]:
    try:
        import os as _os
        return _os.path.getmtime(path)
    except Exception:
        return None


# ── Multimodal capability detection ──────────────────────────────────
# When Andrew's primary model can see (Grok 4 family, Claude 3+, GPT-4o,
# Gemini via OpenAI-compat), we send camera frames *directly* to his brain
# instead of routing through the secondary VLM and feeding back its text
# description. The secondary VLM still runs for cheap spatial labels.
# Anthropic uses a different image-message format and is NOT enabled here
# yet (see TODO at _build_vision_messages_for_provider).
_MULTIMODAL_MODEL_PATTERNS = (
    "grok-4",          # grok-4, grok-4.3, grok-4-fast, grok-4-1-fast (all vision-capable)
    "gpt-4o",          # OpenAI vision
    "gpt-4-vision",
    "gpt-4-turbo",     # turbo also vision
    "gemini-",         # all Gemini 1.5+ flash/pro support vision (via OpenAI compat)
    "llama-3.2",       # NVIDIA's llama-3.2-vision (text-only also exists, but vision variant works)
    "llava",           # generic
    "qwen2-vl",
    "qwen2.5-vl",
)


def _provider_supports_vision(provider: str, model: str) -> bool:
    """True iff the given (provider, model) pair accepts OpenAI-format
    vision messages (content as a list with image_url blocks).

    Conservative match by model-name substring. We only enable when we're
    sure — false negatives just keep the text-summary fallback path.
    """
    if not model:
        return False
    m = model.lower()
    # Anthropic uses its own block format — handled separately, off for now.
    if provider == "anthropic":
        return False
    return any(pat in m for pat in _MULTIMODAL_MODEL_PATTERNS)


def _encode_image_data_url(image_path: str, max_bytes: int = 2_500_000) -> Optional[str]:
    """Read an image off disk and return a base64 data URL ready to drop
    into a vision message. Returns None if the file is missing or too big
    after encoding (we cap to keep request bodies reasonable)."""
    try:
        import base64
        with open(image_path, "rb") as f:
            raw = f.read()
        if len(raw) > max_bytes:
            return None
        ext = (image_path.rsplit(".", 1)[-1] or "jpeg").lower()
        if ext == "jpg":
            ext = "jpeg"
        mime = f"image/{ext}" if ext in ("jpeg", "png", "webp", "gif") else "image/jpeg"
        b64 = base64.b64encode(raw).decode("ascii")
        return f"data:{mime};base64,{b64}"
    except Exception:
        return None


def _build_vision_user_message(text: str, image_data_urls: List[str]) -> Dict:
    """Build an OpenAI-format vision user message: a single user turn whose
    content is a list of {type:text} + {type:image_url} blocks. Works on
    xAI Grok 4 family, GPT-4o, Gemini via OpenAI compat, and any
    OpenAI-compatible provider that follows the same schema.
    """
    parts: List[Dict[str, Any]] = [{"type": "text", "text": text}]
    for url in image_data_urls:
        parts.append({"type": "image_url", "image_url": {"url": url}})
    return {"role": "user", "content": parts}


