# ================================================================
# AUTONOMOUS AGENT BEHAVIORS — Department-Based Professional Work
# ================================================================
# Behaviors are generated dynamically from department taxonomy.
# Each department maps to a behavior set with domain-specific
# goals, think prompts, and act prompts focused on real work output.

def _build_department_behaviors() -> Dict[str, Dict]:
    """Build AUTONOMOUS_BEHAVIORS from DEPARTMENTS — real professional work."""
    behaviors = {}
    for dept_id, dept in DEPARTMENTS.items():
        roles_desc = ", ".join(r["title"] for r in dept["roles"])
        focus_areas = "; ".join(r["focus"] for r in dept["roles"][:3])
        dept_short = dept.get('short', dept.get('name', dept_id))
