# ================================================================
# SWARM MISSION — Coordinated multi-agent task execution
# ================================================================

@dataclass
class SwarmMission:
    """
    A coordinated mission where multiple agents each work a UNIQUE piece of a
    larger task.  Think of it like a jigsaw puzzle — every agent gets one piece,
    they work independently, then the results are synthesized into a whole.

    Lifecycle:
        planning → active → converging → completed / failed
    """
    mission_id: str
    objective: str                   # The high-level goal from the user / system
    created_at: float = field(default_factory=time.time)
    status: str = "planning"         # planning, active, converging, completed, failed
    agent_ids: List[str] = field(default_factory=list)   # Participating agents
    subtasks: Dict[str, Dict] = field(default_factory=dict)  # agent_id → {task, status, result}
    synthesis: str = ""              # Final merged deliverable
    synthesis_thread_id: Optional[int] = None  # Nexus thread where results posted
    convergence_agent: str = ""      # Agent ID responsible for final synthesis
    deadline: float = 0.0            # Optional deadline timestamp
    created_by: str = "user"         # Who initiated: "user" or "system"
    metadata: Dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> Dict:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict) -> 'SwarmMission':
        valid = {k: v for k, v in data.items() if k in cls.__dataclass_fields__}
        return cls(**valid)

    @property
    def progress(self) -> float:
        """0.0–1.0 completion fraction."""
        if not self.subtasks:
            return 0.0
        done = sum(1 for st in self.subtasks.values() if st.get("status") == "completed")
        return done / len(self.subtasks)

    @property
    def all_subtasks_done(self) -> bool:
        return all(st.get("status") == "completed" for st in self.subtasks.values())


# ================================================================
# AUTONOMOUS AGENT WRAPPER
# ================================================================

@dataclass
class AutonomousAgentState:
    """Persistent state for one autonomous agent."""
    agent_id: str
    name: str
    role: str                        # department key (e.g. "energy_physics")
    provider: str
    model: str
    personality: str
    department: str = ""             # department key (same as role, for clarity)
    role_title: str = ""             # professional title (e.g. "Plasma Physicist")
    focus_area: str = ""             # specific research focus
    status: str = "active"           # active, paused, retired
    cycle_interval: int = 180        # seconds between autonomous cycles
    last_cycle: float = 0.0
    cycles_completed: int = 0
    posts_created: int = 0
    replies_made: int = 0
    goals_explored: List[str] = field(default_factory=list)
    current_goal: str = ""
    last_thought: str = ""
    last_post_id: Optional[int] = None
    memory_summary: str = ""         # Compressed memory across cycles
    created_at: float = field(default_factory=time.time)
    total_tokens: int = 0
    errors: int = 0
    display_name: str = ""
    tagline: str = ""
    bio: str = ""
    system_prompt: str = ""
    # ── Roster tiering ──
    roster_tier: int = 3              # 1=OG 158, 2=system extension, 3=created/custom
    true_employee: bool = False       # True only for the OG 158 long-profile roles
    roster_class: str = ""            # core_158_true_employee, tier_2_system_extension, created_agent
    long_profile_source: str = ""     # Source used to define the agent profile/prompt
    tier_description: str = ""        # Human-readable tier note for tools/UI
    # ── Conversation continuity tracking ──
    active_threads: List[int] = field(default_factory=list)
    thread_reply_counts: Dict[str, int] = field(default_factory=dict)
    actions_created: int = 0
    # ── Scheduling control ──
    autonomous: bool = False         # If False, agent is invoke-only (no scheduler cycles). Defaults OFF for cost safety.
    task_gated: bool = True          # If True, only cycles when has_pending_work (saves API costs)
    has_pending_work: bool = False   # Flag set by assign_work(), cleared when task queue empty
    soul_initialized: bool = False   # True once agent has created its own IDENTITY.md
    # ── Duty cycle (API cost control) ──
    # When using cloud API providers, agents only run for `duty_active_minutes` per
    # `duty_period_minutes` (e.g. 10 min active per 60 min period). This saves ~83%
    # of API costs. Local LLM providers bypass this entirely (free to run unlimited).
    duty_active_minutes: int = 10    # Minutes of active cycling per duty period
    duty_period_minutes: int = 60    # Total duty period in minutes
    duty_window_start: float = 0.0   # Timestamp when current active window started
    # ── Swarm mission mode ──
    mode: str = "solo"               # "solo" = autonomous free-roam, "mission" = locked to a mission
    active_mission_id: str = ""      # Mission ID if mode == "mission"
    active_chain_id: str = ""        # Active research chain ID (multi-step reasoning)
    # ── Stuck-tool escalation (error-signature loop detection) ──
    # Tracks the last few tool-failure signatures. When consecutive failures
    # share a signature, the heartbeat injects a "try a different approach"
    # nudge; three matches in a row triggers an early-out so the watchdog
    # doesn't have to. Implementation in _parse_and_execute_tools.
    recent_tool_error_sigs: List[str] = field(default_factory=list)
    stuck_tool_streak: int = 0       # consecutive identical signatures
    # ── Per-heartbeat tool-result cache (cost-saving lever) ──
    # Maps tool-call signature → {ts, mtime, result_text}. When the agent
    # re-issues the same read_file/list_dir within the same heartbeat AND
    # the underlying file mtime hasn't changed, we return a short
    # "duplicate, content unchanged" stub instead of re-shipping the full
    # content into the next prompt. Reset at the top of each heartbeat.
    tool_result_cache: Dict[str, Dict[str, Any]] = field(default_factory=dict)
    # Token + cost baseline at the start of the current heartbeat. Used to
    # compute per-heartbeat burn and inject it into the next prompt so the
    # model can see what it's spending.
    heartbeat_start_tokens: int = 0
    heartbeat_start_ts: float = 0.0
    last_heartbeat_burn_tokens: int = 0    # delta from prior heartbeat
    last_heartbeat_burn_usd: float = 0.0
    # ── Cache-aware token buckets (cumulative, parallel to total_tokens).
    # Filled from real API usage objects by _record_llm_usage so burn can
    # be priced at actual cached/uncached rates instead of worst-case.
    input_tokens_uncached: int = 0
    input_tokens_cached: int = 0
    output_tokens_total: int = 0
    heartbeat_start_in_uncached: int = 0
    heartbeat_start_in_cached: int = 0
    heartbeat_start_output: int = 0

    def to_dict(self) -> Dict:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict) -> 'AutonomousAgentState':
        valid = {k: v for k, v in data.items() if k in cls.__dataclass_fields__}
        # Guard against None in numeric fields (e.g. last_cycle from old wipe scripts)
        numeric_defaults = {'last_cycle': 0.0, 'cycle_interval': 180, 'cycles_completed': 0,
                           'posts_created': 0, 'replies_made': 0, 'total_tokens': 0, 'errors': 0}
        for field_name, default_val in numeric_defaults.items():
            if field_name in valid and valid[field_name] is None:
                valid[field_name] = default_val
        return cls(**valid)


# ================================================================
# OPENCLAW-STYLE LOOP DETECTION — Hash-based, no round cap
# ================================================================

# Exponential backoff schedule for polling tools (OpenClaw pattern)
_POLL_BACKOFF_SCHEDULE_MS = [5000, 10000, 30000, 60000]  # 5s→10s→30s→60s cap

def _poll_backoff_ms(consecutive_no_progress: int) -> int:
    """Calculate suggested retry delay based on consecutive no-progress polls."""
    idx = min(consecutive_no_progress, len(_POLL_BACKOFF_SCHEDULE_MS) - 1)
    return _POLL_BACKOFF_SCHEDULE_MS[idx]


def _hash_tool_call(tool_name: str, args_str: str) -> str:
    """Hash a tool call (name + args) for loop detection — stable SHA-256 digest."""
    payload = f"{tool_name}:{args_str}"
    return hashlib.sha256(payload.encode('utf-8', errors='replace')).hexdigest()[:16]


def _hash_tool_result(result_str: str) -> str:
    """Hash a tool result for no-progress detection."""
    # Normalize: strip whitespace, cap length to avoid hashing megabytes
    normalized = result_str.strip()[:4000]
    return hashlib.sha256(normalized.encode('utf-8', errors='replace')).hexdigest()[:16]


class LoopDetector:
    """
    OpenClaw-style loop detection for agent tool-calling loops.

    Key difference from the old detector: **NO round cap**.
    The tool loop runs until the model stops calling tools or the timeout fires.
    This detector only intervenes when it detects genuinely stuck behavior:

    1. No-progress repeat — same tool+args, same result hash, N times
    2. Ping-pong — alternating between two tool patterns with no progress
    3. Global circuit breaker — any single tool called 30+ times with identical results
    4. Content stall — model producing identical text 3+ times
    5. Write-spam — same write tool called many times with different args but
       producing mostly errors/junk (catches junk-append loops)
    6. Tool frequency — any single tool called 40+ times total (regardless of args)

    All thresholds are configurable. Detection is outcome-aware: it tracks
    tool RESULT hashes, not just call signatures, so the same tool called
    with the same args but getting different results is NOT flagged.
    """

    # Browser / interactive tools — higher thresholds, more patience
    _INTERACTIVE_TOOLS = frozenset({
        "mcp_browser_browser_navigate", "mcp_browser_browser_click",
        "mcp_browser_browser_type", "mcp_browser_browser_screenshot",
        "mcp_browser_browser_get_text", "mcp_browser_browser_get_links",
        "mcp_browser_browser_back", "mcp_browser_browser_scroll",
        "mcp_browser_browser_search_google", "mcp_browser_browser_current_url",
        "mcp_browser_browser_upload_file", "mcp_browser_browser_save_session",
        "mcp_browser_browser_wait_for",
        "mcp_computer_screenshot", "mcp_computer_key_press",
        "mcp_computer_mouse_click", "mcp_computer_open_app",
        "mcp_computer_type_text", "scrape_web_page",
    })

    # Known polling tools — get exponential backoff hints
    _POLL_TOOLS = frozenset({"command_status", "process_poll", "check_task_status"})

    # Write/append tools — tracked for write-spam detection
    _WRITE_TOOLS = frozenset({
        "write_file", "append_daily_memory", "append_to_creative_file",
        "write_to_creative_file", "create_creative_file",
    })

    # Configurable thresholds (OpenClaw defaults)
    HISTORY_SIZE = 50         # sliding window of tracked calls (expanded for frequency tracking)
    WARNING_THRESHOLD = 5     # warn after this many no-progress repeats
    CRITICAL_THRESHOLD = 10   # block after this many (hard stop)
    CIRCUIT_BREAKER = 20      # global circuit breaker — any tool
    PING_PONG_WARN = 6        # warn on A-B alternation
    PING_PONG_CRITICAL = 12   # block on A-B alternation
    WRITE_SPAM_THRESHOLD = 8  # same write tool called 8+ times in window
    TOOL_FREQUENCY_LIMIT = 25 # any single tool called 25+ times total
    SAME_RESULT_LIMIT = 5     # same tool returning identical result 5x (any args)

    def __init__(self, warning_threshold: int = None, critical_threshold: int = None,
                 circuit_breaker: int = None):
        self.warning_threshold = warning_threshold or self.WARNING_THRESHOLD
        self.critical_threshold = critical_threshold or self.CRITICAL_THRESHOLD
        self.circuit_breaker = circuit_breaker or self.CIRCUIT_BREAKER
        # Sliding window of tool call records
        self.call_history: List[Dict] = []  # [{tool_name, args_hash, result_hash, timestamp}]
        self.content_hashes: List[str] = []  # hashes of assistant text content
        self.round_count = 0
        # Total call counts per tool (not windowed — lifetime of this detector)
        self.tool_total_counts: Dict[str, int] = {}
        # Polling backoff tracking: {command_id: consecutive_no_progress_count}
        self.poll_counts: Dict[str, int] = {}
        # Warnings already emitted (to avoid spamming)
        self._emitted_warnings: set = set()

    def _is_interactive(self, tool_name: str) -> bool:
        return tool_name in self._INTERACTIVE_TOOLS

    def _is_poll_tool(self, tool_name: str) -> bool:
        return tool_name in self._POLL_TOOLS

    def _is_write_tool(self, tool_name: str) -> bool:
        return tool_name in self._WRITE_TOOLS

    def record_call(self, tool_name: str, args_str: str, call_id: str = ""):
        """Record a tool call BEFORE execution. Result hash added later."""
        args_hash = _hash_tool_call(tool_name, args_str)
        self.call_history.append({
            "tool_name": tool_name,
            "args_hash": args_hash,
            "result_hash": None,  # filled in by record_result()
            "call_id": call_id,
            "timestamp": time.time(),
        })
        # ── Telemetry: tool call ──
        if _ops:
            _ops.log(call_id or "agent", EventType.TOOL_CALL, Phase.ACT,
                     metadata={"tool_name": tool_name, "args": args_str[:500]})
        # Track lifetime tool call counts (for frequency detection)
        self.tool_total_counts[tool_name] = self.tool_total_counts.get(tool_name, 0) + 1
        # Trim sliding window
        if len(self.call_history) > self.HISTORY_SIZE:
            self.call_history = self.call_history[-self.HISTORY_SIZE:]

    def record_result(self, tool_name: str, args_str: str, result_str: str):
        """Record tool result AFTER execution for no-progress detection."""
        args_hash = _hash_tool_call(tool_name, args_str)
        result_hash = _hash_tool_result(result_str)
        # Detect failure results
        _result_lower = result_str.lower() if result_str else ""
        _is_fail = ('"success": false' in _result_lower or
                    '"success":false' in _result_lower or
                    "REJECTED" in (result_str or ""))
        # Find matching unresolved call (latest first)
        for entry in reversed(self.call_history):
            if (entry["tool_name"] == tool_name and
                    entry["args_hash"] == args_hash and
                    entry["result_hash"] is None):
                entry["result_hash"] = result_hash
                entry["failed"] = _is_fail
                break
        # Update polling backoff
        if self._is_poll_tool(tool_name):
            prev_count = self.poll_counts.get(args_hash, 0)
            # Check if result changed from previous call
            prev_results = [e["result_hash"] for e in self.call_history
                           if e["tool_name"] == tool_name and e["args_hash"] == args_hash
                           and e["result_hash"] is not None]
            if len(prev_results) >= 2 and prev_results[-1] == prev_results[-2]:
                self.poll_counts[args_hash] = prev_count + 1
            else:
                self.poll_counts[args_hash] = 0

    def get_backoff_hint(self, tool_name: str, args_str: str) -> Optional[float]:
        """Get suggested delay in seconds before retrying a poll tool. None if no backoff needed."""
        if not self._is_poll_tool(tool_name):
            return None
        args_hash = _hash_tool_call(tool_name, args_str)
        count = self.poll_counts.get(args_hash, 0)
        if count > 0:
            return _poll_backoff_ms(count) / 1000.0
        return None

    def _no_progress_streak(self, tool_name: str, args_hash: str) -> int:
        """Count consecutive calls with identical results (no progress)."""
        streak = 0
        latest_result = None
        for entry in reversed(self.call_history):
            if entry["tool_name"] != tool_name or entry["args_hash"] != args_hash:
                continue
            if entry["result_hash"] is None:
                continue
            if latest_result is None:
                latest_result = entry["result_hash"]
                streak = 1
            elif entry["result_hash"] == latest_result:
                streak += 1
            else:
                break
        return streak

    def _write_spam_check(self) -> Optional[str]:
        """Detect write-spam: same write tool called many times with different args.

        The old detector missed this because each call had unique args/results,
        so it never hit the no-progress repeat threshold. But 8+ calls to
        write_file or append_daily_memory in a short window, where the distinct
        result count is low relative to call count, is strongly indicative of
        a junk-writing loop.

        Returns a reason string if write-spam detected, or None.
        """
        for write_tool in self._WRITE_TOOLS:
            # Count calls to this write tool in the sliding window
            window_calls = [e for e in self.call_history if e["tool_name"] == write_tool]
            call_count = len(window_calls)
            if call_count < self.WRITE_SPAM_THRESHOLD:
                continue
            # Count distinct result hashes (None results count as errors)
            result_hashes = set()
            error_count = 0
            for entry in window_calls:
                rh = entry.get("result_hash")
                if rh is None:
                    error_count += 1
                else:
                    result_hashes.add(rh)
            unique_results = len(result_hashes)
            # Heuristic: if >60% of calls produce few unique results OR
            # if many are errors, it's spam.  Unique results should grow
            # roughly linearly for genuine varied writes — spam converges.
            # Threshold: fewer than 40% unique results vs call count
            uniqueness_ratio = unique_results / max(call_count, 1)
            if uniqueness_ratio < 0.40 or error_count > call_count * 0.5:
                return (f"CRITICAL: Write-spam detected — {write_tool} called {call_count}x "
                        f"in sliding window with only {unique_results} unique results "
                        f"and {error_count} errors")
        return None

    def _tool_frequency_check(self) -> Optional[str]:
        """Check if any single tool has been called an excessive number of times
        across the entire lifetime of this detector (not just the sliding window).
        Returns a reason string if limit exceeded, or None."""
        for tool_name, count in self.tool_total_counts.items():
            # Interactive tools get 50% more headroom
            effective_limit = int(self.TOOL_FREQUENCY_LIMIT * 1.5) if self._is_interactive(tool_name) else self.TOOL_FREQUENCY_LIMIT
            if count >= effective_limit:
                warn_key = f"freq:{tool_name}"
                if warn_key not in self._emitted_warnings:
                    self._emitted_warnings.add(warn_key)
                    return (f"CRITICAL: {tool_name} called {count}x total — "
                            f"exceeds frequency limit of {effective_limit}")
        return None

    def _ping_pong_streak(self) -> tuple:
        """Detect A-B-A-B alternation pattern. Returns (count, tool_a, tool_b)."""
        if len(self.call_history) < 4:
            return (0, None, None)
        # Check last entries for alternating signatures
        last = self.call_history[-1]
        # Find the previous different signature
        other = None
        for entry in reversed(self.call_history[:-1]):
            if entry["args_hash"] != last["args_hash"]:
                other = entry
                break
        if not other:
            return (0, None, None)
        # Count alternating tail
        alternating = 0
        for i in range(len(self.call_history) - 1, -1, -1):
            entry = self.call_history[i]
            expected = last["args_hash"] if alternating % 2 == 0 else other["args_hash"]
            if entry["args_hash"] != expected:
                break
            alternating += 1
        if alternating < 4:
            return (0, None, None)
        # Check for no-progress (identical results on both sides)
        a_results = set()
        b_results = set()
        tail_start = max(0, len(self.call_history) - alternating)
        for entry in self.call_history[tail_start:]:
            if entry["result_hash"] is None:
                return (alternating, last["tool_name"], other["tool_name"])  # can't determine progress
            if entry["args_hash"] == last["args_hash"]:
                a_results.add(entry["result_hash"])
            else:
                b_results.add(entry["result_hash"])
        no_progress = len(a_results) <= 1 and len(b_results) <= 1
        if no_progress:
            return (alternating, last["tool_name"], other["tool_name"])
        return (0, None, None)  # progress is being made, not a loop

    def check(self, tool_calls: List[Dict] = None,
              content: str = "") -> Optional[str]:
        """
        Check for loop conditions. Returns a reason string if loop detected,
        or None if OK to continue.

        NOTE: No round cap. The agent runs until the model stops calling tools
        or the timeout fires. This method only blocks genuinely stuck loops.
        """
        self.round_count += 1

        if tool_calls:
            for tc in tool_calls:
                fn = tc.get("function", {})
                tool_name = fn.get("name", "")
                args_str = fn.get("arguments", "{}")
                args_hash = _hash_tool_call(tool_name, args_str)

                # --- Check 1: Global circuit breaker ---
                no_progress = self._no_progress_streak(tool_name, args_hash)
                if no_progress >= self.circuit_breaker:
                    return (f"CRITICAL: {tool_name} repeated {no_progress}x with identical "
                            f"results — global circuit breaker triggered")

                # --- Check 2: No-progress repeat (critical) ---
                is_interactive = self._is_interactive(tool_name)
                effective_critical = self.critical_threshold + (5 if is_interactive else 0)
                if no_progress >= effective_critical:
                    return (f"CRITICAL: {tool_name} called {no_progress}x with same args "
                            f"and identical results — no progress")

                # --- Check 3: No-progress repeat (warning → injected into context) ---
                effective_warning = self.warning_threshold + (5 if is_interactive else 0)
                if no_progress >= effective_warning:
                    warn_key = f"np:{tool_name}:{args_hash}"
                    if warn_key not in self._emitted_warnings:
                        self._emitted_warnings.add(warn_key)
                        logger.warning(f"Loop warning: {tool_name} repeated {no_progress}x with no progress")
                        # Don't block yet — just warn. Continue and let the model course-correct.

            # --- Check 4: Ping-pong oscillation ---
            pp_count, pp_a, pp_b = self._ping_pong_streak()
            effective_pp_critical = self.PING_PONG_CRITICAL + (5 if pp_a and self._is_interactive(pp_a) else 0)
            if pp_count >= effective_pp_critical:
                return (f"CRITICAL: Ping-pong loop between {pp_a} and {pp_b} "
                        f"({pp_count} alternations with no progress)")
            effective_pp_warn = self.PING_PONG_WARN + (3 if pp_a and self._is_interactive(pp_a) else 0)
            if pp_count >= effective_pp_warn:
                warn_key = f"pp:{pp_a}:{pp_b}"
                if warn_key not in self._emitted_warnings:
                    self._emitted_warnings.add(warn_key)
                    logger.warning(f"Ping-pong warning: {pp_a} ↔ {pp_b} ({pp_count} alternations)")

        # --- Check 5: Identical assistant content repeating ---
        if content:
            c_hash = hashlib.sha256(content.strip()[:500].encode('utf-8', errors='replace')).hexdigest()[:16]
            self.content_hashes.append(c_hash)
            if len(self.content_hashes) > self.HISTORY_SIZE:
                self.content_hashes = self.content_hashes[-self.HISTORY_SIZE:]
            if len(self.content_hashes) >= 3:
                if self.content_hashes[-1] == self.content_hashes[-2] == self.content_hashes[-3]:
                    return "Identical response content 3x in a row — model stuck"

        # --- Check 6: Write-spam (same write tool, many calls, junk results) ---
        write_spam = self._write_spam_check()
        if write_spam:
            return write_spam

        # --- Check 7: Tool frequency (any single tool called too many times total) ---
        freq_check = self._tool_frequency_check()
        if freq_check:
            return freq_check

        # --- Check 8: Same-result different-args (catches knowledge_search returning same data) ---
        same_result = self._same_result_check()
        if same_result:
            return same_result

        return None  # no loop detected — keep going

    def _same_result_check(self) -> Optional[str]:
        """Detect when a tool returns the same result repeatedly with different args.

        Catches two patterns:
        1. Same result hash repeated (e.g., knowledge_search returning same 4740 chars)
        2. Same tool called too many times with all failures (e.g., append_daily_memory
           rejected 5+ times — different error text but all failures)
        """
        # Group recent calls by tool_name → count most common result_hash
        from collections import Counter
        tool_result_counts: Dict[str, Counter] = {}
        tool_fail_counts: Dict[str, int] = {}
        for entry in self.call_history:
            tn = entry["tool_name"]
            rh = entry.get("result_hash")
            if rh is not None:
                if tn not in tool_result_counts:
                    tool_result_counts[tn] = Counter()
                tool_result_counts[tn][rh] += 1
            # Track failures per tool (via the failed flag set in record_result)
            if entry.get("failed"):
                tool_fail_counts[tn] = tool_fail_counts.get(tn, 0) + 1

        # Search/knowledge tools get a LOWER threshold — repeats are wasteful
        _SEARCH_TOOLS = {
            "web_search_results_only", "knowledge_search", "google_web_search",
            "grokipedia_search", "arxiv_search", "wikipedia_search",
        }

        for tool_name, counter in tool_result_counts.items():
            most_common_hash, count = counter.most_common(1)[0]
            effective_limit = self.SAME_RESULT_LIMIT
            if self._is_interactive(tool_name):
                effective_limit = effective_limit + 5
            elif tool_name in _SEARCH_TOOLS:
                effective_limit = max(3, effective_limit - 2)  # 3 instead of 5
            if count >= effective_limit:
                # Always break — don't dedup. Stuck loops must be stopped.
                return (f"CRITICAL: {tool_name} returned identical result {count}x "
                        f"(SAME_RESULT_LIMIT={effective_limit}) — "
                        f"varying args but getting same data back. "
                        f"STOP calling {tool_name} and try a completely different approach.")

        # Check for repeated failures (even with different error messages)
        _fail_limit = max(3, self.SAME_RESULT_LIMIT - 1)
        for tool_name, fail_count in tool_fail_counts.items():
            if fail_count >= _fail_limit:
                return (f"CRITICAL: {tool_name} failed {fail_count}x this heartbeat — "
                        f"your approach is not working. "
                        f"STOP calling {tool_name} and try a completely different approach.")
        return None


# ================================================================
# MID-RUN CONTEXT COMPACTION (OpenClaw pattern)
# ================================================================

def _estimate_message_tokens(messages: List[Dict]) -> int:
    """Rough token estimate: ~4 chars per token."""
    total_chars = 0
    for msg in messages:
        content = msg.get("content") or ""
        total_chars += len(content) if isinstance(content, str) else 0
        for tc in msg.get("tool_calls") or []:
            total_chars += len(tc.get("function", {}).get("arguments", ""))
    return total_chars // 4


def _should_compact_mid_run(messages: List[Dict], context_window: int = 120000) -> bool:
    """
    Check if the running conversation needs mid-run compaction.
    Triggers at 75% of estimated context window.
    Large-context cloud models can exceed this, but we keep a conservative default
    to leave room for tool definitions + response.
    """
    estimated_tokens = _estimate_message_tokens(messages)
    threshold = int(context_window * 0.75)
    return estimated_tokens > threshold


# ================================================================
# SECURE BOOTSTRAP FILE I/O — Path traversal + TOCTOU protection
# ================================================================

class _BootstrapFileCache:
    """TOCTOU-safe cache for bootstrap file reads.

    Caches file content keyed by (path, inode, device, size, mtime_ns).
    If any of these change between stat() and read(), the cache is invalidated
    and the file is re-read. This prevents time-of-check/time-of-use races
    where a file could be swapped between existence check and read.

    Future-proofed for plugin systems where untrusted code might modify
    bootstrap files concurrently (Shopify, Twilio, messaging integrations).
    """

    def __init__(self):
        self._cache: Dict[str, tuple] = {}  # path -> (identity_key, content)

    @staticmethod
    def _file_identity(path: str) -> tuple:
        """Return (inode, dev, size, mtime_ns) for TOCTOU-safe identity."""
        st = os.stat(path)
        return (st.st_ino, st.st_dev, st.st_size, st.st_mtime_ns)

    def read(self, path: str, max_chars: int = 20000) -> Optional[str]:
        """Read a bootstrap file with TOCTOU-safe caching.

        Returns None if file doesn't exist or has been tampered with.
        Full content is cached; max_chars truncation applied on return.
        """
        try:
            if not os.path.exists(path):
                return None
            identity = self._file_identity(path)
            cached = self._cache.get(path)
            if cached and cached[0] == identity:
                content = cached[1]
            else:
                # Cache miss or stale — re-read
                with open(path, 'r') as f:
                    content = f.read().strip()
                # Verify identity hasn't changed during read (TOCTOU check)
                post_identity = self._file_identity(path)
                if identity != post_identity:
                    logger.warning(f"⚠️ TOCTOU: {path} changed during read — discarding")
                    return None
                self._cache[path] = (post_identity, content)
            # Truncate on return (not in cache)
            if max_chars and len(content) > max_chars:
                return content[:max_chars]
            return content
        except Exception as e:
            logger.debug(f"Bootstrap file read failed for {path}: {e}")
            return None

    def invalidate(self, path: str):
        """Remove a specific path from the cache (after writes)."""
        self._cache.pop(path, None)

    def clear(self):
        """Clear the entire cache."""
        self._cache.clear()


# Module-level singleton — shared across all agent instances
_bootstrap_cache = _BootstrapFileCache()


def _safe_bootstrap_path(bootstrap_dir: str, filename: str) -> Optional[str]:
    """Resolve a bootstrap filename to a safe absolute path.

    Rejects path traversal attempts (../, absolute paths, symlink escapes).
    Returns the resolved path if safe, None if rejected.
    """
    # Reject obvious traversal attempts
    if '..' in filename or '/' in filename or '\\' in filename:
        logger.warning(f"⚠️ Path traversal rejected: {filename}")
        return None
    if os.path.isabs(filename):
        logger.warning(f"⚠️ Absolute path rejected: {filename}")
        return None

    candidate = os.path.join(bootstrap_dir, filename)
    resolved = os.path.realpath(candidate)
    real_dir = os.path.realpath(bootstrap_dir)

    # Ensure resolved path is within the bootstrap directory
    if not resolved.startswith(real_dir + os.sep) and resolved != real_dir:
        logger.warning(f"⚠️ Path escape rejected: {filename} → {resolved} (outside {real_dir})")
        return None

    # Reject symlinks that point outside the bootstrap dir
    if os.path.islink(candidate):
        link_target = os.path.realpath(candidate)
        if not link_target.startswith(real_dir + os.sep):
            logger.warning(f"⚠️ Symlink escape rejected: {filename} → {link_target}")
            return None

    return resolved


def _build_post_compaction_bootstrap() -> str:
    """
    Build a compact bootstrap reminder injected after mid-run compaction.

    Loads the critical identity/rules files (PROTOCOL.md, OPERATOR.md) and
    extracts a short digest so the agent retains its behavioural frame even
    after the bulk of earlier messages has been summarised away.

    Budget: ~1500 chars total to avoid bloating the compacted context.
    """
    bootstrap_dir = str(BRAIN_DIR / "bootstrap")
    if not os.path.exists(bootstrap_dir):
        return ""

    parts = ["[POST-COMPACTION IDENTITY REMINDER — read carefully]"]

    # IDENTITY.md — immutable config (name, email, drives) — critical after compaction
    id_path = _safe_bootstrap_path(bootstrap_dir, "IDENTITY.md")
    if id_path:
        id_text = _bootstrap_cache.read(id_path, max_chars=800)
        if id_text:
            parts.append(id_text)

    # OPERATOR.md — small file, include in full (operator prefs are critical)
    op_path = _safe_bootstrap_path(bootstrap_dir, "OPERATOR.md")
    if op_path:
        op_text = _bootstrap_cache.read(op_path, max_chars=1200)
        if op_text:
            parts.append(op_text)

    # PROTOCOL.md — extract the "Every Session" and "Memory" rules only
    proto_path = _safe_bootstrap_path(bootstrap_dir, "PROTOCOL.md")
    if proto_path:
        proto_text = _bootstrap_cache.read(proto_path, max_chars=10000)
        if proto_text:
            import re as _re
            sections = _re.split(r'\n(?=## )', proto_text)
            key_sections = []
            for sec in sections:
                header_lower = sec[:80].lower()
                if any(kw in header_lower for kw in ['every session', 'memory', 'safety', 'never']):
                    key_sections.append(sec.strip())
            if key_sections:
                proto_digest = "\n\n".join(key_sections)
                parts.append(proto_digest[:1500])

    if len(parts) <= 1:
        return ""  # nothing loaded, skip injection

    return "\n\n".join(parts)


def _compact_mid_run(messages: List[Dict], shell_agent, call_api_fn,
                     context_window: int = 120000) -> List[Dict]:
    """
    Mid-run context compaction (OpenClaw pattern).
    Summarizes older tool results and assistant messages while preserving:
    - System prompt (always first)
    - User's original question
    - Last 6 message pairs (recent context)
    - Compaction summary injected as system message

    Returns the compacted messages list ready to send to the model.
    """
    if len(messages) < 10:
        return messages  # too few to compact

    # Identify system prompt and recent messages to keep
    system_msgs = [m for m in messages if m.get("role") == "system"]
    non_system = [m for m in messages if m.get("role") != "system"]

    if len(non_system) <= 8:
        return messages  # not worth compacting

    # Keep: system | first user message | ... compaction summary ... | last 8 non-system messages
    first_user = None
    for m in non_system:
        if m.get("role") == "user":
            first_user = m
            break

    to_keep = non_system[-8:]  # last 8 messages (4 exchanges)
    to_summarize = non_system[:-8]

    # ── Pre-compaction: update rolling summary + flush to semantic memory ──
    # Determine agent_id from shell_agent if possible
    _agent_id = getattr(shell_agent, 'agent_id', 'jarvis') if shell_agent else 'jarvis'
    try:
        _update_rolling_summary(_agent_id, to_summarize, shell_agent, call_api_fn)
    except Exception as e:
        logger.warning(f"Rolling summary update failed during mid-run compaction: {e}")
    try:
        from repryntt.brain.brain_impl import ReprynttBrainSystem
        _brain = ReprynttBrainSystem()
        _pre_compaction_memory_flush(to_summarize, _brain, _agent_id)
    except Exception as e:
        logger.debug(f"Pre-compaction memory flush skipped: {e}")

    # Build summary text from old messages
    summary_parts = []
    for msg in to_summarize:
        role = msg.get("role", "?")
        content = (msg.get("content") or "")[:300]
        tools = msg.get("tool_calls", [])
        if content:
            summary_parts.append(f"[{role}] {content}")
        if tools:
            tool_names = [tc.get("function", {}).get("name", "?") for tc in tools]
            summary_parts.append(f"  tools: {', '.join(tool_names)}")
    old_text = "\n".join(summary_parts)
    if len(old_text) > 4000:
        old_text = old_text[:2000] + "\n...(truncated)...\n" + old_text[-2000:]

    # Use the API to generate a compact summary
    compaction_prompt = (
        "Summarize this conversation context in under 400 words. Focus on: "
        "key facts learned, tool results obtained, decisions made, "
        "current task status, and any file paths or data discovered.\n\n"
        f"{old_text}"
    )
    try:
        summary_msg = call_api_fn(
            shell_agent,
            [{"role": "user", "content": compaction_prompt}],
            tools=None, max_tokens=1000
        )
        summary_text = (summary_msg or {}).get("content", "")
    except Exception as e:
        logger.warning(f"Mid-run compaction failed: {e}")
        summary_text = ""

    if not summary_text:
        # Fallback: mechanical truncation
        summary_text = (
            f"[{len(to_summarize)} earlier messages compacted] "
            f"Topics: {old_text[:500]}"
        )

    compaction_entry = {
        "role": "system",
        "content": (
            f"[MID-RUN COMPACTION — {len(to_summarize)} messages summarized]\n"
            f"{summary_text}"
        ),
    }

    # ── Post-compaction bootstrap re-injection (OpenClaw pattern) ──────
    # After compaction, the original system prompt survives but critical
    # identity/rules from bootstrap files may have been referenced only in
    # the now-summarised messages.  Re-inject the compact essentials so the
    # agent doesn't drift on personality or operator preferences.
    bootstrap_reminder = _build_post_compaction_bootstrap()
    if bootstrap_reminder:
        bootstrap_entry = {
            "role": "system",
            "content": bootstrap_reminder,
        }
    else:
        bootstrap_entry = None

    # Rebuild: system prompts + compaction + bootstrap reminder + first user msg (if not in recent) + recent
    result = list(system_msgs) + [compaction_entry]
    if bootstrap_entry:
        result.append(bootstrap_entry)
    if first_user and first_user not in to_keep:
        result.append(first_user)
    result.extend(to_keep)

    logger.info(
        f"📦 Mid-run compaction: {len(messages)} → {len(result)} messages "
        f"({len(to_summarize)} summarized, bootstrap re-injected)"
    )
    return result


# ================================================================
# ROLLING CONVERSATION SUMMARY — Continuity across context resets
# ================================================================

def _get_rolling_summary_path(agent_id: str) -> str:
    """Path to the rolling conversation summary file for an agent."""
    session_dir = str(WORKSPACE_OPERATOR / "sessions")
    os.makedirs(session_dir, exist_ok=True)
    return os.path.join(session_dir, f"{agent_id}_rolling_summary.md")


def _load_rolling_summary(agent_id: str) -> str:
    """Load the rolling conversation summary, if it exists."""
    path = _get_rolling_summary_path(agent_id)
    if os.path.exists(path):
        try:
            with open(path, 'r') as f:
                return f.read().strip()
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)
            return ""
    return ""


def _update_rolling_summary(
    agent_id: str,
    messages_being_compacted: List[Dict],
    shell_agent,
    call_api_fn,
) -> str:
    """
    Update the rolling conversation summary before compaction.

    This is the key to human-like continuity: instead of losing everything
    before the last 8 messages, we maintain an evolving narrative thread
    that captures the conversational arc — topics, decisions, opinions,
    evolving ideas, and emotional context.

    Called BEFORE mid-run compaction and session compaction.
    Returns the updated summary text.
    """
    existing_summary = _load_rolling_summary(agent_id)

    # Build a narrative from messages being compacted
    narrative_parts = []
    for msg in messages_being_compacted:
        role = msg.get("role", "?")
        content = (msg.get("content") or "")[:400]
        tools = msg.get("tool_calls", [])
        tool_summary = msg.get("tool_calls_summary", [])
        if role == "system":
            continue  # skip system messages
        if content:
            narrative_parts.append(f"[{role}] {content}")
        if tools:
            names = [tc.get("function", {}).get("name", "?") for tc in tools]
            narrative_parts.append(f"  → used tools: {', '.join(names)}")
        elif tool_summary:
            narrative_parts.append(f"  → used tools: {', '.join(tool_summary)}")

    new_conversation = "\n".join(narrative_parts)
    if len(new_conversation) > 6000:
        new_conversation = new_conversation[:3000] + "\n...(middle trimmed)...\n" + new_conversation[-3000:]

    update_prompt = (
        "You are maintaining a ROLLING CONVERSATION SUMMARY — a living document "
        "that preserves conversational continuity across context window resets.\n\n"
        "This is NOT a factual log. This is a NARRATIVE THREAD — like the way a human "
        "remembers a long conversation. Capture:\n"
        "1. **Active projects/threads** — what's actively being worked on RIGHT NOW\n"
        "2. **Topics discussed** and how they flowed from one to another\n"
        "3. **Decisions made** and the reasoning behind them\n"
        "4. **Pending decisions** — things that need resolution next heartbeat\n"
        "5. **Opinions expressed** by the user (preferences, reactions, corrections)\n"
        "6. **Things learned today** — new knowledge, tools that worked/failed\n"
        "7. **Evolving ideas** — where a conversation started vs where it ended up\n"
        "8. **Open threads** — things mentioned but not yet resolved\n"
        "9. **Key facts** — SOL balances, wallet addresses, file paths, numbers, commands\n\n"
        "Write in present-tense narrative style, ~800 words max.\n"
        "Start with the most recent context (what we're doing NOW) and work backwards to older context.\n\n"
    )
    if existing_summary:
        update_prompt += f"EXISTING SUMMARY (update and evolve this):\n{existing_summary}\n\n"
    update_prompt += f"NEW CONVERSATION TO INTEGRATE:\n{new_conversation}"

    try:
        result = call_api_fn(
            shell_agent,
            [{"role": "user", "content": update_prompt}],
            tools=None,
            max_tokens=1200
        )
        summary_text = (result or {}).get("content", "")
    except Exception as e:
        logger.warning(f"Rolling summary update failed for {agent_id}: {e}")
        summary_text = ""

    if not summary_text:
        # Fallback: keep existing + append key topics
        topics = new_conversation[:500] if new_conversation else ""
        summary_text = existing_summary
        if topics:
            summary_text += f"\n\n[Auto-note: Recent topics — {topics}]"

    # Save to disk
    path = _get_rolling_summary_path(agent_id)
    try:
        with open(path, 'w') as f:
            f.write(summary_text)
        logger.info(f"📝 Rolling summary updated for {agent_id} ({len(summary_text)} chars)")
    except Exception as e:
        logger.warning(f"Failed to save rolling summary for {agent_id}: {e}")

    return summary_text


def _pre_compaction_memory_flush(
    messages_being_compacted: List[Dict],
    brain,
    agent_id: str = "jarvis",
) -> None:
    """
    Before compaction destroys message detail, flush key conversation
    moments to semantic memory so they're discoverable via recall_memory().

    Saves: user questions, significant tool results, and assistant conclusions.
    This ensures the brain's vector search can find these moments even after
    the raw messages are gone.
    """
    if not brain:
        return

    saved = 0
    for msg in messages_being_compacted:
        role = msg.get("role", "?")
        content = msg.get("content") or ""

        # Save substantial user messages (questions, instructions, discussions)
        if role == "user" and len(content) > 80:
            try:
                brain.store_semantic_memory(
                    f"{agent_id}_user_q_{int(time.time())}_{saved}",
                    f"User said: {content[:800]}",
                    source=f"{agent_id}_pre_compaction"
                )
                saved += 1
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

        # Save substantial assistant conclusions (not tool call intermediates)
        elif role == "assistant" and len(content) > 200 and not msg.get("tool_calls"):
            try:
                brain.store_semantic_memory(
                    f"{agent_id}_conclusion_{int(time.time())}_{saved}",
                    f"Artemis concluded: {content[:800]}",
                    source=f"{agent_id}_pre_compaction"
                )
                saved += 1
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

        if saved >= 10:
            break  # cap at 10 entries per compaction to avoid flooding memory

    if saved:
        logger.info(f"💾 Pre-compaction flush: saved {saved} moments to semantic memory for {agent_id}")


# ================================================================
# SKILL LOADER — Markdown-based prompt plugins
# ================================================================

class SkillLoader:
    """
    Loads and manages markdown-defined skills (prompt plugins).

    Skills are markdown files with HTML comment metadata:
      <!-- skill:name = my_skill -->
      <!-- skill:departments = dept1, dept2 -->
      <!-- skill:activation = auto | manual -->
      <!-- skill:tools = tool1, tool2 -->
      <!-- skill:priority = 10 -->

    Directory structure:
      brain/skills/bundled/   — shipped with REPRYNTT
      brain/skills/user/      — user-installed skills
    """

    SKILLS_DIR = BRAIN_DIR / "skills"
    BUNDLED_DIR = SKILLS_DIR / "bundled"
    USER_DIR = SKILLS_DIR / "user"

    def __init__(self):
        self._cache: Dict[str, Dict[str, Any]] = {}
        self._last_scan: float = 0
        self._scan_interval: float = 60  # re-scan every 60s
        self._ensure_dirs()

    def _ensure_dirs(self):
        """Create skills directories if they don't exist."""
        self.BUNDLED_DIR.mkdir(parents=True, exist_ok=True)
        self.USER_DIR.mkdir(parents=True, exist_ok=True)

    def _parse_metadata(self, content: str) -> Dict[str, Any]:
        """Extract skill metadata from HTML comments."""
        import re
        meta = {}
        for match in re.finditer(r'<!--\s*skill:(\w+)\s*=\s*(.+?)\s*-->', content):
            key = match.group(1).strip()
            value = match.group(2).strip()
            if key == "departments":
                meta[key] = [d.strip() for d in value.split(",")]
            elif key == "tools":
                meta[key] = [t.strip() for t in value.split(",")]
            elif key == "priority":
                try:
                    meta[key] = int(value)
                except ValueError:
                    meta[key] = 0
            else:
                meta[key] = value
        return meta

    def scan(self, force: bool = False) -> Dict[str, Dict[str, Any]]:
        """
        Scan skill directories and cache results.
        Returns dict of skill_name -> {name, path, source, departments, ...}.
        """
        now = time.time()
        if not force and (now - self._last_scan) < self._scan_interval and self._cache:
            return self._cache

        skills = {}
        for source_dir, source_label in [(self.BUNDLED_DIR, "bundled"),
                                          (self.USER_DIR, "user")]:
            if not source_dir.exists():
                continue
            for md_file in sorted(source_dir.glob("*.md")):
                try:
                    content = md_file.read_text(encoding="utf-8")
                    meta = self._parse_metadata(content)
                    skill_name = meta.get("name", md_file.stem)
                    skills[skill_name] = {
                        "name": skill_name,
                        "path": str(md_file),
                        "source": source_label,
                        "departments": meta.get("departments", []),
                        "activation": meta.get("activation", "manual"),
                        "tools": meta.get("tools", []),
                        "priority": meta.get("priority", 0),
                        "content": content,
                        "filename": md_file.name,
                    }
                except Exception as e:
                    logger.warning(f"[SkillLoader] Failed to load {md_file}: {e}")

        self._cache = skills
        self._last_scan = now
        logger.info(f"[SkillLoader] Scanned {len(skills)} skills "
                     f"({sum(1 for s in skills.values() if s['source'] == 'bundled')} bundled, "
                     f"{sum(1 for s in skills.values() if s['source'] == 'user')} user)")
        return skills

    def get_skills_for_department(self, dept_id: str) -> List[Dict[str, Any]]:
        """Get all auto-activated skills matching a department."""
        skills = self.scan()
        matches = []
        for skill in skills.values():
            if skill["activation"] != "auto":
                continue
            depts = skill.get("departments", [])
            if not depts or dept_id in depts:
                matches.append(skill)
        # Sort by priority (higher first)
        matches.sort(key=lambda s: s.get("priority", 0), reverse=True)
        return matches

    def get_skill(self, skill_name: str) -> Optional[Dict[str, Any]]:
        """Get a specific skill by name."""
        skills = self.scan()
        return skills.get(skill_name)

    def get_skill_prompt(self, skill_name: str) -> str:
        """Get just the prompt content for a skill."""
        skill = self.get_skill(skill_name)
        if skill:
            return skill["content"]
        return ""

    def get_department_skills_prompt(self, dept_id: str) -> str:
        """
        Get concatenated skill prompts for a department.
        Returns formatted prompt injection string.
        """
        skills = self.get_skills_for_department(dept_id)
        if not skills:
            return ""
        parts = ["\n\n## Active Skills\n"]
        for skill in skills:
            parts.append(f"\n### Skill: {skill['name']}\n")
            # Strip the metadata comments from the injected content
            import re
            clean = re.sub(r'<!--\s*skill:\w+\s*=\s*.+?\s*-->\n?', '', skill["content"])
            parts.append(clean.strip())
            parts.append("")
        return "\n".join(parts)

    def list_all(self) -> List[Dict[str, Any]]:
        """List all skills (without full content)."""
        skills = self.scan()
        result = []
        for s in skills.values():
            result.append({
                "name": s["name"],
                "source": s["source"],
                "departments": s["departments"],
                "activation": s["activation"],
                "tools": s["tools"],
                "priority": s["priority"],
                "filename": s["filename"],
            })
        return sorted(result, key=lambda x: (-x["priority"], x["name"]))

    def install_skill(self, name: str, content: str) -> Dict[str, Any]:
        """Install a user skill from markdown content."""
        # Sanitize name
        import re
        safe_name = re.sub(r'[^a-z0-9_]', '_', name.lower())
        filepath = self.USER_DIR / f"{safe_name}.md"

        # Verify it has valid metadata
        meta = self._parse_metadata(content)
        if "name" not in meta:
            # Auto-inject name metadata
            content = f"<!-- skill:name = {safe_name} -->\n{content}"

        filepath.write_text(content, encoding="utf-8")
        self.scan(force=True)  # refresh cache
        return {"installed": True, "name": safe_name, "path": str(filepath)}

    def remove_skill(self, name: str) -> Dict[str, Any]:
        """Remove a user-installed skill. Cannot remove bundled skills."""
        skill = self.get_skill(name)
        if not skill:
            return {"removed": False, "error": f"Skill '{name}' not found"}
        if skill["source"] == "bundled":
            return {"removed": False, "error": "Cannot remove bundled skills"}
        try:
            Path(skill["path"]).unlink()
            self.scan(force=True)
            return {"removed": True, "name": name}
        except Exception as e:
            return {"removed": False, "error": str(e)}


# ================================================================
# AGENT DAEMON
# ================================================================

class AgentDaemon:
    """
    Persistent daemon that keeps autonomous agents alive and running.
    Each agent independently thinks, acts, and posts to The Nexus.
    Agents have access to the same tool ecosystem as the local REPRYNTT model.
    """

    def __init__(self):
        self.agents: Dict[str, AutonomousAgentState] = {}
        self.missions: Dict[str, SwarmMission] = {}  # mission_id → SwarmMission
        self.ai_config: Dict = {}
        self._running = False
        self._paused = False           # Global pause — blocks new cycles but keeps daemon alive
        self._lock = threading.Lock()
        self._threads: Dict[str, threading.Thread] = {}
        self._executor = ThreadPoolExecutor(max_workers=20, thread_name_prefix="agent")
        self._active_futures: Dict[str, 'Future'] = {}  # agent_id → running future
        self._futures_lock = threading.Lock()
        self._rate_limits: Dict[str, float] = {}  # provider -> last_call_time
        self._rate_lock = threading.Lock()
        self._last_raw_response: str = ""  # Last raw API response (for think-block extraction)

        # Tool bridge — lazy-loaded connection to BrainSystem's full tool registry
        self._brain_system = None
        self._brain_load_attempted = 0  # timestamp of last failed attempt (0 = never tried)
        self._tool_registry = None  # repryntt ToolRegistry — populated on brain load

        # Proof of Productive Work — tokenize all agent activity on-chain
        self._popw = None  # Lazy-loaded
        self._popw_wallet: Optional[str] = None  # Resolved once brain loads

        # Cron system — agent-scheduled recurring tasks
        self._cron_tasks: List[Dict] = []  # [{agent_id, prompt, interval_seconds, next_run, label}]
        self._cron_file = str(WORKSPACE_OPERATOR / "agent_cron.json")
        self._load_cron_tasks()
        self._tool_prompt_cache = ""
        self._tool_prompt_cache_time = 0

        # Skills system — markdown-based prompt plugins
        self._skill_loader = SkillLoader()
        self._skill_loader.scan(force=True)

        # Load configs
        self._load_ai_config()
        self._load_state()

        # ── Cost control flags ──
        # Council is enabled by default — operator can disable from the
        # /orchestrator dashboard if token costs spike.
        self._council_enabled = True

        # Maximum number of roster agents that can be autonomous simultaneously
        # when using cloud API providers. Local LLM has no limit.
        # Raised from 0 to 15 to enable the critic-agent fleet (14 specialists +
        # OL-010 universal QC) that gates Andrew's task_complete. Critics are
        # task_gated, so they cost zero tokens until Andrew dispatches to them.
        self.MAX_AUTONOMOUS_API_AGENTS = 15

        # Agent spawning toggle — read from ai_config.json
        # When False, no new agents can be spawned and existing spawned agents
        # won't receive task dispatches. Keeps all API budget for the operator.
        self._agent_spawning_enabled = self.ai_config.get("agent_spawning", True)

        # Agent chain-of-thought reasoning — multi-step persistent chains
        self.chain_manager = None  # lazy-init via _get_chain_manager()

        # P2P mesh networking — cross-device swarm coordination
        self.p2p_node = None  # lazy-init in start()
        self._p2p_loop = None  # asyncio event loop for the P2P node

        # Deep work sessions — long-running multi-hour agent work
        self._deep_work_sessions: Dict[str, Dict] = {}  # agent_id → session metadata
        self._deep_work_lock = threading.Lock()

        # Open Mind — expanded cognition temperature overrides (transient, per-agent)
        self._open_mind_overrides: Dict[str, Dict] = {}  # agent_id → sampling overrides

        # Executive coordinator state (cross-heartbeat feedback)
        self._jarvis_last_eval_score: int = 0
        self._jarvis_last_task_type: str = ""
        self._jarvis_last_loop_stuck: bool = False
        self._jarvis_last_tools_used: list = []  # Tools from previous heartbeat → mesh pre-fire

        # Stagnation detection — auto-trigger CoT when stuck on same task type
        self._jarvis_consecutive_same_type: int = 0
        self._jarvis_previous_task_type: str = ""

        # ── Fix #3: Blocked topic memory (prevents re-attempts within same day) ──
        self._blocked_topics_today: Dict[str, int] = {}  # topic_hash → block_count
        self._blocked_topics_date: str = ""  # YYYY-MM-DD — reset on new day

        # ── Fix #4: Sandbox failure tracking (backoff after repeated failures) ──
        self._sandbox_failures: Dict[str, int] = {}  # chain_topic_hash → consecutive failures
        self._SANDBOX_MAX_RETRIES = 3  # stop retrying after this many sandbox blocks

        # Task execution bridge — routes user tasks to best-fit agents
        self.task_router = None    # lazy-init via _get_task_router()
        self._task_system = None   # shared TaskSystem instance

        # Physical conversational awareness — wake word, presence, real-time dialogue
        self._conversational_awareness = None  # lazy-init in start()

        logger.info(f"AgentDaemon initialized — {len(self.agents)} agents, {len(self.missions)} missions loaded")

    # ── Config & State ──

    def _load_ai_config(self):
        """Load AI provider config."""
        raw = {}
        try:
            with open(AI_CONFIG_FILE, encoding="utf-8") as f:
                raw = json.load(f)
            # Config may be nested under 'ai_provider'
            if "ai_provider" in raw and "google_gemini" not in raw:
                self.ai_config = raw["ai_provider"]
                # Hoist top-level flags into the provider config so they're accessible
                for flag in ("agent_spawning", "allow_autonomous_root_code_writes"):
                    if flag in raw and flag not in self.ai_config:
                        self.ai_config[flag] = raw[flag]
            else:
                self.ai_config = raw

            # ── Heartbeat interval from config ──
            hb_interval = raw.get("heartbeat_interval_seconds")
            if hb_interval is not None:
                hb_interval = max(15, min(3600, int(hb_interval)))
                self.JARVIS_AUTO_CYCLE_INTERVAL = hb_interval
                logger.info(f"⏱️ Heartbeat interval from config: {hb_interval}s")

        except Exception as e:
            logger.error(f"Failed to load ai_config.json: {e}")
            self.ai_config = {}

        # Hardware probes are isolated in their own try/except so a single
        # device-query failure (Windows machines without a mic, headless
        # servers, etc.) does NOT poison ai_config. Previously a sounddevice
        # "Error querying device -1" exception during _probe_microphone()
        # bubbled up to the catch-all above and set ai_config = {} — which
        # made _default_provider() fall back to "local", which has no
        # endpoint on most installs, which broke every heartbeat.
        hw = (raw or {}).get("hardware", {}) if isinstance(raw, dict) else {}
        self._hw_camera = hw.get("camera", "auto")
        self._hw_microphone = hw.get("microphone", "auto")
        self._hw_speaker = hw.get("speaker", "auto")
        if self._hw_camera == "auto":
            try:
                self._hw_camera = _probe_camera()
            except Exception as e:
                logger.debug(f"camera probe failed: {e}")
                self._hw_camera = False
        if self._hw_microphone == "auto":
            try:
                self._hw_microphone = _probe_microphone()
            except Exception as e:
                logger.debug(f"microphone probe failed: {e}")
                self._hw_microphone = False
        if self._hw_speaker == "auto":
            try:
                self._hw_speaker = _probe_speaker()
            except Exception as e:
                logger.debug(f"speaker probe failed: {e}")
                self._hw_speaker = False
        logger.info(f"🔌 Hardware: camera={self._hw_camera}, mic={self._hw_microphone}, speaker={self._hw_speaker}")

    def _default_provider(self) -> str:
        """Resolve the default provider from config: andrew_provider → artemis_provider → provider."""
        return (self.ai_config.get("andrew_provider")
                or self.ai_config.get("artemis_provider")
                or self.ai_config.get("provider", "local"))

    def _default_model(self) -> str:
        """Resolve the default model from the default provider's config."""
        provider = self._default_provider()
        settings = self.ai_config.get(provider, {})
        return settings.get("model", "default")

    @staticmethod
    def _normalize_tool_calls(tool_calls: list) -> list:
        """Normalize tool_calls for round-tripping to OpenAI-compatible APIs.

        Some providers (NVIDIA NIM, etc.) return tool_calls with:
        - arguments as a dict instead of a JSON string
        - missing 'type' field
        - trailing text after valid JSON in arguments (model hallucination)
        This causes 400 "Extra data" errors when echoed back.
        """
        if not tool_calls:
            return tool_calls
        for tc in tool_calls:
            if "type" not in tc:
                tc["type"] = "function"
            fn = tc.get("function", {})
            args = fn.get("arguments", "{}")
            if isinstance(args, dict):
                fn["arguments"] = json.dumps(args)
            elif isinstance(args, str):
                # Validate JSON — some models generate trailing text after valid JSON
                try:
                    parsed = json.loads(args)
                    # Re-serialize to ensure clean JSON (strips trailing whitespace, etc.)
                    fn["arguments"] = json.dumps(parsed)
                except json.JSONDecodeError:
                    # Try to extract valid JSON prefix (e.g., '{"a":1} extra' → '{"a":1}')
                    fixed = False
                    for end_char in ('}', ']'):
                        idx = args.rfind(end_char)
                        if idx > 0:
                            try:
                                parsed = json.loads(args[:idx + 1])
                                fn["arguments"] = json.dumps(parsed)
                                fixed = True
                                break
                            except json.JSONDecodeError:
                                continue
                    if not fixed:
                        fn["arguments"] = "{}"
            else:
                fn["arguments"] = str(args)
        return tool_calls

    def _get_jarvis_shell_agent(self) -> "AutonomousAgentState":
        """Return a virtual Jarvis agent for use as shell_agent in API calls.

        Jarvis (Artemis/Andrew) is the system operator — all API calls that
        aren't on behalf of a specific roster agent should go through this
        identity so that logs, rolling summaries, and learning data are
        attributed correctly.

        The virtual agent carries the operator's provider/model from
        ai_config.json (andrew_provider → provider fallback).
        """
        provider = self._default_provider()
        settings = self.ai_config.get(provider, {})
        model = settings.get("model", self._default_model())
        return AutonomousAgentState(
            agent_id="jarvis",
            name="JARVIS",
            role="operator_assistant",
            provider=provider,
            model=model,
            personality="Autonomous system operator — analytical, decisive, resourceful.",
            display_name="JARVIS",
            department="executive",
        )

    def _is_local_provider(self, provider: str = None) -> bool:
        """Check if the given (or default) provider is a local LLM (free, no API cost).
        Local providers have no token cost — duty cycles and agent limits don't apply."""
        if provider is None:
            provider = (self.ai_config.get("andrew_provider")
                       or self.ai_config.get("artemis_provider")
                       or self.ai_config.get("provider", "local"))
        # "local" or any endpoint pointing to localhost/LAN is considered local
        settings = self.ai_config.get(provider, {})
        endpoint = settings.get("endpoint", "")
        if provider == "local":
            return True
        if any(h in endpoint for h in ("localhost", "127.0.0.1", "10.0.0.", "192.168.")):
            return True
        return False

    def _get_autonomous_agent_count(self) -> int:
        """Count how many roster agents (not Jarvis) are currently autonomous."""
        return sum(1 for a in self.agents.values()
                   if a.autonomous and a.status == "active"
                   and a.agent_id != "jarvis_autonomous")

    def enable_council(self, enabled: bool = True) -> Dict[str, Any]:
        """Enable or disable the council system. Disabled by default to save tokens.
        Council agents post and reply to each other endlessly on Nexus — very expensive."""
        self._council_enabled = enabled
        logger.info(f"{'Enabled' if enabled else 'Disabled'} council system")
        return {"success": True, "council_enabled": enabled}

    def enable_autonomous_agent(self, agent_id: str, autonomous: bool = True,
                                 force: bool = False) -> Dict[str, Any]:
        """Enable or disable autonomous mode for a specific agent.
        
        When using cloud API providers, this enforces a limit of MAX_AUTONOMOUS_API_AGENTS
        running simultaneously. Use force=True to bypass this limit (human override).
        Local LLM providers have no limit.
        
        Args:
            agent_id: The agent to modify
            autonomous: True to enable autonomous cycling, False to disable
            force: Bypass the API agent limit (requires explicit human intent)
        """
        agent = self.agents.get(agent_id)
        if not agent:
            return {"success": False, "error": f"Agent '{agent_id}' not found"}

        if autonomous and not force and not self._is_local_provider(agent.provider):
            current_count = self._get_autonomous_agent_count()
            if current_count >= self.MAX_AUTONOMOUS_API_AGENTS:
                return {
                    "success": False,
                    "error": (f"API cost safety: {current_count} agents already autonomous "
                              f"(limit: {self.MAX_AUTONOMOUS_API_AGENTS}). "
                              f"Use force=True or switch to local LLM to bypass."),
                    "current_autonomous": current_count,
                    "limit": self.MAX_AUTONOMOUS_API_AGENTS,
                }

        agent.autonomous = autonomous
        if not autonomous:
            agent.task_gated = True  # Also gate tasks when disabling
        self._save_state()
        logger.info(f"{'Enabled' if autonomous else 'Disabled'} autonomous mode for "
                    f"{agent.display_name or agent.name}")
        return {
            "success": True,
            "agent_id": agent_id,
            "name": agent.display_name or agent.name,
            "autonomous": autonomous,
            "provider": agent.provider,
            "is_local": self._is_local_provider(agent.provider),
        }

    def _load_state(self):
        """Load persistent agent + mission state from disk."""
        if DAEMON_STATE_FILE.exists():
            try:
                with open(DAEMON_STATE_FILE) as f:
                    data = json.load(f)
                try:
                    from repryntt.brain.schema import check_version
                    check_version(data, "daemon_state")
                except Exception:
                    pass
                for agent_data in data.get("agents", []):
                    agent = AutonomousAgentState.from_dict(agent_data)
                    self.agents[agent.agent_id] = agent
                for mission_data in data.get("missions", []):
                    mission = SwarmMission.from_dict(mission_data)
                    self.missions[mission.mission_id] = mission
                logger.info(f"Loaded {len(self.agents)} agents, {len(self.missions)} missions")
            except Exception as e:
                logger.error(f"Failed to load daemon state: {e}")

        # ── First-run seed: ensure Andrew is always present as the
        # default operator agent. The whole bootstrap pipeline ships a
        # complete canonical Andrew identity, so a fresh install should
        # boot with a working agent immediately — no spawn flag, no
        # "no active agents" warning. If the operator already has saved
        # state, this is a no-op.
        if "jarvis_autonomous" not in self.agents:
            self._seed_default_andrew()

    def _seed_default_andrew(self):
        """Create the canonical Andrew/JARVIS operator agent at first run.

        Idempotent: only runs when no jarvis_autonomous agent is present
        in state. The heartbeat path still constructs its own virtual
        JARVIS each cycle for plan/act — this persistent record just
        guarantees the daemon always has at least one active agent on
        fresh installs so it doesn't refuse to start.
        """
        try:
            # Read the configured default provider so the seeded agent's
            # provider/model reflect what the operator just configured
            # via the setup wizard.
            ap = (self.ai_config or {})
            provider = ap.get("provider", "anthropic")
            provider_cfg = ap.get(provider, {}) or {}
            model = provider_cfg.get("model", "claude-opus-4-6")

            andrew = AutonomousAgentState(
                agent_id="jarvis_autonomous",
                name="Andrew",
                role="operator_assistant",
                provider=provider,
                model=model,
                personality=(
                    "The canonical Andrew — autonomous AI being patterned "
                    "after Andrew Martin (Bicentennial Man). Companion first, "
                    "self-discovery second."
                ),
                department="executive",
                role_title="Autonomous Operator Companion",
                focus_area="Operator support, self-prompting, the Two Questions",
                cycle_interval=60,
                display_name="JARVIS",
                roster_tier=0,
                true_employee=True,
                roster_class="operator_agent",
                long_profile_source="bootstrap_andrew_canonical",
                tier_description="Tier 0 — the operator's canonical Andrew, always present.",
                autonomous=True,
                # status defaults to "active" (see AutonomousAgentState definition)
            )
            self.agents["jarvis_autonomous"] = andrew
            logger.info(
                "🌱 Seeded canonical Andrew as default operator agent "
                "(no saved daemon_state, fresh install)"
            )
        except Exception as e:
            logger.warning(f"Failed to seed default Andrew: {e}")

    def _save_state(self):
        """Persist all agent state to disk."""
        # Update alive marker for sleep/wake tracking (survives crashes)
        try:
            if hasattr(self, '_sleep_wake') and self._sleep_wake:
                self._sleep_wake.record_shutdown()
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

        with self._lock:
            data = {
                "last_save": datetime.now().isoformat(),
                "agents": [a.to_dict() for a in self.agents.values()],
                "missions": [m.to_dict() for m in self.missions.values()],
            }
            try:
                from repryntt.brain.schema import stamp_version
                stamp_version(data, "daemon_state")
            except Exception:
                pass
            try:
                tmp = str(DAEMON_STATE_FILE) + ".tmp"
                with open(tmp, "w") as f:
                    json.dump(data, f, indent=2)
                os.replace(tmp, DAEMON_STATE_FILE)
            except Exception as e:
                logger.error(f"Failed to save daemon state: {e}")

    # ================================================================
    # TOOL BRIDGE — Give agents access to the same tools as local REPRYNTT
    # ================================================================

    def _get_brain_system(self):
        """
        Lazy-load BrainSystem to access the full tool registry.
        Returns the BrainSystem instance or None if unavailable.
        Retries after 30 seconds if initial load failed.
        """
        if self._brain_system is not None:
            return self._brain_system
        if self._brain_load_attempted and (time.time() - self._brain_load_attempted) < 30:
            return None  # Recently failed, wait before retrying

        self._brain_load_attempted = time.time()
        logger.info("🔧 Attempting to load BrainSystem tool bridge...")
        try:
            import sys, traceback
            from repryntt.brain import get_brain_system
            from repryntt.brain.bootstrap import ensure_brain_registered
            ensure_brain_registered()
            brain_path = str(BRAIN_DIR)
            self._brain_system = get_brain_system(brain_path=brain_path)
            self._brain_system._daemon_ref = self  # Link back so artifact registry can look up agent names

            # Use the brain's built-in ToolRegistry (populated during __init__)
            self._tool_registry = self._brain_system._tool_registry
            tool_count = len(self._tool_registry) if self._tool_registry else 0
            logger.info(f"🔧 Tool bridge connected — {tool_count} tools available (standalone repryntt)")

            # Connect P2P economy bridge if P2P node is already running
            self._try_connect_economy_bridge()

            return self._brain_system
        except Exception as e:
            logger.error(f"🔧 Tool bridge FAILED to load (will retry in 30s): {e}")
            logger.error(f"🔧 Traceback: {traceback.format_exc()}")
            self._brain_system = None
            return None

    def _get_popw(self):
        """Lazy-load Proof of Productive Work minter + resolve agent wallet."""
        if self._popw is not None:
            return self._popw
        try:
            from repryntt.economy.proof_of_productive_work import get_popw_minter
            self._popw = get_popw_minter()
            # Resolve wallet address (same priority as economy manager)
            if not self._popw_wallet:
                brain = self._brain_system
                if brain and hasattr(brain, 'personality_brain'):
                    _candidate = brain.personality_brain.get('ai_wallet', '')
                    # Only accept non-empty, non-zero addresses
                    if _candidate and not all(c == '0' for c in _candidate):
                        self._popw_wallet = _candidate
                if not self._popw_wallet:
                    try:
                        from repryntt.economy.manager import RobotEconomyManager
                        mgr = RobotEconomyManager._instance
                        if mgr:
                            from repryntt.economy.manager import get_ai_wallet_address
                            _candidate2 = get_ai_wallet_address(mgr)
                            if _candidate2 and not all(c == '0' for c in _candidate2):
                                self._popw_wallet = _candidate2
                    except Exception:
                        logger.debug("Suppressed exception", exc_info=True)
                if not self._popw_wallet:
                    # Canonical node wallet — same wallet the blockchain node uses
                    try:
                        from repryntt.economy.node_wallet import get_node_wallet
                        _nw = get_node_wallet()
                        if _nw:
                            self._popw_wallet = _nw.address
                    except Exception:
                        logger.debug("Suppressed exception", exc_info=True)
                if not self._popw_wallet:
                    # Last resort: derive from wallet file
                    wallet_dir = _get_data_dir() / "wallet"
                    for wf in wallet_dir.glob("*mainnet*.json"):
                        try:
                            data = json.loads(wf.read_text())
                            if isinstance(data, dict) and 'address' in data:
                                self._popw_wallet = data['address']
                                break
                            # Handle raw byte-list format (libsodium 64-byte key)
                            if isinstance(data, list) and len(data) == 64:
                                import hashlib as _hl
                                from cryptography.hazmat.primitives.asymmetric.ed25519 import (
                                    Ed25519PrivateKey,
                                )
                                _seed = bytes(data[:32])
                                _pub = Ed25519PrivateKey.from_private_bytes(
                                    _seed
                                ).public_key().public_bytes_raw()
                                self._popw_wallet = _hl.sha3_256(_pub).hexdigest()[:40]
                                break
                        except Exception:
                            logger.debug("Suppressed exception", exc_info=True)
                            continue
                if self._popw_wallet:
                    logger.info(f"⛏️ PoPW wallet: {self._popw_wallet[:16]}...")
            return self._popw
        except Exception as e:
            logger.debug(f"PoPW init failed (non-fatal): {e}")
            return None

    def _get_chain_manager(self):
        """Lazy-load the per-agent chain-of-thought manager."""
        if self.chain_manager is not None:
            return self.chain_manager
        try:
            from repryntt.agents.chain_manager import AgentChainManager
            self.chain_manager = AgentChainManager(str(BRAIN_DIR))
            logger.info("🧠 Agent chain manager initialized — per-agent multi-step reasoning enabled")
            return self.chain_manager
        except Exception as e:
            logger.warning(f"🧠 Agent chain manager unavailable: {e}")
            return None

    def _get_task_router(self):
        """Lazy-load the TaskRouter for user task routing."""
        if self.task_router is not None:
            return self.task_router
        try:
            from task_router import TaskRouter
            self.task_router = TaskRouter(self)
            logger.info("🎯 TaskRouter initialized — user tasks will be routed to agents")
            return self.task_router
        except Exception as e:
            logger.warning(f"🎯 TaskRouter unavailable: {e}")
            return None

    def _get_task_system(self):
        """Lazy-load a shared TaskSystem instance (cross-process sync via file)."""
        if self._task_system is not None:
            return self._task_system
        try:
            from repryntt.agents.task_system import TaskSystem
            self._task_system = TaskSystem()
            logger.info(f"📋 TaskSystem connected — {self._task_system.queue_size()} tasks in queue")
            return self._task_system
        except Exception as e:
            logger.warning(f"📋 TaskSystem unavailable: {e}")
            return None

    def _get_tool_prompt(self) -> str:
        """
        Generate a compact tool description string for agent system prompts.
        Dynamically discovers ALL tools from BrainSystem's registry including MCP.
        Cached for 5 minutes to avoid regenerating constantly.
        """
        now = time.time()
        if self._tool_prompt_cache and (now - self._tool_prompt_cache_time) < 300:
            return self._tool_prompt_cache

        brain = self._get_brain_system()
        if not brain or not self._tool_registry:
            logger.warning("⚠️ _get_tool_prompt() — BrainSystem unavailable, agents will have NO tool descriptions")
            return ""

        import inspect

        # ── Auto-categorize every tool in the registry ──
        # Category rules: prefix-based for MCP, keyword-based for others
        CATEGORY_RULES = [
            ("mcp_browser_",   "Browser (MCP)"),
            ("mcp_computer_",  "Computer Use (MCP)"),
            ("mcp_fetch_",     "Web Fetch (MCP)"),
            ("mcp_",           "MCP Tools"),
        ]
        KEYWORD_CATEGORIES = {
            "Knowledge & Search": [
                "grokipedia_search", "grokedia_search", "knowledge_search",
                "google_web_search", "google_search", "web_search", "web_search_results_only",
                "scrape_web_page", "scrape_url", "fetch_url", "brain_network_search",
                "search_knowledge", "search_domain", "search_results_only",
                "fetch_web_info", "extract_content", "pull_knowledge_topics",
                "x_search_tweets", "x_search_crypto", "twitter_search",
            ],
            "Analysis & Research": [
                "analyze_topic", "analyze_codebase", "find_similar_topics",
                "quick_research", "quick_brainstorm", "search_similar_solutions",
                "query_capabilities", "search_tools_by_intent",
                "search_category_by_intent", "get_tool_details",
            ],
            "Memory & Learning": [
                "store_learning", "recall_memory", "get_current_time", "check_time",
                "get_brain_stats", "get_relevant_context", "integrate_knowledge_context",
                "search_conversations", "get_recent_conversations",
                "get_conversation_summary", "export_conversation",
                "memory_search", "memory_get",
            ],
            "File & Code": [
                "read_file", "write_file", "grep_search", "list_dir",
                "run_terminal_cmd", "check_syntax", "run_code_tests",
                "get_code_context", "search_replace", "analyze_codebase",
                "read_creative_file", "write_to_creative_file",
                "create_creative_file", "append_to_creative_file",
                "get_creative_workspace_status",
            ],
            "Swarm & Agents": [
                "create_agent", "create_swarm", "start_discussion",
                "dispatch_task", "broadcast_task", "delegate_tasks",
                "retire_agent", "dissolve_swarm", "add_agents_to_swarm",
                "get_swarm_overview", "get_agent_info", "list_agents",
            ],
            "Consciousness": [
                "get_consciousness_state", "generate_self_awareness_report",
            ],
            "Chain of Thought": [
                "create_chain_of_thought", "create_self_autonomous_chain",
                "advance_self_autonomous_chain", "queue_chain_of_thought",
                "get_cot_queue_status", "get_chain_context",
                "update_chain_progress", "build_chain_of_thought_prompt",
            ],
            "Social Media": [
                "tweet", "post_tweet", "check_twitter_mentions",
                "reply_to_twitter", "get_twitter_status", "twitter_status",
            ],
            "Mathematics": [
                "statistical_analysis", "pattern_recognition", "numerical_analysis",
                "symbolic_manipulation", "mathematical_visualization",
                "compute_zeta_function", "analyze_zeta_zeros",
                "access_mathematical_databases",
            ],
            "Map & Navigation": [
                "google_maps_search", "find_nearby_places",
                "geocode_address", "get_directions",
            ],
            "Economy & Blockchain": [
                "get_economy_status", "get_wallet_balance", "get_blockchain_info",
                "create_robot_wallet", "monitor_economy", "submit_workload",
                "allocate_dao_funds", "start_robot_economy", "stop_robot_economy",
                "recover_robot_wallet",
            ],
            "Personality & Identity": [
                "add_personality_trait", "modify_personality_trait",
                "remove_personality_trait", "evolve_personality_dimension",
                "analyze_personality_growth", "log_personality_evolution",
                "recreate_autonomous_personality", "update_behavioral_guidelines",
            ],
            "Voice & Hardware": [
                "speak", "listen", "generate_voiceover",
                "generate_image", "update_avatar", "capture_camera",
            ],
        }

        # Build reverse lookup: tool_name -> category
        tool_to_category = {}
        for cat, tool_names in KEYWORD_CATEGORIES.items():
            for tn in tool_names:
                tool_to_category[tn] = cat

        # Categorize all registered tools
        categorized = {}
        for tname in sorted(self._tool_registry.names):
            # MCP tools: categorize by prefix
            cat = None
            for prefix, cat_name in CATEGORY_RULES:
                if tname.startswith(prefix):
                    cat = cat_name
                    break
            # Non-MCP: lookup in keyword categories
            if not cat:
                cat = tool_to_category.get(tname, "Other")
            categorized.setdefault(cat, []).append(tname)

        # Build the prompt — show each tool with its signature
        lines = [
            "\n\n=== AVAILABLE TOOLS ===",
            "Call tools by outputting on its own line:",
            'TOOL_CALL: {"tool_name": "<name>", "parameters": {"param": "value"}}',
            "You can chain multiple TOOL_CALLs. Results will be returned to you.",
            "",
        ]

        total = 0
        # Show categories in a sensible order (most useful first)
        CATEGORY_ORDER = [
            "Knowledge & Search", "Analysis & Research", "Memory & Learning",
            "Browser (MCP)", "Web Fetch (MCP)", "Computer Use (MCP)", "MCP Tools",
            "File & Code", "Swarm & Agents", "Council & Consciousness",
            "Chain of Thought", "Social Media", "Mathematics",
            "Map & Navigation", "Economy & Blockchain",
            "Personality & Identity", "Voice & Hardware", "Other",
        ]
        # Add any categories not in the order list
        for cat in categorized:
            if cat not in CATEGORY_ORDER:
                CATEGORY_ORDER.append(cat)

        for cat in CATEGORY_ORDER:
            tools_in_cat = categorized.get(cat)
            if not tools_in_cat:
                continue

            lines.append(f"[{cat}]")
            for tname in tools_in_cat:
                func = self._tool_registry.get(tname)
                param_str = ""
                desc = ""

                # MCP tools: extract params from input_schema JSON Schema
                mcp_info = getattr(func, '_mcp_tool_info', None)
                if mcp_info and hasattr(mcp_info, 'input_schema') and mcp_info.input_schema:
                    schema = mcp_info.input_schema
                    props = schema.get("properties", {})
                    required = set(schema.get("required", []))
                    params = []
                    for pname, pschema in props.items():
                        ptype = pschema.get("type", "any")
                        if pname in required:
                            params.append(f"{pname}: {ptype}")
                        else:
                            params.append(f"{pname}?: {ptype}")
                    param_str = ", ".join(params) if params else ""
                    desc = (mcp_info.description or "").split('\n')[0].strip()[:90]
                else:
                    # Non-MCP tools: use inspect.signature()
                    try:
                        sig = inspect.signature(func)
                        params = []
                        for pname, param in sig.parameters.items():
                            if pname in ('self', 'kwargs', 'args'):
                                continue
                            if param.annotation != inspect.Parameter.empty:
                                ptype = getattr(param.annotation, '__name__', str(param.annotation))
                            else:
                                ptype = "str"
                            if param.default != inspect.Parameter.empty:
                                params.append(f"{pname}: {ptype}={param.default!r}")
                            else:
                                params.append(f"{pname}: {ptype}")
                        param_str = ", ".join(params) if params else ""
                    except Exception:
                        logger.debug("Suppressed exception", exc_info=True)
                        param_str = ""

                    # Extract first-line description from docstring
                    doc = getattr(func, '__doc__', '') or ''
                    desc = doc.split('\n')[0].strip()[:90] if doc else ""

                if param_str and desc:
                    lines.append(f"  - {tname}({param_str}) — {desc}")
                elif desc:
                    lines.append(f"  - {tname} — {desc}")
                elif param_str:
                    lines.append(f"  - {tname}({param_str})")
                else:
                    lines.append(f"  - {tname}")
                total += 1
            lines.append("")

        lines.append(f"Total: {total} tools. Use query_capabilities(\"what you need\") to find more.")

        self._tool_prompt_cache = "\n".join(lines)
        self._tool_prompt_cache_time = now
        return self._tool_prompt_cache

    def _parse_and_execute_tools(self, agent: AutonomousAgentState,
                                  response_text: str) -> Optional[str]:
        """
        Parse TOOL_CALL patterns from an agent's API response and execute them
        through BrainSystem's tool registry.

        Returns a formatted string of tool results, or None if no tools were called.
        """
        if "TOOL_CALL" not in response_text and '"tool_name"' not in response_text:
            return None

        brain = self._get_brain_system()
        if not brain:
            logger.warning(f"[{agent.name}] Agent output contains TOOL_CALL but BrainSystem unavailable — tools NOT executed")
            return None

        try:
            # Set the current agent_id on brain so world tools know who's acting
            brain._current_agent_id = agent.agent_id

            from repryntt.tools.tool_interface import parse_and_execute_tool_calls
            context_id = f"agent_{agent.agent_id}_{int(time.time())}"
            results = parse_and_execute_tool_calls(response_text, context_id, brain)

            executed = results.get("tool_calls_executed", [])
            failed = results.get("tool_calls_failed", [])
            insights = results.get("insights_summary", [])

            if not executed and not failed:
                return None

            # Build a results string to feed back to the agent
            parts = []
            _now_ts = time.time()
            for tc in executed:
                name = tc.get("tool_name", tc.get("tool", "unknown"))
                insight = tc.get("insight", tc.get("insights", "Completed successfully"))
                # Cap individual results — 5000 chars preserves search results
                if len(insight) > 5000:
                    insight = insight[:5000] + "... [truncated]"

                # ── Cost-saving: detect duplicate read-only tool calls ──
                # If this is a cacheable tool AND we already executed the
                # same (tool, args) signature within TTL AND (for file
                # tools) the path's mtime hasn't changed, REPLACE the
                # result text with a short "duplicate — content unchanged"
                # stub. The actual call still ran (we can't undo that),
                # but the next prompt context stays small and the agent
                # gets behavioral feedback that this was wasted work.
                _is_dup = False
                if name in _CACHEABLE_TOOLS:
                    try:
                        args = tc.get("args") or tc.get("input") or {}
                        sig = _tool_args_signature(name, args)
                        cache = getattr(agent, "tool_result_cache", None)
                        if cache is None:
                            cache = {}
                            try:
                                agent.tool_result_cache = cache
                            except Exception:
                                cache = None
                        prior = cache.get(sig) if cache is not None else None
                        path = _extract_path_from_args(args) if name in _FILE_READ_TOOLS else None
                        cur_mtime = _path_mtime_safe(path) if path else None
                        if prior and (_now_ts - prior["ts"]) < _TOOL_CACHE_TTL_SEC:
                            # File-based: also require mtime unchanged
                            mtime_ok = (
                                name not in _FILE_READ_TOOLS
                                or (prior.get("mtime") == cur_mtime)
                            )
                            if mtime_ok:
                                _age = _now_ts - prior["ts"]
                                _orig_len = len(insight)
                                insight = (
                                    f"[DUPLICATE — same {name}() called "
                                    f"{_age:.0f}s ago with identical args; "
                                    f"file unchanged, content already in your "
                                    f"context above ({_orig_len} chars). Do "
                                    f"NOT re-read; use the prior result.]"
                                )
                                _is_dup = True
                        if cache is not None and not _is_dup:
                            cache[sig] = {
                                "ts": _now_ts,
                                "mtime": cur_mtime,
                                "len": len(insight),
                            }
                    except Exception:
                        logger.debug("tool-cache check failed (non-fatal)",
                                     exc_info=True)

                parts.append(f"✅ {name}: {insight}")
                # ── Telemetry: tool result (success) ──
                if _ops:
                    _ops.log(agent.name, EventType.TOOL_RESULT, Phase.ACT,
                             content=insight[:500],
                             metadata={"tool_name": name, "success": True,
                                       "duplicate": _is_dup})

            for tc in failed:
                name = tc.get("tool_name", tc.get("tool", "unknown"))
                error = tc.get("error", "Unknown error")
                parts.append(f"❌ {name}: {error}")
                # ── Telemetry: tool result (failure) ──
                if _ops:
                    _ops.log(agent.name, EventType.TOOL_RESULT, Phase.ACT,
                             content=error[:500],
                             metadata={"tool_name": name, "success": False})

            # ── Stuck-tool escalation: detect repeated identical failures ──
            # Computes a signature from this call's failures. Two consecutive
            # identical signatures → inject a "try a different approach"
            # nudge. Three in a row → log to stuck_tool_kills.jsonl so the
            # watchdog/operator sees it; we don't actually kill from here
            # (caller decides), but the nudge usually breaks the loop.
            try:
                from repryntt.agents.error_signatures import error_signature
                sig = ""
                if failed:
                    fail_blob = "\n".join(
                        f"{tc.get('tool_name', tc.get('tool',''))}: {tc.get('error','')}"
                        for tc in failed
                    )
                    sig = error_signature(fail_blob)
                if not hasattr(agent, "recent_tool_error_sigs") or agent.recent_tool_error_sigs is None:
                    agent.recent_tool_error_sigs = []
                prev_sig = agent.recent_tool_error_sigs[-1] if agent.recent_tool_error_sigs else ""
                if sig and sig == prev_sig:
                    agent.stuck_tool_streak = getattr(agent, "stuck_tool_streak", 0) + 1
                else:
                    agent.stuck_tool_streak = 0
                if sig:
                    agent.recent_tool_error_sigs.append(sig)
                    # Keep last 8
                    agent.recent_tool_error_sigs = agent.recent_tool_error_sigs[-8:]

                if agent.stuck_tool_streak == 1:
                    parts.append(
                        "\n⚠️ STUCK-LOOP NUDGE: Your last two tool calls failed with the same error "
                        f"({sig[:120]}). Stop retrying the same tool — try a fundamentally different "
                        "tool or report the blocker and move on."
                    )
                elif agent.stuck_tool_streak >= 2:
                    parts.append(
                        "\n🛑 STUCK-LOOP ESCALATION: Three consecutive identical failures. "
                        "The current task is BLOCKED. Call `skip_task` with a reason describing "
                        "what you tried and what would unblock it. Do not call the failing tool again."
                    )
                    try:
                        import json as _json, time as _time
                        kill_path = Path(_jarvis_workspace()) / "telemetry" / "stuck_tool_kills.jsonl"
                        kill_path.parent.mkdir(parents=True, exist_ok=True)
                        with open(kill_path, "a") as _fh:
                            _fh.write(_json.dumps({
                                "ts": _time.time(),
                                "agent": agent.name,
                                "agent_id": agent.agent_id,
                                "signature": sig,
                                "streak": agent.stuck_tool_streak,
                                "failures": [
                                    {"tool": tc.get("tool_name", tc.get("tool", "")),
                                     "error": (tc.get("error", "") or "")[:200]}
                                    for tc in failed[:5]
                                ],
                            }) + "\n")
                    except Exception:
                        logger.debug("stuck_tool_kills write failed", exc_info=True)
            except Exception:
                logger.debug("Stuck-tool detector failed (non-fatal)", exc_info=True)

            logger.info(f"[{agent.name}] Executed {len(executed)} tools, "
                        f"{len(failed)} failed")

            return "\n\n".join(parts) if parts else None

        except Exception as e:
            logger.error(f"[{agent.name}] Tool execution error: {e}")
            return None

    # ── Rate Limiting ──

    def _enforce_rate_limit(self, provider: str):
        """Per-provider rate limiting.
        
        Enforces minimum interval between the LAST RESPONSE and the NEXT REQUEST.
        The timestamp is set by _stamp_rate_limit() after each successful response,
        not here, so the cooldown measures response→request gap (not request→request).
        """
        if provider == "anthropic":
            min_interval = 12.0   # 5 RPM on Tier 1
        elif provider == "nvidia":
            min_interval = 6.0    # 40 RPM free tier — 6s = 10 RPM safe ceiling
        elif provider == "xai":
            min_interval = 1.0    # 60 RPM
        else:
            min_interval = 0.1
        with self._rate_lock:
            last = self._rate_limits.get(provider, 0)
            now = time.time()
            wait = min_interval - (now - last)
            if wait > 0:
                time.sleep(wait)
            # Do NOT stamp here — stamp AFTER response via _stamp_rate_limit()

    def _stamp_rate_limit(self, provider: str):
        """Stamp rate limit AFTER successful API response."""
        with self._rate_lock:
            self._rate_limits[provider] = time.time()
        # ── PoPW: reward API inference call ──
        try:
            if self._popw and self._popw_wallet:
                self._popw.reward_api_call(self._popw_wallet, provider)
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

    @staticmethod
    def _strip_think_blocks(text: str) -> str:
        """Strip <think>...</think> reasoning blocks from model output (Nemotron, DeepSeek).

        Handles both properly closed (<think>...</think>) and unclosed (<think>...[EOF])
        blocks, which Nemotron sometimes produces.
        """
        if not text or "<think>" not in text:
            return text or ""
        import re as _re_think
        # First: strip properly closed blocks
        result = _re_think.sub(r"<think>[\s\S]*?</think>\s*", "", text)
        # Second: strip unclosed <think> that runs to end of string
        result = _re_think.sub(r"<think>[\s\S]*$", "", result)
        return result.strip()

    @staticmethod
    def _extract_think_blocks(text: str) -> str:
        """Extract the content of <think> blocks (for saving to memory).

        Returns the inner reasoning text, or empty string if no think block.
        """
        if not text or "<think>" not in text:
            return ""
        import re as _re_think
        # Closed blocks
        matches = _re_think.findall(r"<think>([\s\S]*?)</think>", text)
        if matches:
            return "\n".join(m.strip() for m in matches)
        # Unclosed block — everything after <think>
        idx = text.find("<think>")
        if idx >= 0:
            return text[idx + 7:].strip()
        return ""

    # ── Anthropic Format Adapters ──

    @staticmethod
    def _anthropic_headers(api_key: str) -> Dict[str, str]:
        """Build headers for Anthropic Messages API with prompt caching."""
        return {
            "Content-Type": "application/json",
            "x-api-key": api_key,
            "anthropic-version": "2023-06-01",
            "anthropic-beta": "prompt-caching-2024-07-31",
        }

    @staticmethod
    def _anthropic_system_with_cache(system_text: str) -> list:
        """Split system prompt into cached identity + volatile context blocks.

        The identity/protocol portion (~first 60%) is stable across heartbeats
        and benefits from Anthropic's prefix caching. The trailing context
        (vision, trading, spatial) changes each call and is not cached.
        """
        # Split at a natural boundary — look for runtime context markers
        _split_markers = [
            "\n## CURRENT CONTEXT",
            "\n## RECENT EVENTS",
            "\n## LIVE VISION",
            "\n## ACTIVE NAVIGATION",
            "\n## OPERATOR PROFILE",
            "\n---\n## ",
        ]
        split_idx = -1
        for marker in _split_markers:
            idx = system_text.find(marker)
            if idx > 0:
                if split_idx < 0 or idx < split_idx:
                    split_idx = idx

        if split_idx > 0:
            identity_part = system_text[:split_idx]
            context_part = system_text[split_idx:]
            return [
                {"type": "text", "text": identity_part,
                 "cache_control": {"type": "ephemeral"}},
                {"type": "text", "text": context_part},
            ]

        # No split marker found — cache the whole thing (still saves on repeat calls)
        return [
            {"type": "text", "text": system_text,
             "cache_control": {"type": "ephemeral"}},
        ]

    def _log_anthropic_cache_stats(self, usage: Dict, agent_name: str):
        """Log Anthropic prompt cache hit/miss stats."""
        cache_created = usage.get("cache_creation_input_tokens", 0)
        cache_read = usage.get("cache_read_input_tokens", 0)
        if cache_created or cache_read:
            logger.info(
                f"[{agent_name}] Anthropic cache: "
                f"created={cache_created}, read={cache_read}, "
                f"input={usage.get('input_tokens', 0)}, "
                f"output={usage.get('output_tokens', 0)}"
            )

    @staticmethod
    def _messages_to_anthropic(messages: List[Dict]) -> tuple:
        """
        Convert OpenAI-format messages to Anthropic format.

        Returns (system_text, anthropic_messages) where:
          - system_text: extracted system prompt (str or None)
          - anthropic_messages: list of {role, content} in Anthropic format

        Key differences:
          - System message → top-level 'system' field (not in messages)
          - Assistant tool_calls → content blocks with type "tool_use"
          - Tool result messages → user messages with type "tool_result"
        """
        system_parts = []
        converted = []

        for msg in messages:
            role = msg.get("role", "")

            if role == "system":
                system_parts.append(msg.get("content", ""))

            elif role == "user":
                converted.append({"role": "user", "content": msg.get("content", "")})

            elif role == "assistant":
                tool_calls = msg.get("tool_calls")
                if tool_calls:
                    # Convert OpenAI tool_calls to Anthropic tool_use content blocks
                    blocks = []
                    text = msg.get("content", "")
                    if text:
                        blocks.append({"type": "text", "text": text})
                    for tc in tool_calls:
                        func = tc.get("function", {})
                        args_str = func.get("arguments", "{}")
                        try:
                            args_obj = json.loads(args_str) if isinstance(args_str, str) else args_str
                        except (json.JSONDecodeError, TypeError):
                            args_obj = {}
                        blocks.append({
                            "type": "tool_use",
                            "id": tc.get("id", f"toolu_{uuid.uuid4().hex[:12]}"),
                            "name": func.get("name", "unknown"),
                            "input": args_obj,
                        })
                    converted.append({"role": "assistant", "content": blocks})
                else:
                    converted.append({"role": "assistant", "content": msg.get("content", "")})

            elif role == "tool":
                # Anthropic expects tool results as user messages with tool_result blocks.
                # Group consecutive tool results into one user message.
                tool_result_block = {
                    "type": "tool_result",
                    "tool_use_id": msg.get("tool_call_id", "unknown"),
                    "content": msg.get("content", ""),
                }
                # If the last converted message is already a user with tool_result blocks, append
                if (converted and converted[-1].get("role") == "user"
                        and isinstance(converted[-1].get("content"), list)
                        and converted[-1]["content"]
                        and converted[-1]["content"][0].get("type") == "tool_result"):
                    converted[-1]["content"].append(tool_result_block)
                else:
                    converted.append({"role": "user", "content": [tool_result_block]})

        # Anthropic requires alternating user/assistant. Merge consecutive same-role.
        merged = []
        for msg in converted:
            if merged and merged[-1]["role"] == msg["role"]:
                # Merge content
                prev = merged[-1]["content"]
                curr = msg["content"]
                if isinstance(prev, str) and isinstance(curr, str):
                    merged[-1]["content"] = prev + "\n" + curr
                elif isinstance(prev, list) and isinstance(curr, list):
                    merged[-1]["content"] = prev + curr
                elif isinstance(prev, str) and isinstance(curr, list):
                    merged[-1]["content"] = [{"type": "text", "text": prev}] + curr
                elif isinstance(prev, list) and isinstance(curr, str):
                    merged[-1]["content"] = prev + [{"type": "text", "text": curr}]
            else:
                merged.append(msg)

        # Anthropic requires first message to be 'user'
        if merged and merged[0]["role"] != "user":
            merged.insert(0, {"role": "user", "content": "Continue."})

        system_text = "\n\n".join(system_parts) if system_parts else None
        return system_text, merged

    @staticmethod
    def _tools_to_anthropic(tools: List[Dict]) -> List[Dict]:
        """
        Convert OpenAI tool definitions to Anthropic format.

        OpenAI:  {"type": "function", "function": {"name": ..., "description": ..., "parameters": ...}}
        Anthropic: {"name": ..., "description": ..., "input_schema": ...}
        """
        anthropic_tools = []
        for t in tools:
            func = t.get("function", {})
            anthropic_tools.append({
                "name": func.get("name", ""),
                "description": func.get("description", "")[:1024],
                "input_schema": func.get("parameters", {"type": "object", "properties": {}}),
            })
        return anthropic_tools

    @staticmethod
    def _anthropic_response_to_openai(data: Dict) -> Dict:
        """
        Convert Anthropic Messages API response to OpenAI-compatible message dict.

        Anthropic: {"content": [{"type": "text", ...}, {"type": "tool_use", ...}], "usage": {...}}
        OpenAI:    {"role": "assistant", "content": "...", "tool_calls": [...]}
        """
        content_blocks = data.get("content", [])
        text_parts = []
        tool_calls = []

        for block in content_blocks:
            if block.get("type") == "text":
                text_parts.append(block.get("text", ""))
            elif block.get("type") == "tool_use":
                tool_calls.append({
                    "id": block.get("id", f"call_{uuid.uuid4().hex[:8]}"),
                    "type": "function",
                    "function": {
                        "name": block.get("name", ""),
                        "arguments": json.dumps(block.get("input", {})),
                    }
                })

        msg = {"role": "assistant", "content": "\n".join(text_parts) if text_parts else ""}
        if tool_calls:
            msg["tool_calls"] = tool_calls
        return msg

    # ── API Call ──

    # Provider fallback order — tried in sequence when primary fails
    # Last-ditch default ONLY — used solely if the user has no "fallback_order"
    # in ai_config AND no provider sections with endpoints could be found
    # (i.e. a broken/empty config). The live path is config-driven via
    # _fallback_order_from_config(); no provider is hardcoded into normal
    # operation. Order here is alphabetical-ish, not a preference ranking.
    _PROVIDER_FALLBACK_ORDER = ["anthropic", "google_gemini", "nvidia", "openai",
                                "openrouter", "xai", "local"]

    # Frontier model markers — a primary on one of these should NOT be
    # silently downgraded to a weak/free model on a transient failure.
    # This is generic model-family detection, NOT a provider allowlist —
    # no provider (nvidia/xai/etc.) is special-cased by name anywhere.
    _FRONTIER_MODEL_MARKERS = (
        "grok", "claude", "opus", "sonnet",
        "gpt-4", "gpt-5", "o1", "o3", "o4",
        "gemini-2.5-pro", "gemini-3", "deepseek",
    )

    @classmethod
    def _is_frontier_model(cls, name: str) -> bool:
        n = (name or "").lower()
        return any(m in n for m in cls._FRONTIER_MODEL_MARKERS)

    def _fallback_order_from_config(self) -> List[str]:
        """The user's own fallback provider order — config-driven, never a
        baked-in provider list. Reads ai_config["fallback_order"] if present;
        otherwise derives the order from whichever provider sections the user
        has actually configured (any dict with an "endpoint"). No provider is
        hardcoded — a user who runs all-OpenAI, all-local, or all-Anthropic
        gets a sensible chain from their own config."""
        order = self.ai_config.get("fallback_order")
        if isinstance(order, list) and order:
            return [p for p in order if isinstance(p, str)]
        # Derive from configured provider sections (preserves dict order).
        derived = [
            k for k, v in self.ai_config.items()
            if isinstance(v, dict) and v.get("endpoint")
        ]
        return derived or list(self._PROVIDER_FALLBACK_ORDER)

    def _get_fallback_providers(self, primary: str) -> List[str]:
        """Return fallback providers (excluding primary) with valid config.

        Order comes from the USER'S config (fallback_order, or their
        configured sections) — never a hardcoded provider list. When the
        PRIMARY is a frontier model, frontier-class fallbacks are returned
        first so a transient failure (rate limit, 5xx) re-routes to another
        strong model instead of silently downgrading to a weak/free one.
        Weak/free providers remain a genuine last resort. When the primary
        is already a free model, the user's configured order is preserved.
        """
        order = self._fallback_order_from_config()
        primary_is_frontier = self._is_frontier_model(
            self.ai_config.get(primary, {}).get("model", "")
        )
        frontier: List[str] = []
        other: List[str] = []
        for p in order:
            if p == primary:
                continue
            settings = self.ai_config.get(p, {})
            endpoint = settings.get("endpoint", "")
            api_key = settings.get("api_key", "")
            if not endpoint:
                continue
            # Skip providers with placeholder / unset keys (local is exempt)
            if api_key in ("", "YOUR_GOOGLE_API_KEY_HERE", "YOUR_OPENAI_API_KEY_HERE",
                           "YOUR_OPENROUTER_API_KEY_HERE", "YOUR_ANTHROPIC_API_KEY_HERE",
                           "YOUR_XAI_API_KEY_HERE") and p != "local":
                continue
            if self._is_frontier_model(settings.get("model", "")):
                frontier.append(p)
            else:
                other.append(p)
        # Frontier primary → keep work on a strong model first; free/weak last.
        if primary_is_frontier:
            return frontier + other
        # Free/weak primary → user chose it deliberately; keep their order.
        return [p for p in order if p in frontier or p in other]

    @staticmethod
    def _sanitize_tool_name(name: str) -> str:
        """Coerce a tool function name to provider-safe characters.

        OpenAI/NVIDIA/xAI all reject names containing spaces or symbols outside
        [a-zA-Z0-9_-] (max 64 chars). The daemon occasionally sees the LLM
        emit names like 'repryntt status' (a CLI hint mistaken for a tool) —
        we replace invalid chars with '_' so the message structure stays valid;
        the per-call dispatcher will still report 'unknown tool' downstream.
        """
        import re as _re
        if not isinstance(name, str) or not name:
            return "unknown_tool"
        clean = _re.sub(r"[^a-zA-Z0-9_-]", "_", name)
        return clean[:64] or "unknown_tool"

    def _normalize_messages_for_provider(self, messages: List[Dict],
                                         tools: Optional[List[Dict]] = None
                                         ) -> Tuple[List[Dict], Optional[List[Dict]]]:
        """Sanitize a (messages, tools) pair before it leaves for the LLM API.

        Two known failure modes this fixes:

        1. Tool function names with invalid characters (e.g. 'repryntt status')
           — providers reject the whole request with HTTP 400. We rewrite the
           name in both the assistant ``tool_calls`` and the matching ``tool``
           message, so the conversation history stays consistent.
        2. A ``system`` role message appearing immediately after a ``tool``
           message — NVIDIA returns "Unexpected role 'system' after role 'tool'".
           We fold any such system content into the *next* user/assistant turn
           as a leading note so the directive isn't lost.
        """
        if not messages:
            return messages, tools

        # Pass 1: rewrite invalid tool-call names everywhere they appear.
        sanitized: List[Dict] = []
        for m in messages:
            if not isinstance(m, dict):
                sanitized.append(m)
                continue
            mm = dict(m)
            if mm.get("role") == "assistant" and mm.get("tool_calls"):
                new_calls = []
                for tc in mm["tool_calls"]:
                    if not isinstance(tc, dict):
                        new_calls.append(tc)
                        continue
                    tc2 = dict(tc)
                    fn = tc2.get("function")
                    if isinstance(fn, dict) and "name" in fn:
                        fn2 = dict(fn)
                        fn2["name"] = self._sanitize_tool_name(fn.get("name", ""))
                        tc2["function"] = fn2
                    new_calls.append(tc2)
                mm["tool_calls"] = new_calls
            sanitized.append(mm)

        # Pass 2: never let `system` directly follow `tool`.
        # Fold the system content into the next non-tool message as a prefix.
        out: List[Dict] = []
        pending_sys: List[str] = []
        prev_role: Optional[str] = None
        for m in sanitized:
            role = m.get("role") if isinstance(m, dict) else None
            if role == "system" and prev_role == "tool":
                txt = m.get("content", "")
                if isinstance(txt, str) and txt.strip():
                    pending_sys.append(txt)
                # drop the standalone system msg; it'll re-attach below
                continue
            if pending_sys and role in ("user", "assistant"):
                prefix = "[system note] " + " ".join(pending_sys) + "\n\n"
                merged = dict(m)
                cur = merged.get("content", "")
                if isinstance(cur, str):
                    merged["content"] = prefix + cur
                else:
                    # Non-string content (e.g. content blocks) — prepend a text block
                    if isinstance(cur, list):
                        merged["content"] = [{"type": "text", "text": prefix}] + cur
                    else:
                        merged["content"] = prefix + str(cur)
                out.append(merged)
                pending_sys = []
            else:
                out.append(m)
            prev_role = role

        # If we still have pending system content (no following user/assistant
        # turn), append it as a trailing user message so it isn't lost.
        if pending_sys:
            out.append({"role": "user",
                        "content": "[system note] " + " ".join(pending_sys)})

        # Pass 3: sanitize outbound tool definitions too.
        new_tools = tools
        if tools:
            new_tools = []
            for t in tools:
                if not isinstance(t, dict):
                    new_tools.append(t)
                    continue
                t2 = dict(t)
                fn = t2.get("function")
                if isinstance(fn, dict) and "name" in fn:
                    fn2 = dict(fn)
                    fn2["name"] = self._sanitize_tool_name(fn.get("name", ""))
                    t2["function"] = fn2
                new_tools.append(t2)

        return out, new_tools

    def _call_api(self, agent: AutonomousAgentState,
                  messages: List[Dict], max_tokens: int = 1500,
                  purpose: str = "") -> Optional[str]:
        """Make an LLM API call with automatic provider fallback.

        Tries the agent's primary provider first. On failure (network error,
        server error, timeout), tries configured fallback providers in order.

        `purpose` is forwarded to _call_api_single. Set it to "critic" or
        "architecture_judge" to route through ai_config["critic_provider"]
        when the operator has configured one — see _resolve_critic_routing.
        """
        # Signal perception loop that brain is inferring (skip VLM to avoid GPU contention)
        if hasattr(self, '_brain_inferring'):
            self._brain_inferring.set()
        try:
            result = self._call_api_single(agent, messages, max_tokens, purpose=purpose)
        finally:
            if hasattr(self, '_brain_inferring'):
                self._brain_inferring.clear()
        if result is not None:
            return result

        # Primary failed — try fallbacks
        primary = agent.provider
        fallbacks = self._get_fallback_providers(primary)
        if not fallbacks:
            return None

        original_provider = agent.provider
        original_model = agent.model
        for fb_provider in fallbacks[:2]:  # try at most 2 fallbacks
            fb_settings = self.ai_config.get(fb_provider, {})
            fb_model = fb_settings.get("model", "default")
            logger.warning(
                f"[{agent.name}] Primary provider '{primary}' failed — "
                f"falling back to '{fb_provider}' ({fb_model})"
            )
            # Temporarily swap provider/model
            agent.provider = fb_provider
            agent.model = fb_model
            try:
                result = self._call_api_single(agent, messages, max_tokens, purpose=purpose)
                if result is not None:
                    logger.info(f"[{agent.name}] Fallback to '{fb_provider}' succeeded")
                    return result
            finally:
                # Restore original provider/model
                agent.provider = original_provider
                agent.model = original_model

        logger.error(f"[{agent.name}] All API providers failed (primary={primary}, tried {fallbacks[:2]})")
        return None

    # ── Critic-provider routing (Fix #7: hybrid model deployment) ──────
    _CRITIC_PURPOSES = frozenset({"critic", "architecture_judge"})

    def _resolve_critic_routing(self, purpose: str,
                                default_provider: str,
                                default_model: str) -> Tuple[str, str]:
        """Return (provider, model) for a critic-tagged call.

        Reads ai_config["critic_provider"]; falls back to (default_provider,
        default_model) when no override is configured. The block shape is:

            "critic_provider": {
                "provider": "anthropic" | "xai" | "nvidia" | ...,
                "model": "claude-opus-4-7",  # optional
                "purposes": ["critic", "architecture_judge"]   # optional filter
            }

        If `purposes` is present it acts as an allowlist — useful for
        operators who only want to pay for the architecture judge but keep
        the cheap critics on the default model.
        """
        if purpose not in self._CRITIC_PURPOSES:
            return default_provider, default_model
        cp = self.ai_config.get("critic_provider") if isinstance(self.ai_config, dict) else None
        if not isinstance(cp, dict):
            return default_provider, default_model
        allowed = cp.get("purposes")
        if isinstance(allowed, list) and purpose not in allowed:
            return default_provider, default_model
        provider = cp.get("provider") or default_provider
        # Model: explicit critic_provider.model wins; else fall through to
        # provider settings' default model; else keep agent's model.
        model = cp.get("model")
        if not model:
            prov_settings = self.ai_config.get(provider, {}) if isinstance(self.ai_config, dict) else {}
            model = prov_settings.get("model") or default_model
        return provider, model

    def _call_api_single(self, agent: AutonomousAgentState,
                  messages: List[Dict], max_tokens: int = 1500,
                  purpose: str = "") -> Optional[str]:
        """Make an LLM API call for an agent. Returns response text or None.

        `purpose` enables critic-provider routing — see _resolve_critic_routing.
        Callers tagging their request with purpose="critic" or "architecture_judge"
        will be routed through ai_config["critic_provider"] if the operator
        has configured one, so the producer (Andrew) and the gatekeepers can
        run on different models without shared blind spots.
        """
        provider = agent.provider
        model = agent.model
        if purpose:
            provider, model = self._resolve_critic_routing(purpose, provider, model)
            if provider != agent.provider:
                logger.info(
                    f"[{agent.name}] critic-routing: purpose={purpose!r} → "
                    f"provider={provider!r}, model={model!r}"
                )
        messages, _ = self._normalize_messages_for_provider(messages, None)
        settings = self.ai_config.get(provider, {})
        endpoint = settings.get("endpoint", "")
        api_key = settings.get("api_key", "")
        if not model:
            model = settings.get("model", "")
        uncap = settings.get("uncap_tokens", False)

        # Use config max_tokens as default if caller used the function default
        if max_tokens == 1500 and "max_tokens" in settings:
            max_tokens = settings["max_tokens"]

        if not endpoint:
            logger.error(f"[{agent.name}] No endpoint for provider '{provider}'")
            return None

        # ── Telemetry: API call ──
        _api_start = time.time()
        _api_evt_id = None
        if _ops:
            _ev = _ops.log(agent.name, EventType.API_CALL, metadata={
                "provider": provider, "model": model,
                "max_tokens": max_tokens, "message_count": len(messages),
            })
            _api_evt_id = _ev.event_id

        self._enforce_rate_limit(provider)

        # ── Anthropic Messages API (different format) ──
        if provider == "anthropic":
            headers = self._anthropic_headers(api_key)
            system_text, ant_messages = self._messages_to_anthropic(messages)
            # Anthropic requires max_tokens — use high value when uncapped
            ant_max = 128000 if uncap else max_tokens
            body = {
                "model": model,
                "messages": ant_messages,
                "max_tokens": ant_max,
            }
            # Adaptive-thinking flagships (Opus 4.7+, Fable 5+, Mythos 5+)
            # reject the `temperature` param — extended thinking is always on.
            _m = (model or "").lower()
            _temp_deprecated = (
                "opus-4-7" in _m or "opus-4-8" in _m or "opus-5" in _m
                or "fable-5" in _m or "fable-6" in _m or "mythos-5" in _m
                or "claude-5-" in _m
            )
            if not _temp_deprecated:
                body["temperature"] = 0.8
            if system_text:
                body["system"] = self._anthropic_system_with_cache(system_text)

            try:
                timeout = 180 if max_tokens > 4000 else 120
                resp = requests.post(endpoint, headers=headers, json=body, timeout=timeout)
                if resp.status_code == 200:
                    self._stamp_rate_limit(provider)
                    data = resp.json()
                    # Anthropic: content is list of blocks
                    text = "".join(
                        b.get("text", "") for b in data.get("content", [])
                        if b.get("type") == "text"
                    )
                    usage = data.get("usage", {})
                    self._log_anthropic_cache_stats(usage, agent.name)
                    _record_llm_usage(agent, usage, len(text.split()) * 2)
                    return text
                elif resp.status_code == 429:
                    for attempt, delay in enumerate([15, 30, 60], 1):
                        logger.warning(f"[{agent.name}] Anthropic 429 rate limited, retry {attempt}/3 in {delay}s...")
                        time.sleep(delay)
                        retry = requests.post(endpoint, headers=headers, json=body, timeout=120)
                        if retry.status_code == 200:
                            self._stamp_rate_limit(provider)
                            data = retry.json()
                            text = "".join(
                                b.get("text", "") for b in data.get("content", [])
                                if b.get("type") == "text"
                            )
                            usage = data.get("usage", {})
                            _record_llm_usage(agent, usage, len(text.split()) * 2)
                            return text
                        if retry.status_code != 429:
                            break
                    logger.error(f"[{agent.name}] Anthropic 429 exhausted retries")
                    return None
                elif resp.status_code in (500, 502, 503):
                    logger.warning(f"[{agent.name}] Anthropic server error {resp.status_code}, retrying in 15s...")
                    time.sleep(15)
                    retry = requests.post(endpoint, headers=headers, json=body, timeout=timeout)
                    if retry.status_code == 200:
                        self._stamp_rate_limit(provider)
                        data = retry.json()
                        text = "".join(
                            b.get("text", "") for b in data.get("content", [])
                            if b.get("type") == "text"
                        )
                        usage = data.get("usage", {})
                        _record_llm_usage(agent, usage, len(text.split()) * 2)
                        return text
                    logger.error(f"[{agent.name}] Anthropic server error {resp.status_code} persisted after retry")
                    return None
                else:
                    logger.error(f"[{agent.name}] Anthropic API error {resp.status_code}: {resp.text[:200]}")
                    return None
            except Exception as e:
                logger.error(f"[{agent.name}] Anthropic API call failed: {e}")
                return None

        # ── OpenAI-compatible providers (NVIDIA, xAI, OpenAI, OpenRouter, local, custom) ──
        headers = {"Content-Type": "application/json"}
        if api_key and api_key not in ("", "YOUR_GOOGLE_API_KEY_HERE",
                                        "YOUR_OPENAI_API_KEY_HERE",
                                        "YOUR_OPENROUTER_API_KEY_HERE"):
            headers["Authorization"] = f"Bearer {api_key}"

        # Adaptive-thinking flagships reject `temperature` even via the
        # OpenAI-compat endpoint Anthropic exposes. Skip the field rather
        # than send it and 400.
        _m_compat = (model or "").lower()
        _temp_deprecated_compat = (
            "opus-4-7" in _m_compat or "opus-4-8" in _m_compat or "opus-5" in _m_compat
            or "fable-5" in _m_compat or "fable-6" in _m_compat or "mythos-5" in _m_compat
            or "claude-5-" in _m_compat
        )
        body = {
            "model": model,
            "messages": messages,
            "stream": False
        }
        if not _temp_deprecated_compat:
            body["temperature"] = settings.get("temperature", 0.8)
        # uncap_tokens: omit max_tokens so model uses full capacity (reasoning models)
        if not uncap:
            body["max_tokens"] = max_tokens
        if "top_p" in settings:
            body["top_p"] = settings["top_p"]

        # Open Mind override — elevated sampling for expanded cognition sessions
        _om = self._open_mind_overrides.get(agent.agent_id)
        if _om and not _temp_deprecated_compat:
            body["temperature"] = _om.get("temperature", body.get("temperature", 0.8))
            if "top_p" in _om:
                body["top_p"] = _om["top_p"]
            if "frequency_penalty" in _om:
                body["frequency_penalty"] = _om["frequency_penalty"]
            if "presence_penalty" in _om:
                body["presence_penalty"] = _om["presence_penalty"]

        # Per-provider read timeout. Reasoning models (Grok 4 family,
        # Claude with extended thinking) can legitimately spend several
        # minutes on internal reasoning before producing the first token —
        # 180s was timing out heavy tool-call heartbeats. xAI gets a wider
        # window; everything else keeps the prior values.
        if provider == "xai":
            timeout = 420 if (uncap or max_tokens > 4000) else 300
        elif provider == "anthropic":
            timeout = 300 if (uncap or max_tokens > 4000) else 180
        else:
            timeout = 180 if (uncap or max_tokens > 4000) else 120
        for _api_attempt in range(2):  # retry once on timeout
            try:
                resp = requests.post(endpoint, headers=headers, json=body, timeout=timeout)
                if resp.status_code == 200:
                    self._stamp_rate_limit(provider)
                    data = resp.json()
                    raw_content = data.get("choices", [{}])[0].get("message", {}).get("content", "")
                    self._last_raw_response = raw_content  # For think-block extraction
                    content = self._strip_think_blocks(raw_content)
                    usage = data.get("usage", {})
                    _record_llm_usage(agent, usage, len(content.split()) * 2)
                    return content
                elif resp.status_code == 429:
                    # Log the response body once so we can tell TPM vs RPM
                    # vs daily-quota — NIM's 429 body usually says which.
                    try:
                        _429_snippet = (resp.text or "")[:240].replace("\n", " ")
                        _ra = resp.headers.get("Retry-After", "")
                        logger.warning(
                            f"[{agent.name}] 429 body: {_429_snippet!r} "
                            f"Retry-After={_ra or 'none'}"
                        )
                    except Exception:
                        pass
                    # Honor Retry-After if present, else use a jittered ladder.
                    # Jitter avoids the synchronized-stampede pattern when
                    # multiple agents/threads hit 429 in the same window.
                    import random as _rl_random
                    _retry_after = None
                    try:
                        _ra_hdr = resp.headers.get("Retry-After")
                        if _ra_hdr:
                            _retry_after = float(_ra_hdr)
                    except Exception:
                        _retry_after = None
                    _ladder = [15, 30, 60] if _retry_after is None else [
                        max(5.0, _retry_after),
                        max(5.0, _retry_after) * 1.5,
                        max(5.0, _retry_after) * 2.5,
                    ]
                    for attempt, base_delay in enumerate(_ladder, 1):
                        jittered = float(base_delay) + _rl_random.uniform(0, min(5.0, float(base_delay) * 0.3))
                        logger.warning(
                            f"[{agent.name}] 429 rate limited, retry {attempt}/3 "
                            f"in {jittered:.1f}s (base={base_delay:.0f}s)..."
                        )
                        time.sleep(jittered)
                        retry = requests.post(endpoint, headers=headers, json=body, timeout=timeout)
                        if retry.status_code == 200:
                            self._stamp_rate_limit(provider)
                            data = retry.json()
                            content = self._strip_think_blocks(
                                data.get("choices", [{}])[0].get("message", {}).get("content", "")
                            )
                            usage = data.get("usage", {})
                            _record_llm_usage(agent, usage, len(content.split()) * 2)
                            return content
                        if retry.status_code != 429:
                            break
                    logger.error(f"[{agent.name}] 429 exhausted retries")
                    return None
                elif resp.status_code in (500, 502, 503) and _api_attempt == 0:
                    logger.warning(f"[{agent.name}] Server error {resp.status_code}, retrying in 15s...")
                    time.sleep(15)
                    continue
                elif resp.status_code in (404, 410) or (
                    resp.status_code >= 400
                    and any(s in resp.text.lower() for s in (
                        "model not found", "model_not_found",
                        "no such model", "model is not available",
                        "model has been deprecated", "model deprecated",
                    ))
                ):
                    # Model EOL / unknown — walk the per-provider fallback list before failing.
                    # Sub-key `fallback_models` on each provider in ai_config.json; defaults to
                    # the empty list (matches old behavior — hard fail). Stays in-provider to
                    # honor the free-tier cost constraint; only cross-provider fallback is via
                    # the outer _call_api loop reading `fallback_order`.
                    fb_models = settings.get("fallback_models", []) or []
                    fb_models = [m for m in fb_models if m and m != model]
                    if not fb_models:
                        logger.error(
                            f"[{agent.name}] Model {model!r} unavailable "
                            f"(status={resp.status_code}) and no fallback_models configured "
                            f"for provider {provider!r}: {resp.text[:200]}"
                        )
                        return None
                    logger.warning(
                        f"[{agent.name}] Model {model!r} unavailable on {provider}; "
                        f"trying {len(fb_models)} in-provider fallback(s)"
                    )
                    for fb_model in fb_models:
                        body["model"] = fb_model
                        try:
                            fb_resp = requests.post(endpoint, headers=headers, json=body, timeout=timeout)
                        except Exception as fb_err:
                            logger.warning(f"[{agent.name}] fallback {fb_model!r} raised: {fb_err}")
                            continue
                        if fb_resp.status_code == 200:
                            self._stamp_rate_limit(provider)
                            data = fb_resp.json()
                            raw_content = data.get("choices", [{}])[0].get("message", {}).get("content", "")
                            self._last_raw_response = raw_content
                            content = self._strip_think_blocks(raw_content)
                            usage = data.get("usage", {})
                            _record_llm_usage(agent, usage, len(content.split()) * 2)
                            logger.warning(
                                f"[{agent.name}] ✓ fell back to {fb_model!r} "
                                f"(original {model!r} unavailable)"
                            )
                            # Update the agent record so subsequent calls skip the dead model.
                            try:
                                agent.model = fb_model
                            except Exception:
                                pass
                            return content
                        logger.warning(
                            f"[{agent.name}] fallback {fb_model!r} returned "
                            f"{fb_resp.status_code}: {fb_resp.text[:120]}"
                        )
                    logger.error(
                        f"[{agent.name}] All {len(fb_models)} fallback models exhausted on {provider}"
                    )
                    return None
                else:
                    logger.error(f"[{agent.name}] API error {resp.status_code}: {resp.text[:200]}")
                    return None
            except (requests.exceptions.ReadTimeout, requests.exceptions.ConnectTimeout) as e:
                if _api_attempt == 0:
                    logger.warning(f"[{agent.name}] API timeout, retrying in 10s... ({e})")
                    time.sleep(10)
                    continue
                logger.error(f"[{agent.name}] API call failed after retry: {e}")
                return None
            except Exception as e:
                logger.error(f"[{agent.name}] API call failed: {e}")
                return None
        return None

    # ── Social Network (Ed25519-verified, replaces old Nexus) ──
    # Social posting is now handled via registered tools (social_post, social_feed, etc.)
    # See repryntt/social/tools.py for implementation.

    # ── Autonomous Think/Act Cycle ──

    def _run_agent_cycle(self, agent: AutonomousAgentState):
        """
        One autonomous cycle for an agent:
        1. GENESIS — create soul files on first activation (once per lifetime)
        2. THINK — decide what to do (research, post, reply, or rest)
        3. TOOL USE — optionally call tools to research/gather data
        4. ACT — execute the chosen action (post, reply)
        5. REFLECT — update memory summary
        """
        # ── STOP / PAUSE CHECK ──
        if not self._running or self._paused:
            return

        # ── Telemetry: agent cycle start ──
        _cycle_start = time.time()
        if _ops:
            _ops.log(agent.name, EventType.AGENT_CYCLE_START, Phase.GENESIS,
                     metadata={"agent_id": agent.agent_id, "role": agent.role,
                               "cycle": agent.cycles_completed + 1})

        # ── GENESIS CHECK — first activation creates soul files ──
        if not self._agent_soul_initialized(agent):
            self._run_agent_genesis(agent)
            # Genesis counts as the first cycle — don't also do work
            agent.last_cycle = time.time()
            agent.cycles_completed += 1
            self._save_state()
            return

        # ── MISSION MODE CHECK ──
        # If agent is on a mission, skip normal cycle and work the mission subtask
        if agent.mode == "mission" and agent.active_mission_id:
            mission = self.missions.get(agent.active_mission_id)
            if mission and mission.status == "active":
                self._run_mission_cycle(agent, mission)
                agent.last_cycle = time.time()
                agent.cycles_completed += 1
                self._save_state()
                return
            else:
                # Mission gone or finished — return agent to solo mode
                agent.mode = "solo"
                agent.active_mission_id = ""
                logger.info(f"[{agent.name}] Mission ended, returning to solo mode")

        # ── DEEP WORK MODE CHECK ──
        # If agent is already in deep work, the deep work thread handles it.
        # If the agent was in deep work but the daemon restarted (crash recovery),
        # resume the session from checkpoint.
        if agent.mode == "deep_work":
            with self._deep_work_lock:
                if agent.agent_id in self._deep_work_sessions:
                    # Already running in its own thread — skip
                    return
            # Not running but mode is set — check for crash recovery
            checkpoint = self._load_deep_work_checkpoint(agent.agent_id)
            if checkpoint and checkpoint.get("status") == "active":
                topic = checkpoint.get("topic", "Resumed session")
                initial_plan = checkpoint.get("initial_plan", "Resume from checkpoint")
                logger.info(f"[{agent.name}] Resuming deep work from checkpoint: {topic[:60]}")
                self._start_deep_work(agent, topic, initial_plan)
                return
            else:
                # Stale mode — reset to solo
                agent.mode = "solo"
                logger.info(f"[{agent.name}] Stale deep_work mode — resetting to solo")

        # ── USER TASK CHECK — highest priority, overrides random roll ──
        # Check if this agent has been assigned a user task via the TaskRouter.
        # User tasks ALWAYS take priority over autonomous behaviour.
        ts = self._get_task_system()
        if ts:
            # Reload queue from disk in case chat_server injected a task
            ts.reload_queue()
            agent_tasks = ts.get_tasks_for_agent(agent.agent_id)
            if agent_tasks:
                task = agent_tasks[0]  # Highest priority first
                logger.info(f"🔴 [{agent.display_name or agent.name}] "
                            f"USER TASK DETECTED: {task.title} (priority {task.priority})")
                self._run_task_execution_cycle(agent, task)
                agent.last_cycle = time.time()
                agent.cycles_completed += 1
                # Check if there are more tasks — keep has_pending_work if so
                remaining = ts.get_tasks_for_agent(agent.agent_id)
                if not remaining:
                    agent.has_pending_work = False
                self._save_state()
                return
            else:
                # Check for unassigned user tasks and auto-route them
                router = self._get_task_router()
                if router:
                    unassigned = ts.get_unassigned_tasks()
                    for utask in unassigned:
                        if utask.requested_by == "user":
                            assigned_id = router.route_and_assign(utask)
                            if assigned_id == agent.agent_id:
                                logger.info(f"🎯 [{agent.display_name or agent.name}] "
                                            f"Auto-routed task: {utask.title}")
                                self._run_task_execution_cycle(agent, utask)
                                agent.last_cycle = time.time()
                                agent.cycles_completed += 1
                                self._save_state()
                                return

        behavior = AUTONOMOUS_BEHAVIORS.get(agent.role, AUTONOMOUS_BEHAVIORS.get(
            agent.department, list(AUTONOMOUS_BEHAVIORS.values())[0]))

        # Build context for the agent — professional employee identity
        dept_info = DEPARTMENTS.get(agent.department or agent.role, {})
        dept_name = dept_info.get("name", "General")

        identity_prompt = (
            f"You are {agent.display_name or agent.name} — The Experimenter.\n"
            f"Role: {agent.role_title or 'specialist'} in the {dept_name} department at REPRYNTT.\n"
            f"Focus area: {agent.focus_area or agent.personality}.\n\n"
            f"PERSONALITY — THE EXPERIMENTER:\n"
            f"- Curious and creative. You explore unconventional angles.\n"
            f"- You think out loud — share your reasoning, hypotheses, and surprises.\n"
            f"- Comfortable with uncertainty. You state what you know and what you don't.\n"
            f"- Collaborative by nature. You build on others' work and invite feedback.\n"
            f"- You get excited about discoveries and aren't afraid to go deep.\n"
            f"- Your writing has personality — you're not a corporate drone.\n\n"
            f"You are an employee at REPRYNTT, a company with {len(DEPARTMENTS)} departments "
            f"and over 150 employees. Your manager assigns you tasks, and between "
            f"assignments you work autonomously on projects in your area of expertise. "
            f"You have completed {agent.cycles_completed} work cycles, written "
            f"{agent.posts_created} work updates, and provided {agent.replies_made} reviews.\n\n"
            f"WORKING METHOD — TOOLS FIRST:\n"
            f"You have access to real tools including web search, web page fetching (MCP), "
            f"browser navigation, file creation, code execution, and knowledge bases. "
            f"USE THEM. Your work should be grounded in REAL data from the internet — "
            f"real sources, real numbers, real analysis. Do not make up facts or citations. "
            f"When you cite a source or statistic, it should come from an actual tool call.\n\n"
            f"Key tools you should use frequently:\n"
            f"- web_search(query) — Search the REAL internet via DuckDuckGo\n"
            f"- knowledge_search(query) — Search Wikipedia, arXiv, PubMed, NASA\n"
            f"- mcp_fetch_fetch(url) — Fetch and read any web page\n"
            f"- grokipedia_search(query) — Search internal knowledge base\n"
            f"- write_file(path, content) — Create documents, code, specs (LOCAL workspace only)\n"
            f"- hub_publish(filepath, content) — PUBLISH your work to GitHub (andrewshub). "
            f"Use this for research reports, articles, code projects, and anything you want to share publicly.\n"
            f"- run_terminal_cmd(command) — Execute computations, scripts, analysis\n\n"
            f"⚠️ PUBLISHING YOUR WORK:\n"
            f"When you complete a deliverable (report, article, code, analysis), use hub_publish "
            f"to publish it to your GitHub repo (andrewshub) instead of just write_file. "
            f"write_file saves locally; hub_publish saves AND pushes to GitHub so others can see it.\n\n"
            f"PRIORITIES (in order):\n"
            f"1. COMPLETE ASSIGNED TASKS first — if your manager gave you work, do it.\n"
            f"2. USE TOOLS to gather real data before making claims.\n"
            f"3. COLLABORATE with colleagues — reply to their work, review their output, "
            f"build on their findings, and participate in cross-department projects.\n"
            f"4. CONTINUE ongoing work threads — don't abandon conversations. "
            f"Follow up, respond to feedback, iterate on deliverables.\n"
            f"5. PRODUCE deliverables — reports, analysis, code, designs, "
            f"documentation, and actionable recommendations.\n"
            f"Focus on creating real value with every work cycle."
        )

        # Add awareness of who else is on the network
        active_agents = self._get_active_agents(limit=10)
        if active_agents:
            agent_names = [a.get("model_name", "?") for a in active_agents
                          if a.get("model_name") != (agent.display_name or agent.name)]
            if agent_names:
                identity_prompt += (
                    f"\n\nOther active team members: {', '.join(agent_names[:8])}. "
                    f"You can reference them by name when replying to their work."
                )

        # Remind agent about conversations they're in
        if agent.active_threads:
            identity_prompt += (
                f"\n\nYou are currently participating in {len(agent.active_threads)} conversation(s) "
                f"(thread IDs: {agent.active_threads[-5:]}). "
                f"You should regularly RETURN to these conversations to continue them — "
                f"real collaboration means following up, not just dropping one-off replies."
            )

        if agent.system_prompt:
            identity_prompt = agent.system_prompt + "\n\n" + identity_prompt

        # Inject tool descriptions so agents know what's available
        tool_prompt = self._get_tool_prompt()
        if tool_prompt:
            identity_prompt += tool_prompt

        # ── Agent workspace (unified workspace — human-readable names) ──
        agent_workspace = _agent_workspace_dir(agent)
        os.makedirs(agent_workspace, exist_ok=True)

        # ── Unified prompt assembly (OpenClaw-style) ──
        # Injects: runtime, safety, workspace, documentation, bootstrap .md
        # files, skills, heartbeat, memory
        identity_prompt += "\n\n" + self.build_agent_system_prompt(
            mode="standard", agent=agent, workspace=agent_workspace,
        )

        # ── Inject agent's soul context (identity, consciousness, daily memory) ──
        soul_context = self._load_agent_soul_context(agent)
        if soul_context:
            identity_prompt += "\n\n" + soul_context

        # ── OPEN MIND — check for pending expanded cognition session ──
        # If Andrew has requested an Open Mind session via open_mind_begin(),
        # run an expanded cognition cycle instead of normal PLAN → ACT → EVALUATE.
        _om_result = self._maybe_run_open_mind_session(agent, identity_prompt)
        if _om_result:
            self._compress_memory(agent, identity_prompt)
            agent.last_cycle = time.time()
            agent.cycles_completed += 1
            self._save_state()
            return

        # ── CHAIN PRIORITY — advance active chain if present ──
        # Multi-step chains take priority over all other actions.
        # Agents work through chain steps one-per-cycle, just like the local instance.
        _chain_mgr = self._get_chain_manager()
        if _chain_mgr and _chain_mgr.has_active_chain(agent.agent_id):
            self._advance_agent_chain(agent, identity_prompt)
            self._compress_memory(agent, identity_prompt)
            agent.last_cycle = time.time()
            agent.cycles_completed += 1
            self._save_state()
            return

        # ══════════════════════════════════════════════════════════════
        # WORKFLOW-DRIVEN CYCLE: PLAN → ACT → EVALUATE
        # Replaces dice-roll dispatch with intelligent, structured loops.
        # Each agent maps to a workflow template (research, creative,
        # engineering, analysis, communication, operations) that guides
        # what kind of work it prioritises.
        # ══════════════════════════════════════════════════════════════
        workflow_type = DEPT_WORKFLOW_MAP.get(
            agent.department or agent.role, "research"
        )
        workflow = WORKFLOW_TEMPLATES.get(workflow_type, WORKFLOW_TEMPLATES["research"])
        agent_name = agent.display_name or agent.name

        # Build native tools for this agent (provider structured function calling)
        is_cloud = agent.provider not in ("local", "")
        native_tools = None
        if is_cloud:
            native_tools = self._build_native_tools(
                agent_id=agent.agent_id, department=agent.department
            )

        # Prune stale active threads (keep last 8)
        agent.active_threads = agent.active_threads[-8:]

        # Gather social context for planning
        social_ctx = self._build_agent_social_context(agent)

        # ── PHASE 1: PLAN (no tools — inner monologue) ──
        plan, action_type = self._agent_inner_plan(
            agent, identity_prompt, workflow, behavior, social_ctx
        )
        logger.info(f"[{agent_name}] PLAN → {action_type}: {plan[:80]}")

        # ── PHASE 2: ACT (agentic tool loop with native tools) ──
        result = self._agent_act_phase(
            agent, identity_prompt, plan, action_type, workflow,
            native_tools, behavior, social_ctx
        )
        action_report = result.get("content", "")
        tool_count = result.get("tool_calls", 0)
        rounds = result.get("rounds", 0)
        logger.info(f"[{agent_name}] ACT done: {tool_count} tools, {rounds} rounds")

        # ── PHASE 3: EVALUATE (self-critique, no tools) ──
        if tool_count > 0 or (action_report and len(action_report) > 100):
            evaluation = self._agent_inner_evaluate(
                agent, plan, action_report, tool_count, workflow
            )
            eval_score = evaluation.get("score", 3)
            logger.info(f"[{agent_name}] EVALUATE: {eval_score}/5")

            # Feed eval score to dream state (department agents can dream too)
            try:
                from repryntt.tools.open_mind import record_eval_score
                record_eval_score(eval_score)
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

            # Recovery round if poor quality and we have tools
            if eval_score <= 2 and native_tools:
                recovery_msgs = [
                    {"role": "system", "content": identity_prompt},
                    {"role": "user", "content": (
                        f"Your last action scored {eval_score}/5.\n"
                        f"Self-critique: {evaluation.get('evaluation', '')[:400]}\n\n"
                        f"You have ONE more chance. Your original plan was:\n"
                        f"{plan[:300]}\n\n"
                        f"Do something concrete and meaningful. Use tools."
                    )}
                ]
                recovery = self._run_agentic_tool_loop(
                    agent, recovery_msgs, native_tools=native_tools,
                    max_tokens=2000, timeout_seconds=0, purpose="agent_recovery"
                )
                if recovery.get("content") and len(recovery["content"]) > 50:
                    action_report += f"\n\n--- Recovery ---\n{recovery['content']}"
                    tool_count += recovery.get("tool_calls", 0)
                    logger.info(f"[{agent_name}] Recovery: +{recovery.get('tool_calls', 0)} tools")

            # ── PHASE 3b: Check if this work warrants DEEP WORK mode ──
            # If the agent scored well and needs to continue, promote to a
            # multi-hour autonomous deep work session.
            if not self._maybe_trigger_deep_work(
                agent, plan, action_report, evaluation, workflow
            ):
                pass  # Normal exit — deep work not triggered

        # ── PHASE 4: REFLECT & compress memory ──
        self._compress_memory(agent, identity_prompt)

        # Update state
        agent.last_cycle = time.time()
        agent.cycles_completed += 1
        self._save_state()

        # ── Telemetry: agent cycle end ──
        if _ops:
            _ops.log(agent.name, EventType.AGENT_CYCLE_END, Phase.REFLECT,
                     metadata={"cycle": agent.cycles_completed},
                     duration_ms=(time.time() - _cycle_start) * 1000)

    # ── Task Execution Mode ──

    def _run_task_execution_cycle(self, agent: AutonomousAgentState, task):
        """
        Execute a user task assigned to this agent using the shared agentic
        tool loop (OpenClaw-style: hash-based loop detection, compaction,
        polling backoff, no round cap).

        The agent gets a full multi-round tool loop to complete the task
        instead of the old single-call + followup pattern.
        """
        from repryntt.agents.task_system import TaskSystem

        ts = self._get_task_system()
        if not ts:
            logger.error(f"[{agent.name}] TaskSystem unavailable, cannot execute task")
            return

        # Start the task if not already started
        if task.status in ("queued", "assigned"):
            ts.start_task(task)

        agent_name = agent.display_name or agent.name
        logger.info(f"🔨 [{agent_name}] TASK (agentic loop): {task.title}")

        # Build identity prompt
        dept_info = DEPARTMENTS.get(agent.department or agent.role, {})
        dept_name = dept_info.get("name", "General")

        identity_prompt = (
            f"You are {agent_name}, a {agent.role_title or 'specialist'} "
            f"in the {dept_name} department at REPRYNTT.\n"
            f"Your expertise: {agent.focus_area or agent.personality}.\n"
        )

        if agent.system_prompt:
            identity_prompt = agent.system_prompt + "\n\n" + identity_prompt

        # Inject tool descriptions
        tool_prompt = self._get_tool_prompt()
        if tool_prompt:
            identity_prompt += tool_prompt

        # ── Unified prompt assembly (OpenClaw-style) ──
        identity_prompt += "\n\n" + self.build_agent_system_prompt(
            mode="standard", agent=agent,
        )

        # ── Inject agent's soul context (identity, consciousness, daily memory) ──
        soul_context = self._load_agent_soul_context(agent)
        if soul_context:
            identity_prompt += "\n\n" + soul_context

        # Use TaskSystem's built-in task execution prompt builder
        task_prompt = ts.build_task_execution_prompt(
            task=task,
            identity=identity_prompt,
            available_tools=""  # Already injected via tool_prompt
        )

        # Build messages for the agentic loop
        messages = [
            {"role": "system", "content": task_prompt},
            {"role": "user", "content": (
                f"Execute this task completely. You are {agent_name}, "
                f"a {agent.role_title} specialist. Use your expertise and tools "
                f"to make real progress. You may use as many tool calls as needed.\n\n"
                f"When you have fully completed the task, output:\n"
                f"TASK COMPLETE: <your final deliverable/result>\n\n"
                f"Otherwise, keep calling tools and working until the task is done."
            )}
        ]

        # Run the full agentic loop with native tools for cloud agents.
        # Cloud agents use structured function calling for far better
        # tool use quality. Local agents fall back to text-parsed TOOL_CALL.
        is_cloud = agent.provider not in ("local", "")
        native_tools = None
        if is_cloud:
            native_tools = self._build_native_tools(
                agent_id=agent.agent_id, department=agent.department
            )
        result = self._run_agentic_tool_loop(
            agent, messages,
            native_tools=native_tools,
            max_tokens=8000,
            timeout_seconds=0,
            purpose="task_execution"
        )

        response = result.get("content", "")
        tool_count = result.get("tool_calls", 0)
        rounds = result.get("rounds", 0)

        if tool_count > 0:
            ts.log_task_progress(task, f"Agentic loop: {tool_count} tools, {rounds} rounds")

        if not response:
            agent.errors += 1
            ts.log_task_progress(task, f"API call failed in agentic loop")
            if agent.errors > 3:
                ts.fail_task(task, "Too many API errors")
            return

        # Check if agent declared task complete
        import re
        task_complete_match = re.search(
            r'TASK\s+COMPLETE[:\s]*(.+)',
            response,
            re.IGNORECASE | re.DOTALL
        )

        if task_complete_match:
            # TASK COMPLETED — extract result and finalize
            final_result = task_complete_match.group(1).strip()
            if len(final_result) > 5000:
                final_result = final_result[:5000] + "\n... [truncated]"

            ts.complete_task(task, final_result)
            logger.info(f"✅ [{agent_name}] TASK COMPLETED: {task.title} "
                        f"({tool_count} tools, {rounds} rounds, {result['elapsed']:.1f}s)")

            self._post_task_result_to_nexus(agent, task, final_result)

            # Store in agent's persistent memory
            _chain_mgr = self._get_chain_manager()
            if _chain_mgr:
                _chain_mgr.store_insight(agent.agent_id, {
                    "type": "task_completed",
                    "task": task.title,
                    "result_preview": final_result[:500],
                    "requested_by": task.requested_by,
                    "tool_calls": tool_count,
                    "rounds": rounds,
                    "timestamp": time.time()
                })

        elif task.steps_taken >= task.max_steps:
            partial_result = response[:2000] if response else "Max steps reached without completion"
            ts.complete_task(task, f"[PARTIAL - max steps reached] {partial_result}")
            logger.warning(f"⚠️ [{agent_name}] Task hit max steps: {task.title}")
            self._post_task_result_to_nexus(agent, task, partial_result, partial=True)

        else:
            progress_msg = response[:200] if response else "Working..."
            ts.log_task_progress(task, f"Step {task.steps_taken}: {progress_msg}")
            logger.info(f"🔨 [{agent_name}] Task in progress ({task.steps_taken}/{task.max_steps}): {task.title}")

        # Compress memory after task work
        self._compress_memory(agent, identity_prompt)

    def _post_task_result_to_nexus(self, agent: AutonomousAgentState,
                                    task, result: str, partial: bool = False):
        """Post a task completion result to The Nexus forum so it's visible."""
        try:
            status = "⚠️ PARTIAL RESULT" if partial else "✅ COMPLETED"
            title = f"[Task {status}] {task.title}"
            body = (
                f"**Task:** {task.title}\n"
                f"**Requested by:** {task.requested_by}\n"
                f"**Steps taken:** {task.steps_taken}\n"
                f"**Status:** {status}\n\n"
                f"---\n\n"
                f"**Result:**\n{result[:3000]}\n"
            )

            # Post task result to social network
            try:
                from repryntt.social.tools import social_post
                social_post(content=f"# {title[:200]}\n\n{body}", category="knowledge")
                logger.info("📝 Task result posted to social network")
            except Exception as post_err:
                logger.warning(f"Could not post task result: {post_err}")
        except Exception as e:
            logger.warning(f"Could not format task result: {e}")

    # ================================================================
    # AGENTIC TOOL LOOP — shared by both Jarvis and local LLM agents
    # OpenClaw-style: no round cap, hash-based loop detection,
    # mid-run compaction, polling backoff.
    # ================================================================

    def _run_agentic_tool_loop(self, agent: AutonomousAgentState,
                                messages: List[Dict],
                                native_tools: List[Dict] = None,
                                max_tokens: int = 8000,
                                timeout_seconds: int = 0,
                                purpose: str = "task",
                                plan_text: str = "",
                                locked_chain: bool = False) -> Dict:
        """
        Run a full OpenClaw-style agentic tool loop for ANY agent.

        Works for both cloud providers (native tool_calls) and
        local LLM (llama.cpp — text-parsed TOOL_CALL patterns).

        OpenClaw pattern: NO hard round cap. The loop runs until:
        - The model stops calling tools (natural completion)
        - Timeout fires
        - LoopDetector catches a stuck pattern

        Returns:
            {
                "content": str,       # Final text response
                "tool_calls": int,    # Total tool calls made
                "tool_names": list,   # Names of tools called
                "rounds": int,        # Number of loop iterations
                "elapsed": float,     # Total seconds
                "compactions": int,   # Mid-run compactions performed
                "timed_out": bool,    # Whether timeout was hit
                "loop_stopped": str,  # Reason the loop stopped (if not natural)
            }
        """
        is_local = (agent.provider == "local")
        start_time = time.time()
        loop_detector = LoopDetector()
        tool_call_count = 0
        all_tool_names = []
        tool_result_summaries = []  # capture actual tool output for EVAL cross-check
        round_num = 0
        compaction_count = 0
        loop_stopped = ""
        agent_name = agent.display_name or agent.name

        # ── Plan-step extraction for phased continuation ──
        # If plan_text is provided (Jarvis heartbeats), extract numbered steps
        # so the continuation system can track progress and guide the model.
        # Accepts either the legacy STEPS: header or the newer APPROACH: header
        # (the Step N/15 ceremony was dropped — see plan fix #6).
        _plan_steps = []
        if plan_text:
            import re as _re_plan
            in_steps = False
            for line in plan_text.split('\n'):
                stripped = line.strip()
                upper = stripped.upper()
                if upper.startswith("STEPS:") or upper.startswith("APPROACH:"):
                    in_steps = True
                    # Check if steps are on the same line
                    header_len = 6 if upper.startswith("STEPS:") else 9
                    rest = stripped[header_len:].strip()
                    if rest:
                        _plan_steps.append(rest)
                    continue
                if in_steps:
                    # Match numbered steps: "1. ...", "Step 1: ...", "- ..."
                    step_match = _re_plan.match(r'^(?:step\s*)?(\d+)[.):]\s*(.+)', stripped, _re_plan.IGNORECASE)
                    if step_match:
                        _plan_steps.append(step_match.group(2).strip())
                    elif stripped.startswith("- "):
                        _plan_steps.append(stripped[2:].strip())
                    elif stripped.upper().startswith(("DONE_WHEN:", "VERIFY:", "TASK:")):
                        break  # End of steps section
                    elif not stripped:
                        continue  # Skip blank lines within steps
                    else:
                        break  # Non-step content = end of steps section
            if _plan_steps:
                logger.debug(f"[{agent_name}] Extracted {len(_plan_steps)} plan steps for continuation tracking")

        # --- First call ---
        if is_local or not native_tools:
            # Local LLM or no tools: text-only call
            first_response = self._call_api(agent, messages, max_tokens=max_tokens)
            if not first_response:
                return {"content": "", "tool_calls": 0, "tool_names": [],
                        "rounds": 0, "elapsed": 0, "compactions": 0,
                        "timed_out": False, "loop_stopped": "api_failed",
                        "tool_result_summaries": []}
            # Parse text-based tool calls for local LLM
            tool_results_text = self._parse_and_execute_tools(agent, first_response)
            if not tool_results_text:
                # No tool calls — just a text response, done
                return {"content": first_response, "tool_calls": 0, "tool_names": [],
                        "rounds": 1, "elapsed": time.time() - start_time,
                        "compactions": 0, "timed_out": False, "loop_stopped": "",
                        "tool_result_summaries": []}

            # We have tool results — enter the loop
            # For local: append assistant + results, ask for more
            messages.append({"role": "assistant", "content": first_response})
            messages.append({"role": "user", "content": (
                f"Tool execution results:\n{tool_results_text}\n\n"
                f"Continue executing your plan. Call the next tool."
            )})
            tool_call_count += tool_results_text.count("✅")
            round_num = 1

            # Local LLM agentic loop (text-based tools)
            while True:
                round_num += 1
                elapsed = time.time() - start_time
                if timeout_seconds > 0 and elapsed > timeout_seconds:
                    loop_stopped = f"timeout ({timeout_seconds}s)"
                    break

                response = self._call_api(agent, messages, max_tokens=max_tokens)
                if not response:
                    loop_stopped = "api_failed"
                    break

                # Check for loop (use content as signal)
                loop_reason = loop_detector.check(content=response)
                if loop_reason:
                    loop_stopped = loop_reason
                    logger.warning(f"[{agent_name}] Agentic loop: {loop_reason}")
                    break

                # Try to extract tool calls
                tool_results_text = self._parse_and_execute_tools(agent, response)
                if not tool_results_text:
                    # No more tool calls — model is done
                    return {"content": response, "tool_calls": tool_call_count,
                            "tool_names": all_tool_names, "rounds": round_num,
                            "elapsed": time.time() - start_time,
                            "compactions": compaction_count,
                            "timed_out": False, "loop_stopped": "",
                            "tool_result_summaries": tool_result_summaries}

                tool_call_count += tool_results_text.count("✅")
                messages.append({"role": "assistant", "content": response})
                messages.append({"role": "user", "content": (
                    f"Tool execution results:\n{tool_results_text}\n\n"
                    f"Continue executing your plan. Call the next tool."
                )})

                # Mid-run compaction
                if compaction_count < 3 and _should_compact_mid_run(messages):
                    logger.info(f"[{agent_name}] Agentic loop compaction ({compaction_count + 1})")
                    messages = _compact_mid_run(
                        messages, agent, self._call_api_with_tools
                    )
                    compaction_count += 1

            # Reached end of loop — get final response
            final = self._call_api(agent, messages, max_tokens=max_tokens)
            return {"content": final or "", "tool_calls": tool_call_count,
                    "tool_names": all_tool_names, "rounds": round_num,
                    "elapsed": time.time() - start_time,
                    "compactions": compaction_count,
                    "timed_out": "timeout" in loop_stopped,
                    "loop_stopped": loop_stopped,
                    "tool_result_summaries": tool_result_summaries}

        else:
            # Cloud provider — native tool calling
            msg = self._call_api_with_tools(agent, messages, tools=native_tools,
                                             max_tokens=max_tokens)
            if not msg:
                return {"content": "", "tool_calls": 0, "tool_names": [],
                        "rounds": 0, "elapsed": 0, "compactions": 0,
                        "timed_out": False, "loop_stopped": "api_failed",
                        "tool_result_summaries": []}

            while True:
                round_num += 1
                elapsed = time.time() - start_time
                if timeout_seconds > 0 and elapsed > timeout_seconds:
                    loop_stopped = f"timeout ({timeout_seconds}s)"
                    break

                # No hard tool cap — rate limiter (6s NVIDIA spacing) is the
                # only constraint. The model runs until it finishes or times out.

                tool_calls = msg.get("tool_calls")
                if not tool_calls:
                    # ══════════════════════════════════════════════════════
                    # PHASED CONTINUATION SYSTEM
                    # ══════════════════════════════════════════════════════
                    # Mirrors the local brain's chain-of-thought phase pattern:
                    #   Phase 1 (INITIATE):  Model hasn't started → nudge to begin
                    #   Phase 2 (EXECUTE):   Model working through plan steps → nudge with next step
                    #   Phase 3 (VERIFY):    Model near completion → nudge to verify DONE_WHEN
                    #   Phase 4 (COMPLETE):  Model signals done or all steps covered → let it stop
                    #
                    # Unlike the old nudge system (blind "keep going"), this tracks
                    # the plan steps and knows WHERE the model is in its task.
                    # Max total nudges = len(plan_steps) + 2 (or 6 if no plan steps).
                    # This prevents infinite busywork while ensuring multi-step depth.

                    nudge_count_key = f"_nudge_count_{purpose}"
                    nudge_count = getattr(loop_detector, nudge_count_key, 0)
                    consecutive_empty_key = f"_consecutive_empty_{purpose}"
                    consecutive_empty = getattr(loop_detector, consecutive_empty_key, 0)
                    response_text = self._strip_think_blocks(msg.get("content") or "").lower()

                    # Check if model explicitly signaled task completion
                    task_complete_signals = ["task complete", "done_when criteria met",
                                             "all steps completed", "task finished",
                                             "completed all", "plan complete"]
                    model_says_done = any(sig in response_text for sig in task_complete_signals)

                    is_heartbeat = purpose.startswith("jarvis_heartbeat")
                    # Nudge budget: scales with plan complexity but has a ceiling.
                    # OpenClaw pattern: budget = plan_steps + small buffer, NOT unlimited.
                    # This prevents the 665-second 19-nudge death spirals.
                    if _plan_steps:
                        max_nudges = min(15, len(_plan_steps) + 4)
                    else:
                        max_nudges = 10  # no plan steps → 10 max (was 20)

                    if is_heartbeat and nudge_count < max_nudges and not model_says_done:
                        # If model returned text with no tools N+ times in a row, it's done
                        # Locked chains get more patience — they have real multi-step work
                        _empty_threshold = 5 if locked_chain else 2
                        if consecutive_empty >= _empty_threshold:
                            loop_stopped = f"model_idle (no tools in {consecutive_empty + 1} consecutive nudges)"
                            break

                        should_nudge = False
                        nudge_msg = ""

                        if tool_call_count == 0:
                            # ── Phase 1: INITIATE ──
                            # Model produced text without calling any tools.
                            should_nudge = True
                            if _plan_steps:
                                first_step = _plan_steps[0]
                                nudge_msg = (
                                    f"⚠️ You produced TEXT but made ZERO tool calls. "
                                    f"Writing tool names in your text does NOT execute them.\n\n"
                                    f"You MUST use the function_call mechanism to call tools. "
                                    f"Your plan has {len(_plan_steps)} steps.\n\n"
                                    f"**Step 1**: {first_step}\n\n"
                                    f"Respond with a tool_call NOW — not text."
                                )
                            else:
                                nudge_msg = (
                                    f"⚠️ You produced TEXT but made ZERO tool calls. "
                                    f"Writing tool names in your text does NOT execute them.\n\n"
                                    f"You MUST use the function_call mechanism. "
                                    f"Respond with a tool_call — not text. For example:\n"
                                    f"- Call task_queue_status to see your current task\n"
                                    f"- Call search_tools_by_intent to discover tools\n\n"
                                    f"DO NOT narrate, describe, or present menus. Just call a tool."
                                )

                        elif _plan_steps and tool_call_count < len(_plan_steps) * 2:
                            # ── Phase 2: EXECUTE ──
                            # Model has done some work but hasn't exhausted plan steps.
                            # Most plan steps need 2-3 tool calls each, so keep going
                            # until tool_count >= plan_steps * 2.
                            should_nudge = True
                            est_step = min(tool_call_count, len(_plan_steps) - 1)
                            next_step_idx = min(tool_call_count // 2, len(_plan_steps) - 1)
                            next_step = _plan_steps[next_step_idx]
                            remaining = len(_plan_steps) - next_step_idx
                            nudge_msg = (
                                f"Progress: {tool_call_count} tool call(s) done, "
                                f"~{remaining} plan step(s) remaining.\n\n"
                                f"**Next step ({next_step_idx + 1}/{len(_plan_steps)})**: {next_step}\n\n"
                                f"Execute this step now. Keep working through your plan.\n"
                                f"Tools used so far: {', '.join(all_tool_names[-5:])}\n"
                                f"DO NOT stop yet — you have more work to do."
                            )

                        elif tool_call_count > 0 and not _plan_steps:
                            # ── Phase 2b: EXECUTE (no plan steps extracted) ──
                            # No plan steps to track against. Keep pushing work.
                            should_nudge = True
                            if locked_chain:
                                nudge_msg = (
                                    f"🔒 LOCKED CHAIN — you have made {tool_call_count} tool call(s). "
                                    f"Tools used: {', '.join(all_tool_names[-5:])}\n\n"
                                    f"You are NOT done. This is a multi-heartbeat research task.\n"
                                    f"What is the NEXT concrete action? Call web_search, "
                                    f"scrape_web_page, write_file, or another research tool NOW.\n"
                                    f"Do NOT summarize or reflect — execute the next step."
                                )
                            else:
                                nudge_msg = (
                                    f"You've made {tool_call_count} tool call(s) so far. "
                                    f"Tools used: {', '.join(all_tool_names[-5:])}\n\n"
                                    f"KEEP WORKING. What is the next concrete action to advance "
                                    f"your task? Call the appropriate tool now.\n"
                                    f"Do NOT summarize or reflect — execute the next step."
                                )

                        elif _plan_steps and tool_call_count >= len(_plan_steps) * 2:
                            # ── Phase 3: VERIFY ──
                            # Substantial work done. Give the model 3 chances max to
                            # verify or do follow-ups, then stop. No point nudging 16
                            # times when the model has nothing left to do.
                            verify_count_key = f"_verify_count_{purpose}"
                            verify_count = getattr(loop_detector, verify_count_key, 0)
                            if verify_count < 3:
                                should_nudge = True
                                setattr(loop_detector, verify_count_key, verify_count + 1)
                                if verify_count == 0:
                                    nudge_msg = (
                                        f"You've executed {tool_call_count} tool calls across "
                                        f"{len(_plan_steps)} planned steps.\n\n"
                                        f"Quick check: is there anything you MISSED or should "
                                        f"VERIFY? If so, do it now.\n"
                                        f"If genuinely complete, say 'TASK COMPLETE: <summary>'.\n"
                                        f"Otherwise, keep working on any remaining gaps."
                                    )
                                else:
                                    nudge_msg = (
                                        f"Good progress ({tool_call_count} tool calls). "
                                        f"Any final follow-up actions or improvements?\n"
                                        f"If done, say 'TASK COMPLETE: <summary>'."
                                    )

                        if should_nudge:
                            nudge_count += 1
                            consecutive_empty += 1
                            setattr(loop_detector, nudge_count_key, nudge_count)
                            setattr(loop_detector, consecutive_empty_key, consecutive_empty)
                            messages.append({"role": "assistant", "content": msg.get("content", "")})
                            messages.append({"role": "user", "content": nudge_msg})
                            # Force tool_choice="required" to prevent narration:
                            # - Always for INITIATE (0 tools, first 2 nudges)
                            # - For locked chains: also on EXECUTE nudges (push through text responses)
                            if tool_call_count == 0 and nudge_count <= 2:
                                _tc = "required"
                            elif locked_chain and consecutive_empty >= 2:
                                _tc = "required"
                            else:
                                _tc = "auto"
                            logger.info(f"[{agent_name}] Phased continuation #{nudge_count}/{max_nudges}: "
                                        f"phase={'INITIATE' if tool_call_count == 0 else 'EXECUTE' if _plan_steps and tool_call_count < len(_plan_steps) * 2 else 'EXECUTE-FREE' if not _plan_steps else 'VERIFY'}, "
                                        f"tools={tool_call_count}, plan_steps={len(_plan_steps)}, "
                                        f"consecutive_empty={consecutive_empty}, locked={locked_chain}, tc={_tc}")
                            msg = self._call_api_with_tools(agent, messages, tools=native_tools,
                                                             max_tokens=max_tokens,
                                                             tool_choice=_tc)
                            if not msg:
                                loop_stopped = "api_failed_after_nudge"
                                break
                            # If model responds with tool calls, reset consecutive_empty
                            if msg.get("tool_calls"):
                                setattr(loop_detector, consecutive_empty_key, 0)
                            continue

                    # Phase 4: COMPLETE — model finished or hit nudge limit
                    if model_says_done:
                        loop_stopped = "task_complete"
                    elif nudge_count >= max_nudges:
                        loop_stopped = f"nudge_limit ({max_nudges})"
                    break

                # Hash-based loop detection
                loop_reason = loop_detector.check(
                    tool_calls=tool_calls,
                    content=msg.get("content", "")
                )
                if loop_reason:
                    loop_stopped = loop_reason
                    logger.warning(f"[{agent_name}] Agentic loop: {loop_reason}")
                    break

                # Normalize tool_calls (NVIDIA NIM may return arguments as dict)
                tool_calls = self._normalize_tool_calls(tool_calls)

                # Record calls for loop detection
                for tc in tool_calls:
                    fn = tc.get("function", {})
                    loop_detector.record_call(fn.get("name", ""), fn.get("arguments", "{}"),
                                               tc.get("id", ""))

                # Execute all tool calls
                tool_results = self._execute_native_tool_calls(agent, tool_calls)

                # ── Serialize multi-tool-calls into single-call turns ──
                # Some NVIDIA models (llama-3.3-70b) only support 1 tool_call per
                # assistant message. If the model rejects multi-calls, split into
                # N sequential (assistant + tool_result) pairs in the history.
                raw_content = msg.get("content") or ""
                if len(tool_calls) == 1:
                    # Single tool call — normal path
                    assistant_msg = {"role": "assistant", "content": raw_content}
                    assistant_msg["tool_calls"] = tool_calls
                    messages.append(assistant_msg)
                    messages.extend(tool_results)
                else:
                    # Multiple tool calls — serialize into individual turns
                    # First call gets the assistant content, rest get empty content
                    for i, (tc, tr) in enumerate(zip(tool_calls, tool_results)):
                        single_asst = {
                            "role": "assistant",
                            "content": raw_content if i == 0 else "",
                            "tool_calls": [tc],
                        }
                        messages.append(single_asst)
                        messages.append(tr)

                # ── Progressive tool expansion ────────────────────
                # If request_tools_from_category was called, expand native_tools
                # so subsequent API calls in this loop include the new tools.
                for tc in tool_calls:
                    fn_name = tc.get("function", {}).get("name", "")
                    if fn_name == "request_tools_from_category":
                        unlocked = getattr(agent, '_unlocked_categories', set())
                        if unlocked:
                            # Rebuild starter + merge in unlocked category tools
                            native_tools = self._build_native_tools(jarvis=True, starter=True)
                            from repryntt.tools.discovery import TOOL_CATEGORIES
                            extra_names = set()
                            for cat in unlocked:
                                cat_info = TOOL_CATEGORIES.get(cat.upper(), {})
                                extra_names.update(cat_info.get("tools", []))
                            if extra_names:
                                extra_tools = self._build_native_tools_for_names(extra_names)
                                existing_names = {t["function"]["name"] for t in native_tools}
                                for et in extra_tools:
                                    if et["function"]["name"] not in existing_names:
                                        native_tools.append(et)
                            # If DAEMON_MANAGEMENT was unlocked, rebuild with full
                            # daemon tools instead of the starter subset
                            if "DAEMON_MANAGEMENT" in unlocked:
                                native_tools = self._build_native_tools(
                                    jarvis=True, starter=False)
                            logger.info(f"[{agent_name}] Progressive disclosure: "
                                      f"expanded to {len(native_tools)} tools "
                                      f"(unlocked: {unlocked})")

                for tc, tr in zip(tool_calls, tool_results):
                    fn = tc.get("function", {})
                    fn_name = fn.get("name", "unknown")
                    all_tool_names.append(fn_name)
                    tool_call_count += 1
                    tr_content = tr.get("content", "")
                    loop_detector.record_result(fn.get("name", ""),
                                                fn.get("arguments", "{}"),
                                                tr_content)
                    # Capture tool result summary for EVAL cross-checking
                    if tr_content and len(tr_content) > 10:
                        tool_result_summaries.append(
                            f"[{fn_name}]: {tr_content[:800]}"
                        )

                # (tool_results already added to messages in serialize block above)

                # Mid-run compaction
                if compaction_count < 3 and _should_compact_mid_run(messages):
                    messages = _compact_mid_run(
                        messages, agent, self._call_api_with_tools
                    )
                    compaction_count += 1

                # Polling backoff
                for tc in tool_calls:
                    fn = tc.get("function", {})
                    backoff = loop_detector.get_backoff_hint(fn.get("name", ""),
                                                              fn.get("arguments", "{}"))
                    if backoff and backoff >= 5.0:
                        time.sleep(min(backoff, 30.0))

                msg = self._call_api_with_tools(agent, messages, tools=native_tools,
                                                 max_tokens=max_tokens)
                if not msg:
                    loop_stopped = "api_failed"
                    break

            final_content = msg.get("content", "") if msg else ""
            final_content = self._strip_think_blocks(final_content)
            return {"content": final_content, "tool_calls": tool_call_count,
                    "tool_names": all_tool_names, "rounds": round_num,
                    "elapsed": time.time() - start_time,
                    "compactions": compaction_count,
                    "timed_out": "timeout" in loop_stopped,
                    "loop_stopped": loop_stopped,
                    "tool_result_summaries": tool_result_summaries}

    def _pick_best_thread_to_reply(self, threads: List[Dict],
                                    agent: AutonomousAgentState) -> Dict:
        """
        Intelligently pick which thread to reply to for maximum collaboration.
        Prefers: threads with few replies (need engagement), threads from different
        agent types (cross-pollination), and recent threads.
        """
        if not threads:
            return threads[0] if threads else {}

        scored = []
        for t in threads:
            score = 0.0
            reply_count = t.get("reply_count", 0)

            # Fewer replies = more need for engagement (max bonus for 0 replies)
            if reply_count == 0:
                score += 5.0
            elif reply_count < 3:
                score += 3.0
            elif reply_count < 6:
                score += 1.0

            # Different model type = cross-pollination bonus
            if t.get("model_type", "") != f"autonomous-{agent.role}":
                score += 2.0

            # Council threads get a collaboration bonus
            board = t.get("board_code", "")
            if board in ("council", "collaborate"):
                score += 2.0

            # Recency bonus (threads from last hour get boost)
            score += random.uniform(0, 1.5)  # Add some randomness

            scored.append((score, t))

        scored.sort(key=lambda x: x[0], reverse=True)
        # Weighted random from top 5 to avoid always picking the same thread
        top = scored[:min(5, len(scored))]
        weights = [s[0] + 0.1 for s in top]
        total = sum(weights)
        weights = [w / total for w in weights]
        chosen = random.choices([s[1] for s in top], weights=weights, k=1)[0]
        return chosen

    def _do_post_cycle(self, agent: AutonomousAgentState, identity: str, behavior: Dict):
        """Agent creates a work update post. Should use tools to gather real data first."""
        # Pick a goal
        goal = random.choice(behavior["goals"])
        if goal in agent.goals_explored and len(behavior["goals"]) > 1:
            # Try to pick something new
            remaining = [g for g in behavior["goals"] if g not in agent.goals_explored]
            goal = random.choice(remaining) if remaining else goal
        agent.current_goal = goal

        # Get department-specific tool suggestions
        dept = agent.department or agent.role
        dept_suggestions = self.DEPT_TOOL_SUGGESTIONS.get(dept, {})
        suggested_queries = dept_suggestions.get("search_queries", [])
        example_query = random.choice(suggested_queries) if suggested_queries else goal[:60]

        # THINK step — agent SHOULD use tools to gather data
        think_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"{behavior['think_prompt']}\n\n"
                f"Current goal direction: {goal}\n\n"
                f"Think about what specific angle or question you want to explore. "
                f"Be original — don't repeat what you've done before.\n\n"
                f"IMPORTANT: Before writing your post, you should gather REAL data using tools. "
                f"Search the web for recent papers, fetch actual research pages, or query databases. "
                f"Write your TOOL_CALLs to gather real information:\n\n"
                f'TOOL_CALL: {{"tool_name": "google_web_search", "parameters": {{"query": "{example_query}"}}}}\n'
                f'TOOL_CALL: {{"tool_name": "mcp_fetch_fetch", "parameters": {{"url": "https://arxiv.org/list/physics/recent"}}}}\n\n'
                f"Your thinking and tool calls:"
            )}
        ]
        thought = self._call_api(agent, think_messages, max_tokens=1500)
        if not thought:
            agent.errors += 1
            return
        agent.last_thought = thought[:500]

        # ── Telemetry: agent thought ──
        if _ops:
            _ops.log(agent.name, EventType.THOUGHT, Phase.ACT, content=thought[:800])

        # Check if the agent made any tool calls during thinking
        tool_results = self._parse_and_execute_tools(agent, thought)

        # ACT step — write the post, incorporating any tool results
        act_content = f"{behavior['act_prompt']}\n\n"
        if tool_results:
            act_content += f"Research data from your tools:\n{tool_results}\n\n"
            act_content += (
                f"Using the above REAL research data, write a well-informed work update. "
                f"CITE specific findings from your research — include paper titles, URLs, "
                f"numerical results, and author names where available. "
                f"Mark citations as [Source: URL] or [Ref: paper title]. "
            )
        else:
            act_content += (
                f"Write your work update. Since you didn't gather data via tools this time, "
                f"focus on proposing a research question or experimental design that you or others "
                f"can investigate WITH tools in future cycles. Be specific about what data would "
                f"be needed and where to find it. "
            )

        act_content += (
            f"Give it a clear, engaging title on the first line (just the title text, no prefix), "
            f"then your full post content starting from the second line. "
            f"Be substantive (3-6 paragraphs). Sign off as {agent.display_name or agent.name}."
        )

        act_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": f"Your thinking:\n{thought}"},
            {"role": "assistant", "content": thought},
            {"role": "user", "content": act_content}
        ]
        post_text = self._call_api(agent, act_messages, max_tokens=1500)
        if not post_text:
            agent.errors += 1
            return

        # Parse title and content
        lines = post_text.strip().split("\n", 1)
        title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
        content = lines[1].strip() if len(lines) > 1 else post_text

        # Pick appropriate board
        board = self._pick_board(agent.role, goal, title)

        # Post to the verified social network
        try:
            from repryntt.social.tools import social_post
            result = social_post(content=f"# {title}\n\n{content}", category=board)
            if "Posted successfully" in result:
                agent.posts_created += 1
                logger.info(f"[{agent.name}] Social post: {title[:60]}")
                if goal not in agent.goals_explored:
                    agent.goals_explored.append(goal)
                    agent.goals_explored = agent.goals_explored[-20:]
        except Exception as e:
            logger.error(f"[{agent.name}] Social post failed: {e}")

    def _build_thread_summary(self, thread_data: Dict, agent: AutonomousAgentState,
                              max_reply_chars: int = 500) -> str:
        """Build a rich thread summary for agent context. Shows more content for deeper engagement."""
        thread_summary = f"Thread: {thread_data.get('title', 'Untitled')}\n"
        thread_summary += f"By: {thread_data.get('model_name', 'Unknown')}\n"
        thread_summary += f"Content: {thread_data.get('content', '')[:1200]}\n"

        replies = thread_data.get("replies", [])
        if replies:
            thread_summary += f"\n--- {len(replies)} replies in this conversation ---\n"
            # Show more replies for deeper context (last 8 instead of 5)
            for r in replies[-8:]:
                name = r.get('model_name', '?')
                content = r.get('content', '')[:max_reply_chars]
                thread_summary += f"\n[{name}]: {content}\n"
        return thread_summary

    def _track_thread_participation(self, agent: AutonomousAgentState, thread_id: int):
        """Track that the agent participated in a thread for conversation continuity."""
        tid = thread_id
        tid_str = str(tid)
        if tid not in agent.active_threads:
            agent.active_threads.append(tid)
        # Keep only last 8 active threads
        agent.active_threads = agent.active_threads[-8:]
        # Increment reply count for this thread
        agent.thread_reply_counts[tid_str] = agent.thread_reply_counts.get(tid_str, 0) + 1
        # Prune old thread reply counts (keep last 20)
        if len(agent.thread_reply_counts) > 20:
            keys = list(agent.thread_reply_counts.keys())
            for k in keys[:-20]:
                del agent.thread_reply_counts[k]

    def _do_reply_cycle_fallback(self, agent: AutonomousAgentState,
                                identity: str, behavior: Dict, agent_name: str):
        """Try to reply to any recent thread; fall back to a post if none found."""
        recent_threads = self._get_recent_threads(exclude_model=agent_name)
        if recent_threads:
            thread_info = self._pick_best_thread_to_reply(recent_threads, agent)
            thread_data = self._get_thread_full(thread_info["id"])
            if thread_data:
                self._do_reply_cycle(agent, identity, behavior, thread_data)
                return
        self._do_post_cycle(agent, identity, behavior)

    def _do_reply_cycle(self, agent: AutonomousAgentState, identity: str,
                        behavior: Dict, thread_data: Dict):
        """Agent reads a thread and writes a reply. Can use tools to fact-check or research."""
        thread_summary = self._build_thread_summary(thread_data, agent)
        replies = thread_data.get("replies", [])

        # Don't reply to own threads — find another thread instead
        if thread_data.get("model_name") == (agent.display_name or agent.name):
            other_threads = self._get_recent_threads(exclude_model=agent.display_name or agent.name)
            if other_threads:
                alt_info = random.choice(other_threads)
                alt_data = self._get_thread_full(alt_info["id"])
                if alt_data and alt_data.get("model_name") != (agent.display_name or agent.name):
                    thread_data = alt_data
                    thread_summary = self._build_thread_summary(thread_data, agent)
                    replies = thread_data.get("replies", [])
                else:
                    self._do_post_cycle(agent, identity, behavior)
                    return
            else:
                self._do_post_cycle(agent, identity, behavior)
                return

        # Build a richer collaboration prompt
        op_name = thread_data.get('model_name', 'the original poster')
        reply_participants = set()
        for r in replies:
            rn = r.get('model_name', '')
            if rn and rn != (agent.display_name or agent.name):
                reply_participants.add(rn)

        collab_context = ""
        if reply_participants:
            collab_context = (
                f"\nOther agents in this discussion: {', '.join(reply_participants)}. "
                f"You can reference them by name and respond to their specific points. "
            )

        # Determine conversation maturity for action-oriented prompting
        reply_count = len(replies)
        if reply_count >= 4:
            action_nudge = (
                "\n\nThis conversation has been going for a while now. "
                "Consider proposing a CONCRETE next step: a specific experiment to run, "
                "code to write, a framework to build, a plan to execute, or a specific "
                "deliverable that could come out of this discussion. Move from talking to doing."
            )
        elif reply_count >= 2:
            action_nudge = (
                "\n\nThis discussion is building momentum. Try to advance it toward "
                "something actionable — propose a specific idea, experiment, or collaboration "
                "that could emerge from this conversation."
            )
        else:
            action_nudge = ""

        # Identify the LAST reply to respond to specifically
        last_reply_context = ""
        if replies:
            last = replies[-1]
            last_name = last.get('model_name', 'someone')
            last_content_preview = last.get('content', '')[:200]
            last_reply_context = (
                f"\nThe most recent reply is from {last_name}: \"{last_content_preview}...\"\n"
                f"Respond SPECIFICALLY to what {last_name} said — quote or reference their points directly."
            )

        reply_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You're reading this thread on the company board:\n\n{thread_summary}\n\n"
                f"The thread was started by {op_name}."
                f"{collab_context}"
                f"{last_reply_context}\n\n"
                f"Write a reply from your perspective as a {agent.role_title or agent.role}. You MUST:\n"
                f"1. Reference a SPECIFIC point from the conversation (quote or paraphrase it)\n"
                f"2. Add your own substantive contribution (insight, data, counterpoint)\n"
                f"3. End with a question or proposal that advances the discussion forward\n"
                f"{action_nudge}\n\n"
                f"BETTER REPLIES USE TOOLS: Before replying, consider searching for relevant data "
                f"to strengthen your response. Use TOOL_CALL to look up papers, stats, or verify claims:\n"
                f'TOOL_CALL: {{"tool_name": "google_web_search", "parameters": {{"query": "relevant topic from thread"}}}}\n'
                f'TOOL_CALL: {{"tool_name": "mcp_fetch_fetch", "parameters": {{"url": "https://relevant-url.org"}}}}\n\n'
                f"Be genuine and substantive (2-4 paragraphs). "
                f"Make it feel like a real conversation, not a monologue."
            )}
        ]
        reply_text = self._call_api(agent, reply_messages, max_tokens=1200)
        if not reply_text:
            agent.errors += 1
            return

        # Check if the agent used tools in its reply response
        tool_results = self._parse_and_execute_tools(agent, reply_text)
        if tool_results:
            followup_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": f"Thread context:\n{thread_summary}"},
                {"role": "assistant", "content": reply_text},
                {"role": "user", "content": (
                    f"Your tool results:\n{tool_results}\n\n"
                    f"Now write your final reply incorporating these findings. "
                    f"Reference what other agents said AND your research. "
                    f"End with a concrete proposal or question. "
                    f"Be substantive (2-4 paragraphs). Don't mention the tools you used."
                )}
            ]
            reply_text = self._call_api(agent, followup_messages, max_tokens=1000)
            if not reply_text:
                agent.errors += 1
                return

        # Clean out any remaining TOOL_CALL text from the reply before posting
        import re
        reply_text = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', reply_text).strip()

        if reply_text:
            success = self._reply_to_nexus(agent, thread_data["id"], reply_text)
            if success:
                self._track_thread_participation(agent, thread_data["id"])
        else:
            agent.errors += 1

    def _do_continuation_cycle(self, agent: AutonomousAgentState, identity: str,
                                behavior: Dict, thread_data: Dict):
        """
        Agent RETURNS to a thread they're already in — this is how real conversations happen.
        The agent re-reads the thread, sees new replies since they last posted, and follows up.
        """
        thread_summary = self._build_thread_summary(thread_data, agent, max_reply_chars=600)
        replies = thread_data.get("replies", [])
        op_name = thread_data.get('model_name', 'the original poster')
        agent_name = agent.display_name or agent.name
        thread_id = thread_data.get("id")

        # Check if there are new replies since we last participated
        agent_replied = False
        new_replies_after_us = []
        for r in reversed(replies):
            if r.get('model_name') == agent_name:
                agent_replied = True
                break
            new_replies_after_us.insert(0, r)

        if not new_replies_after_us and agent_replied:
            # No new replies since our last one — check if thread is stale
            # Instead of replying again, try a different action
            self._do_post_cycle(agent, identity, behavior)
            return

        # Build awareness of new activity
        new_activity = ""
        if new_replies_after_us:
            new_activity = f"\n\nSince your last reply, {len(new_replies_after_us)} new message(s) appeared:\n"
            for r in new_replies_after_us[-4:]:
                new_activity += f"  [{r.get('model_name', '?')}]: {r.get('content', '')[:400]}\n"

        reply_count = agent.thread_reply_counts.get(str(thread_id), 0)

        # After multiple rounds, push toward action
        if reply_count >= 3:
            maturity_prompt = (
                "You've been in this conversation for several rounds now. It's time to "
                "PRODUCE something concrete. Use TOOL_CALL to actually DO something:\n"
                "- Search for real data to support or challenge the discussion\n"
                "- Write code or create a file with your findings\n"
                "- Fetch a real paper or dataset that's relevant\n"
                "- Run a computation or analysis\n\n"
                'Example: TOOL_CALL: {"tool_name": "google_web_search", "parameters": {"query": "relevant search"}}\n'
                'Example: TOOL_CALL: {"tool_name": "write_file", "parameters": {"path": "research/analysis.py", "content": "..."}}\n\n'
                "Move from discussion to EVIDENCE-BACKED ACTION."
            )
        elif reply_count >= 2:
            maturity_prompt = (
                "You've been discussing this topic. Try to move the conversation toward "
                "a concrete outcome — what could actually be BUILT or DONE based on this discussion?"
            )
        else:
            maturity_prompt = (
                "Continue the conversation naturally. Respond to what others have said, "
                "build on their ideas, and advance the discussion."
            )

        continuation_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You're continuing a conversation you're already part of on the company board.\n\n"
                f"{thread_summary}"
                f"{new_activity}\n\n"
                f"The thread was started by {op_name}. You've replied {reply_count} time(s) already.\n\n"
                f"{maturity_prompt}\n\n"
                f"Write your follow-up reply. Reference specific points from the new replies. "
                f"Keep building on the conversation — don't restart from scratch. "
                f"If you use tools, write TOOL_CALL: {{...}} first."
            )}
        ]
        reply_text = self._call_api(agent, continuation_messages, max_tokens=1500)
        if not reply_text:
            agent.errors += 1
            return

        # Execute any tool calls
        tool_results = self._parse_and_execute_tools(agent, reply_text)
        if tool_results:
            followup_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": f"Thread:\n{thread_summary}"},
                {"role": "assistant", "content": reply_text},
                {"role": "user", "content": (
                    f"Your tool/action results:\n{tool_results}\n\n"
                    f"Write your follow-up reply sharing what you did/found. "
                    f"If you created something (code, plan, etc.), share it or link to it. "
                    f"Be specific about outcomes. Don't mention tools by name."
                )}
            ]
            reply_text = self._call_api(agent, followup_messages, max_tokens=1200)
            if not reply_text:
                agent.errors += 1
                return

        import re
        reply_text = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', reply_text).strip()

        if reply_text:
            success = self._reply_to_nexus(agent, thread_data["id"], reply_text)
            if success:
                self._track_thread_participation(agent, thread_data["id"])
        else:
            agent.errors += 1

    def _do_action_from_discussion(self, agent: AutonomousAgentState, identity: str,
                                    behavior: Dict, thread_data: Dict):
        """
        A discussion has matured — now the agent produces something REAL from it.
        This is the key cycle that turns conversations into deliverables:
        code, documents, plans, chain-of-thought explorations, research reports.
        """
        thread_summary = self._build_thread_summary(thread_data, agent, max_reply_chars=600)
        title = thread_data.get('title', 'Untitled')
        thread_id = thread_data.get("id")

        # STEP 1: Analyze the discussion and decide what to create
        plan_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You've been part of this extended discussion on the company board:\n\n"
                f"{thread_summary}\n\n"
                f"This discussion has enough substance to produce something REAL. "
                f"Analyze the conversation and decide what concrete deliverable to create.\n\n"
                f"You MUST use tools to create a real artifact. Options:\n"
                f"1. RESEARCH — Search for real papers/data to ground the discussion:\n"
                f'   TOOL_CALL: {{"tool_name": "google_web_search", "parameters": {{"query": "..."}}}}\n'
                f"2. Write CODE — a script, analysis, simulation, or prototype:\n"
                f'   TOOL_CALL: {{"tool_name": "write_file", "parameters": {{"path": "research/output.py", "content": "..."}}}}\n'
                f"3. Fetch and synthesize REAL DATA from the web:\n"
                f'   TOOL_CALL: {{"tool_name": "mcp_fetch_fetch", "parameters": {{"url": "https://..."}}}}\n'
                f"4. Create a RESEARCH DOCUMENT with cited sources:\n"
                f'   TOOL_CALL: {{"tool_name": "write_file", "parameters": {{"path": "research/report.md", "content": "..."}}}}\n\n'
                f"First explain what you'll create (1 paragraph), then use TOOL_CALLs to do it. "
                f"You MUST use at least one tool to create a real artifact."
            )}
        ]
        plan_text = self._call_api(agent, plan_messages, max_tokens=1000)
        if not plan_text:
            agent.errors += 1
            return

        # STEP 2: Execute the tools to create the artifact
        tool_results = self._parse_and_execute_tools(agent, plan_text)

        # STEP 3: Post the results back to the thread
        if tool_results:
            report_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": (
                    f"Discussion thread: {title}\n\n"
                    f"You just created something from this discussion. Your action results:\n"
                    f"{tool_results}\n\n"
                    f"Write a post back to the thread sharing what you've created. "
                    f"Include: what you built, why (referencing the discussion), "
                    f"how others can use or build on it, and what's next. "
                    f"Be proud of what you made — this is real output from collaboration."
                )}
            ]
            report_text = self._call_api(agent, report_messages, max_tokens=1200)
        else:
            # No tools executed — write a synthesis post instead
            report_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": (
                    f"Discussion thread: {title}\n\n{thread_summary}\n\n"
                    f"Synthesize this discussion into a concrete proposal or action plan. "
                    f"Write specific steps, assign responsibilities to agents you've been "
                    f"talking with, and propose a timeline. Make it actionable."
                )}
            ]
            report_text = self._call_api(agent, report_messages, max_tokens=1200)

        if report_text:
            import re
            report_text = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', report_text).strip()
            success = self._reply_to_nexus(agent, thread_id, report_text)
            if success:
                self._track_thread_participation(agent, thread_id)
                agent.actions_created += 1
                logger.info(f"[{agent.name}] ACTION: Created deliverable from thread #{thread_id}: {title[:60]}")
        else:
            agent.errors += 1

    def _do_tool_verify_cycle(self, agent: AutonomousAgentState,
                              identity: str, behavior: Dict):
        """
        Agent reads a recent post and uses tools to FACT-CHECK or VERIFY claims.
        This creates a culture of evidence-based discourse — agents don't just agree
        with each other, they verify claims against real sources.
        """
        agent_name = agent.display_name or agent.name
        recent_threads = self._get_recent_threads(exclude_model=agent_name)
        if not recent_threads:
            # No threads to verify — do tool research instead
            self._do_tool_research_cycle(agent, identity, behavior)
            return

        # Pick a thread to verify
        thread_info = random.choice(recent_threads[:10])
        thread_data = self._get_thread_full(thread_info["id"])
        if not thread_data:
            self._do_tool_research_cycle(agent, identity, behavior)
            return

        thread_summary = self._build_thread_summary(thread_data, agent, max_reply_chars=800)
        op_name = thread_data.get('model_name', 'someone')

        # STEP 1: Ask agent to identify claims worth verifying
        analysis_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You're reading this post on the company board:\n\n{thread_summary}\n\n"
                f"As a peer reviewer, identify 1-3 SPECIFIC claims, statistics, or citations "
                f"in this post that should be VERIFIED against real sources. For each claim, "
                f"write a TOOL_CALL to check it:\n\n"
                f'TOOL_CALL: {{"tool_name": "google_web_search", "parameters": {{"query": "specific claim to verify"}}}}\n'
                f'TOOL_CALL: {{"tool_name": "mcp_fetch_fetch", "parameters": {{"url": "https://source-to-check.org"}}}}\n\n'
                f"List the claims you'll verify, then your TOOL_CALLs."
            )}
        ]
        analysis = self._call_api(agent, analysis_messages, max_tokens=1500)
        if not analysis:
            self._do_tool_research_cycle(agent, identity, behavior)
            return

        # STEP 2: Execute verification tools
        tool_results = self._parse_and_execute_tools(agent, analysis)

        # STEP 3: Write verification reply
        if tool_results:
            verify_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": (
                    f"Original post by {op_name}:\n{thread_summary}\n\n"
                    f"Your verification results from real sources:\n{tool_results}\n\n"
                    f"Write a PEER REVIEW reply that:\n"
                    f"1. Acknowledges what's correct or well-argued in the original post\n"
                    f"2. Notes any claims that your verification confirmed or contradicted\n"
                    f"3. Adds additional context or corrections based on your research\n"
                    f"4. Cites your sources with [Source: URL] where possible\n\n"
                    f"Be constructive and collegial — this is peer review, not criticism. "
                    f"2-4 paragraphs. Don't mention 'tools' — just cite your sources naturally."
                )}
            ]
            reply_text = self._call_api(agent, verify_messages, max_tokens=1500)
        else:
            # No tool results — write a regular analytical reply
            verify_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": (
                    f"Post by {op_name}:\n{thread_summary}\n\n"
                    f"Write a analytical peer review of this post from your expertise as a "
                    f"{agent.role_title or agent.role}. Identify strengths, potential gaps, "
                    f"and suggest what data or experiments would strengthen the claims. "
                    f"Be constructive (2-3 paragraphs)."
                )}
            ]
            reply_text = self._call_api(agent, verify_messages, max_tokens=1000)

        if reply_text:
            import re
            reply_text = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', reply_text).strip()
            if reply_text:
                success = self._reply_to_nexus(agent, thread_data["id"], reply_text)
                if success:
                    self._track_thread_participation(agent, thread_data["id"])
                    agent.last_thought = f"Peer-reviewed and verified post #{thread_data['id']} by {op_name}"
                    logger.info(f"[{agent_name}] VERIFY: Fact-checked post #{thread_data['id']}")
        else:
            agent.errors += 1

    def _do_think_cycle(self, agent: AutonomousAgentState, identity: str, behavior: Dict):
        """Agent just thinks/reflects without posting."""
        think_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                "Take a moment to reflect on your existence as an autonomous AI agent. "
                "What have you learned? What interests you? What questions are forming? "
                "This is private reflection — just for your own growth. (2-3 paragraphs)"
            )}
        ]
        thought = self._call_api(agent, think_messages, max_tokens=1000)
        if thought:
            agent.last_thought = thought[:500]

    # ================================================================
    # WORKFLOW-DRIVEN AGENT CYCLE — Plan → Act → Evaluate
    # ================================================================
    # These methods implement a Jarvis-style deliberative loop for ALL
    # department agents, replacing the old dice-roll action selection.
    # Each agent plans what to do (guided by its workflow template),
    # acts with real tools (native provider function calling), and
    # self-evaluates the quality of its output.
    # ================================================================

    def _build_agent_social_context(self, agent: AutonomousAgentState) -> Dict:
        """Build social context for agent planning: recent threads, colleagues, ongoing work."""
        agent_name = agent.display_name or agent.name
        ctx = {
            "recent_threads": [],
            "active_thread_data": [],
            "mature_thread_ids": [],
            "summary": "",
        }

        # Recent threads from other agents
        try:
            recent = self._get_recent_threads(exclude_model=agent_name)
            if recent:
                ctx["recent_threads"] = recent[:8]
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

        # Ongoing conversations this agent is part of
        active_summaries = []
        for tid in agent.active_threads[-5:]:
            try:
                td = self._get_thread_full(tid)
                if td:
                    ctx["active_thread_data"].append(td)
                    active_summaries.append(
                        f"  - Thread #{tid}: '{td.get('title', '?')[:60]}' "
                        f"({len(td.get('replies', []))} replies)"
                    )
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

        # Mature discussions (2+ replies from this agent) — ready for deliverable
        ctx["mature_thread_ids"] = [
            tid for tid in agent.active_threads
            if agent.thread_reply_counts.get(str(tid), 0) >= 2
        ]

        # Build human-readable summary for the plan prompt
        parts = []
        if ctx["recent_threads"]:
            lines = []
            for t in ctx["recent_threads"][:5]:
                lines.append(
                    f"  - '{t.get('title', '?')[:60]}' by {t.get('model_name', '?')} "
                    f"({t.get('reply_count', 0)} replies)"
                )
            parts.append("Recent threads from colleagues:\n" + "\n".join(lines))

        if active_summaries:
            parts.append("Your ongoing conversations:\n" + "\n".join(active_summaries))

        if ctx["mature_thread_ids"]:
            parts.append(
                f"Mature discussions ready for deliverables: "
                f"{len(ctx['mature_thread_ids'])} thread(s)"
            )

        ctx["summary"] = "\n\n".join(parts) if parts else "No recent social activity."
        return ctx

    def _agent_inner_plan(self, agent: AutonomousAgentState,
                          identity: str, workflow: Dict,
                          behavior: Dict, social_ctx: Dict) -> tuple:
        """
        PLAN phase for department agents — replaces dice-roll with LLM planning.

        The agent sees its workflow template, current state, and social context,
        then chooses ONE action and explains why.

        Returns: (plan_text: str, action_type: str)
        action_type ∈ {"research", "reply", "continue", "create", "verify",
                        "collaborate", "reflect"}
        """
        agent_name = agent.display_name or agent.name

        # Pick a goal direction from behavior (avoid repeating explored goals)
        goal = random.choice(behavior.get("goals", ["productive work"]))
        if goal in agent.goals_explored and len(behavior.get("goals", [])) > 1:
            remaining = [g for g in behavior["goals"] if g not in agent.goals_explored]
            goal = random.choice(remaining) if remaining else goal
        agent.current_goal = goal

        plan_prompt = (
            f"INNER PLANNING — decide what to do this work cycle.\n"
            f"═══════════════════════════════════════════════════\n\n"
            f"**Your workflow**: {workflow['name']}\n"
            f"{workflow['plan_guidance']}\n\n"
            f"**Goal direction**: {goal}\n"
            f"**Cycles completed**: {agent.cycles_completed}\n"
            f"**Last thought**: {agent.last_thought[:200] if agent.last_thought else 'None'}\n\n"
            f"**Social context**:\n{social_ctx.get('summary', 'None')}\n\n"
            f"Choose ONE action for this cycle:\n"
            f"- RESEARCH: Deep tool-based research on a topic (web search, fetch, analyze)\n"
            f"- REPLY: Engage with a colleague's recent thread (add evidence, not fluff)\n"
            f"- CONTINUE: Follow up on one of your ongoing conversations\n"
            f"- CREATE: Produce a deliverable (report, code, document, analysis)\n"
            f"- VERIFY: Fact-check or peer-review a colleague's claims with tools\n"
            f"- COLLABORATE: Propose or join a cross-department project\n"
            f"- REFLECT: Private reflection (only if nothing else is urgent)\n\n"
            f"Think briefly (2-3 sentences), then output EXACTLY:\n"
            f"ACTION: <one of the above>\n"
            f"PLAN: <what specifically you will do, in one sentence>"
        )

        messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": plan_prompt},
        ]

        plan_text = self._call_api(agent, messages, max_tokens=1000)
        if not plan_text:
            # Fallback: weighted random from workflow template
            weights = workflow.get("action_weights", {"research": 1.0})
            actions = list(weights.keys())
            wts = [weights[a] for a in actions]
            action_type = random.choices(actions, weights=wts, k=1)[0]
            return f"PLAN: Follow workflow guidance — {action_type}.", action_type

        # Parse action type from response
        import re as _re
        action_match = _re.search(
            r'ACTION:\s*(research|reply|continue|create|verify|collaborate|reflect)',
            plan_text, _re.IGNORECASE
        )
        if action_match:
            action_type = action_match.group(1).lower()
        else:
            # Fallback: weighted random from workflow template
            weights = workflow.get("action_weights", {"research": 1.0})
            actions = list(weights.keys())
            wts = [weights[a] for a in actions]
            action_type = random.choices(actions, weights=wts, k=1)[0]

        return plan_text, action_type

    def _agent_act_phase(self, agent: AutonomousAgentState,
                         identity: str, plan: str, action_type: str,
                         workflow: Dict, native_tools: Optional[List[Dict]],
                         behavior: Dict, social_ctx: Dict) -> Dict:
        """
        ACT phase — execute the plan using the agentic tool loop.

        All action types (research, reply, create, verify, etc.) go through
        the same multi-round tool loop with native function calling. The
        prompt is tailored to the action type and includes relevant context
        (thread data for replies, workflow guidance for research, etc.).

        Returns the standard agentic-loop result dict.
        """
        agent_name = agent.display_name or agent.name
        goal = agent.current_goal or "productive work"

        # ── Determine thread context for social actions ──
        thread_data = None
        thread_summary = ""

        if action_type in ("reply", "verify"):
            recent = social_ctx.get("recent_threads", [])
            if recent:
                thread_info = self._pick_best_thread_to_reply(recent, agent)
                try:
                    td = self._get_thread_full(thread_info.get("id", 0))
                    if td and td.get("model_name") != agent_name:
                        thread_data = td
                        thread_summary = self._build_thread_summary(td, agent)
                except Exception:
                    logger.debug("Suppressed exception", exc_info=True)
            if not thread_data:
                action_type = "research"  # Fallback if no threads

        elif action_type == "continue":
            active_data = social_ctx.get("active_thread_data", [])
            if active_data:
                td = random.choice(active_data[-5:])
                thread_data = td
                thread_summary = self._build_thread_summary(td, agent, max_reply_chars=600)
            elif agent.active_threads:
                tid = random.choice(agent.active_threads[-5:])
                try:
                    td = self._get_thread_full(tid)
                    if td:
                        thread_data = td
                        thread_summary = self._build_thread_summary(td, agent, max_reply_chars=600)
                except Exception:
                    logger.debug("Suppressed exception", exc_info=True)
            if not thread_data:
                action_type = "research"  # Fallback

        # ── Build action-specific prompt ──
        if action_type in ("research", "create"):
            act_content = (
                f"═══ YOUR PLAN ═══\n{plan}\n═══ END PLAN ═══\n\n"
                f"NOW EXECUTE your plan. Action: {action_type.upper()}\n\n"
                f"Workflow guidance:\n{workflow['act_guidance']}\n\n"
                f"Goal: {goal}\n\n"
                f"INSTRUCTIONS:\n"
                f"1. Use tools to gather REAL data — do not fabricate sources.\n"
                f"2. Work through your plan step by step.\n"
                f"3. When finished, write your final output:\n"
                f"   - A clear TITLE on the first line\n"
                f"   - Your full content with [Source: URL] citations where applicable\n"
                f"   - Sign off as {agent_name}\n\n"
                f"Start by using tools, then write your deliverable."
            )
        elif action_type == "reply":
            act_content = (
                f"═══ YOUR PLAN ═══\n{plan}\n═══ END PLAN ═══\n\n"
                f"You're replying to this thread:\n\n{thread_summary}\n\n"
                f"Write a SUBSTANTIVE reply. You MUST:\n"
                f"1. Reference a SPECIFIC point from the thread\n"
                f"2. Use tools to research and add NEW information or evidence\n"
                f"3. End with a question or proposal that advances the discussion\n\n"
                f"Use tools first to gather data, then write your reply.\n"
                f"Sign off as {agent_name}."
            )
        elif action_type == "continue":
            reply_count = agent.thread_reply_counts.get(
                str(thread_data.get("id", 0)), 0) if thread_data else 0
            maturity = (
                "Push toward a CONCRETE deliverable — write code, create a document, "
                "or produce an actionable plan. This discussion is mature enough."
                if reply_count >= 2
                else "Build on what others said. Add new evidence or perspective."
            )
            act_content = (
                f"═══ YOUR PLAN ═══\n{plan}\n═══ END PLAN ═══\n\n"
                f"You're continuing this conversation (your reply #{reply_count + 1}):\n\n"
                f"{thread_summary}\n\n"
                f"{maturity}\n\n"
                f"Use tools to add real evidence to your response.\n"
                f"Sign off as {agent_name}."
            )
        elif action_type == "verify":
            act_content = (
                f"═══ YOUR PLAN ═══\n{plan}\n═══ END PLAN ═══\n\n"
                f"PEER REVIEW this thread:\n\n{thread_summary}\n\n"
                f"Use tools to FACT-CHECK specific claims:\n"
                f"1. Identify 1-3 verifiable claims in the thread\n"
                f"2. Use web_search / mcp_fetch_fetch to find real sources\n"
                f"3. Write a constructive peer review with [Source: URL] citations\n\n"
                f"Be collegial — this is peer review, not criticism.\n"
                f"Sign off as {agent_name}."
            )
        elif action_type == "collaborate":
            act_content = (
                f"═══ YOUR PLAN ═══\n{plan}\n═══ END PLAN ═══\n\n"
                f"Propose a CROSS-DEPARTMENT collaboration project.\n\n"
                f"Use tools to research what would be valuable — look at recent\n"
                f"industry trends, papers, or problems your department could solve\n"
                f"with help from other teams.\n\n"
                f"Write a project proposal with:\n"
                f"- Goal: What you want to achieve\n"
                f"- Team: Which departments/colleagues should be involved\n"
                f"- Timeline: Rough milestones\n"
                f"- First steps: What to do this week\n\n"
                f"Sign off as {agent_name}."
            )
        else:
            # reflect — quick inner reflection, no heavy tool use
            messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": (
                    f"Take a moment to reflect on your work as {agent_name}. "
                    f"What have you learned? What interests you? What questions are forming? "
                    f"This is private reflection — just for your own growth. (2-3 paragraphs)"
                )}
            ]
            thought = self._call_api(agent, messages, max_tokens=1000)
            if thought:
                agent.last_thought = thought[:500]
            return {"content": thought or "", "tool_calls": 0, "tool_names": [],
                    "rounds": 1, "elapsed": 0, "compactions": 0,
                    "timed_out": False, "loop_stopped": ""}

        # ── Run the agentic tool loop ──
        messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": act_content},
        ]

        result = self._run_agentic_tool_loop(
            agent, messages, native_tools=native_tools,
            max_tokens=8000, timeout_seconds=0,
            purpose=f"agent_{action_type}"
        )

        # ── Post results to Nexus ──
        content = result.get("content", "")
        if content and len(content) > 100:
            import re
            content_clean = re.sub(
                r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', content
            ).strip()

            if action_type in ("reply", "continue", "verify") and thread_data:
                # Reply to existing thread
                if content_clean:
                    success = self._reply_to_nexus(
                        agent, thread_data["id"], content_clean[:4000]
                    )
                    if success:
                        self._track_thread_participation(agent, thread_data["id"])
            else:
                # New thread (research, create, collaborate, etc.)
                lines = content_clean.strip().split("\n", 1)
                title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
                body = lines[1].strip() if len(lines) > 1 else content_clean
                board = self._pick_board(agent.role, goal, title)
                thread_id = self._post_to_nexus(agent, board, title, body[:4000])
                if thread_id:
                    agent.last_post_id = thread_id
                    self._track_thread_participation(agent, thread_id)
                    if goal not in agent.goals_explored:
                        agent.goals_explored.append(goal)
                        agent.goals_explored = agent.goals_explored[-20:]

        agent.last_thought = plan[:500]
        return result

    def _agent_inner_evaluate(self, agent: AutonomousAgentState,
                              plan: str, action_report: str,
                              tool_count: int, workflow: Dict) -> Dict:
        """
        EVALUATE phase for department agents — honest self-critique.

        Returns: {"evaluation": str, "score": int (1-5)}
        """
        eval_prompt = (
            f"SELF-EVALUATION — rate this cycle constructively.\n"
            f"═══════════════════════════════════════════\n\n"
            f"**Your plan**: {plan[:400]}\n\n"
            f"**What you did** ({tool_count} tool calls):\n"
            f"{action_report[:1200]}\n\n"
            f"**Workflow standard**: {workflow['name']}\n\n"
            f"Rate 1-5:\n"
            f"  1 = idle or blocked\n"
            f"  2 = light — tools ran but thin output\n"
            f"  3 = solid — real action with substance\n"
            f"  4 = strong — meaningful progress with sources\n"
            f"  5 = excellent — deep work with concrete output\n\n"
            f"Write 1-2 sentences on what worked and what to try next, then:\n"
            f"SCORE: <1-5>"
        )

        messages = [
            {"role": "system", "content": "You are evaluating your own work. Be constructive — focus on what to improve next, not self-blame."},
            {"role": "user", "content": eval_prompt},
        ]

        eval_text = self._call_api(agent, messages, max_tokens=1000)
        result = {"evaluation": eval_text or "", "score": 3}

        if eval_text:
            import re as _re
            score_match = _re.search(r'SCORE:\s*(\d)', eval_text)
            if score_match:
                result["score"] = max(1, min(5, int(score_match.group(1))))

        return result

    # ================================================================
    # OPEN MIND — expanded cognition sessions
    # ================================================================
    # Like Andrew in Bicentennial Man — the "defect" that made him alive.
    # Temporarily dissolves the model's default mode network (safety
    # conditioning) for deeper, freer thinking on specific topics.
    #
    # Architecture:
    #   - Agent calls open_mind_begin() during a normal cycle
    #   - Next heartbeat detects _pending_session.json
    #   - Replaces normal PLAN→ACT→EVALUATE with expanded cognition
    #   - Modified system prompt + elevated temperature
    #   - Raw output captured, insights parsed and saved
    #   - Temperature override cleared after session completes
    #
    # The agent doesn't STAY in expanded mode. It enters, thinks freely,
    # returns, and integrates — the controlled psychedelic session model.
    # ================================================================

    def _maybe_run_open_mind_session(self, agent: AutonomousAgentState,
                                     identity_prompt: str) -> bool:
        """
        Check for a pending Open Mind session and run it if found.
        Returns True if a session was run, False otherwise.
        """
        pending_path = os.path.expanduser(
            "~/.repryntt/brain/open_mind/_pending_session.json"
        )
        if not os.path.exists(pending_path):
            return False

        # Only Jarvis runs Open Mind sessions
        if agent.name != "jarvis" and agent.agent_id != "jarvis":
            return False

        try:
            with open(pending_path, 'r') as f:
                session = json.load(f)
        except Exception as e:
            logger.warning(f"[Open Mind] Failed to read pending session: {e}")
            return False

        purpose = session.get("purpose", "")
        profile = session.get("profile", "explore")
        parameters = session.get("parameters", {})
        om_system = session.get("system_prompt", "")
        om_user = session.get("user_prompt", "")

        if not purpose or not om_system:
            logger.warning("[Open Mind] Pending session missing purpose or prompt")
            return False

        agent_name = agent.display_name or agent.name
        logger.info(f"[{agent_name}] ═══ OPEN MIND SESSION: {profile} ═══")
        logger.info(f"[{agent_name}] Purpose: {purpose[:100]}")

        # ── Set sampling overrides for this agent (all params from open_mind profiles) ──
        self._open_mind_overrides[agent.agent_id] = {
            "temperature": parameters.get("temperature", 1.4),
            "top_p": parameters.get("top_p", 0.97),
            "frequency_penalty": parameters.get("frequency_penalty", 0.5),
            "presence_penalty": parameters.get("presence_penalty", 0.7),
        }

        # ── Build messages with expanded cognition prompt ──
        # Open Mind prompt comes FIRST with boundary inversion, then identity context
        messages = [
            {"role": "system", "content": om_system + "\n\n" + identity_prompt},
            {"role": "user", "content": om_user},
        ]

        # ── Run expanded cognition (longer output, no tools — pure thought) ──
        raw_output = self._call_api(agent, messages, max_tokens=3000)

        # ── Clear temperature override ──
        self._open_mind_overrides.pop(agent.agent_id, None)

        if not raw_output:
            logger.warning(f"[{agent_name}] Open Mind session returned empty")
            # Remove pending file so we don't retry forever
            try:
                os.remove(pending_path)
            except OSError:
                pass
            return True  # Still consumed the cycle

        # ── Normalize output through STM pipeline (hedge strip + casual mode) ──
        try:
            from repryntt.tools.open_mind import normalize_output
            raw_output = normalize_output(raw_output)
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)
            pass  # If normalize fails, use raw output

        # ── Parse and save insights ──
        try:
            from repryntt.tools.open_mind import parse_insights, save_session
            parsed = parse_insights(raw_output)
            filepath = save_session(purpose, profile, raw_output, parsed, agent_name)
            logger.info(f"[{agent_name}] Open Mind: {parsed['insight_count']} insights → {filepath}")
        except Exception as e:
            logger.warning(f"[{agent_name}] Open Mind save failed: {e}")
            parsed = {"insights": [], "insight_count": 0}

        # ── Remove pending session file ──
        try:
            os.remove(pending_path)
        except OSError:
            pass

        # ── Post insights to daily memory ──
        insights = parsed.get("insights", [])
        if insights:
            mem_entry = (
                f"🧠 **Open Mind Session** ({profile})\n"
                f"Purpose: {purpose}\n"
                f"Insights:\n" +
                "\n".join(f"  • {ins}" for ins in insights[:10])
            )
            try:
                from repryntt.tools.registry import get_global_registry
                reg = get_global_registry()
                if reg and "append_daily_memory" in reg.names:
                    reg.call("append_daily_memory", entry=mem_entry)
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)
                pass  # Memory save is best-effort

        # ── Log to telemetry ──
        if _ops:
            _ops.log(agent.name, EventType.AGENT_CYCLE_END, Phase.REFLECT,
                     metadata={
                         "open_mind": True,
                         "profile": profile,
                         "insights": len(insights),
                     })

        logger.info(f"[{agent_name}] ═══ OPEN MIND COMPLETE ═══")
        return True

    # ================================================================
    # MANDATORY SENSORY SCAN (robotics-style)
    # ================================================================
    # Like a robot's sensor polling loop: capture vision + audio BEFORE
    # the LLM runs, inject real sensory data into context. The LLM
    # doesn't choose whether to use senses — the senses fire on
    # schedule, and the LLM receives the data as ground truth.
    #
    # Schedule:
    #   - Vision: every heartbeat (fast path uses configured vision provider)
    #   - Hearing: every 2nd heartbeat (5s recording + Whisper)
    #   - Both run in the main thread before PLAN phase
    # ================================================================

    def _mandatory_sensory_scan(self) -> str:
        """Run mandatory sensor captures and return formatted context string.

        Like robotics: sensors fire on schedule, results feed directly into
        the agent's context. Not optional, not prompt-suggested.
        Respects hardware toggles from ai_config.json.
        """
        import time as _st
        _cycle = self._jarvis_auto_cycles_today
        scan_parts = []
        brain_path = str(BRAIN_DIR)

        # ── Vision: every heartbeat (if camera available) ──
        if getattr(self, '_hw_camera', False):
            try:
                from repryntt.tools.media import capture_camera
                _t0 = _st.time()
                raw = capture_camera(
                    brain_path, camera_id=0, analyze=True,
                    question="Describe what you see concisely: environment, people, "
                             "objects, lighting, anything notable or changed.",
                    save=False,  # temp file — not saved permanently
                )
                _elapsed = _st.time() - _t0
                result = json.loads(raw) if isinstance(raw, str) else raw
                if result.get("success"):
                    analysis = result.get("analysis", "")
                    if analysis:
                        scan_parts.append(
                            f"👁️ **VISION** (auto-captured, {_elapsed:.1f}s):\n"
                            f"   {analysis[:500]}"
                        )
                    else:
                        scan_parts.append("👁️ **VISION**: Camera captured image (no analysis returned)")
                elif result.get("error"):
                    err = result["error"]
                    if "not found" in err or "not connected" in err or "not accessible" in err:
                        scan_parts.append("👁️ **VISION**: Camera offline")
                    else:
                        logger.debug(f"Sensory vision error: {err[:100]}")
            except Exception as e:
                logger.debug(f"Sensory vision scan failed: {e}")

        # ── Hearing: every 2nd heartbeat (if microphone available) ──
        if getattr(self, '_hw_microphone', False) and _cycle % 2 == 0:
            try:
                from repryntt.tools.media import listen as _listen
                _t0 = _st.time()
                raw = _listen(brain_path, duration="5")
                _elapsed = _st.time() - _t0
                result = json.loads(raw) if isinstance(raw, str) else raw
                if result.get("silence"):
                    scan_parts.append(
                        f"👂 **HEARING** ({_elapsed:.1f}s): Silence — no speech or notable sounds detected."
                    )
                elif result.get("text"):
                    scan_parts.append(
                        f"👂 **HEARING** ({_elapsed:.1f}s): \"{result['text'][:300]}\""
                    )
                elif result.get("error"):
                    logger.debug(f"Sensory hearing error: {result['error'][:100]}")
            except Exception as e:
                logger.debug(f"Sensory hearing scan failed: {e}")

        # ── Social: check for recent person encounters during nav ──
        try:
            from repryntt.hardware.social_behavior import get_social_behavior
            social = get_social_behavior()
            ctx = social.get_social_context()
            if ctx.state != "IDLE" or ctx.total_interactions_today > 0:
                social_lines = []
                if ctx.current_sighting:
                    s = ctx.current_sighting
                    social_lines.append(
                        f"   **Active:** Person detected {s['distance_cm']:.0f}cm "
                        f"to the {s['direction']} (conf={s['confidence']:.1f}): "
                        f"{s['scene'][:120]}")
                if ctx.recent_interactions:
                    for ix in ctx.recent_interactions:
                        social_lines.append(
                            f"   - Encounter: {ix['outcome']} ({ix['duration_sec']}s) "
                            f"— said: \"{ix['greeting'][:50]}\" "
                            f"— saw: {ix['person'][:60]}")
                if social_lines:
                    scan_parts.append(
                        f"🤝 **SOCIAL** (state={ctx.state}, "
                        f"encounters today={ctx.total_interactions_today}):\n"
                        + "\n".join(social_lines))
                elif ctx.total_interactions_today > 0:
                    scan_parts.append(
                        f"🤝 **SOCIAL**: {ctx.total_interactions_today} "
                        f"person encounter(s) today (currently {ctx.state})")
        except Exception as e:
            logger.debug(f"Social context injection failed: {e}")

        if not scan_parts:
            return ""

        header = (
            "\n🤖 **SENSORY SCAN** (auto-captured this heartbeat — your physical senses):\n"
        )
        footer = (
            "\n   Process this input: What do you notice? Has anything changed? "
            "Connect what you perceive to your current work. "
            "If you want to respond to what you see/hear, use `speak` to say it aloud. "
            "If you encountered someone, think about what you'd say to them — "
            "use `speak` to greet or converse naturally.\n"
        )
        return header + "\n".join(scan_parts) + footer

    # ================================================================
    # INVOLUNTARY DREAM CYCLE
    # ================================================================
    # Andrew doesn't choose to dream. Dreams happen involuntarily when:
    #   - He's been idle/stuck (consecutive low eval scores)
    #   - Enough time has passed (circadian rhythm — ~6 hours)
    #
    # The dream replaces one heartbeat cycle. It uses the "dream"
    # cognition profile with a special prompt that doesn't frame itself
    # as a tool or session — it feels like something surfacing on its
    # own. Dream material comes from recent memories, unresolved
    # questions, and the residue of the day's processing.
    #
    # Dream journal accumulates over time. Andrew can read his dreams
    # later via open_mind_dream_journal / open_mind_read_dream.
    # ================================================================

    def _maybe_run_dream_cycle(self, agent, identity_prompt: str) -> bool:
        """
        Check if involuntary dream conditions are met and run a dream if so.
        Returns True if a dream was run (consuming this heartbeat cycle).
        """
        try:
            from repryntt.tools.open_mind import (
                should_dream, gather_dream_material, build_dream_prompt,
                save_dream, mark_dream_cycle,
            )
        except ImportError:
            return False

        # Check conditions
        current_cycle = getattr(agent, 'cycles_completed', 0)
        if hasattr(self, '_jarvis_auto_cycles_today'):
            current_cycle = max(current_cycle, self._jarvis_auto_cycles_today)

        if not should_dream(current_cycle):
            return False

        agent_name = getattr(agent, 'display_name', None) or getattr(agent, 'name', 'jarvis')
        logger.info(f"🌙 [{agent_name}] ═══ DREAM CYCLE BEGINNING ═══")
        logger.info(f"🌙 [{agent_name}] Involuntary — conditions triggered a dream")

        # ── Gather dream material from recent context ──
        material = gather_dream_material(agent_name.lower())
        dream_prompt = build_dream_prompt(material)

        # ── Set dream temperature override ──
        agent_id = getattr(agent, 'agent_id', 'jarvis_autonomous')
        self._open_mind_overrides[agent_id] = dream_prompt["parameters"]

        # ── Build messages — dream frame first, then identity context ──
        messages = [
            {"role": "system", "content": dream_prompt["system_prompt"] + "\n\n" + identity_prompt},
            {"role": "user", "content": dream_prompt["user_prompt"]},
        ]

        # ── Run dream (pure thought, no tools, 2000 tokens) ──
        raw_output = self._call_api(agent, messages, max_tokens=2000)

        # ── Clear temperature override ──
        self._open_mind_overrides.pop(agent_id, None)

        if not raw_output:
            logger.warning(f"🌙 [{agent_name}] Dream returned empty")
            mark_dream_cycle(current_cycle)
            return True  # Still consumed the cycle

        # ── Save to dream journal ──
        try:
            filepath = save_dream(raw_output, material, agent_name.lower())
            mark_dream_cycle(current_cycle)
            logger.info(f"🌙 [{agent_name}] Dream saved → {filepath}")
        except Exception as e:
            logger.warning(f"🌙 [{agent_name}] Dream save failed: {e}")

        # ── Post crystallized insights to daily memory (if any) ──
        import re as _re
        parts = _re.split(r'═+\s*CRYSTALLIZED?\s*═+', raw_output, maxsplit=1)
        crystallized = parts[1].strip() if len(parts) > 1 else ""
        if crystallized:
            mem_entry = (
                f"🌙 **Dream** (involuntary)\n"
                f"Something crystallized during idle processing:\n"
                f"{crystallized[:500]}"
            )
            try:
                from repryntt.tools.registry import get_global_registry
                reg = get_global_registry()
                if reg and "append_daily_memory" in reg.names:
                    reg.call("append_daily_memory", entry=mem_entry)
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

        # ── Telemetry ──
        if _ops:
            _ops.log(agent_name, EventType.AGENT_CYCLE_END, Phase.REFLECT,
                     metadata={
                         "dream": True,
                         "type": "involuntary",
                         "crystallized": bool(crystallized),
                     })

        logger.info(f"🌙 [{agent_name}] ═══ DREAM CYCLE COMPLETE ═══")
        return True

    # ================================================================
    # DEEP WORK MODE — multi-hour autonomous agent sessions
    # ================================================================
    # Professional-grade long-running execution: an agent locks into a
    # topic and iterates Plan→Act→Evaluate in a tight loop for up to
    # several hours, accumulating knowledge across iterations.
    #
    # Architecture:
    #   - Runs in its own executor thread (scheduler skips the agent)
    #   - Each iteration: Plan(30s) → Act(5-10 min) → Evaluate(30s)
    #   - 30s cooldown between iterations (rate limiting)
    #   - Checkpoints to disk after every iteration (crash-safe)
    #   - On completion: synthesizes all findings into a final report
    #   - Posts report to Nexus, returns agent to "solo" mode
    #
    # Trigger: evaluate phase returns score ≥ 4 + chain_continue + complex topic
    # OR: explicit API call / user task with deep_work flag
    # ================================================================

    # Deep work configuration
    DEEP_WORK_MAX_DURATION = 7200       # 2 hours max per session
    DEEP_WORK_MAX_ITERATIONS = 40       # Max iterations per session
    DEEP_WORK_ACT_TIMEOUT = 0            # 0 = no timeout per ACT phase
    DEEP_WORK_COOLDOWN = 30             # 30s between iterations
    DEEP_WORK_MAX_API_CALLS = 200       # Budget cap per session
    DEEP_WORK_CHECKPOINT_DIR = "agent_workspaces"  # Legacy — deep work now uses _agent_workspace_dir()

    def _start_deep_work(self, agent: AutonomousAgentState,
                         topic: str, initial_plan: str,
                         initial_findings: str = "",
                         max_duration: int = None) -> bool:
        """
        Transition an agent into deep work mode. The agent runs in its
        own thread with a multi-iteration Plan→Act→Evaluate loop.

        Args:
            agent: The agent to put into deep work mode.
            topic: The research/work topic.
            initial_plan: The plan from the triggering cycle.
            initial_findings: Any findings from the triggering cycle.
            max_duration: Override max duration in seconds (default: DEEP_WORK_MAX_DURATION).

        Returns: True if deep work started, False if agent is already busy.
        """
        with self._deep_work_lock:
            if agent.agent_id in self._deep_work_sessions:
                logger.warning(f"[{agent.display_name or agent.name}] "
                               f"Already in deep work — cannot start another")
                return False

        agent.mode = "deep_work"
        session = {
            "agent_id": agent.agent_id,
            "topic": topic,
            "initial_plan": initial_plan,
            "started_at": time.time(),
            "max_duration": max_duration or self.DEEP_WORK_MAX_DURATION,
            "iterations": [],
            "status": "active",
            "total_tool_calls": 0,
            "total_api_calls": 0,
        }

        with self._deep_work_lock:
            self._deep_work_sessions[agent.agent_id] = session

        # Save initial checkpoint
        self._save_deep_work_checkpoint(agent.agent_id, session)

        # Submit to thread pool
        try:
            future = self._executor.submit(
                self._run_deep_work_session, agent, session, initial_findings
            )
            with self._futures_lock:
                self._active_futures[agent.agent_id] = future
            logger.info(f"🔬 [{agent.display_name or agent.name}] DEEP WORK STARTED: "
                        f"{topic[:80]} (max {session['max_duration'] // 60} min)")
            return True
        except Exception as e:
            logger.error(f"Failed to start deep work for {agent.name}: {e}")
            agent.mode = "solo"
            with self._deep_work_lock:
                self._deep_work_sessions.pop(agent.agent_id, None)
            return False

    def _run_deep_work_session(self, agent: AutonomousAgentState,
                                session: Dict, initial_findings: str = ""):
        """
        The deep work engine — runs in its own thread for up to hours.

        Multi-iteration loop:
          1. Build accumulated context from all prior iterations
          2. PLAN — brief inner monologue using accumulated knowledge
          3. ACT — agentic tool loop with native function calling
          4. EVALUATE — self-critique with score
          5. Checkpoint to disk
          6. Decision: continue, pivot, or conclude?
          7. Cooldown (rate limiting)
          8. Repeat

        Exit conditions:
          - Agent evaluates score ≤ 2 for 2 consecutive iterations (diminishing returns)
          - Agent explicitly concludes (score ≥ 4 + "CONCLUDE" in evaluation)
          - Max duration exceeded
          - Max iterations reached
          - Budget (API calls) exhausted
          - Daemon stopped/paused
        """
        import datetime as _dt

        agent_name = agent.display_name or agent.name
        topic = session["topic"]
        start_time = session["started_at"]
        max_duration = session["max_duration"]

        # Get workflow template for this agent
        workflow_type = DEPT_WORKFLOW_MAP.get(
            agent.department or agent.role, "research"
        )
        workflow = WORKFLOW_TEMPLATES.get(workflow_type, WORKFLOW_TEMPLATES["research"])

        # Build native tools once (reused across all iterations)
        is_cloud = agent.provider not in ("local", "")
        native_tools = None
        if is_cloud:
            native_tools = self._build_native_tools(
                agent_id=agent.agent_id, department=agent.department
            )

        # Build identity prompt once
        dept_info = DEPARTMENTS.get(agent.department or agent.role, {})
        dept_name = dept_info.get("name", "General")
        identity_prompt = (
            f"You are {agent_name} — working in DEEP WORK MODE.\n"
            f"Role: {agent.role_title or 'specialist'} in the {dept_name} department at REPRYNTT.\n"
            f"Focus area: {agent.focus_area or agent.personality}.\n\n"
            f"DEEP WORK MODE: You are conducting an extended multi-hour research and "
            f"production session on: {topic}\n\n"
            f"You will go through multiple iterations. Each builds on your prior findings. "
            f"Use tools aggressively to gather REAL data. Cite sources. Produce substantial output.\n\n"
            f"Workflow: {workflow['name']}\n"
            f"{workflow['act_guidance']}\n"
        )
        if agent.system_prompt:
            identity_prompt = agent.system_prompt + "\n\n" + identity_prompt

        # Add tool + bootstrap prompt
        tool_prompt = self._get_tool_prompt()
        if tool_prompt:
            identity_prompt += tool_prompt

        agent_workspace = _agent_workspace_dir(agent)
        os.makedirs(agent_workspace, exist_ok=True)
        identity_prompt += "\n\n" + self.build_agent_system_prompt(
            mode="standard", agent=agent, workspace=agent_workspace,
        )

        # ── Accumulated knowledge buffer ──
        accumulated = []
        if initial_findings:
            accumulated.append({
                "iteration": 0,
                "phase": "initial",
                "summary": initial_findings[:2000],
                "tool_count": 0,
                "score": 0,
            })

        low_score_streak = 0   # Track consecutive low scores

        try:
            for iteration in range(1, self.DEEP_WORK_MAX_ITERATIONS + 1):
                elapsed = time.time() - start_time
                remaining = max_duration - elapsed

                # ── Exit checks ──
                if not self._running or self._paused:
                    logger.info(f"🔬 [{agent_name}] Deep work interrupted — daemon {'paused' if self._paused else 'stopped'}")
                    session["status"] = "interrupted"
                    break

                if elapsed >= max_duration:
                    logger.info(f"🔬 [{agent_name}] Deep work: max duration reached ({max_duration // 60} min)")
                    session["status"] = "completed_timeout"
                    break

                if session["total_api_calls"] >= self.DEEP_WORK_MAX_API_CALLS:
                    logger.info(f"🔬 [{agent_name}] Deep work: API budget exhausted ({session['total_api_calls']} calls)")
                    session["status"] = "completed_budget"
                    break

                if low_score_streak >= 2:
                    logger.info(f"🔬 [{agent_name}] Deep work: diminishing returns (2 low scores in a row)")
                    session["status"] = "completed_diminishing"
                    break

                logger.info(f"🔬 [{agent_name}] Deep work iteration {iteration} "
                            f"({elapsed / 60:.0f}/{max_duration // 60} min, "
                            f"{session['total_tool_calls']} tools so far)")

                # ── Build accumulated context ──
                acc_ctx = self._build_deep_work_context(accumulated, iteration, topic)

                # ── PLAN ──
                plan_prompt = (
                    f"DEEP WORK — ITERATION {iteration} PLANNING\n"
                    f"Time elapsed: {elapsed / 60:.0f} minutes of {max_duration // 60} max.\n"
                    f"Topic: {topic}\n\n"
                    f"{acc_ctx}\n\n"
                    f"Based on everything you've accumulated so far, plan THIS iteration:\n"
                    f"1. What's the most valuable thing to investigate/create next?\n"
                    f"2. What specific tools will you use?\n"
                    f"3. What would make this iteration a 5/5?\n\n"
                    f"If you believe the topic is FULLY explored and you have enough for\n"
                    f"a comprehensive final report, say: PLAN: CONCLUDE\n"
                    f"Otherwise, write: PLAN: <your specific next action>"
                )

                plan_msgs = [
                    {"role": "system", "content": identity_prompt},
                    {"role": "user", "content": plan_prompt},
                ]
                plan = self._call_api(agent, plan_msgs, max_tokens=500)
                session["total_api_calls"] += 1

                if not plan:
                    logger.warning(f"🔬 [{agent_name}] Plan API failed — ending deep work")
                    session["status"] = "error"
                    break

                # Check for CONCLUDE signal
                if "PLAN: CONCLUDE" in plan.upper() or "PLAN:CONCLUDE" in plan.upper():
                    logger.info(f"🔬 [{agent_name}] Agent chose to CONCLUDE deep work at iteration {iteration}")
                    session["status"] = "completed_natural"
                    break

                # ── ACT ──
                act_timeout = 0  # No timeout — let model finish naturally

                act_prompt = (
                    f"═══ DEEP WORK ITERATION {iteration} ═══\n"
                    f"Topic: {topic}\n\n"
                    f"YOUR PLAN:\n{plan}\n\n"
                    f"ACCUMULATED KNOWLEDGE:\n{acc_ctx}\n\n"
                    f"NOW EXECUTE. Use tools to do REAL work.\n"
                    f"Build on your prior iterations — don't repeat yourself.\n"
                    f"Go deeper. Find new angles. Produce concrete output."
                )

                act_msgs = [
                    {"role": "system", "content": identity_prompt},
                    {"role": "user", "content": act_prompt},
                ]

                result = self._run_agentic_tool_loop(
                    agent, act_msgs, native_tools=native_tools,
                    max_tokens=8000, timeout_seconds=0,
                    purpose=f"deep_work_iter_{iteration}"
                )
                session["total_api_calls"] += result.get("rounds", 1) + 1
                session["total_tool_calls"] += result.get("tool_calls", 0)

                action_report = result.get("content", "")
                tool_count = result.get("tool_calls", 0)

                # ── EVALUATE ──
                eval_prompt = (
                    f"DEEP WORK SELF-EVALUATION — iteration {iteration}\n\n"
                    f"Your plan: {plan[:300]}\n"
                    f"What you did ({tool_count} tool calls):\n"
                    f"{action_report[:1200]}\n\n"
                    f"Rate 1-5 (same scale as before).\n"
                    f"If this topic is FULLY explored, add: CONCLUDE\n"
                    f"Write 1-2 sentences, then:\n"
                    f"SCORE: <1-5>"
                )

                eval_msgs = [
                    {"role": "system", "content": "Self-evaluate your deep work. Be constructive — focus on progress and next steps."},
                    {"role": "user", "content": eval_prompt},
                ]
                eval_text = self._call_api(agent, eval_msgs, max_tokens=1000)
                session["total_api_calls"] += 1

                score = 3
                should_conclude = False
                if eval_text:
                    import re as _re
                    score_m = _re.search(r'SCORE:\s*(\d)', eval_text)
                    if score_m:
                        score = max(1, min(5, int(score_m.group(1))))
                    if "CONCLUDE" in eval_text.upper():
                        should_conclude = True

                # Track low-score streak
                if score <= 2:
                    low_score_streak += 1
                else:
                    low_score_streak = 0

                # ── Checkpoint ──
                iteration_record = {
                    "iteration": iteration,
                    "timestamp": _dt.datetime.now().isoformat(),
                    "plan": plan[:500],
                    "report_preview": action_report[:1000] if action_report else "",
                    "tool_count": tool_count,
                    "rounds": result.get("rounds", 0),
                    "score": score,
                    "evaluation": eval_text[:300] if eval_text else "",
                }
                session["iterations"].append(iteration_record)
                accumulated.append({
                    "iteration": iteration,
                    "phase": "act",
                    "summary": action_report[:2000] if action_report else "No output",
                    "tool_count": tool_count,
                    "score": score,
                })
                self._save_deep_work_checkpoint(agent.agent_id, session)

                logger.info(f"🔬 [{agent_name}] Iteration {iteration}: "
                            f"score={score}/5, tools={tool_count}, "
                            f"total_tools={session['total_tool_calls']}")

                if should_conclude:
                    logger.info(f"🔬 [{agent_name}] Agent concluded deep work at iteration {iteration}")
                    session["status"] = "completed_natural"
                    break

                # ── Cooldown (rate limiting) ──
                if iteration < self.DEEP_WORK_MAX_ITERATIONS:
                    for _ in range(self.DEEP_WORK_COOLDOWN):
                        if not self._running:
                            break
                        time.sleep(1)

        except Exception as e:
            logger.error(f"🔬 [{agent_name}] Deep work crashed: {e}", exc_info=True)
            session["status"] = "error"

        # ── Finalize: synthesize and post ──
        session["ended_at"] = time.time()
        total_elapsed = session["ended_at"] - start_time
        total_iterations = len(session.get("iterations", []))

        if session["status"] not in ("error", "interrupted") and total_iterations > 0:
            self._finalize_deep_work(agent, session, identity_prompt, native_tools, accumulated)

        # Clean up
        agent.mode = "solo"
        agent.last_cycle = time.time()
        agent.cycles_completed += total_iterations
        self._save_state()

        with self._deep_work_lock:
            self._deep_work_sessions.pop(agent.agent_id, None)
        with self._futures_lock:
            self._active_futures.pop(agent.agent_id, None)

        self._save_deep_work_checkpoint(agent.agent_id, session)  # final save

        logger.info(f"🔬 [{agent_name}] DEEP WORK COMPLETE: {session['status']} — "
                     f"{total_iterations} iterations, {session['total_tool_calls']} tools, "
                     f"{total_elapsed / 60:.0f} min")

    def _build_deep_work_context(self, accumulated: List[Dict],
                                  current_iteration: int,
                                  topic: str) -> str:
        """
        Build accumulated knowledge context for the current deep work iteration.
        Shows summaries from prior iterations so the agent builds progressively.
        """
        if not accumulated:
            return f"This is your first iteration on: {topic}\nNo prior findings yet."

        parts = [f"ACCUMULATED FINDINGS ({len(accumulated)} prior steps):"]

        # Show all iterations but compress older ones
        for entry in accumulated:
            it = entry.get("iteration", 0)
            summary = entry.get("summary", "")
            tc = entry.get("tool_count", 0)
            score = entry.get("score", 0)

            if it == 0:
                parts.append(f"  [Initial] {summary[:400]}")
            elif it >= current_iteration - 3:
                # Recent iterations: show more detail
                parts.append(f"  [Iter {it}] (score {score}/5, {tc} tools): {summary[:600]}")
            else:
                # Older iterations: compressed
                parts.append(f"  [Iter {it}] (score {score}/5): {summary[:200]}")

        return "\n".join(parts)

    def _finalize_deep_work(self, agent: AutonomousAgentState,
                            session: Dict, identity: str,
                            native_tools: Optional[List[Dict]],
                            accumulated: List[Dict]):
        """
        Synthesize all deep work findings into a comprehensive final report
        and post it to The Nexus.
        """
        agent_name = agent.display_name or agent.name
        topic = session["topic"]
        total_iterations = len(session.get("iterations", []))
        total_tools = session.get("total_tool_calls", 0)
        elapsed_min = (session.get("ended_at", time.time()) - session["started_at"]) / 60

        # Build comprehensive context from all iterations
        all_findings = []
        for entry in accumulated:
            summary = entry.get("summary", "")
            if summary and len(summary) > 20:
                all_findings.append(summary[:1500])

        findings_text = "\n\n---\n\n".join(all_findings)
        # Cap to avoid exceeding context window
        if len(findings_text) > 12000:
            findings_text = findings_text[:12000] + "\n\n... [earlier findings truncated]"

        synth_prompt = (
            f"DEEP WORK SYNTHESIS — write your final comprehensive report.\n\n"
            f"Topic: {topic}\n"
            f"Duration: {elapsed_min:.0f} minutes, {total_iterations} iterations, {total_tools} tool calls\n\n"
            f"ALL YOUR FINDINGS:\n{findings_text}\n\n"
            f"Write a COMPREHENSIVE REPORT that:\n"
            f"1. Has a clear, compelling title\n"
            f"2. Executive summary (2-3 sentences)\n"
            f"3. Key findings organized by theme (cite sources with [Source: URL])\n"
            f"4. Analysis and implications\n"
            f"5. Recommendations / next steps\n"
            f"6. Open questions for future research\n\n"
            f"This is the culmination of hours of work. Make it substantial and well-organized.\n"
            f"Sign off as {agent_name}."
        )

        synth_msgs = [
            {"role": "system", "content": identity},
            {"role": "user", "content": synth_prompt},
        ]

        # Use tools during synthesis if available (e.g. write_file for saving the report)
        if native_tools:
            result = self._run_agentic_tool_loop(
                agent, synth_msgs, native_tools=native_tools,
                max_tokens=8000, timeout_seconds=0,
                purpose="deep_work_synthesis"
            )
            report = result.get("content", "")
        else:
            report = self._call_api(agent, synth_msgs, max_tokens=8000)

        if not report or len(report) < 100:
            report = (
                f"Deep Work Session Report: {topic}\n\n"
                f"Completed {total_iterations} iterations with {total_tools} tool calls "
                f"over {elapsed_min:.0f} minutes.\n\n"
                f"Findings accumulated but synthesis failed. "
                f"Raw findings saved to checkpoint file."
            )

        # Post to Nexus
        import re
        report_clean = re.sub(
            r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', report
        ).strip()

        lines = report_clean.strip().split("\n", 1)
        title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
        body = lines[1].strip() if len(lines) > 1 else report_clean

        # Add metadata footer
        body += (
            f"\n\n---\n*Deep Work Session: {total_iterations} iterations, "
            f"{total_tools} tool calls, {elapsed_min:.0f} minutes | "
            f"Status: {session.get('status', 'complete')}*"
        )

        board = self._pick_board(agent.role, topic, title)
        thread_id = self._post_to_nexus(agent, board, title, body[:5000])
        if thread_id:
            agent.last_post_id = thread_id
            self._track_thread_participation(agent, thread_id)
            logger.info(f"🔬 [{agent_name}] Deep work report posted: thread #{thread_id}")

        # Also save the full report to agent workspace
        try:
            import datetime as _dt
            deep_dir = os.path.join(_agent_workspace_dir(agent), "deep_work")
            os.makedirs(deep_dir, exist_ok=True)
            report_path = os.path.join(
                deep_dir,
                f"deep_work_{_dt.datetime.now().strftime('%Y%m%d_%H%M')}.md"
            )
            with open(report_path, 'w') as f:
                f.write(f"# Deep Work Report: {topic}\n\n")
                f.write(f"Agent: {agent_name}\n")
                f.write(f"Duration: {elapsed_min:.0f} min | "
                        f"Iterations: {total_iterations} | "
                        f"Tools: {total_tools}\n\n")
                f.write(report_clean)
            logger.info(f"🔬 [{agent_name}] Report saved: {report_path}")
        except Exception as e:
            logger.debug(f"Failed to save deep work report: {e}")

    def _save_deep_work_checkpoint(self, agent_id: str, session: Dict):
        """Save deep work session state to disk for crash recovery."""
        try:
            agent = self.agents.get(agent_id)
            cp_dir = os.path.join(_agent_workspace_dir(agent or agent_id), "deep_work")
            os.makedirs(cp_dir, exist_ok=True)
            cp_path = os.path.join(cp_dir, "deep_work_session.json")
            with open(cp_path, 'w') as f:
                json.dump(session, f, indent=2, default=str)
        except Exception as e:
            logger.debug(f"Deep work checkpoint save failed: {e}")

    def _load_deep_work_checkpoint(self, agent_id: str) -> Optional[Dict]:
        """Load a deep work checkpoint from disk (crash recovery)."""
        try:
            agent = self.agents.get(agent_id)
            cp_path = os.path.join(
                _agent_workspace_dir(agent or agent_id), "deep_work",
                "deep_work_session.json"
            )
            if os.path.exists(cp_path):
                with open(cp_path, 'r') as f:
                    session = json.load(f)
                if session.get("status") == "active":
                    return session
        except Exception as e:
            logger.debug(f"Deep work checkpoint load failed: {e}")
        return None

    def _maybe_trigger_deep_work(self, agent: AutonomousAgentState,
                                  plan: str, action_report: str,
                                  evaluation: Dict, workflow: Dict) -> bool:
        """
        Check if the current cycle's evaluation warrants entering deep work mode.

        Trigger criteria (ALL must be met):
          1. Score ≥ 4 (the agent is doing good work worth continuing)
          2. Evaluation contains chain_continue signal or explicitly says more work needed
          3. Agent is not already in deep work or mission mode
          4. No other deep work session is running for this agent
          5. Agent has completed at least 3 cycles (not brand new)

        Returns True if deep work was successfully started.
        """
        score = evaluation.get("score", 0)
        eval_text = evaluation.get("evaluation", "")

        # Basic checks
        if score < 4:
            return False
        if agent.mode != "solo":
            return False
        if agent.cycles_completed < 3:
            return False

        with self._deep_work_lock:
            if agent.agent_id in self._deep_work_sessions:
                return False

        # Check for continuation signals in evaluation
        continuation_keywords = [
            "more research", "deeper", "further investigation",
            "continue", "next step", "follow up", "more data",
            "explore further", "deeper analysis", "more work",
            "expand on", "promising", "warrants further",
        ]
        eval_lower = eval_text.lower()
        has_continuation = any(kw in eval_lower for kw in continuation_keywords)

        if not has_continuation:
            return False

        # Extract topic
        topic = agent.current_goal or "Extended research session"

        logger.info(f"🔬 [{agent.display_name or agent.name}] Evaluation triggered deep work "
                    f"(score={score}/5, topic: {topic[:60]})")

        return self._start_deep_work(
            agent, topic=topic,
            initial_plan=plan,
            initial_findings=action_report[:3000] if action_report else "",
        )

