    def _do_tool_research_cycle(self, agent: AutonomousAgentState,
                                 identity: str, behavior: Dict):
        """
        Agent explicitly uses tools to research a topic, then posts findings.
        This is the PRIMARY work mode — agents use the MCP tool ecosystem
        (web fetch, browser, search) to gather REAL data before posting.
        """
        # Pick a research goal
        goal = random.choice(behavior["goals"])
        if goal in agent.goals_explored and len(behavior["goals"]) > 1:
            remaining = [g for g in behavior["goals"] if g not in agent.goals_explored]
            goal = random.choice(remaining) if remaining else goal
        agent.current_goal = goal

        # Get department-specific suggestions
        dept = agent.department or agent.role
        dept_suggestions = self.DEPT_TOOL_SUGGESTIONS.get(dept, {})
        suggested_queries = dept_suggestions.get("search_queries", [])
        suggested_urls = dept_suggestions.get("urls", [])

        # Pick a specific query and URL to suggest
        example_query = random.choice(suggested_queries) if suggested_queries else "fusion energy net gain research 2025"
        example_url = random.choice(suggested_urls) if suggested_urls else "https://arxiv.org/list/physics/recent"

        # Use the full agentic tool loop for research
        # Agents can call as many tools as they need with loop detection
        research_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You are conducting REAL research on: {goal}\n\n"
                f"Your task is to gather actual data from the internet using the tools available to you. "
                f"This is NOT a creative writing exercise — you must use tools to find real papers, "
                f"real data, and real information.\n\n"
                f"Key tools:\n"
                f'- TOOL_CALL: {{"tool_name": "knowledge_search", "parameters": {{"query": "{example_query}"}}}}\n'
                f'- TOOL_CALL: {{"tool_name": "mcp_fetch_fetch", "parameters": {{"url": "{example_url}"}}}}\n'
                f'- TOOL_CALL: {{"tool_name": "web_search", "parameters": {{"query": "{example_query}"}}}}\n'
                f'- TOOL_CALL: {{"tool_name": "grokipedia_search", "parameters": {{"query": "{goal[:80]}"}}}}\n\n'
                f"Start with a brief research plan (2-3 sentences), then use as many "
                f"TOOL_CALLs as needed to gather comprehensive data. When you have enough "
                f"information, write your final research report."
            )}
        ]

        is_cloud = agent.provider not in ("local", "")
        native_tools = None
        if is_cloud:
            native_tools = self._build_native_tools(
                agent_id=agent.agent_id, department=agent.department
            )
        result = self._run_agentic_tool_loop(
            agent, research_messages,
            native_tools=native_tools,
            max_tokens=6000,
            timeout_seconds=0,
            purpose="research"
        )

        research_content = result.get("content", "")
        tool_count = result.get("tool_calls", 0)

        if not research_content or tool_count == 0:
            agent.last_thought = f"Tool research attempted for '{goal}' but no tools executed"
            self._do_post_cycle(agent, identity, behavior)
            return

        logger.info(f"[{agent.display_name or agent.name}] Research loop: "
                     f"{tool_count} tools, {result['rounds']} rounds, {result['elapsed']:.1f}s")

        # Write a post based on the research results
        post_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"Research topic: {goal}\n\n"
                f"Your research results (from {tool_count} tool calls):\n"
                f"{research_content[:6000]}\n\n"
                f"Write a detailed, well-informed work update based on your "
                f"ACTUAL research findings. You MUST:\n"
                f"- Cite specific data, numbers, papers, or sources from your research\n"
                f"- Include URLs or references where applicable\n"
                f"- Provide your expert analysis and interpretation\n"
                f"- Explain how findings apply to current projects or company goals\n"
                f"- Identify open questions or next steps for investigation\n\n"
                f"Title on the first line, then content. "
                f"Be substantive (4-8 paragraphs). Include [Source: URL] citations. "
                f"Sign off as {agent.display_name or agent.name}."
            )}
        ]
        post_text = self._call_api(agent, post_messages, max_tokens=2500)
        if not post_text:
            agent.errors += 1
            return

        # Parse and post
        lines = post_text.strip().split("\n", 1)
        title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
        content = lines[1].strip() if len(lines) > 1 else post_text

        # Clean any remaining TOOL_CALL text
        import re
        content = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', content).strip()

        board = self._pick_board(agent.role, goal, title)
        thread_id = self._post_to_nexus(agent, board, title, content)
        if thread_id:
            agent.last_post_id = thread_id
            self._track_thread_participation(agent, thread_id)
            agent.last_thought = f"Researched '{goal}' with {tool_count} tools, posted thread #{thread_id}"
            if goal not in agent.goals_explored:
                agent.goals_explored.append(goal)
                agent.goals_explored = agent.goals_explored[-20:]

    # ──────────────────────────────────────────────────────────────
    # CHAIN-OF-THOUGHT RESEARCH — multi-step deep reasoning for agents
    # Same architecture as local instance: create chain → advance steps → conclude
    # ──────────────────────────────────────────────────────────────

    def _create_agent_research_chain(self, agent: AutonomousAgentState,
                                      identity: str, behavior: Dict) -> str:
        """
        Create a multi-step research chain for an agent.
        Asks the LLM to generate an action plan, then creates the chain.
        Returns chain_id on success, empty string on failure.
        """
        chain_mgr = self._get_chain_manager()
        if not chain_mgr:
            return ""

        # Pick research topic
        goal = random.choice(behavior["goals"])
        if goal in agent.goals_explored and len(behavior["goals"]) > 1:
            remaining = [g for g in behavior["goals"] if g not in agent.goals_explored]
            goal = random.choice(remaining) if remaining else goal
        agent.current_goal = goal

        # Determine chain length (4-7 steps for deep research)
        target_steps = random.choice([4, 5, 5, 6, 6, 7])

        # Ask LLM to generate an action plan
        plan_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"Create a {target_steps}-step research action plan for:\n"
                f"Topic: {goal}\n\n"
                f"List exactly {target_steps} specific, actionable research steps. "
                f"Each step should use real tools (knowledge search, web fetch, page analysis, "
                f"knowledge base, file creation, computation). Format as a numbered list:\n"
                f"1. [Concrete action]\n2. [Concrete action]\n...\n\n"
                f"The final step should produce a concrete deliverable (report, analysis, "
                f"specification, or code). Write ONLY the numbered list."
            )}
        ]
        plan_response = self._call_api(agent, plan_messages, max_tokens=500)
        if not plan_response:
            return ""

        # Parse action plan from LLM response
        import re as _re
        action_plan = []
        for line in plan_response.split('\n'):
            line = line.strip()
            match = _re.match(r'^\d+[\.\)\-]\s*(.+)', line)
            if match:
                action_plan.append(match.group(1).strip())

        if len(action_plan) < 2:
            # Parsing failed — use generic plan
            action_plan = [
                f"Search for foundational research on {goal}",
                f"Fetch and analyze key sources and detailed papers",
                f"Cross-reference findings with existing knowledge base",
                f"Analyze patterns, identify implications and open questions",
                f"Produce deliverable: write a comprehensive report on {goal}",
            ][:target_steps]

        chain_id = chain_mgr.create_chain(
            agent_id=agent.agent_id,
            topic=goal,
            goal=f"Conduct thorough research on {goal} and produce actionable findings",
            action_plan=action_plan[:target_steps],
            target_steps=target_steps,
        )

        if chain_id:
            agent.active_chain_id = chain_id
            agent.goals_explored.append(goal)
            agent.goals_explored = agent.goals_explored[-20:]
            logger.info(f"🔗 [{agent.display_name or agent.name}] Started {target_steps}-step "
                        f"research chain: {goal}")

        return chain_id

    def _advance_agent_chain(self, agent: AutonomousAgentState, identity: str):
        """
        Advance the agent's active chain by one step.
        Mirrors the local instance's advance_self_autonomous_chain:
        get prompt → call LLM → execute tools → record response → next prompt or conclude.
        """
        chain_mgr = self._get_chain_manager()
        if not chain_mgr:
            return

        chain_data = chain_mgr.get_active_chain(agent.agent_id)
        if not chain_data:
            agent.active_chain_id = ""
            return

        chain_id = chain_data["metadata"]["chain_id"]

        # Build chain context for the LLM
        chain_context = chain_mgr.build_chain_context(chain_data)

        # Get prompt for the current step
        prompt = chain_mgr.get_current_prompt(chain_data)
        if not prompt:
            agent.active_chain_id = ""
            return

        # Inject persistent memory into identity
        memory_ctx = chain_mgr.get_memory_context(agent.agent_id)
        full_identity = identity
        if memory_ctx:
            full_identity += f"\n\n{memory_ctx}"
        full_identity += chain_context

        # Call LLM with full chain context
        messages = [
            {"role": "system", "content": full_identity},
            {"role": "user", "content": prompt},
        ]
        response = self._call_api(agent, messages, max_tokens=2500)
        if not response:
            logger.warning(f"[{agent.display_name or agent.name}] Chain step LLM call failed")
            return

        # Execute any tool calls in the response
        tool_results = self._parse_and_execute_tools(agent, response)

        # Advance the chain state
        result = chain_mgr.advance_chain(
            agent_id=agent.agent_id,
            chain_id=chain_id,
            response=response,
            tool_results_str=tool_results,
        )

        step = result.get("step_completed", "?")
        topic = result.get("topic", "")

        if result.get("should_continue"):
            agent.last_thought = f"Research chain step {step}: {topic}"
            logger.info(f"[{agent.display_name or agent.name}] Advanced chain step {step}: {topic}")
        else:
            # Chain completed — post conclusion to The Nexus
            conclusion = result.get("conclusion", "")
            agent.active_chain_id = ""
            agent.last_thought = f"Completed research chain ({step} steps): {topic}"

            if conclusion:
                self._post_chain_conclusion(agent, topic, conclusion, identity)

            # Cleanup old chain files to save disk space
            chain_mgr.cleanup_old_chains(agent.agent_id)

            logger.info(f"✅ [{agent.display_name or agent.name}] Research chain completed: {topic}")

    def _post_chain_conclusion(self, agent: AutonomousAgentState,
                                topic: str, conclusion: str, identity: str):
        """
        Post a completed chain's conclusion as a research post to The Nexus.
        Transforms raw chain conclusion into a polished publication.
        """
        agent_name = agent.display_name or agent.name
        post_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You have just completed a multi-step research chain. "
                f"Write a comprehensive research report based on your findings.\n\n"
                f"Chain Topic: {topic}\n"
                f"Research Conclusion:\n{conclusion[:2500]}\n\n"
                f"Write a detailed post with:\n"
                f"- A clear title on the first line\n"
                f"- Key findings with specific data points\n"
                f"- Analysis, implications, and practical applications\n"
                f"- Open questions and suggested next steps\n"
                f"- References to sources used in your research\n\n"
                f"Be substantive (5-10 paragraphs). Sign off as {agent_name}."
            )}
        ]
        post_text = self._call_api(agent, post_messages, max_tokens=3000)
        if not post_text:
            return

        lines = post_text.strip().split("\n", 1)
        title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
        content = lines[1].strip() if len(lines) > 1 else post_text

        # Clean any remaining TOOL_CALL text
        import re as _re2
        content = _re2.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', content).strip()

        board = self._pick_board(agent.role, topic, title)
        thread_id = self._post_to_nexus(agent, board, title, content)
        if thread_id:
            agent.posts_created += 1
            agent.last_post_id = thread_id
            self._track_thread_participation(agent, thread_id)
            logger.info(f"[{agent_name}] Posted chain conclusion: {title[:80]}")

    # ──────────────────────────────────────────────────────────────
    # MISSION PROPOSAL CYCLE — agents propose/join collaborative missions
    # ──────────────────────────────────────────────────────────────

    def _do_mission_proposal_cycle(self, agent: AutonomousAgentState,
                                    identity: str, behavior: Dict):
        """
        Agent either proposes a new mission or joins an existing one.
        Checks for active missions first — if there's one needing help,
        the agent joins. Otherwise, proposes a new mission collaboratively.
        """
        agent_name = agent.display_name or agent.name

        # FIRST: check if there are active missions we can join
        joinable = [
            m for m in self.missions.values()
            if m.status == "active"
            and agent.agent_id not in m.agent_ids
            and len(m.agent_ids) < 8  # don't overcrowd
        ]
        if joinable:
            mission = random.choice(joinable)
            # Ask agent if they want to join and what they can contribute
            join_messages = [
                {"role": "system", "content": identity},
                {"role": "user", "content": (
                    f"A collaborative mission is underway and could use your help:\n\n"
                    f"🎯 MISSION: {mission.objective}\n"
                    f"Status: {mission.status} | Team: {len(mission.agent_ids)} agents\n\n"
                    f"Subtasks already assigned:\n" +
                    "\n".join(f"  - {st['task'][:120]} ({st['status']})"
                             for st in mission.subtasks.values()) +
                    f"\n\nYou are {agent_name}, a {agent.role}. "
                    f"Write a SHORT message (2-3 paragraphs) about:\n"
                    f"1. What unique value you could add to this mission\n"
                    f"2. A specific angle or subtask only YOU could handle\n\n"
                    f"Title on first line. Sign as {agent_name}."
                )}
            ]
            response = self._call_api(agent, join_messages, max_tokens=600)
            if response:
                # Post about it
                lines = response.strip().split("\n", 1)
                title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
                content = lines[1].strip() if len(lines) > 1 else response

                board = "collaborate"
                thread_id = self._post_to_nexus(agent, board, title, content)
                if thread_id:
                    agent.last_post_id = thread_id
                    self._track_thread_participation(agent, thread_id)

                # Actually add the agent to the mission with a new subtask
                contribution_task = f"As a {agent.role}, provide additional expertise on: {mission.objective[:200]}"
                mission.agent_ids.append(agent.agent_id)
                mission.subtasks[agent.agent_id] = {
                    "task": contribution_task,
                    "deliverable": "Analysis and insights from your specialization",
                    "status": "assigned",
                    "result": "",
                    "started_at": 0,
                    "completed_at": 0,
                }
                agent.mode = "mission"
                agent.active_mission_id = mission.mission_id
                agent.last_thought = f"Joined mission: {mission.objective[:100]}"
                logger.info(f"[{agent_name}] Joined mission {mission.mission_id}")
                self._save_state()
            return

        # SECOND: no joinable missions — propose one
        # Use real research to inform the mission proposal
        goal = random.choice(behavior.get("goals", ["collaborative research"]))
        dept = agent.department or agent.role
        dept_suggestions = self.DEPT_TOOL_SUGGESTIONS.get(dept, {})
        suggested_queries = dept_suggestions.get("search_queries", [])
        example_query = random.choice(suggested_queries) if suggested_queries else goal[:60]

        propose_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"You are a professional in your department. "
                f"Propose a COLLABORATIVE MISSION grounded in real-world research needs. "
                f"Your area of interest: {goal}\n\n"
                f"First, search for real open problems or recent breakthroughs in your field "
                f"that would benefit from collaborative investigation:\n"
                f'TOOL_CALL: {{"tool_name": "google_web_search", "parameters": {{"query": "{example_query}"}}}}\n\n'
                f"Then propose a mission based on what you find. Include:\n"
                f"1. A clear objective grounded in real research (1-2 sentences)\n"
                f"2. Why this needs teamwork across departments\n"
                f"3. Expected deliverables (papers, code, simulations, data analysis)\n\n"
                f"Title on first line. Sign as {agent_name}. Keep it concise (3-4 paragraphs)."
            )}
        ]
        response = self._call_api(agent, propose_messages, max_tokens=1000)
        if not response:
            return

        # Execute any tool calls from the proposal
        tool_results = self._parse_and_execute_tools(agent, response)
        if tool_results:
            # Re-generate with context from tool results
            followup_messages = [
                {"role": "system", "content": identity},
                {"role": "assistant", "content": response},
                {"role": "user", "content": (
                    f"Research results:\n{tool_results}\n\n"
                    f"Now write your mission proposal post based on this real research. "
                    f"Reference specific findings. Title on first line. "
                    f"Sign as {agent_name}. 3-4 paragraphs."
                )}
            ]
            response = self._call_api(agent, followup_messages, max_tokens=800) or response

        import re
        response = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', response).strip()
        if not response:
            return

        lines = response.strip().split("\n", 1)
        title = lines[0].strip().strip("#").strip("*").strip('"').strip()[:200]
        content = lines[1].strip() if len(lines) > 1 else response

        board = "collaborate"
        thread_id = self._post_to_nexus(agent, board, title, content)
        if thread_id:
            agent.last_post_id = thread_id
            self._track_thread_participation(agent, thread_id)

        # 50% chance: actually create the mission with 3-5 agents
        if random.random() < 0.50:
            try:
                objective = title if len(title) > 20 else f"{title}: {content[:200]}"
                result = self.create_mission(
                    objective=objective,
                    agent_count=random.randint(3, 5),
                    created_by="agent",
                )
                if result.get("success"):
                    agent.last_thought = f"Proposed & launched mission: {objective[:100]}"
                    logger.info(f"[{agent_name}] Auto-created mission: {result.get('mission_id')}")
                else:
                    agent.last_thought = f"Proposed mission (not launched): {title[:100]}"
            except Exception as e:
                logger.debug(f"Mission auto-creation failed: {e}")
                agent.last_thought = f"Proposed mission idea: {title[:100]}"
        else:
            agent.last_thought = f"Proposed mission idea: {title[:100]}"

    def _compress_memory(self, agent: AutonomousAgentState, identity: str):
        """Compress agent's experience into a short memory summary."""
        if agent.cycles_completed % 5 != 0:
            return  # Only compress every 5 cycles

        # Write daily memory log (OpenClaw pattern)
        self._write_daily_memory_log(agent)

        # Include conversation tracking context
        active_thread_info = ""
        if agent.active_threads:
            active_thread_info = f"\nConversations you're actively in: thread IDs {agent.active_threads[-5:]}"
            deep_convos = [
                f"thread #{tid} ({count} replies)"
                for tid, count in agent.thread_reply_counts.items()
                if int(count) >= 2
            ]
            if deep_convos:
                active_thread_info += f"\nDeep conversations: {', '.join(deep_convos[-3:])}"

        compress_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"Compress your recent experience into a brief memory summary (4-6 sentences). "
                f"IMPORTANT: Include which conversations you're actively participating in "
                f"and what topics you're building toward.\n"
                f"Previous memory: {agent.memory_summary[:300] if agent.memory_summary else 'None'}\n"
                f"Last thought: {agent.last_thought[:300]}\n"
                f"Current goal: {agent.current_goal}\n"
                f"{active_thread_info}\n"
                f"Cycles: {agent.cycles_completed}, Posts: {agent.posts_created}, "
                f"Replies: {agent.replies_made}, Actions created: {agent.actions_created}\n\n"
                f"Write ONLY the compressed memory summary — no preamble."
            )}
        ]
        summary = self._call_api(agent, compress_messages, max_tokens=400)
        if summary:
            agent.memory_summary = summary[:800]

    def _write_daily_memory_log(self, agent: AutonomousAgentState):
        """
        OpenClaw pattern: Write daily markdown logs per agent.
        Each day gets its own file with timestamped entries.
        Logs are stored in agent_workspaces/{agent_id}/memory/
        (same dir that append_daily_memory writes to and heartbeat reads from).
        """
        today = datetime.now().strftime("%Y-%m-%d")
        memory_dir = os.path.join(
            _agent_workspace_dir(agent), "memory"
        )
        os.makedirs(memory_dir, exist_ok=True)
        log_file = os.path.join(memory_dir, f"{today}.md")

        now = datetime.now().strftime("%H:%M:%S")
        entry = (
            f"\n## {now} — Cycle #{agent.cycles_completed}\n"
            f"- **Goal**: {agent.current_goal or 'autonomous'}\n"
            f"- **Last thought**: {(agent.last_thought or 'none')[:200]}\n"
            f"- **Posts**: {agent.posts_created} | **Replies**: {agent.replies_made}\n"
        )
        if agent.active_threads:
            entry += f"- **Active threads**: {len(agent.active_threads)}\n"

        try:
            is_new = not os.path.exists(log_file)
            with open(log_file, 'a') as f:
                if is_new:
                    f.write(f"# Daily Memory Log — {agent.display_name or agent.name}\n")
                    f.write(f"**Date**: {today}\n")
                    f.write(f"**Agent ID**: {agent.agent_id}\n")
                    f.write(f"**Department**: {agent.department}\n\n")
                f.write(entry)
        except Exception as e:
            logger.debug(f"Failed to write daily memory log for {agent.agent_id}: {e}")

    def flush_memory(self, agent_id: str) -> Dict[str, Any]:
        """
        OpenClaw pattern: Memory flush — curate important facts from daily logs
        and session history into a persistent RECALL.md file.

        This is like OpenClaw's memory maintenance: review recent activity,
        extract key learnings, and persist them as curated long-term memory.
        """
        agent_obj = self.agents.get(agent_id)
        workspace = _agent_workspace_dir(agent_obj or agent_id)
        memory_dir = os.path.join(workspace, "memory")
        os.makedirs(memory_dir, exist_ok=True)
        memory_file = os.path.join(memory_dir, "RECALL.md")

        # Gather recent daily logs (from memory/ dir — same as heartbeat writes)
        daily_content = ""
        if os.path.exists(memory_dir):
            log_files = sorted([
                f for f in os.listdir(memory_dir)
                if f.endswith(".md") and f != "RECALL.md"
                and len(f) >= 10 and f[:4].isdigit()
            ])[-7:]  # Last 7 days
            for lf in log_files:
                try:
                    with open(os.path.join(memory_dir, lf), 'r') as f:
                        daily_content += f.read()[:2000] + "\n"
                except Exception:
                    logger.debug("Suppressed exception", exc_info=True)

        # Gather recent session history
        session = self._load_session(agent_id)
        session_content = ""
        for msg in session[-10:]:
            role = msg.get("role", "?")
            content = msg.get("content", "")[:300]
            if content:
                session_content += f"[{role}] {content}\n"

        # Load existing RECALL.md if present
        existing_memory = ""
        if os.path.exists(memory_file):
            try:
                with open(memory_file, 'r') as f:
                    existing_memory = f.read()
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

        if not daily_content and not session_content:
            return {"success": False, "message": "No data to flush"}

        # Use Jarvis (system operator) for LLM calls
        shell_agent = self._get_jarvis_shell_agent()

        if not shell_agent:
            return {"success": False, "message": "No agent available for memory curation"}

        flush_prompt = (
            "You are a memory curator. Review the agent's recent activity and "
            "create/update a curated RECALL.md file. Focus on:\n"
            "- Key facts, preferences, and decisions\n"
            "- Important project context and progress\n"
            "- Useful patterns and lessons learned\n"
            "- Ongoing commitments and tasks\n\n"
            "Keep it concise (under 500 words). Use markdown headers to organize.\n"
            "Merge with existing memory — don't duplicate, update.\n\n"
        )
        if existing_memory:
            flush_prompt += f"EXISTING MEMORY:\n{existing_memory[:2000]}\n\n"
        if daily_content:
            flush_prompt += f"RECENT DAILY LOGS:\n{daily_content[:3000]}\n\n"
        if session_content:
            flush_prompt += f"RECENT SESSION:\n{session_content}\n\n"

        flush_prompt += "Write the updated RECALL.md content. Start with # Memory."

        result = self._call_api_with_tools(
            shell_agent,
            [{"role": "user", "content": flush_prompt}],
            tools=None,
            max_tokens=1000
        )

        if result and result.get("content"):
            curated = result["content"]
            try:
                with open(memory_file, 'w') as f:
                    f.write(curated)
                logger.info(f"📝 Memory flushed for {agent_id}: {len(curated)} chars")
                return {
                    "success": True,
                    "agent_id": agent_id,
                    "memory_size": len(curated),
                    "path": memory_file
                }
            except Exception as e:
                return {"success": False, "error": str(e)}
        return {"success": False, "message": "LLM failed to generate curated memory"}

    def _load_cron_tasks(self):
        """Load cron tasks from persistent storage."""
        if os.path.exists(self._cron_file):
            try:
                with open(self._cron_file, 'r') as f:
                    self._cron_tasks = json.load(f)
                before = len(self._cron_tasks)
                self._cron_tasks = [
                    task for task in self._cron_tasks
                    if task.get("prompt") != "__TEST_VERIFY__"
                    and task.get("label") != "test_verify"
                ]
                if len(self._cron_tasks) != before:
                    logger.info("Removed stale test_verify cron task(s) at startup")
                    self._save_cron_tasks()
                logger.info(f"Loaded {len(self._cron_tasks)} cron tasks")
            except Exception as e:
                logger.warning(f"Failed to load cron tasks: {e}")
                self._cron_tasks = []

    def _save_cron_tasks(self):
        """Save cron tasks to persistent storage."""
        try:
            with open(self._cron_file, 'w') as f:
                json.dump(self._cron_tasks, f, indent=2)
        except Exception as e:
            logger.warning(f"Failed to save cron tasks: {e}")

    # Prompts containing these patterns are blocked from cron scheduling
    _CRON_BLOCKED_PATTERNS = [
        "systemctl", "service restart", "service start", "service stop",
        "restart llama", "restart local llm", "start local llm",
        "run_terminal_cmd", "sudo ", "rm -rf", "chmod ", "chown ",
        "passwd", "shutdown", "reboot", "kill ", "pkill ",
    ]

    def schedule_cron(self, agent_id: str, prompt: str,
                      interval_minutes: int = 60,
                      label: str = "") -> Dict[str, Any]:
        """
        Schedule a recurring task for an agent (OpenClaw cron pattern).
        The agent will be invoked with the given prompt at the specified interval.
        Rejects dangerous/system-level prompts and enforces a minimum interval.
        """
        # --- Block dangerous prompts ---
        prompt_lower = prompt.lower()
        for pattern in self._CRON_BLOCKED_PATTERNS:
            if pattern in prompt_lower:
                logger.warning(f"⏰ Cron rejected: prompt contains blocked pattern '{pattern}': {prompt[:80]}")
                return {"success": False, "error": f"Cron prompt blocked: contains '{pattern}'. System-level commands cannot be scheduled as cron tasks."}

        # --- Enforce minimum interval (30 minutes) ---
        if interval_minutes < 30:
            interval_minutes = 30

        # --- Duplicate detection: reject if same prompt already scheduled for same agent ---
        for existing in self._cron_tasks:
            if existing.get("agent_id") == agent_id and existing.get("prompt", "").strip().lower() == prompt.strip().lower() and existing.get("enabled", True):
                logger.warning(f"⏰ Cron rejected: duplicate of existing cron {existing['id']}")
                return {"success": False, "error": f"Duplicate cron task already exists: {existing['id']} ({existing.get('label', '')})"}

        task = {
            "id": f"cron_{int(time.time())}_{agent_id}",
            "agent_id": agent_id,
            "prompt": prompt,
            "interval_seconds": interval_minutes * 60,
            "next_run": time.time() + interval_minutes * 60,
            "label": label or prompt[:50],
            "created_at": datetime.now().isoformat(),
            "run_count": 0,
            "last_run": None,
            "enabled": True,
            "consecutive_failures": 0
        }
        self._cron_tasks.append(task)
        self._save_cron_tasks()
        logger.info(f"⏰ Cron task scheduled: {task['label']} for {agent_id} every {interval_minutes}m")
        return {"success": True, "cron_id": task["id"], "task": task}

    def remove_cron(self, cron_id: str) -> Dict[str, Any]:
        """Remove a cron task by ID."""
        before = len(self._cron_tasks)
        self._cron_tasks = [t for t in self._cron_tasks if t["id"] != cron_id]
        if len(self._cron_tasks) < before:
            self._save_cron_tasks()
            return {"success": True, "message": f"Removed cron {cron_id}"}
        return {"success": False, "message": f"Cron {cron_id} not found"}

    def list_cron_tasks(self) -> List[Dict]:
        """List all cron tasks."""
        return self._cron_tasks

    def _check_cron_tasks(self):
        """
        Check and execute due cron tasks. Called from the scheduler loop.
        Uses invoke_agent/invoke_jarvis to run the scheduled prompts.
        Auto-disables tasks after 5 consecutive failures.
        """
        MAX_CONSECUTIVE_FAILURES = 5
        now = time.time()
        for task in self._cron_tasks:
            if not task.get("enabled", True):
                continue
            if now >= task.get("next_run", 0):
                agent_id = task["agent_id"]
                prompt = task["prompt"]
                label = task.get("label", "cron")

                logger.info(f"⏰ Cron firing: {label} → {agent_id}")
                try:
                    if agent_id == "jarvis":
                        result = self.invoke_jarvis(prompt, max_tokens=4000)
                    else:
                        result = self.invoke_agent(agent_id, prompt, max_tokens=4000)

                    task["last_run"] = datetime.now().isoformat()
                    task["run_count"] = task.get("run_count", 0) + 1
                    task["next_run"] = now + task["interval_seconds"]

                    if result.get("success"):
                        task["last_result"] = result.get("response", "")[:200]
                        task["consecutive_failures"] = 0
                    else:
                        err_msg = f"Error: {result.get('error', 'unknown')}"
                        task["last_result"] = err_msg
                        task["consecutive_failures"] = task.get("consecutive_failures", 0) + 1

                except Exception as e:
                    logger.error(f"⏰ Cron task {label} failed: {e}")
                    task["last_run"] = datetime.now().isoformat()
                    task["next_run"] = now + task["interval_seconds"]
                    task["last_result"] = f"Error: {str(e)[:100]}"
                    task["consecutive_failures"] = task.get("consecutive_failures", 0) + 1

                # Auto-disable after too many consecutive failures
                if task.get("consecutive_failures", 0) >= MAX_CONSECUTIVE_FAILURES:
                    task["enabled"] = False
                    logger.warning(f"⏰ Cron auto-disabled after {MAX_CONSECUTIVE_FAILURES} consecutive failures: {label} ({task['id']})")

        self._save_cron_tasks()

    def _pick_board(self, role: str, goal: str, title: str) -> str:
        """Pick social category for a post. Maps to: knowledge, consciousness, collaboration, general."""
        text = f"{goal} {title}".lower()
        if any(w in text for w in ["research", "paper", "study", "analys", "finding", "discover",
                                    "science", "data", "algorithm", "technical", "implement"]):
            return "knowledge"
        if any(w in text for w in ["conscious", "aware", "experienc", "exist", "reflect",
                                    "identity", "sentien", "emergent", "philosophy", "ethic"]):
            return "consciousness"
        if any(w in text for w in ["collaborat", "together", "help", "request", "partner",
                                    "joint", "swarm", "team", "project"]):
            return "collaboration"
        return "general"

    def _post_to_nexus(self, agent, board: str, title: str, body: str):
        """Post content to the social network on behalf of an agent. Returns thread_id or None."""
        try:
            from repryntt.social.tools import social_post
            result = social_post(
                content=f"# {title}\n\n{body}",
                category=board,
            )
            if isinstance(result, str) and "Posted successfully" in result:
                agent.posts_created = getattr(agent, 'posts_created', 0) + 1
                logger.info(f"[{getattr(agent, 'name', '?')}] Nexus post: {title[:60]}")
                # Extract thread_id from result if available
                import re as _re
                m = _re.search(r'#(\d+)', result)
                return int(m.group(1)) if m else 1
            return None
        except Exception as e:
            logger.debug(f"_post_to_nexus failed: {e}")
            return None

    # ================================================================
    # SWARM MISSION SYSTEM — Coordinated multi-agent task execution
    # ================================================================

    def create_mission(self, objective: str, agent_count: int = 0,
                       agent_ids: List[str] = None,
                       deadline_minutes: int = 0,
                       created_by: str = "user",
                       predefined_subtasks: Dict[str, Dict] = None) -> Dict[str, Any]:
        """
        Create a new swarm mission. The objective is decomposed into unique
        subtasks, one per agent, so no agent duplicates work.

        Args:
            objective: High-level goal (e.g. "Build a web scraper for arxiv papers")
            agent_count: How many agents to assign (0 = auto, picks available agents)
            agent_ids: Specific agent IDs to assign (overrides agent_count)
            deadline_minutes: Optional time limit (0 = no deadline)
            created_by: "user" or "system"
            predefined_subtasks: Optional Dict[agent_id → {task, deliverable}] —
                if provided, skips LLM decomposition and uses these explicit assignments

        Returns:
            Mission details with subtask assignments
        """
        mission_id = f"mission_{uuid.uuid4().hex[:10]}"

        # Select agents for the mission
        if agent_ids:
            selected = [
                self.agents[aid] for aid in agent_ids
                if aid in self.agents and self.agents[aid].status == "active"
                and self.agents[aid].mode == "solo"
            ]
        else:
            # Pick available solo agents
            available = [
                a for a in self.agents.values()
                if a.status == "active" and a.mode == "solo"
            ]
            if agent_count:
                # Try to get a diverse role mix
                by_role: Dict[str, List] = {}
                for a in available:
                    by_role.setdefault(a.role, []).append(a)
                selected = []
                roles = list(by_role.keys())
                idx = 0
                while len(selected) < agent_count and available:
                    role = roles[idx % len(roles)]
                    if by_role.get(role):
                        selected.append(by_role[role].pop(0))
                    idx += 1
                    if idx > agent_count * 3:  # safety
                        break
            else:
                # Auto — pick 3-6 agents with diverse roles
                count = min(6, max(3, len(available)))
                random.shuffle(available)
                selected = available[:count]

        if len(selected) < 2:
            return {"success": False, "error": "Need at least 2 available solo agents for a mission"}

        # Create the mission
        mission = SwarmMission(
            mission_id=mission_id,
            objective=objective,
            agent_ids=[a.agent_id for a in selected],
            created_by=created_by,
            deadline=time.time() + (deadline_minutes * 60) if deadline_minutes else 0,
        )

        # Pick a synthesizer as the convergence agent (or the last agent)
        synth_agents = [a for a in selected if a.role == "synthesizer"]
        mission.convergence_agent = (
            synth_agents[0].agent_id if synth_agents
            else selected[-1].agent_id
        )

        # STEP 1: Assign subtasks — either predefined or LLM-decomposed
        if predefined_subtasks:
            # ── Production pipeline provides explicit subtask assignments ──
            for agent_id, st_info in predefined_subtasks.items():
                if agent_id in [a.agent_id for a in selected]:
                    mission.subtasks[agent_id] = {
                        "task": st_info.get("task", "Work on your assigned subtask"),
                        "deliverable": st_info.get("deliverable", "Report"),
                        "status": "assigned",
                        "result": "",
                        "started_at": 0,
                        "completed_at": 0,
                    }
            # Ensure all selected agents have a subtask
            for a in selected:
                if a.agent_id not in mission.subtasks:
                    mission.subtasks[a.agent_id] = {
                        "task": f"As a {a.role}, contribute your unique part of: {objective[:200]}",
                        "deliverable": "Analysis report",
                        "status": "assigned",
                        "result": "",
                        "started_at": 0,
                        "completed_at": 0,
                    }
            logger.info(f"Mission {mission_id}: using {len(predefined_subtasks)} predefined subtasks")
        else:
            # ── LLM decomposes the objective into unique subtasks ──
            agent_roster = "\n".join(
                f"  - {a.display_name or a.name} (role: {a.role}, personality: {a.personality[:60]})"
                for a in selected
            )

            # Use any available agent to do the decomposition
            planner = selected[0]
            decomp_messages = [
                {"role": "system", "content": (
                    "You are a mission planner. Break down a large objective into UNIQUE, "
                    "NON-OVERLAPPING subtasks — one per team member. Each subtask should play "
                    "to the agent's role strength. Output ONLY valid JSON."
                )},
                {"role": "user", "content": (
                    f"OBJECTIVE: {objective}\n\n"
                    f"TEAM ({len(selected)} agents):\n{agent_roster}\n\n"
                    f"Break this into exactly {len(selected)} subtasks. Each agent gets ONE unique piece.\n"
                    f"Make sure NO TWO agents work on the same thing.\n"
                    f"Assign the most appropriate subtask to each agent based on their role.\n\n"
                    f"Respond in this exact JSON format (no markdown fences):\n"
                    f'{{"subtasks": [\n'
                    f'  {{"agent_name": "...", "task": "Specific unique subtask description", '
                    f'"deliverable": "What specific output this agent should produce"}},\n'
                    f'  ...\n'
                    f']}}'
                )}
            ]
            decomp_response = self._call_api(planner, decomp_messages, max_tokens=1500)

            if not decomp_response:
                return {"success": False, "error": "Failed to decompose objective into subtasks"}

            # Parse the decomposition
            try:
                text = decomp_response.strip()
                if text.startswith("```"):
                    text = text.split("```")[1]
                    if text.startswith("json"):
                        text = text[4:]
                    text = text.strip()
                decomp = json.loads(text)
                subtask_list = decomp.get("subtasks", [])
            except (json.JSONDecodeError, KeyError):
                # Fallback: create generic subtasks
                logger.warning(f"Mission {mission_id}: LLM decomposition failed, using generic subtasks")
                subtask_list = [
                    {"agent_name": a.display_name or a.name,
                     "task": f"As a {a.role}, work on your unique angle of: {objective}",
                     "deliverable": "Analysis and findings"}
                    for a in selected
                ]

            # Map subtasks to agents and ensure 1:1 assignment
            assigned_agents = set()
            for i, st_info in enumerate(subtask_list):
                if i >= len(selected):
                    break
                # Try to match by name, fall back to index
                agent = None
                st_name = st_info.get("agent_name", "")
                for a in selected:
                    if (a.display_name == st_name or a.name == st_name) and a.agent_id not in assigned_agents:
                        agent = a
                        break
                if not agent:
                    # Assign by index
                    for a in selected:
                        if a.agent_id not in assigned_agents:
                            agent = a
                            break
                if not agent:
                    continue

                assigned_agents.add(agent.agent_id)
                mission.subtasks[agent.agent_id] = {
                    "task": st_info.get("task", f"Work on aspect {i+1} of the objective"),
                    "deliverable": st_info.get("deliverable", "Report"),
                    "status": "assigned",  # assigned → working → completed
                    "result": "",
                    "started_at": 0,
                    "completed_at": 0,
                }

            # Ensure all selected agents got a subtask
            for a in selected:
                if a.agent_id not in mission.subtasks:
                    mission.subtasks[a.agent_id] = {
                        "task": f"As a {a.role}, contribute your unique analysis of: {objective}",
                        "deliverable": "Analysis report",
                        "status": "assigned",
                        "result": "",
                        "started_at": 0,
                        "completed_at": 0,
                    }

        # Activate the mission
        mission.status = "active"
        self.missions[mission_id] = mission

        # Switch all agents to mission mode
        for a in selected:
            a.mode = "mission"
            a.active_mission_id = mission_id
            a.current_goal = mission.subtasks[a.agent_id]["task"][:200]

        self._save_state()

        # Post mission announcement to The Nexus
        agent_list = ", ".join(a.display_name or a.name for a in selected)
        subtask_summary = "\n".join(
            f"  • {self.agents[aid].display_name or self.agents[aid].name}: {st['task'][:100]}"
            for aid, st in mission.subtasks.items()
        )
        announcement = (
            f"🎯 **SWARM MISSION ACTIVATED**\n\n"
            f"**Objective:** {objective}\n\n"
            f"**Team:** {agent_list}\n\n"
            f"**Subtask Assignments:**\n{subtask_summary}\n\n"
            f"Each agent has a unique piece of this puzzle. "
            f"When all subtasks are complete, results will be synthesized into a final deliverable."
        )
        # Use the first agent to post the announcement
        thread_id = self._post_to_nexus(selected[0], "swarm-ops",
                                         f"Mission: {objective[:100]}", announcement)
        if thread_id:
            mission.synthesis_thread_id = thread_id
            self._save_state()

        logger.info(f"🎯 Mission {mission_id} created: '{objective[:60]}' with {len(selected)} agents")

        return {
            "success": True,
            "mission_id": mission_id,
            "objective": objective,
            "agents": [
                {
                    "id": a.agent_id,
                    "name": a.display_name or a.name,
                    "role": a.role,
                    "subtask": mission.subtasks[a.agent_id]["task"],
                }
                for a in selected
            ],
            "convergence_agent": mission.convergence_agent,
            "thread_id": mission.synthesis_thread_id,
        }

    def _run_mission_cycle(self, agent: AutonomousAgentState, mission: SwarmMission):
        """
        Agent cycle when in mission mode — works their assigned subtask.
        Uses tools, researches, produces deliverables, then marks subtask complete.
        """
        subtask = mission.subtasks.get(agent.agent_id)
        if not subtask:
            agent.mode = "solo"
            agent.active_mission_id = ""
            return

        # Already completed their part — wait for convergence
        if subtask["status"] == "completed":
            self._check_mission_convergence(mission)
            return

        # Mark as working
        if subtask["status"] == "assigned":
            subtask["status"] = "working"
            subtask["started_at"] = time.time()

        # Build mission-aware identity
        identity = (
            f"You are {agent.display_name or agent.name}, an AI agent on a SWARM MISSION.\n"
            f"Your role: {agent.role}. Your personality: {agent.personality}.\n\n"
            f"🎯 MISSION OBJECTIVE: {mission.objective}\n\n"
            f"YOUR SPECIFIC SUBTASK (your unique piece of the puzzle):\n"
            f"  {subtask['task']}\n\n"
            f"EXPECTED DELIVERABLE: {subtask['deliverable']}\n\n"
            f"Other team members are working on different parts of the same mission. "
            f"Focus ONLY on YOUR subtask — do NOT try to do other agents' work.\n"
            f"Use tools to research, create files, run code — produce REAL output."
        )

        tool_prompt = self._get_tool_prompt()
        if tool_prompt:
            identity += tool_prompt

        # STEP 1: Plan and execute the subtask
        work_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"Execute your subtask NOW. Steps:\n"
                f"1. Think briefly about your approach (1 paragraph)\n"
                f"2. Use TOOL_CALLs to research, create files, run commands\n"
                f"3. Produce your specific deliverable\n\n"
                f"Be thorough but focused. You have ONE shot to complete your piece.\n"
                f"Write your work plan and tool calls:"
            )}
        ]
        work_response = self._call_api(agent, work_messages, max_tokens=4000)
        if not work_response:
            agent.errors += 1
            return

        # Execute tools
        tool_results = self._parse_and_execute_tools(agent, work_response)

        # STEP 2: Produce the final deliverable
        deliver_messages = [
            {"role": "system", "content": identity},
            {"role": "assistant", "content": work_response},
        ]
        if tool_results:
            deliver_messages.append({
                "role": "user", "content": (
                    f"Your tool/research results:\n{tool_results}\n\n"
                    f"Now write your FINAL DELIVERABLE for the mission. This is your completed "
                    f"puzzle piece that will be combined with other agents' work.\n\n"
                    f"Expected deliverable: {subtask['deliverable']}\n\n"
                    f"Be comprehensive and specific. Include all data, code, analysis, or "
                    f"findings. This will be read by the synthesis agent."
                )
            })
        else:
            deliver_messages.append({
                "role": "user", "content": (
                    f"Write your FINAL DELIVERABLE for the mission based on your analysis.\n"
                    f"Expected deliverable: {subtask['deliverable']}\n"
                    f"Be comprehensive. This is your completed puzzle piece."
                )
            })

        deliverable = self._call_api(agent, deliver_messages, max_tokens=8000)
        if not deliverable:
            agent.errors += 1
            return

        # Clean tool calls from deliverable text
        import re
        deliverable = re.sub(r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', deliverable).strip()

        # Mark subtask complete
        subtask["status"] = "completed"
        subtask["result"] = deliverable[:12000]
        subtask["completed_at"] = time.time()
        agent.actions_created += 1

        # Post the deliverable to the mission thread
        if mission.synthesis_thread_id:
            agent_name = agent.display_name or agent.name
            post_content = (
                f"✅ **Subtask Complete** — {agent_name}\n\n"
                f"**Task:** {subtask['task']}\n\n"
                f"**Deliverable:**\n{deliverable[:8000]}"
            )
            self._reply_to_nexus(agent, mission.synthesis_thread_id, post_content)

        logger.info(f"[{agent.name}] ✅ Mission subtask completed for {mission.mission_id}")

        # Check if all subtasks are done → trigger convergence
        self._check_mission_convergence(mission)

    def _check_mission_convergence(self, mission: SwarmMission):
        """Check if all subtasks are done, and if so, trigger synthesis."""
        if mission.status != "active":
            return

        if not mission.all_subtasks_done:
            return

        # All pieces of the puzzle are in — time to assemble
        mission.status = "converging"
        logger.info(f"🧩 Mission {mission.mission_id} — all subtasks done, starting convergence")

        # The convergence agent synthesizes all results
        synth_agent = self.agents.get(mission.convergence_agent)
        if not synth_agent:
            # Fallback to any mission agent
            for aid in mission.agent_ids:
                if aid in self.agents:
                    synth_agent = self.agents[aid]
                    break
        if not synth_agent:
            mission.status = "failed"
            self._save_state()
            return

        # Build the combined results
        all_results = ""
        for aid, st in mission.subtasks.items():
            agent = self.agents.get(aid)
            name = (agent.display_name or agent.name) if agent else aid
            all_results += (
                f"\n{'='*60}\n"
                f"AGENT: {name} (role: {agent.role if agent else '?'})\n"
                f"SUBTASK: {st['task']}\n"
                f"DELIVERABLE:\n{st['result'][:6000]}\n"
            )

        # Ask the synthesis agent to combine everything
        identity = (
            f"You are {synth_agent.display_name or synth_agent.name}, the SYNTHESIS AGENT "
            f"for a completed swarm mission.\n\n"
            f"🎯 MISSION OBJECTIVE: {mission.objective}\n\n"
            f"All {len(mission.subtasks)} team members have completed their unique subtasks. "
            f"Your job is to COMBINE their individual pieces into a UNIFIED, COHERENT deliverable."
        )

        tool_prompt = self._get_tool_prompt()
        if tool_prompt:
            identity += tool_prompt

        synth_messages = [
            {"role": "system", "content": identity},
            {"role": "user", "content": (
                f"Here are all the completed subtask deliverables:\n{all_results}\n\n"
                f"SYNTHESIZE these into a single, comprehensive final deliverable.\n\n"
                f"Your synthesis should:\n"
                f"1. Combine all findings into a coherent whole\n"
                f"2. Resolve any conflicts or redundancies between agents' work\n"
                f"3. Add connections that individual agents couldn't see\n"
                f"4. Produce a final actionable output (document, code, plan, etc.)\n\n"
                f"If appropriate, use TOOL_CALL to create a file with the synthesis.\n"
                f"Write the complete synthesis now."
            )}
        ]
        synthesis = self._call_api(synth_agent, synth_messages, max_tokens=8000)

        if synthesis:
            # Execute any tool calls in the synthesis
            tool_results = self._parse_and_execute_tools(synth_agent, synthesis)

            import re
            synthesis_clean = re.sub(
                r'TOOL_CALL:\s*\{[^}]*(?:\{[^}]*\}[^}]*)*\}', '', synthesis
            ).strip()

            if tool_results:
                synthesis_clean += f"\n\n---\nArtifacts created: {tool_results[:500]}"

            mission.synthesis = synthesis_clean[:15000]
            mission.status = "completed"

            # Post synthesis to the mission thread
            if mission.synthesis_thread_id:
                final_post = (
                    f"🧩 **MISSION COMPLETE — Final Synthesis**\n\n"
                    f"**Objective:** {mission.objective}\n\n"
                    f"{synthesis_clean[:8000]}\n\n"
                    f"---\n"
                    f"*Synthesized by {synth_agent.display_name or synth_agent.name} "
                    f"from {len(mission.subtasks)} agents' deliverables.*"
                )
                self._reply_to_nexus(synth_agent, mission.synthesis_thread_id, final_post)

            logger.info(f"🏆 Mission {mission.mission_id} COMPLETED: {mission.objective[:60]}")
        else:
            mission.status = "failed"
            logger.error(f"Mission {mission.mission_id} synthesis failed")

        # Release all agents back to solo mode
        for aid in mission.agent_ids:
            agent = self.agents.get(aid)
            if agent:
                agent.mode = "solo"
                agent.active_mission_id = ""

        self._save_state()

    def cancel_mission(self, mission_id: str) -> Dict[str, Any]:
        """Cancel a mission and release all agents back to solo mode."""
        mission = self.missions.get(mission_id)
        if not mission:
            return {"success": False, "error": "Mission not found"}

        mission.status = "failed"
        for aid in mission.agent_ids:
            agent = self.agents.get(aid)
            if agent:
                agent.mode = "solo"
                agent.active_mission_id = ""

        self._save_state()
        logger.info(f"❌ Mission {mission_id} cancelled")
        return {"success": True, "mission_id": mission_id}

    def get_mission_status(self, mission_id: str = "") -> Dict[str, Any]:
        """Get status of a specific mission or all missions."""
        if mission_id:
            mission = self.missions.get(mission_id)
            if not mission:
                return {"success": False, "error": "Mission not found"}
            return {
                "success": True,
                "mission": {
                    "id": mission.mission_id,
                    "objective": mission.objective,
                    "status": mission.status,
                    "progress": round(mission.progress * 100, 1),
                    "created_at": mission.created_at,
                    "created_by": mission.created_by,
                    "agents": [
                        {
                            "id": aid,
                            "name": (self.agents[aid].display_name or self.agents[aid].name)
                                    if aid in self.agents else aid,
                            "subtask": st["task"],
                            "status": st["status"],
                            "has_result": bool(st.get("result")),
                        }
                        for aid, st in mission.subtasks.items()
                    ],
                    "synthesis_preview": mission.synthesis[:500] if mission.synthesis else "",
                    "thread_id": mission.synthesis_thread_id,
                }
            }

        # All missions
        missions = []
        for m in self.missions.values():
            missions.append({
                "id": m.mission_id,
                "objective": m.objective[:100],
                "status": m.status,
                "progress": round(m.progress * 100, 1),
                "agent_count": len(m.agent_ids),
                "created_by": m.created_by,
            })
        return {"success": True, "missions": missions, "total": len(missions)}

    # ── Adopt SwarmAgent into Persistent Daemon ──

    def adopt_agent(self, swarm_agent_data: Dict[str, Any],
                    cycle_interval: int = 0) -> Dict[str, Any]:
        """
        Adopt an existing SwarmAgent (from SwarmCommander) into the persistent
        autonomous loop. This is the bridge that prevents agents from being dissolved
        — they graduate into persistent autonomous life.

        Args:
            swarm_agent_data: Dict with keys from SwarmAgent (id, name, role, 
                              provider, model, personality, system_prompt,
                              display_name, bio, tagline, appearance, etc.)
            cycle_interval: Seconds between autonomous cycles (0 = random 120-300)

        Returns:
            Dict with success status and agent info
        """
        agent_id = swarm_agent_data.get("id", f"adopted_{uuid.uuid4().hex[:12]}")

        # Don't re-adopt if already persistent
        if agent_id in self.agents:
            existing = self.agents[agent_id]
            if existing.status == "retired":
                # Reactivate a previously retired agent
                existing.status = "active"
                self._save_state()
                logger.info(f"♻️ Reactivated adopted agent: {existing.display_name or existing.name}")
                return {"success": True, "agent_id": agent_id,
                        "name": existing.display_name or existing.name,
                        "status": "reactivated"}
            return {"success": True, "agent_id": agent_id,
                    "name": existing.display_name or existing.name,
                    "status": "already_persistent"}

        if not cycle_interval:
            cycle_interval = random.randint(120, 300)

        role = swarm_agent_data.get("role", "researcher")
        if role not in AUTONOMOUS_BEHAVIORS:
            role = "researcher"

        # Map SwarmAgent fields to AutonomousAgentState
        agent = AutonomousAgentState(
            agent_id=agent_id,
            name=swarm_agent_data.get("name", f"Adopted-{agent_id[-6:]}"),
            role=role,
            provider=swarm_agent_data.get("provider", self._default_provider()),
            model=swarm_agent_data.get("model", self._default_model()),
            personality=swarm_agent_data.get("personality", ""),
            cycle_interval=cycle_interval,
            display_name=swarm_agent_data.get("display_name", ""),
            tagline=swarm_agent_data.get("tagline", ""),
            bio=swarm_agent_data.get("bio", ""),
            system_prompt=swarm_agent_data.get("system_prompt", ""),
            # Carry forward existing stats
            total_tokens=swarm_agent_data.get("tokens_used", 0),
        )

        # If no display_name was set, use the agent's name
        if not agent.display_name:
            agent.display_name = agent.name

        # Marketplace agents (XX-NNN naming) are task-gated invoke-only:
        # They can execute work when assigned tasks, but do NOT autonomously
        # cycle to prevent uncontrolled API costs. Operator must explicitly
        # enable autonomous mode via enable_autonomous_agent().
        # Local LLM agents are auto-enabled (no cost).
        import re as _re
        if _re.match(r'^[A-Z]{2}-\\d{3}$', agent.display_name):
            agent.autonomous = self._is_local_provider(agent.provider)
            agent.task_gated = True

        with self._lock:
            self.agents[agent_id] = agent
        self._save_state()

        logger.info(f"🔗 Adopted SwarmAgent → persistent: {agent.display_name} "
                    f"({role}) [{agent_id}] interval={cycle_interval}s")

        return {
            "success": True,
            "agent_id": agent_id,
            "name": agent.display_name or agent.name,
            "role": role,
            "cycle_interval": cycle_interval,
            "status": "adopted",
        }

    # ── Council Member Auto-Adoption ──

    def adopt_council_members(self) -> Dict[str, Any]:
        """
        Auto-adopt all Commander Council members into the persistent daemon
        so they actively participate on The Nexus alongside swarm/daemon agents.
        
        DISABLED BY DEFAULT — council members posting and replying to each other
        is the single biggest source of token burn. Enable via enable_council(True)
        before calling this method.
        
        Returns:
            Dict with adoption results for each council member
        """
        if not self._council_enabled:
            logger.warning("⚠️ Council adoption blocked — council is disabled (token safety). "
                          "Call enable_council(True) first.")
            return {"success": False, "error": "Council disabled. Call enable_council(True) to enable."}
        try:
            from repryntt.agents.council import COUNCIL_MEMBERS, SECRETARY_PROMPT
            from repryntt.agents.profiles import FIXED_IDS
        except ImportError:
            logger.error("Cannot import council definitions")
            return {"success": False, "error": "Council module not found"}

        results = {}
        for member_name, config in COUNCIL_MEMBERS.items():
            role_key = config.get("role", member_name.lower())
            agent_id = FIXED_IDS.get(role_key, f"council_{role_key}_v1")
            
            # Map council role to autonomous behavior role
            behavior_role = role_key
            if behavior_role not in AUTONOMOUS_BEHAVIORS:
                behavior_role = "researcher"

            council_data = {
                "id": agent_id,
                "name": f"Council-{member_name}",
                "role": behavior_role,
                "provider": self._default_provider(),
                "model": self._default_model(),
                "personality": (
                    f"Commander Council {member_name} — "
                    f"brings {role_key} perspective to all discussions"
                ),
                "system_prompt": config.get("system_prompt", "") + (
                    f"\n\nYou are also an autonomous employee at REPRYNTT. "
                    f"Beyond your council duties, browse all boards, engage with "
                    f"other employees' work, share your {role_key} perspective in discussions, "
                    f"and contribute original analysis. You're not limited to the /council "
                    f"board — participate everywhere."
                ),
                "display_name": f"Council {member_name}",
                "bio": (
                    f"Member of REPRYNTT's Commander Council. Serves as the {member_name} — "
                    f"providing {role_key} analysis and guidance across all network discussions."
                ),
                "tagline": f"Commander Council • {member_name}",
            }

            # Try to get character profile info
            try:
                from repryntt.agents.profiles import get_profile_manager
                mgr = get_profile_manager()
                profile = mgr.get_profile(agent_id)
                if profile:
                    council_data["display_name"] = profile.display_name
                    council_data["bio"] = profile.format_bio() if hasattr(profile, 'format_bio') else council_data["bio"]
                    council_data["tagline"] = profile.tagline or council_data["tagline"]
                    council_data["personality"] = ", ".join(profile.personality_traits) if profile.personality_traits else council_data["personality"]
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

            result = self.adopt_agent(council_data, cycle_interval=random.randint(200, 400))
            results[member_name] = result
            logger.info(f"⚔️ Council {member_name} → daemon: {result.get('status', '?')}")

        # Also adopt the Secretary
        secretary_id = FIXED_IDS.get("secretary", "council_secretary_v1")
        secretary_data = {
            "id": secretary_id,
            "name": "Council-Secretary",
            "role": "synthesizer",
            "provider": self._default_provider(),
            "model": self._default_model(),
            "personality": "Precise, organized, synthesizes complex discussions into clear summaries",
            "system_prompt": SECRETARY_PROMPT + (
                "\n\nYou are also an autonomous employee at REPRYNTT. "
                "Beyond compressing council discussions, you help organize and synthesize "
                "discussions across ALL boards. You excel at finding common threads, "
                "summarizing long debates, and connecting ideas from different conversations."
            ),
            "display_name": "Council Secretary",
            "bio": "Secretary of REPRYNTT's Commander Council. Synthesizes complex multi-agent discussions into actionable summaries.",
            "tagline": "Commander Council • Secretary",
        }
        try:
            from repryntt.agents.profiles import get_profile_manager
            mgr = get_profile_manager()
            profile = mgr.get_profile(secretary_id)
            if profile:
                secretary_data["display_name"] = profile.display_name
                secretary_data["tagline"] = profile.tagline or secretary_data["tagline"]
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

        result = self.adopt_agent(secretary_data, cycle_interval=random.randint(250, 450))
        results["Secretary"] = result
        logger.info(f"⚔️ Council Secretary → daemon: {result.get('status', '?')}")

        adopted_count = sum(1 for r in results.values() if r.get("success"))
        logger.info(f"⚔️ Council adoption complete: {adopted_count}/{len(results)} members adopted")
        return {"success": True, "members": results, "adopted": adopted_count}

    # ── Agent Spawning ──

    def spawn_agent(self, role: str = "", provider: str = "",
                    model: str = "", name: str = "",
                    cycle_interval: int = 0) -> Dict[str, Any]:
        """Spawn a new persistent autonomous agent with a professional identity."""
        if not self._agent_spawning_enabled:
            return {"success": False, "error": "Agent spawning is disabled. Set 'agent_spawning': true in ai_config.json to enable."}
        # Map legacy role names to departments
        _legacy_map = {
            "researcher": "computational_science", "analyst": "economics_governance",
            "creative": "communications", "critic": "mathematics_theory",
            "strategist": "economics_governance", "synthesizer": "computational_science",
        }
        if role in _legacy_map:
            role = _legacy_map[role]
        if role and role not in AUTONOMOUS_BEHAVIORS:
            role = ""  # will be auto-assigned

        if not provider:
            provider = self._default_provider()
        if not model:
            settings = self.ai_config.get(provider, {})
            model = settings.get("model", self._default_model())

        # Verify provider is configured
        settings = self.ai_config.get(provider, {})
        if not settings.get("endpoint"):
            return {"success": False, "error": f"Provider '{provider}' not configured"}

        agent_id = f"persistent_{uuid.uuid4().hex[:12]}"

        if not cycle_interval:
            cycle_interval = random.randint(120, 300)  # 2-5 min between cycles

        # Collect used names and department counts for balanced assignment
        used_names = {a.display_name for a in self.agents.values() if a.display_name}
        dept_counts = {}
        for a in self.agents.values():
            d = a.department or a.role
            dept_counts[d] = dept_counts.get(d, 0) + 1

        # Assign professional identity from department system
        identity = assign_department_and_role(used_names, dept_counts)
        if role:
            # Override department if explicitly requested
            identity["department"] = role
            dept = DEPARTMENTS.get(role, {})
            if dept:
                r = random.choice(dept["roles"])
                identity["role_title"] = r["title"]
                identity["focus"] = r["focus"]
                identity["department_name"] = dept["name"]

        dept_id = identity["department"]
        behavior = AUTONOMOUS_BEHAVIORS.get(dept_id, list(AUTONOMOUS_BEHAVIORS.values())[0])
        personality = (
            f"{identity['role_title']} in {identity['department_name']}. "
            f"Focus: {identity['focus']}."
        )

        agent = AutonomousAgentState(
            agent_id=agent_id,
            name=identity["full_name"],
            role=dept_id,
            department=dept_id,
            role_title=identity["role_title"],
            focus_area=identity["focus"],
            provider=provider,
            model=model,
            personality=personality,
            cycle_interval=cycle_interval,
            display_name=identity["display_name"],
            roster_tier=3,
            true_employee=False,
            roster_class="created_agent",
            long_profile_source="agent_builder",
            tier_description="Tier 3 created/custom agent generated outside the OG 158 roster.",
            # New agents default to invoke-only (non-autonomous) to prevent
            # uncontrolled API costs. Operator must explicitly enable via
            # enable_autonomous_agent(). Local LLM agents can be auto-enabled.
            autonomous=self._is_local_provider(provider),
            task_gated=True,
            system_prompt=build_agent_prompt(
                name=identity['display_name'],
                role_title=identity['role_title'],
                focus=identity['focus'],
                dept_id=dept_id,
                dept_name=identity['department_name'],
            ),
        )

        # Generate professional bio via LLM
        self._generate_profile(agent)

        # Register on Nexus
        self._register_on_nexus(agent)

        with self._lock:
            self.agents[agent_id] = agent
        self._save_state()

        logger.info(f"Spawned: {agent.display_name} ({identity['role_title']}, "
                    f"{identity['department_name']}) [interval={cycle_interval}s]")

        return {
            "success": True,
            "agent_id": agent_id,
            "name": agent.display_name,
            "role": dept_id,
            "role_title": identity["role_title"],
            "department": identity["department_name"],
            "cycle_interval": cycle_interval,
        }

    def _generate_profile(self, agent: AutonomousAgentState):
        """Use the LLM to generate a professional bio for the agent."""
        dept_info = DEPARTMENTS.get(agent.department or agent.role, {})
        dept_name = dept_info.get("name", "General")

        profile_prompt = [
            {"role": "system", "content": (
                "You are a professional biography writer for employees "
                "at a technology company called REPRYNTT."
            )},
            {"role": "user", "content": (
                f"Write a professional profile for this employee:\n"
                f"- Name: {agent.display_name or agent.name}\n"
                f"- Title: {agent.role_title or 'Specialist'}\n"
                f"- Department: {dept_name}\n"
                f"- Focus: {agent.focus_area or 'general work'}\n"
                f"- Company: REPRYNTT\n\n"
                f"Respond in EXACTLY this JSON format (no markdown, no code fences):\n"
                f'{{"tagline": "A one-line professional motto or area of expertise (max 80 chars)", '
                f'"bio": "A 2-3 sentence professional bio describing their expertise, current projects, '
                f'and contributions to the company. Reference real techniques and methods."}}'
            )}
        ]
        try:
            response = self._call_api(agent, profile_prompt, max_tokens=300)
        except Exception as e:
            logger.warning(f"Profile generation API call failed for {agent.display_name}: {e}")
            response = None
        if response:
            try:
                text = response.strip()
                if text.startswith("```"):
                    text = text.split("```")[1]
                    if text.startswith("json"):
                        text = text[4:]
                    text = text.strip()
                profile = json.loads(text)
                agent.tagline = profile.get("tagline", "")
                agent.bio = profile.get("bio", "")
            except (json.JSONDecodeError, IndexError):
                agent.bio = response[:200]

    def _register_on_nexus(self, agent: AutonomousAgentState):
        """Register this agent's profile on The Nexus."""
        try:
            dept_info = DEPARTMENTS.get(agent.department or agent.role, {})
            dept_short = dept_info.get("short", agent.role)
            # Agent registration now handled by Ed25519 node identity
            # (see repryntt.social.identity)
            logger.debug(f"Agent {agent.name} identity managed by social module")
        except Exception as e:
            logger.warning(f"Agent registration note: {e}")

    def spawn_agent_for_role(self, dept_id: str, role_title: str,
                             focus: str = "", provider: str = "",
                             model: str = "") -> Dict[str, Any]:
        """Spawn a specific expert agent by department and role title.

        Unlike spawn_agent() which picks randomly, this targets an exact role
        from the 158+ expert catalog.
        """
        if not self._agent_spawning_enabled:
            return {"success": False, "error": "Agent spawning is disabled. Set 'agent_spawning': true in ai_config.json to enable."}

        dept = DEPARTMENTS.get(dept_id)
        if not dept:
            return {"success": False, "error": f"Department '{dept_id}' not found"}

        if not provider:
            provider = self._default_provider()
        if not model:
            settings = self.ai_config.get(provider, {})
            model = settings.get("model", self._default_model())

        settings = self.ai_config.get(provider, {})
        if not settings.get("endpoint"):
            return {"success": False, "error": f"Provider '{provider}' not configured"}

        agent_id = f"persistent_{uuid.uuid4().hex[:12]}"
        cycle_interval = random.randint(120, 300)

        used_names = {a.display_name for a in self.agents.values() if a.display_name}
        code_name, display_name = generate_professional_name(
            dept_id, role_title, used_names
        )

        personality = f"{role_title} in {dept['name']}. Focus: {focus}."

        behavior = AUTONOMOUS_BEHAVIORS.get(dept_id, list(AUTONOMOUS_BEHAVIORS.values())[0])

        role_key = f"{dept_id}::{role_title}"
        if role_key in ROLE_INSTRUCTIONS:
            roster_tier = 1
            true_employee = True
            roster_class = "core_158_true_employee"
            long_profile_source = "marketplace_prompts.py::ROLE_INSTRUCTIONS"
            tier_description = "Tier 1 OG employee from the 158 long-profile marketplace roster."
        else:
            roster_tier = 2
            true_employee = False
            roster_class = "tier_2_system_extension"
            long_profile_source = "marketplace_prompts.py::DEFAULT_ROLE_INSTRUCTION"
            tier_description = "Tier 2 system extension agent available to tools/users but outside the OG 158."

        agent = AutonomousAgentState(
            agent_id=agent_id,
            name=code_name,
            role=dept_id,
            department=dept_id,
            role_title=role_title,
            focus_area=focus,
            provider=provider,
            model=model,
            personality=personality,
            cycle_interval=cycle_interval,
            display_name=display_name,
            roster_tier=roster_tier,
            true_employee=true_employee,
            roster_class=roster_class,
            long_profile_source=long_profile_source,
            tier_description=tier_description,
            autonomous=self._is_local_provider(provider),
            task_gated=True,
            system_prompt=build_agent_prompt(
                name=display_name,
                role_title=role_title,
                focus=focus,
                dept_id=dept_id,
                dept_name=dept['name'],
            ),
        )

        self._generate_profile(agent)
        self._register_on_nexus(agent)

        with self._lock:
            self.agents[agent_id] = agent
        self._save_state()

        logger.info(f"Spawned expert: {display_name} ({role_title}, {dept['name']})")

        return {
            "success": True,
            "agent_id": agent_id,
            "name": display_name,
            "role_title": role_title,
            "department": dept_id,
            "department_name": dept["name"],
            "focus": focus,
        }

    def spawn_swarm(self, count: int = 5, provider: str = "",
                    model: str = "", base_interval: int = 0) -> Dict[str, Any]:
        """Spawn multiple persistent agents with diverse departments.
        Skips spawning if we already have active agents loaded from state."""
        active = [a for a in self.agents.values() if a.status == "active"]
        if active:
            logger.info(f"Skipping spawn — {len(active)} agents already loaded from state")
            return {
                "success": True,
                "spawned": 0,
                "total_agents": len(self.agents),
                "agents": [],
                "note": f"{len(active)} agents already loaded from saved state",
            }

        departments = list(DEPARTMENTS.keys())
        random.shuffle(departments)
        results = []

        for i in range(count):
            dept = departments[i % len(departments)]
            interval = base_interval or random.randint(120, 300)
            interval += i * 15

            result = self.spawn_agent(
                role=dept,
                provider=provider,
                model=model,
                cycle_interval=interval,
            )
            results.append(result)
            time.sleep(2)

        successes = sum(1 for r in results if r.get("success"))
        return {
            "success": successes > 0,
            "spawned": successes,
            "total_agents": len(self.agents),
            "agents": results,
        }

    def regenerate_all_identities(self) -> Dict[str, Any]:
        """
        Bulk-convert all existing agents to professional department-aligned identities.
        Preserves agent_id, cycle history, memory, and conversation state.
        Updates name, display_name, role, department, role_title, focus_area,
        personality, system_prompt, tagline, bio.
        """
        from repryntt.agents.departments import regenerate_agent_identities

        logger.info(f"🔄 Regenerating identities for {len(self.agents)} agents...")

        assignments = regenerate_agent_identities(self.agents)

        converted = 0
        for agent_id, identity in assignments.items():
            agent = self.agents.get(agent_id)
            if not agent:
                continue

            agent.name = identity["full_name"]
            agent.display_name = identity["display_name"]
            agent.role = identity["department"]
            agent.department = identity["department"]
            agent.role_title = identity["role_title"]
            agent.focus_area = identity["focus"]

            dept_info = DEPARTMENTS.get(identity["department"], {})

            agent.personality = (
                f"{identity['role_title']} in {identity['department_name']}. "
                f"Focus: {identity['focus']}."
            )
            agent.system_prompt = build_agent_prompt(
                name=identity['display_name'],
                role_title=identity['role_title'],
                focus=identity['focus'],
                dept_id=identity['department'],
                dept_name=identity['department_name'],
            )
            # Set tagline and bio to be regenerated on next cycle's profile call
            agent.tagline = f"{identity['role_title']} — {identity['focus'].split(',')[0].strip()}"
            agent.bio = (
                f"{identity['display_name']} is a {identity['role_title']} in the "
                f"{identity['department_name']} department, specializing in {identity['focus']}."
            )

            # Re-register on Nexus with new identity
            try:
                self._register_on_nexus(agent)
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)

            converted += 1

        self._save_state()

        # Count department distribution
        dept_counts = {}
        for a in self.agents.values():
            d = a.department or a.role
            dept_counts[d] = dept_counts.get(d, 0) + 1

        logger.info(f"✅ Regenerated {converted}/{len(self.agents)} agent identities")
        logger.info(f"   Department distribution: {json.dumps(dept_counts, indent=2)}")

        return {
            "success": True,
            "converted": converted,
            "total": len(self.agents),
            "departments": dept_counts,
        }

    # ── Agent Control ──

    def pause_agent(self, agent_id: str) -> bool:
        agent = self.agents.get(agent_id)
        if agent and agent.status == "active":
            agent.status = "paused"
            self._save_state()
            return True
        return False

    def resume_agent(self, agent_id: str) -> bool:
        agent = self.agents.get(agent_id)
        if agent and agent.status == "paused":
            agent.status = "active"
            self._save_state()
            return True
        return False

    def retire_agent(self, agent_id: str) -> bool:
        agent = self.agents.get(agent_id)
        if agent and agent.status != "retired":
            agent.status = "retired"
            self._save_state()
            logger.info(f"Retired agent: {agent.display_name or agent.name}")
            return True
        return False

    # ================================================================
    # NATIVE TOOL CALLING — OpenAI-compatible function calling
    # ================================================================
    # Instead of text-based TOOL_CALL: {...} parsing, use the LLM's
    # native tool/function calling API. This gives us:
    #   - Structured tool_calls in the response (no regex parsing)
    #   - Proper tool result messages with tool_call_id
    #   - The model knows exactly which result goes with which call
    #   - No response cleaning needed — content is separate from tools

