    def _tool_memory_search(self, agent: AutonomousAgentState, params: Dict) -> Dict:
        """Tool: memory_search — search daily memory files using vector similarity or keyword matching.

        Scans all YYYY-MM-DD.md files in the agent's memory directory, splits them
        into sections (by ## headings), and returns the most relevant sections with
        date citations.
        """
        import datetime as _dt
        import re as _re

        query = params.get("query", "").strip()
        limit = min(int(params.get("limit", 5)), 15)

        if not query:
            return {"success": False, "error": "query is required"}

        # Determine which agent's memory to search
        agent_id = agent.agent_id if hasattr(agent, 'agent_id') else "jarvis"
        # Pass agent object (not agent_id string) so _agent_workspace_dir uses display_name
        memory_dir = os.path.join(_agent_workspace_dir(agent or agent_id), "memory")
        # Some agents use memory/daily/ subdirectory
        daily_subdir = os.path.join(memory_dir, "daily")
        if os.path.isdir(daily_subdir):
            memory_dir = daily_subdir

        if not os.path.isdir(memory_dir):
            return {"success": False, "error": f"No memory directory found for agent '{agent_id}'"}

        # Collect all daily memory files
        date_pattern = _re.compile(r'^\d{4}-\d{2}-\d{2}\.md$')
        memory_files = sorted(
            [f for f in os.listdir(memory_dir) if date_pattern.match(f)],
            reverse=True  # newest first
        )

        if not memory_files:
            return {"success": False, "error": "No daily memory files found"}

        # Parse all files into sections: (date, heading, content)
        sections = []
        for fname in memory_files:
            date_str = fname.replace('.md', '')
            fpath = os.path.join(memory_dir, fname)
            try:
                with open(fpath, 'r', errors='replace') as f:
                    text = f.read()
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)
                continue

            # Split by ## headings
            current_heading = "General"
            current_lines = []
            for line in text.split('\n'):
                if line.startswith('## '):
                    if current_lines:
                        content = '\n'.join(current_lines).strip()
                        if len(content) > 20:
                            sections.append((date_str, current_heading, content))
                    current_heading = line.lstrip('#').strip()
                    current_lines = []
                else:
                    current_lines.append(line)
            # Last section
            if current_lines:
                content = '\n'.join(current_lines).strip()
                if len(content) > 20:
                    sections.append((date_str, current_heading, content))

        if not sections:
            return {"success": False, "error": "Memory files found but no sections with content"}

        # Search using vector similarity if available, else keyword
        ranked = []
        if VECTOR_SEARCH_AVAILABLE:
            try:
                encoder = get_shared_sentence_transformer('all-MiniLM-L6-v2')
                if encoder is not None:
                    # Encode query
                    query_emb = encoder.encode([query], convert_to_numpy=True).astype('float32')
                    # Encode section texts (truncate to first 512 chars for speed)
                    section_texts = [f"{s[1]}: {s[2][:512]}" for s in sections]
                    section_embs = encoder.encode(section_texts, convert_to_numpy=True).astype('float32')

                    # Build temp FAISS index
                    import faiss as _faiss
                    dim = section_embs.shape[1]
                    index = _faiss.IndexFlatIP(dim)
                    # Normalize for cosine similarity
                    _faiss.normalize_L2(query_emb)
                    _faiss.normalize_L2(section_embs)
                    index.add(section_embs)

                    k = min(limit, len(sections))
                    scores, indices = index.search(query_emb, k)
                    for score, idx in zip(scores[0], indices[0]):
                        if idx < len(sections):
                            date_str, heading, content = sections[idx]
                            ranked.append({
                                "date": date_str,
                                "heading": heading,
                                "snippet": content[:600],
                                "relevance": round(float(score), 3),
                            })
            except Exception as e:
                logger.warning(f"🔍 FAISS memory search failed, falling back to keyword: {e}")
                ranked = []  # fall through to keyword

        # Keyword fallback
        if not ranked:
            query_lower = query.lower()
            query_words = set(query_lower.split())
            scored = []
            for date_str, heading, content in sections:
                score = 0.0
                text_lower = (heading + " " + content).lower()
                # Exact phrase match
                if query_lower in text_lower:
                    score += 2.0
                # Word overlap
                text_words = set(text_lower.split())
                overlap = len(query_words & text_words)
                score += overlap * 0.3
                if score > 0.1:
                    scored.append((score, date_str, heading, content))
            scored.sort(key=lambda x: x[0], reverse=True)
            for score, date_str, heading, content in scored[:limit]:
                ranked.append({
                    "date": date_str,
                    "heading": heading,
                    "snippet": content[:600],
                    "relevance": round(score, 3),
                })

        if not ranked:
            return {
                "success": True,
                "results": [],
                "message": f"No memories matched query '{query}'. Try broader terms.",
                "files_scanned": len(memory_files),
                "sections_scanned": len(sections),
            }

        return {
            "success": True,
            "results": ranked,
            "query": query,
            "files_scanned": len(memory_files),
            "sections_scanned": len(sections),
            "method": "vector" if (VECTOR_SEARCH_AVAILABLE and ranked and ranked[0].get("relevance", 0) <= 1.0) else "keyword",
        }

    def _tool_memory_get(self, agent: AutonomousAgentState, params: Dict) -> Dict:
        """Tool: memory_get — retrieve the full contents of a specific day's memory file."""
        import re as _re

        date = params.get("date", "").strip()

        if not date:
            return {"success": False, "error": "date is required (format: YYYY-MM-DD)"}

        # Validate date format
        if not _re.match(r'^\d{4}-\d{2}-\d{2}$', date):
            return {"success": False, "error": f"Invalid date format '{date}'. Use YYYY-MM-DD."}

        # Determine which agent's memory to read
        agent_id = agent.agent_id if hasattr(agent, 'agent_id') else "jarvis"
        # Pass agent object (not agent_id string) so _agent_workspace_dir uses display_name
        memory_dir = os.path.join(_agent_workspace_dir(agent or agent_id), "memory")
        daily_subdir = os.path.join(memory_dir, "daily")
        if os.path.isdir(daily_subdir):
            memory_dir = daily_subdir

        fpath = os.path.join(memory_dir, f"{date}.md")

        if not os.path.exists(fpath):
            # List available dates as suggestions
            date_pattern = _re.compile(r'^\d{4}-\d{2}-\d{2}\.md$')
            available = sorted(
                [f.replace('.md', '') for f in os.listdir(memory_dir) if date_pattern.match(f)],
                reverse=True
            ) if os.path.isdir(memory_dir) else []
            return {
                "success": False,
                "error": f"No memory file for {date}",
                "available_dates": available[:20],
            }

        try:
            with open(fpath, 'r', errors='replace') as f:
                content = f.read()

            # Truncate if extremely large (some days can be 300KB+)
            truncated = False
            if len(content) > 12000:
                content = content[:12000] + f"\n\n... [TRUNCATED — full file is {len(content)} chars. Use memory_search for targeted retrieval.]"
                truncated = True

            return {
                "success": True,
                "date": date,
                "content": content,
                "chars": len(content),
                "truncated": truncated,
                "file": fpath,
            }
        except Exception as e:
            return {"success": False, "error": str(e)}

    def _tool_request_tools_from_category(self, agent: AutonomousAgentState, params: Dict) -> Dict:
        """Tool: request_tools_from_category — unlock a category of tools for this session."""
        from repryntt.tools.discovery import TOOL_CATEGORIES

        category = (params.get("category", "") or "").strip().upper()
        if not category:
            return {"status": "error", "message": "Missing 'category' parameter. Use list_tool_categories() to see options."}

        if category not in TOOL_CATEGORIES:
            available = sorted(TOOL_CATEGORIES.keys())
            return {"status": "error", "message": f"Unknown category '{category}'. Available: {', '.join(available)}"}

        cat_info = TOOL_CATEGORIES[category]
        cat_tools = cat_info.get("tools", [])

        # Track unlocked categories on the agent for the agentic loop to expand
        if not hasattr(agent, '_unlocked_categories'):
            agent._unlocked_categories = set()
        agent._unlocked_categories.add(category)

        # Return which tools were unlocked
        available_tools = [t for t in cat_tools if t in self._tool_registry.names]
        return {
            "status": "ok",
            "category": category,
            "description": cat_info.get("description", ""),
            "tools_unlocked": available_tools,
            "count": len(available_tools),
            "message": f"✅ Unlocked {len(available_tools)} tools from {category}. They are now available for use.",
        }

    def _tool_list_my_tools(self, agent: AutonomousAgentState, params: Dict) -> Dict:
        """Tool: list_my_tools — enumerate all tools the calling agent has access to.
        
        Uses OpenClaw-style tool groups for categorization.
        Tools are shown via BOTH system prompt text AND tool schema (OpenClaw pattern).
        """
        category_filter = (params.get("category", "") or "all").strip().lower()

        # Use cached tools (set during the current call) to avoid rebuild discrepancies
        native_tools = getattr(agent, '_cached_native_tools', None)
        if not native_tools:
            # Fallback: check daemon-level cache (set during Jarvis calls)
            native_tools = getattr(self, '_jarvis_cached_native_tools', None)
        if not native_tools:
            is_jarvis = (agent.agent_id == "jarvis" or agent.name == "JARVIS")
            native_tools = self._build_native_tools(jarvis=is_jarvis, agent_id=agent.agent_id)

        # Build a flat map: tool_name → description
        tool_map = {}
        for tool_def in native_tools:
            fn = tool_def.get("function", {})
            name = fn.get("name", "")
            desc = fn.get("description", "")[:120]
            if name:
                tool_map[name] = desc

        # Categorize using TOOL_GROUPS (OpenClaw-style group:* naming)
        categorized = {}
        assigned = set()

        for group_key, group_tools in self.TOOL_GROUPS.items():
            cat_name = group_key.replace("group:", "")
            cat_entries = []

            if cat_name == "mcp":
                # Auto-populate MCP tools
                for tname in sorted(tool_map.keys()):
                    if tname.startswith("mcp_") and tname not in assigned:
                        cat_entries.append({"name": tname, "description": tool_map[tname]})
                        assigned.add(tname)
            elif cat_name == "daemon":
                # Daemon tools are virtual — check if they're in the tool list
                for tname in group_tools:
                    if tname in tool_map and tname not in assigned:
                        cat_entries.append({"name": tname, "description": tool_map[tname]})
                        assigned.add(tname)
            else:
                for tname in group_tools:
                    if tname in tool_map and tname not in assigned:
                        cat_entries.append({"name": tname, "description": tool_map[tname]})
                        assigned.add(tname)

            if cat_entries:
                categorized[cat_name] = cat_entries

        # Anything not in a group goes to "other"
        other = []
        for tname, desc in sorted(tool_map.items()):
            if tname not in assigned:
                other.append({"name": tname, "description": desc})
        if other:
            categorized["other"] = other

        # Filter by requested category
        if category_filter and category_filter != "all":
            matched = categorized.get(category_filter, [])
            return {
                "category": category_filter,
                "tool_count": len(matched),
                "tools": matched,
            }

        # Return all categories with counts
        summary = {}
        total = 0
        for cat, tools_list in categorized.items():
            if tools_list:
                summary[cat] = {
                    "count": len(tools_list),
                    "tools": [t["name"] for t in tools_list],
                }
                total += len(tools_list)

        return {
            "total_tools": total,
            "categories": summary,
            "note": (
                "These are your actual executable tools (OpenClaw 'full' profile — no restrictions). "
                "Skills (from list_skills) are prompt plugins, not tools."
            ),
        }

    def _tool_create_persistent_task(self, agent: AutonomousAgentState, params: Dict) -> Dict:
        """Tool: create_persistent_task — create a locked reasoning chain that persists across heartbeats."""
        import datetime as _dt

        goal = params.get("goal", "").strip()
        success_criteria = params.get("success_criteria", "").strip()
        max_steps = min(int(params.get("max_steps", 5)), 30)

        if not goal or not success_criteria:
            return {"success": False, "error": "Both 'goal' and 'success_criteria' are required"}

        # ── Anti-repetition: block persistent tasks on stale topics ──
        import datetime as _dt2
        stale_reason = self._chain_topic_is_stale(
            {"topic": goal, "created": _dt2.datetime.now().isoformat()},
            max_age_hours=99, max_topic_repeats=3)
        if stale_reason:
            return {
                "success": False,
                "error": f"Cannot create persistent task — topic is stale: {stale_reason}. "
                         f"Pick a DIFFERENT topic that hasn't been repeated today."
            }

        # Check if there's already an active chain
        existing = self._jarvis_load_reasoning_chain()
        if existing:
            return {
                "success": False,
                "error": f"A reasoning chain is already active: '{existing.get('topic', '?')[:80]}'. "
                         f"Complete or wait for it to finish before creating a new persistent task.",
                "active_chain": {
                    "topic": existing.get("topic", ""),
                    "goal_type": existing.get("goal_type", "flexible"),
                    "steps_done": len(existing.get("steps_completed", [])),
                }
            }

        # Create locked chain
        chain = {
            "status": "active",
            "topic": goal[:200],
            "goal": goal,
            "goal_type": "locked",
            "success_criteria": success_criteria,
            "created": _dt.datetime.now().isoformat(),
            "target_steps": max_steps,
            "steps_completed": [],
            "next_step_hint": "Begin working toward the goal",
            "last_evaluation": "",
        }
        self._jarvis_save_reasoning_chain(chain)
        logger.info(f"\U0001f512 Persistent task created: {goal[:80]}")

        return {
            "success": True,
            "message": f"Locked persistent task created. Every heartbeat will now focus on this until you call complete_persistent_task.",
            "task": {
                "goal": goal,
                "success_criteria": success_criteria,
                "max_steps": max_steps,
                "goal_type": "locked",
            }
        }

    def _tool_complete_persistent_task(self, agent: AutonomousAgentState, params: Dict) -> Dict:
        """Tool: complete_persistent_task — close a locked persistent task with a definitive outcome."""
        import datetime as _dt

        outcome = params.get("outcome", "").strip().lower()
        summary = params.get("summary", "").strip()

        if outcome not in ("success", "failure", "blocked"):
            return {"success": False, "error": "outcome must be 'success', 'failure', or 'blocked'"}
        if not summary:
            return {"success": False, "error": "summary is required — explain what happened"}

        active_chain = self._jarvis_load_reasoning_chain()
        if not active_chain:
            return {"success": False, "error": "No active reasoning chain / persistent task to complete"}

        is_locked = active_chain.get("goal_type") == "locked"
        topic = active_chain.get("topic", "Unknown")
        steps_done = len(active_chain.get("steps_completed", []))

        # Archive the completed task
        active_chain["status"] = "completed"
        active_chain["outcome"] = outcome
        active_chain["outcome_detail"] = summary
        active_chain["completed_at"] = _dt.datetime.now().isoformat()

        # Save archive copy
        archive_dir = os.path.join(_jarvis_workspace(), "completed_tasks")
        os.makedirs(archive_dir, exist_ok=True)
        archive_name = f"{_dt.datetime.now().strftime('%Y%m%d_%H%M%S')}_{outcome}.json"
        try:
            with open(os.path.join(archive_dir, archive_name), 'w') as f:
                json.dump(active_chain, f, indent=2, default=str)
        except Exception as e:
            logger.warning(f"Failed to archive completed task: {e}")

        # Clear the active chain
        self._jarvis_save_reasoning_chain(None)
        logger.info(
            f"\U0001f512 Persistent task completed [{outcome}] after {steps_done} steps: {topic[:60]}")

        return {
            "success": True,
            "message": f"Task '{topic[:80]}' closed with outcome: {outcome}",
            "outcome": outcome,
            "steps_completed": steps_done,
            "summary": summary[:500],
            "archived_to": archive_name,
        }

    def spawn_ephemeral_agent(self, task: str, department: str = "",
                               parent_agent_id: str = "",
                               max_tokens: int = 4000) -> Dict[str, Any]:
        """
        Spawn a temporary agent to handle a single task, then return the result.

        Unlike spawn_agent(), ephemeral agents:
          - Are NOT added to the persistent agent pool
          - Run exactly ONE invocation (no autonomous loop)
          - Get their own workspace and session
          - Return the full result to the caller
          - Are cleaned up after completion

        This enables agent-to-agent delegation for specialized subtasks.
        """
        if not self._agent_spawning_enabled:
            return {"success": False, "error": "Agent spawning is disabled. Set 'agent_spawning': true in ai_config.json to enable."}
        import re as _re

        # Generate an ephemeral ID
        eph_id = f"ephemeral_{uuid.uuid4().hex[:8]}"
        logger.info(f"🚀 Spawning ephemeral agent {eph_id} — dept={department or 'auto'}, "
                     f"task=\"{task[:80]}\"")

        shell_agent = self._get_jarvis_shell_agent()
        if not shell_agent:
            return {"success": False, "error": "No active agent available for API credentials"}

        # Determine department and role
        if department and department in DEPARTMENTS:
            dept_id = department
        else:
            # Auto-detect best department from task keywords
            dept_id = self._auto_detect_department(task)

        dept_info = DEPARTMENTS.get(dept_id, {})
        dept_name = dept_info.get("name", "General")
        # Pick a random role from the department
        roles = dept_info.get("roles", [{"title": "Specialist", "focus": "General tasks"}])
        role_info = random.choice(roles)

        # Create ephemeral workspace under marketplace/
        workspace = os.path.join(str(WORKSPACE_MARKETPLACE), eph_id)
        os.makedirs(workspace, exist_ok=True)

        # Build a temporary agent state (not persisted)
        eph_agent = AutonomousAgentState(
            agent_id=eph_id,
            name=f"Ephemeral-{role_info['title']}",
            role=dept_id,
            department=dept_id,
            role_title=role_info["title"],
            focus_area=role_info["focus"],
            provider=shell_agent.provider,
            model=shell_agent.model,
            personality=f"Ephemeral {role_info['title']} specialist",
            cycle_interval=0,
            display_name=f"Eph-{role_info['title'][:12]}",
            system_prompt="",
        )

        # Build identity prompt
        identity_prompt = (
            f"You are an ephemeral specialist agent — a {role_info['title']} "
            f"in the {dept_name} department, spawned to handle one specific task.\n"
            f"Your expertise: {role_info['focus']}.\n\n"
            f"INSTRUCTIONS:\n"
            f"- Complete the assigned task thoroughly and return the result.\n"
            f"- You have access to tools via function calling.\n"
            f"- Your workspace: {workspace}\n"
            f"- Be focused and efficient — you exist only for this task.\n"
            f"- Return a complete, actionable deliverable.\n"
        )

        # ── Unified prompt assembly (OpenClaw-style) ──
        identity_prompt += "\n\n" + self.build_agent_system_prompt(
            mode="minimal", workspace=workspace,
        )

        if parent_agent_id:
            parent = self.agents.get(parent_agent_id)
            if parent:
                identity_prompt += (
                    f"\n\nYou were spawned by {parent.display_name or parent.name} "
                    f"({parent.role_title}). Return your results clearly so they "
                    f"can integrate your work.\n"
                )

        # Build tools for this department
        native_tools = self._build_native_tools(department=dept_id)

        messages = [
            {"role": "system", "content": identity_prompt},
            {"role": "user", "content": task},
        ]

        # Run single invocation with tool loop
        start_time = time.time()
        timeout_seconds = 300  # 5 min for ephemeral agents (was 3 min)
        loop_detector = LoopDetector()  # Hash-based, no round cap
        tool_call_count = 0

        msg = self._call_api_with_tools(eph_agent, messages, tools=native_tools,
                                         max_tokens=max_tokens)
        if not msg:
            return {"success": False, "error": "LLM API call failed for ephemeral agent",
                    "agent_id": eph_id}

        while True:
            elapsed = time.time() - start_time
            if elapsed > timeout_seconds:
                break

            tool_calls = msg.get("tool_calls")
            if not tool_calls:
                break

            loop_reason = loop_detector.check(
                tool_calls=tool_calls,
                content=msg.get("content", "")
            )
            if loop_reason:
                logger.warning(f"[{eph_id}] Loop detected: {loop_reason}")
                break

            tool_calls = self._normalize_tool_calls(tool_calls)
            assistant_msg = {"role": "assistant", "content": msg.get("content") or ""}
            if tool_calls:
                assistant_msg["tool_calls"] = tool_calls
            messages.append(assistant_msg)

            tool_results = self._execute_native_tool_calls(eph_agent, tool_calls)
            tool_call_count += len(tool_calls)
            messages.extend(tool_results)

            msg = self._call_api_with_tools(eph_agent, messages, tools=native_tools,
                                             max_tokens=max_tokens)
            if not msg:
                break

        final_content = msg.get("content", "") if msg else ""
        elapsed = time.time() - start_time

        logger.info(f"✅ Ephemeral agent {eph_id} completed — "
                     f"{tool_call_count} tool calls, {elapsed:.1f}s")

        return {
            "success": True,
            "agent_id": eph_id,
            "department": dept_id,
            "role": role_info["title"],
            "response": final_content,
            "tool_calls": tool_call_count,
            "elapsed_seconds": round(elapsed, 1),
        }

    def _auto_detect_department(self, task: str) -> str:
        """Simple keyword-based department detection for ephemeral agents."""
        task_lower = task.lower()
        keyword_map = {
            "blockchain_web3": ["smart contract", "solidity", "blockchain", "web3",
                                 "defi", "nft", "ethereum", "token"],
            "software_development": ["code", "program", "debug", "api", "software",
                                      "python", "javascript", "function", "class"],
            "data_processing": ["data", "csv", "database", "sql", "analytics",
                                 "dataset", "statistics"],
            "research_analysis": ["research", "study", "analyze", "paper", "survey",
                                   "literature", "investigate"],
            "content_creation": ["write", "article", "blog", "content", "copy",
                                  "story", "creative writing"],
            "marketing": ["marketing", "campaign", "brand", "social media", "seo",
                           "advertisement", "promotion"],
            "finance_trading": ["finance", "trading", "stock", "investment", "market",
                                 "portfolio", "economic"],
            "security_compliance": ["security", "audit", "vulnerability", "compliance",
                                     "penetration test", "firewall"],
            "customer_service": ["customer", "support", "ticket", "complaint",
                                  "help desk", "issue"],
            "legal": ["legal", "contract", "compliance", "regulation", "law",
                       "patent", "trademark"],
        }
        best_dept = "software_development"  # default
        best_score = 0
        for dept, keywords in keyword_map.items():
            score = sum(1 for kw in keywords if kw in task_lower)
            if score > best_score:
                best_score = score
                best_dept = dept
        return best_dept

    # ================================================================
    # MANUAL AGENT INVOCATION — use a single agent on-demand
    # ================================================================

    def invoke_agent(self, agent_id: str, prompt: str,
                     max_tokens: int = 4000) -> Dict[str, Any]:
        """
        Manually invoke a single agent with NATIVE tool calling.

        Architecture (OpenClaw-style):
          1. Native tool calling — tools sent as structured function schemas,
             not text prompts. Model returns tool_calls, we execute and send
             results back as role:"tool" messages with tool_call_id.
          2. NO round cap — runs until the model stops calling tools (timeout
             is the only hard limit). Hash-based loop detection catches genuine
             stuck loops, not legitimate multi-step workflows.
          3. Mid-run context compaction — auto-summarizes older messages when
             context nears the model's window, allowing arbitrarily long runs.
          4. Per-department tool profiles — each agent only sees tools relevant
             to their department (not all 176).
          5. Agent workspaces — each agent has an isolated output directory.
          6. Session persistence — conversations saved/loaded per agent.
          7. Polling backoff — exponential delay for repeated poll-style tools.
        """
        # Find the agent — exact match first, then partial
        agent = self.agents.get(agent_id)
        if not agent:
            for aid, a in self.agents.items():
                if (a.display_name and a.display_name.lower() == agent_id.lower()) or \
                   a.name.lower() == agent_id.lower() or \
                   aid.lower() == agent_id.lower():
                    agent = a
                    break
        if not agent:
            for aid, a in self.agents.items():
                if agent_id.lower() in aid.lower() or \
                   agent_id.lower() in (a.display_name or a.name).lower():
                    agent = a
                    break
        if not agent:
            return {
                "success": False,
                "error": f"Agent '{agent_id}' not found. Use /api/daemon/agents to list available agents."
            }

        agent_name = agent.display_name or agent.name
        dept_info = DEPARTMENTS.get(agent.department or agent.role, {})
        dept_name = dept_info.get("name", "General")

        logger.info(f"🔧 Manual invoke: [{agent_name}] ({dept_name}) — \"{prompt[:100]}\"")

        # Feature #6: Agent workspace
        workspace = self._get_agent_workspace(agent.agent_id)

        # Build identity system prompt (lean — tools are sent via native API)
        identity_prompt = (
            f"You are {agent_name}, a {agent.role_title or 'specialist'} "
            f"in the {dept_name} department.\n"
            f"Your expertise: {agent.focus_area or agent.personality}.\n\n"
            f"IMPORTANT INSTRUCTIONS:\n"
            f"- You have access to real tools via function calling. The tools are "
            f"provided as structured function definitions — just call them directly.\n"
            f"- DO NOT write 'TOOL_CALL:' in your text. Your tools are called via "
            f"the native function calling mechanism, not text patterns.\n"
            f"- Your workspace directory is: {workspace}\n"
            f"  Save any output files there (e.g. {workspace}/report.md).\n"
            f"- Deliver complete, actionable results. Do NOT ask clarifying questions.\n"
            f"- When you have enough information, provide your final deliverable as "
            f"plain text in your response.\n"
        )

        if agent.system_prompt:
            # Strip old text-based TOOL_CALL instructions from the system prompt.
            import re
            cleaned_prompt = agent.system_prompt
            cleaned_prompt = re.sub(
                r'### TOOL USAGE PROTOCOL.*?(?=###|## |\Z)', '', cleaned_prompt, flags=re.DOTALL)
            cleaned_prompt = re.sub(
                r'```\s*\n\s*TOOL_CALL:\s*\{.*?\}\s*\n\s*```', '', cleaned_prompt, flags=re.DOTALL)
            cleaned_prompt = re.sub(
                r'^.*TOOL_CALL:\s*\{.*$', '', cleaned_prompt, flags=re.MULTILINE)
            cleaned_prompt = re.sub(r'\n{4,}', '\n\n\n', cleaned_prompt)
            identity_prompt = cleaned_prompt.strip() + "\n\n" + identity_prompt

        # ── Unified prompt assembly (OpenClaw-style) ──
        # Injects: runtime, safety, bootstrap .md files, skills, memory
        identity_prompt += "\n\n" + self.build_agent_system_prompt(
            mode="minimal", agent=agent, workspace=workspace,
        )

        # Feature #5: Load previous session context
        session_history = self._load_session(agent.agent_id)
        if session_history:
            identity_prompt += (
                f"\nYou have {len(session_history)} previous messages in your session. "
                f"Use this context if relevant to the current task.\n"
            )

        # Per-agent tool profile: agent_id first, then department fallback
        native_tools = self._build_native_tools(agent_id=agent_name)

        # Build messages
        messages = [{"role": "system", "content": identity_prompt}]

        # Inject recent session history (Feature #5)
        for hist_msg in session_history[-6:]:  # Last 6 exchanges max
            role = hist_msg.get("role", "user")
            content = hist_msg.get("content", "")
            if content and role in ("user", "assistant"):
                messages.append({"role": role, "content": content})

        messages.append({"role": "user", "content": prompt})

        # Track NEW messages only (for session saving — don't re-save loaded history)
        new_messages = [{"role": "user", "content": prompt}]

        # Feature #1 + #4: Native tool calling loop
        # OpenClaw-style: NO round cap — runs until model stops or timeout
        start_time = time.time()
        timeout_seconds = 600  # 10 min (OpenClaw default) — timeout is the only hard cap
        all_tool_names = []
        tool_call_count = 0
        round_num = 0
        compaction_count = 0

        # Hash-based loop detection (no round cap)
        loop_detector = LoopDetector()

        msg = self._call_api_with_tools(agent, messages, tools=native_tools, max_tokens=max_tokens)
        if not msg:
            return {
                "success": False,
                "error": "LLM API call failed",
                "agent": agent_name,
                "agent_id": agent.agent_id,
            }

        while True:
            round_num += 1

            # Check timeout
            elapsed = time.time() - start_time
            if elapsed > timeout_seconds:
                logger.info(f"[{agent_name}] Timeout after {elapsed:.0f}s, {round_num} rounds")
                break

            # Check if model wants to call tools
            tool_calls = msg.get("tool_calls")
            if not tool_calls:
                break  # Model is done — no more tool calls

            # Enhanced loop detection
            loop_reason = loop_detector.check(
                tool_calls=tool_calls,
                content=msg.get("content", "")
            )
            if loop_reason:
                logger.warning(f"[{agent_name}] Loop detected: {loop_reason}")
                break

            # Normalize tool_calls (NVIDIA NIM may return arguments as dict)
            tool_calls = self._normalize_tool_calls(tool_calls)

            # Add the assistant message (with tool_calls) to history
            assistant_msg = {"role": "assistant", "content": msg.get("content") or ""}
            if tool_calls:
                assistant_msg["tool_calls"] = tool_calls
            messages.append(assistant_msg)
            new_messages.append(assistant_msg)

            # Record calls BEFORE execution
            for tc in tool_calls:
                fn = tc.get("function", {})
                loop_detector.record_call(fn.get("name", ""), fn.get("arguments", "{}"), tc.get("id", ""))

            # Execute the tool calls
            logger.info(f"[{agent_name}] Round {round_num}: executing {len(tool_calls)} tool call(s)...")
            tool_results = self._execute_native_tool_calls(agent, tool_calls)

            # Record results AFTER execution (no-progress detection)
            for tc, tr in zip(tool_calls, tool_results):
                fn = tc.get("function", {})
                fn_name = fn.get("name", "unknown")
                all_tool_names.append(fn_name)
                tool_call_count += 1
                loop_detector.record_result(fn.get("name", ""), fn.get("arguments", "{}"), tr.get("content", ""))

            # Add tool results as proper role:"tool" messages (Feature #4)
            messages.extend(tool_results)
            new_messages.extend(tool_results)

            # --- Mid-run context compaction ---
            if compaction_count < 3 and _should_compact_mid_run(messages):
                logger.info(f"[{agent_name}] Mid-run compaction triggered ({compaction_count + 1})")
                messages = _compact_mid_run(
                    messages, agent, self._call_api_with_tools
                )
                compaction_count += 1

            # --- Polling backoff ---
            for tc in tool_calls:
                fn = tc.get("function", {})
                backoff = loop_detector.get_backoff_hint(fn.get("name", ""), fn.get("arguments", "{}"))
                if backoff and backoff >= 5.0:
                    logger.info(f"[{agent_name}] Poll backoff: {backoff:.0f}s for {fn.get('name', '')}")
                    time.sleep(min(backoff, 30.0))

            # Call the model again with the tool results
            msg = self._call_api_with_tools(agent, messages, tools=native_tools, max_tokens=max_tokens)
            if not msg:
                logger.warning(f"[{agent_name}] API call failed on round {round_num}")
                break

        # Extract final response
        final_content = msg.get("content") or "" if msg else ""
        elapsed = time.time() - start_time

        # Append the FINAL assistant response to new_messages (it's never in the loop)
        if final_content:
            new_messages.append({"role": "assistant", "content": final_content})

        # Update agent stats
        agent.cycles_completed += 1
        agent.last_cycle = time.time()
        self._save_state()

        # Feature #5: Save only NEW messages (not re-saved session history)
        self._save_session(agent.agent_id, new_messages)

        logger.info(
            f"✅ Invoke complete: [{agent_name}] — "
            f"{len(final_content)} chars, {tool_call_count} tool calls "
            f"across {round_num} rounds in {elapsed:.1f}s"
        )

        return {
            "success": True,
            "agent": agent_name,
            "agent_id": agent.agent_id,
            "department": dept_name,
            "role_title": agent.role_title or "",
            "response": final_content,
            "tools_used": tool_call_count > 0,
            "tool_calls": tool_call_count,
            "tool_names": list(set(all_tool_names)),
            "rounds": round_num,
            "elapsed_seconds": round(elapsed, 1),
            "workspace": workspace,
        }

    def list_available_agents(self) -> list:
        """Return a compact list of agents available for manual invocation."""
        agents = []
        for a in self.agents.values():
            if a.status == "retired":
                continue
            tool_count = len(self.AGENT_TOOL_PROFILES.get(a.display_name or a.name, self.DEFAULT_TOOL_PROFILE))
            agents.append({
                "id": a.agent_id,
                "name": a.display_name or a.name,
                "department": DEPARTMENTS.get(a.department or a.role, {}).get("name", a.role),
                "role_title": a.role_title or "",
                "focus": a.focus_area or "",
                "status": a.status,
                "autonomous": a.autonomous,
                "tools": tool_count,
            })
        return sorted(agents, key=lambda x: x["department"])

    # ================================================================
    # JARVIS MODE — Operator gets ALL tools, no filtering
    # ================================================================

    def invoke_jarvis(self, prompt: str, max_tokens: int = 8000) -> Dict[str, Any]:
        """
        Jarvis mode: the operator's personal AI with full access to ALL 176 tools.
        No department filtering, no agent restrictions. Like Tony Stark's Jarvis —
        one brain, full toolkit, handles anything.

        Uses the first available agent as the execution shell (or creates a
        virtual one), but with ALL tools unlocked.
        """
        logger.info(f"🤖 JARVIS invoke — \"{prompt[:100]}\"")

        # Use the operator's workspace
        workspace = _jarvis_workspace()
        os.makedirs(workspace, exist_ok=True)

        # Build native tools for Jarvis — progressive disclosure (starter profile)
        native_tools = self._build_native_tools(jarvis=True, starter=True)

        # Cache tools on ALL relevant agent refs so list_my_tools can find them.
        # The tool executor uses shell_agent, so we must cache there too.
        for a in self.agents.values():
            if a.agent_id == "jarvis" or a.name == "JARVIS":
                a._cached_native_tools = native_tools
                break
        # Also cache on daemon itself as fallback
        self._jarvis_cached_native_tools = native_tools

        identity_prompt = self._jarvis_identity_prompt()

        # ── Unified prompt assembly (OpenClaw-style) ──
        identity_prompt += "\n\n" + self.build_agent_system_prompt(
            mode="full", workspace=workspace, prompt=prompt,
        )

        # Session persistence for Jarvis
        jarvis_session = self._load_session("jarvis")

        messages = [{"role": "system", "content": identity_prompt}]

        # Inject recent session context
        for hist_msg in jarvis_session[-6:]:
            role = hist_msg.get("role", "user")
            content = hist_msg.get("content", "")
            if content and role in ("user", "assistant"):
                messages.append({"role": role, "content": content})

        messages.append({"role": "user", "content": prompt})
        new_messages = [{"role": "user", "content": prompt}]

        shell_agent = self._get_jarvis_shell_agent()

        if not shell_agent:
            return {"success": False, "error": "No active agents available for API access"}

        # Cache native tools on the shell_agent so list_my_tools finds them during tool execution
        shell_agent._cached_native_tools = native_tools

        # Run the tool loop — OpenClaw-style: no round cap, timeout + hash-based loop detection
        start_time = time.time()
        timeout_seconds = 600  # 10 min (OpenClaw default) — no round cap
        all_tool_names = []
        tool_call_count = 0
        round_num = 0
        loop_detector = LoopDetector()  # No round cap — hash-based detection only
        compaction_count = 0

        msg = self._call_api_with_tools(shell_agent, messages, tools=native_tools, max_tokens=max_tokens)
        if not msg:
            return {"success": False, "error": "LLM API call failed"}

        while True:
            round_num += 1
            elapsed = time.time() - start_time
            if elapsed > timeout_seconds:
                logger.info(f"[JARVIS] Timeout after {elapsed:.0f}s, {round_num} rounds")
                break

            tool_calls = msg.get("tool_calls")
            if not tool_calls:
                break  # Model is done — natural exit (OpenClaw pattern)

            # Hash-based loop detection (no round cap)
            loop_reason = loop_detector.check(
                tool_calls=tool_calls,
                content=msg.get("content", "")
            )
            if loop_reason:
                logger.warning(f"[JARVIS] Loop detected: {loop_reason}")
                break

            # Normalize tool_calls (NVIDIA NIM may return arguments as dict)
            tool_calls = self._normalize_tool_calls(tool_calls)

            assistant_msg = {"role": "assistant", "content": msg.get("content") or ""}
            if tool_calls:
                assistant_msg["tool_calls"] = tool_calls
            messages.append(assistant_msg)
            new_messages.append(assistant_msg)

            logger.info(f"[JARVIS] Round {round_num}: executing {len(tool_calls)} tool call(s)...")

            # Record calls BEFORE execution
            for tc in tool_calls:
                fn = tc.get("function", {})
                loop_detector.record_call(fn.get("name", ""), fn.get("arguments", "{}"), tc.get("id", ""))

            tool_results = self._execute_native_tool_calls(shell_agent, tool_calls)

            # Record results AFTER execution (no-progress detection)
            for tc, tr in zip(tool_calls, tool_results):
                fn = tc.get("function", {})
                fn_name = fn.get("name", "unknown")
                all_tool_names.append(fn_name)
                tool_call_count += 1
                loop_detector.record_result(fn.get("name", ""), fn.get("arguments", "{}"), tr.get("content", ""))

            messages.extend(tool_results)
            new_messages.extend(tool_results)

            # --- Mid-run context compaction ---
            if compaction_count < 3 and _should_compact_mid_run(messages):
                logger.info(f"[JARVIS] Mid-run compaction triggered ({compaction_count + 1})")
                messages = _compact_mid_run(
                    messages, shell_agent, self._call_api_with_tools
                )
                compaction_count += 1

            # --- Polling backoff ---
            for tc in tool_calls:
                fn = tc.get("function", {})
                backoff = loop_detector.get_backoff_hint(fn.get("name", ""), fn.get("arguments", "{}"))
                if backoff and backoff >= 5.0:
                    logger.info(f"[JARVIS] Poll backoff: {backoff:.0f}s for {fn.get('name', '')}")
                    time.sleep(min(backoff, 30.0))

            msg = self._call_api_with_tools(shell_agent, messages, tools=native_tools, max_tokens=max_tokens)
            if not msg:
                break

        final_content = msg.get("content") or "" if msg else ""
        elapsed = time.time() - start_time

        # Save final assistant message
        if final_content:
            new_messages.append({"role": "assistant", "content": final_content})

        # Save Jarvis session
        self._save_session("jarvis", new_messages)

        # ── Update JarvisConsciousness after interaction ──
        try:
            consciousness = self._get_jarvis_consciousness()
            if consciousness:
                consciousness.classify_interaction(
                    tool_calls=tool_call_count,
                    tools_used=list(set(all_tool_names)),
                    success=bool(final_content and len(final_content) > 20),
                    prompt=prompt,
                    response=final_content or "",
                )
                consciousness.save_state()
        except Exception as e:
            logger.warning(f"Consciousness update failed: {e}")

        # ── Update Operator Profile ──
        try:
            from repryntt.core.identity.operator_profile import get_operator_profile
            _op = get_operator_profile()
            _op.record_message()
            for tn in set(all_tool_names):
                _op.record_tool_use(tn)
            _op.save()
        except Exception as e:
            logger.debug(f"Operator profile update failed: {e}")

        logger.info(
            f"✅ JARVIS complete — {len(final_content)} chars, "
            f"{tool_call_count} tool calls across {round_num} rounds in {elapsed:.1f}s"
        )

        return {
            "success": True,
            "agent": "JARVIS",
            "mode": "operator",
            "response": final_content,
            "tools_used": tool_call_count > 0,
            "tool_calls": tool_call_count,
            "tool_names": list(set(all_tool_names)),
            "tools_available": len(native_tools),
            "rounds": round_num,
            "elapsed_seconds": round(elapsed, 1),
            "workspace": workspace,
        }

    def get_status(self) -> Dict[str, Any]:
        """Get full daemon status."""
        active = [a for a in self.agents.values() if a.status == "active"]
        paused = [a for a in self.agents.values() if a.status == "paused"]
        retired = [a for a in self.agents.values() if a.status == "retired"]
        on_mission = [a for a in self.agents.values() if a.mode == "mission"]
        autonomous_agents = [a for a in active if a.autonomous]
        invoke_only_agents = [a for a in active if not a.autonomous]

        agents_info = []
        for a in self.agents.values():
            next_cycle = max(0, (a.last_cycle + a.cycle_interval) - time.time()) if a.last_cycle else 0
            agent_info = {
                "id": a.agent_id,
                "name": a.display_name or a.name,
                "role": a.role,
                "department": a.department or a.role,
                "role_title": a.role_title or "",
                "status": a.status,
                "mode": a.mode,
                "cycles": a.cycles_completed,
                "posts": a.posts_created,
                "replies": a.replies_made,
                "actions": a.actions_created,
                "errors": a.errors,
                "tokens": a.total_tokens,
                "interval_sec": a.cycle_interval,
                "next_cycle_sec": round(next_cycle),
                "current_goal": a.current_goal[:80] if a.current_goal else "",
                "last_thought": a.last_thought[:120] if a.last_thought else "",
                "tagline": a.tagline,
            }
            if a.active_mission_id:
                agent_info["mission_id"] = a.active_mission_id
            agents_info.append(agent_info)

        # Active missions summary
        active_missions = [
            {
                "id": m.mission_id,
                "objective": m.objective[:80],
                "status": m.status,
                "progress": round(m.progress * 100, 1),
                "agents": len(m.agent_ids),
            }
            for m in self.missions.values()
            if m.status in ("planning", "active", "converging")
        ]

        # Department distribution
        dept_dist = {}
        for a in self.agents.values():
            d = a.department or a.role
            dept_dist[d] = dept_dist.get(d, 0) + 1

        # Count in-flight cycles
        with self._futures_lock:
            in_flight = sum(1 for f in self._active_futures.values() if not f.done())

        return {
            "daemon_running": self._running,
            "daemon_paused": self._paused,
            "in_flight_cycles": in_flight,
            "total_agents": len(self.agents),
            "active": len(active),
            "autonomous": len(autonomous_agents),
            "invoke_only": len(invoke_only_agents),
            "paused": len(paused),
            "retired": len(retired),
            "on_mission": len(on_mission),
            "total_posts": sum(a.posts_created for a in self.agents.values()),
            "total_replies": sum(a.replies_made for a in self.agents.values()),
            "total_actions": sum(a.actions_created for a in self.agents.values()),
            "total_tokens": sum(a.total_tokens for a in self.agents.values()),
            "active_missions": active_missions,
            "departments": dept_dist,
            "agents": agents_info,
            # ── Cost control status ──
            "cost_control": {
                "council_enabled": self._council_enabled,
                "is_local_provider": self._is_local_provider(),
                "max_autonomous_api_agents": self.MAX_AUTONOMOUS_API_AGENTS,
                "duty_cycle": "10min/60min (API)" if not self._is_local_provider() else "unlimited (local)",
            },
        }

    # ── Main Daemon Loop ──

    def _enforce_cost_controls_on_startup(self):
        """Enforce cost controls when daemon starts.
        
        When using cloud API providers, this ensures only MAX_AUTONOMOUS_API_AGENTS
        roster agents are set to autonomous. All others are set to invoke-only.
        Local LLM providers skip enforcement entirely.
        
        This protects against old state files that have all agents autonomous=True
        from before cost controls were added.
        """
        if self._is_local_provider():
            logger.info("💚 Local LLM detected — no cost controls needed, all agents can run freely")
            return

        # Count how many roster agents (not jarvis_autonomous) are autonomous
        autonomous_roster = [
            a for a in self.agents.values()
            if a.autonomous and a.status == "active"
            and a.agent_id != "jarvis_autonomous"
        ]

        if len(autonomous_roster) <= self.MAX_AUTONOMOUS_API_AGENTS:
            logger.info(f"💰 Cost controls OK — {len(autonomous_roster)} autonomous agents "
                       f"(limit: {self.MAX_AUTONOMOUS_API_AGENTS})")
            return

        # Too many autonomous agents — disable excess ones
        # Keep the ones with the most cycles completed (most useful)
        autonomous_roster.sort(key=lambda a: a.cycles_completed, reverse=True)
        keep = autonomous_roster[:self.MAX_AUTONOMOUS_API_AGENTS]
        disable = autonomous_roster[self.MAX_AUTONOMOUS_API_AGENTS:]

        for agent in disable:
            agent.autonomous = False
            agent.task_gated = True
            logger.info(f"💰 Cost safety: disabled autonomous for {agent.display_name or agent.name} "
                       f"(API provider)")

        keep_names = [a.display_name or a.name for a in keep]
        disable_names = [a.display_name or a.name for a in disable]
        logger.warning(
            f"💰 COST CONTROL: Reduced autonomous agents from {len(autonomous_roster)} "
            f"to {self.MAX_AUTONOMOUS_API_AGENTS} (API mode). "
            f"Kept: {keep_names}. Disabled: {disable_names}. "
            f"Use enable_autonomous_agent() to re-enable specific agents."
        )
        self._save_state()

    def start(self):
        """Start the daemon — launches a background thread for each active agent."""
        if self._running:
            logger.warning("Daemon already running")
            return
        self._running = True
        logger.info("=== AGENT DAEMON STARTING ===")

        # Eagerly pre-load BrainSystem so agents have tools from the start
        try:
            logger.info("Step 1/4: Loading BrainSystem tool bridge...")
            brain = self._get_brain_system()
            if brain:
                tool_count = len(self._tool_registry) if self._tool_registry else 0
                logger.info(f"✅ Tool bridge ready — {tool_count} tools available")
            else:
                logger.warning("⚠️ Tool bridge failed to load — agents will operate WITHOUT tools. "
                               "Will retry on next agent cycle (30s cooldown).")
        except Exception as e:
            logger.error(f"⚠️ Tool bridge load error (non-fatal): {e}")

        # ── Neural Cortex — multi-model brain regions ──
        self._cortex = None
        try:
            from repryntt.cortex import initialize_cortex
            self._cortex = initialize_cortex()
        except Exception as e:
            logger.warning(f"⚠️ Neural Cortex init failed (non-fatal, running without): {e}")

        # Council system fully disabled — tools removed, not needed.
        logger.info("Step 2/5: Jarvis is sole autonomous agent")

        # ── Enforce cost controls on startup ──
        # When using cloud API providers, limit autonomous roster agents to
        # MAX_AUTONOMOUS_API_AGENTS. This protects against the state file having
        # all agents set autonomous=True from a previous version.
        self._enforce_cost_controls_on_startup()

        # ── Unified Awareness / WorldState disabled ──
        # Keep the attributes present so older helper paths that check them
        # degrade cleanly, but do not start WorldState, PerceptionLoop, the
        # WorldState hormone bridge, or relational mode. The legacy
        # conversational awareness + explicit camera/nav tools remain the
        # source of physical context.
        self._world_state = None
        self._hormone_bridge = None
        self._perception_loop = None
        self._relational_mode_mgr = None
        self._brain_inferring = threading.Event()
        logger.info("Step 2.5/5: WorldState/perception loop disabled")

        # Start P2P mesh node in background
        try:
            logger.info("Step 3/5: P2P mesh node...")
            self._start_p2p_node()
        except Exception as e:
            logger.warning(f"⚠️ P2P mesh start failed (non-fatal): {e}")

        # Start the main scheduler thread
        logger.info("Step 4/5: Starting scheduler thread...")
        self._scheduler_thread = threading.Thread(
            target=self._scheduler_loop, daemon=True, name="daemon-scheduler"
        )
        self._scheduler_thread.start()
        logger.info(f"✅ Scheduler started — managing {len(self.agents)} agents, {len(self.missions)} missions")

        # ── Record wake event (sleep/wake awareness) ──
        try:
            from repryntt.core.identity.sleep_wake import SleepWakeTracker
            self._sleep_wake = SleepWakeTracker()
            wake_briefing = self._sleep_wake.record_startup()
            logger.info(f"☀️ {wake_briefing[:120]}")

            # ── Abandon stale reasoning chains after long sleep (>1 hour) ──
            # Prevents Andrew from resuming a stuck chain from hours ago.
            _wake_history = self._sleep_wake._load().get("wake_history", [])
            _last_wake = _wake_history[-1] if _wake_history else {}
            _sleep_secs = _last_wake.get("sleep_seconds", 0)
            if _sleep_secs > 3600:  # > 1 hour offline
                _chain_path = os.path.join(
                    _jarvis_workspace(), "reasoning_chain.json")
                if os.path.exists(_chain_path):
                    try:
                        os.remove(_chain_path)
                        logger.info(
                            f"🔗 Cleared stale reasoning chain after "
                            f"{_sleep_secs // 3600}h {(_sleep_secs % 3600) // 60}m sleep")
                    except OSError:
                        pass
        except Exception as e:
            self._sleep_wake = None
            logger.debug(f"Sleep/wake tracker init failed: {e}")
        self._last_alive_persist = time.time()

        # ── Physical conversational awareness (wake word, presence, dialogue) ──
        try:
            from repryntt.core.identity.conversational_awareness import ConversationalAwareness
            ca = ConversationalAwareness()
            ca.configure(
                speak_fn=self._conversation_speak,
                listen_fn=self._conversation_listen,
                think_fn=self._conversation_think,
                think_with_tools_fn=self._conversation_think_with_tools,
                capture_fn=self._conversation_capture,
                identity_fn=self._conversation_identity_context,
                personality_fn=self._conversation_personality_snippet,
                world_fn=self._conversation_world_context,
                capability_context_fn=self._conversation_capability_context,
                action_queue_fn=self._queue_conversation_action,
            )
            ca.start()
            self._conversational_awareness = ca
            logger.info("🎧 Conversational awareness started (wake word + presence + dialogue)")
        except Exception as e:
            self._conversational_awareness = None
            logger.debug(f"Conversational awareness init failed (non-fatal): {e}")

        # ── Operator Profile — record new session ──
        try:
            from repryntt.core.identity.operator_profile import get_operator_profile
            _op_profile = get_operator_profile()
            _op_profile.record_session()
            _op_profile.save()
            logger.info("👤 Operator profile loaded")
        except Exception as e:
            logger.debug(f"Operator profile init failed (non-fatal): {e}")

        # ── Cleanup old camera images on startup ──
        try:
            from repryntt.tools.media import cleanup_images
            deleted = cleanup_images(str(BRAIN_DIR), max_images=100)
            if deleted:
                logger.info(f"🧹 Cleaned up {deleted} old camera images (kept 100)")
        except Exception as e:
            logger.debug(f"Image cleanup failed (non-fatal): {e}")

        # ── Auto-enable Jarvis autonomous mode (self-prompting) ──
        # Like the local LLM's evolution loop, Jarvis should self-prompt
        # on its own without needing an API call to enable it.
        if not self._jarvis_auto_enabled:
            self.enable_jarvis_autonomous(enabled=True)
            logger.info("🤖 Jarvis autonomous self-prompting auto-enabled on daemon start")

        # ── Load trading engine state (survive restarts) ──
        try:
            from repryntt.trading.trading_engine import load_state as _load_engine_state
            _load_engine_state()
            logger.info("📊 Trading engine state loaded")
        except Exception as e:
            logger.debug(f"Trading engine state load skipped: {e}")

        # ── Load whale monitor state (survive restarts) ──
        try:
            from repryntt.trading.whale_monitor import load_state as _load_whale_state
            _load_whale_state()
            logger.info("🐋 Whale monitor state loaded")
        except Exception as e:
            logger.debug(f"Whale monitor state load skipped: {e}")

        # ── Load token pipeline state (survive restarts) ──
        try:
            from repryntt.trading.token_pipeline import load_state as _load_pipeline_state
            _load_pipeline_state()
            logger.info("📊 Token pipeline state loaded")
        except Exception as e:
            logger.debug(f"Token pipeline state load skipped: {e}")

        # ── Start scalp executor daemon (real-time signal watching + tight TP/SL) ──
        try:
            from repryntt.trading.scalp_executor import start as _start_scalp
            _start_scalp()
            logger.info("⚡ Scalp executor daemon started")
        except Exception as e:
            logger.warning(f"Scalp executor start failed (non-fatal): {e}")

    def stop(self):
        """Graceful shutdown — waits for in-flight agent cycles to finish."""
        logger.info("=== AGENT DAEMON STOPPING ===")
        self._running = False
        self._save_state()
        # Stop conversational awareness monitor
        if self._conversational_awareness:
            try:
                self._conversational_awareness.stop()
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)
        # Stop P2P mesh node
        self._stop_p2p_node()

        # Wait for in-flight agent cycles to finish (max 30s)
        with self._futures_lock:
            active = {k: v for k, v in self._active_futures.items() if not v.done()}
        if active:
            logger.info(f"⏳ Waiting for {len(active)} in-flight agent cycles to finish...")
            import concurrent.futures
            done, not_done = concurrent.futures.wait(active.values(), timeout=30)
            if not_done:
                logger.warning(f"⚠️ {len(not_done)} agent cycles did not finish within 30s")
            else:
                logger.info("✅ All in-flight agent cycles completed")
        with self._futures_lock:
            self._active_futures.clear()

        # Shutdown executor and recreate it so start() can be called again
        self._executor.shutdown(wait=False)
        self._executor = ThreadPoolExecutor(max_workers=20, thread_name_prefix="agent")
        logger.info("=== AGENT DAEMON STOPPED ===")

    def pause_all(self) -> Dict[str, Any]:
        """Global pause — stops scheduling new agent cycles but keeps daemon alive.
        In-flight cycles will finish, but no new ones are started.
        Daemon stays running so it can be unpaused instantly."""
        self._paused = True
        with self._futures_lock:
            in_flight = sum(1 for f in self._active_futures.values() if not f.done())
        logger.info(f"⏸️ Global pause activated — {in_flight} cycles still finishing")
        return {
            "success": True,
            "paused": True,
            "in_flight": in_flight,
            "message": f"All agents paused. {in_flight} cycle(s) finishing.",
        }

    def resume_all(self) -> Dict[str, Any]:
        """Unpause — resume scheduling agent cycles."""
        self._paused = False
        active_count = sum(1 for a in self.agents.values() if a.status == "active")
        logger.info(f"▶️ Global resume — {active_count} active agents will cycle")
        return {
            "success": True,
            "paused": False,
            "active_agents": active_count,
            "message": f"Resumed. {active_count} agents active.",
        }

    # ── P2P Mesh Integration ──

    def _start_p2p_node(self):
        """Start the P2P mesh node in a background thread with its own event loop."""
        try:
            from repryntt.comms.p2p import SAIGENode
            import asyncio

            # Read seed peers from config if available
            seed_peers = []
            p2p_config_path = BASE_DIR / "p2p_config.json"
            if p2p_config_path.exists():
                try:
                    with open(p2p_config_path) as f:
                        p2p_cfg = json.load(f)
                    seed_peers = p2p_cfg.get("seed_peers", [])
                except Exception:
                    logger.debug("Suppressed exception", exc_info=True)

            # Use persistent machine identity
            try:
                from repryntt.core.identity.machine_identity import get_identity
                identity = get_identity()
                node_name = identity["node_name"]
                machine_id = identity["machine_id"][:12]
            except Exception:
                logger.debug("Suppressed exception", exc_info=True)
                node_name = None
                machine_id = None

            self.p2p_node = SAIGENode(
                node_name=node_name,
                port=6600,
                seed_peers=seed_peers,
                enable_mdns=True,
                machine_id=machine_id,
            )
            self.p2p_node.daemon = self  # Back-reference so it can query agents

            def _run_p2p():
                loop = asyncio.new_event_loop()
                asyncio.set_event_loop(loop)
                self._p2p_loop = loop
                loop.run_until_complete(self.p2p_node.start())
                loop.run_forever()

            t = threading.Thread(target=_run_p2p, daemon=True, name="p2p-mesh")
            t.start()
            logger.info("🌐 P2P mesh node started on port 6600")

            # Delayed bridge connection — _p2p_loop is set in the background thread,
            # so an immediate call would race and fail the guard check.
            def _delayed_bridge():
                for _ in range(10):
                    time.sleep(2)
                    if self._p2p_loop:
                        self._try_connect_economy_bridge()
                        return
                logger.warning("🌐💰 P2P loop never became ready — economy bridge skipped")
            threading.Thread(target=_delayed_bridge, daemon=True, name="economy-bridge-connect").start()
        except Exception as e:
            logger.warning(f"🌐 P2P mesh node failed to start (non-fatal): {e}")
            self.p2p_node = None

    def _try_connect_economy_bridge(self):
        """Connect the P2P economy bridge when both P2P node and economy manager are available."""
        try:
            if not self.p2p_node or not self._p2p_loop:
                return  # P2P node not ready yet
            if not self._brain_system:
                return  # Brain system not loaded yet
            economy_mgr = getattr(self._brain_system, 'robot_economy_manager', None)
            if not economy_mgr:
                return  # Economy manager not available
            # Check if bridge already connected
            if getattr(economy_mgr, 'economy_bridge', None) and economy_mgr.economy_bridge._running:
                return  # Already connected
            economy_mgr.connect_p2p_node(self.p2p_node, self._p2p_loop)
            logger.info("🌐💰 P2P Economy Bridge connected — multi-device compute economy active")
        except Exception as e:
            logger.warning(f"🌐💰 P2P Economy Bridge connection failed (non-fatal): {e}")

    def _stop_p2p_node(self):
        """Stop the P2P mesh node."""
        if self.p2p_node and self._p2p_loop:
            try:
                import asyncio
                future = asyncio.run_coroutine_threadsafe(
                    self.p2p_node.stop(), self._p2p_loop
                )
                future.result(timeout=10)
                self._p2p_loop.call_soon_threadsafe(self._p2p_loop.stop)
                logger.info("🌐 P2P mesh node stopped")
            except Exception as e:
                logger.warning(f"P2P stop error: {e}")
        self.p2p_node = None
        self._p2p_loop = None

    def get_p2p_status(self) -> dict:
        """Get P2P mesh network status."""
        if self.p2p_node:
            return self.p2p_node.get_status()
        return {
            "success": False,
            "running": False,
            "message": "P2P mesh node not running",
        }

    def p2p_connect_peer(self, address: str) -> dict:
        """Connect to a specific peer by address."""
        if not self.p2p_node or not self._p2p_loop:
            return {"success": False, "error": "P2P node not running"}
        try:
            import asyncio
            future = asyncio.run_coroutine_threadsafe(
                self.p2p_node.connect_to_peer(address), self._p2p_loop
            )
            result = future.result(timeout=15)
            return {"success": result, "address": address}
        except Exception as e:
            return {"success": False, "error": str(e)}

    def p2p_broadcast_mission(self, objective: str, required_agents: int = 4) -> dict:
        """Broadcast a mission to the P2P network."""
        if not self.p2p_node or not self._p2p_loop:
            return {"success": False, "error": "P2P node not running"}
        try:
            import asyncio
            future = asyncio.run_coroutine_threadsafe(
                self.p2p_node.broadcast_mission(objective, required_agents),
                self._p2p_loop
            )
            mission_id = future.result(timeout=15)
            return {"success": True, "mission_id": mission_id}
        except Exception as e:
            return {"success": False, "error": str(e)}

    def p2p_search_network(self, query: str) -> dict:
        """Search the P2P network for knowledge."""
        if not self.p2p_node or not self._p2p_loop:
            return {"success": False, "results": [], "error": "P2P node not running"}
        try:
            import asyncio
            future = asyncio.run_coroutine_threadsafe(
                self.p2p_node.search_network(query), self._p2p_loop
            )
            results = future.result(timeout=15)
            return {"success": True, "results": results, "count": len(results)}
        except Exception as e:
            return {"success": False, "results": [], "error": str(e)}

    def _scheduler_loop(self):
        """Main scheduler — checks which agents need to run their cycle."""
        logger.info("🔄 Scheduler loop thread entered")
        try:
            self._scheduler_loop_inner()
        except Exception as e:
            logger.error(f"💀 SCHEDULER LOOP CRASHED: {e}", exc_info=True)
        logger.warning("⚠️ Scheduler loop thread exiting")

    def _scheduler_loop_inner(self):
        """Inner scheduler loop — separated so crashes are always caught."""
        while self._running:
            now = time.time()

            # Check for deadline-expired missions
            for mid, mission in list(self.missions.items()):
                if mission.status == "active" and mission.deadline and now > mission.deadline:
                    logger.warning(f"⏰ Mission {mid} deadline expired — forcing convergence")
                    # Mark incomplete subtasks as completed with partial results
                    for aid, st in mission.subtasks.items():
                        if st["status"] != "completed":
                            st["status"] = "completed"
                            st["result"] = st.get("result", "") or "(Deadline expired — no deliverable)"
                            st["completed_at"] = now
                    self._check_mission_convergence(mission)

            for agent_id, agent in list(self.agents.items()):
                if agent.status != "active":
                    continue
                # Skip agents that are not autonomous at all
                if not agent.autonomous:
                    continue
                # When agent spawning is disabled, only run Jarvis (the operator)
                if not self._agent_spawning_enabled and agent.agent_id != "jarvis_autonomous":
                    continue
                # Task-gated agents only cycle when they have pending work
                # (saves API costs — they sleep when idle)
                if agent.task_gated and not agent.has_pending_work:
                    continue
                # Skip agents in deep work mode — they run in their own thread
                if agent.mode == "deep_work":
                    continue
                # Skip scheduling when globally paused
                if self._paused:
                    continue

                # ── DUTY CYCLE: disabled — free API, run 24/7 ──

                # Don't double-submit if agent already has an in-flight cycle
                with self._futures_lock:
                    existing = self._active_futures.get(agent_id)
                    if existing and not existing.done():
                        continue

                last = agent.last_cycle or 0.0
                time_since_last = now - last
                if time_since_last >= agent.cycle_interval:
                    # Submit this agent's cycle to the thread pool
                    try:
                        future = self._executor.submit(self._safe_cycle, agent)
                        with self._futures_lock:
                            self._active_futures[agent_id] = future
                    except RuntimeError:
                        # Executor shut down — exit loop
                        break
                    except Exception as e:
                        logger.error(f"Failed to submit cycle for {agent.name}: {e}")

            # Check every 15 seconds
            # Also check cron tasks
            try:
                self._check_cron_tasks()
            except Exception as e:
                logger.error(f"Cron check failed: {e}")

            # ── Check for user tasks assigned to invoke-only agents ──
            # Invoke-only agents don't run autonomous cycles, so they never
            # check the task queue. We sweep it here every 15s and dispatch.
            try:
                self._dispatch_pending_invoke_only_tasks()
            except Exception as e:
                logger.error(f"Invoke-only task dispatch failed: {e}")

            # ── JARVIS AUTONOMOUS MODE ──
            # Rate-limited: runs on its own interval (default 15 min),
            # separate from the 15s scheduler tick. Only runs if enabled.
            if self._jarvis_auto_enabled and not self._paused:
                try:
                    # Check if enough time has elapsed since last Jarvis cycle
                    jarvis_elapsed = now - self._jarvis_auto_last_cycle
                    if jarvis_elapsed >= self.JARVIS_AUTO_CYCLE_INTERVAL:
                        # Don't double-submit if Jarvis is already running
                        with self._futures_lock:
                            jarvis_future = self._active_futures.get("jarvis_autonomous")
                            if not jarvis_future or jarvis_future.done():
                                future = self._executor.submit(self._safe_jarvis_autonomous)
                                self._active_futures["jarvis_autonomous"] = future
                except Exception as e:
                    logger.error(f"Jarvis autonomous scheduling failed: {e}")

            # (Trading cycle, portfolio watchdog, and whale monitor removed —
            #  trading delegated to dedicated FT-001 agent)

            # Persist last_alive every 2 minutes so crash restarts report accurate gaps
            if hasattr(self, '_sleep_wake') and self._sleep_wake:
                if now - getattr(self, '_last_alive_persist', 0) >= 120:
                    try:
                        self._sleep_wake.record_heartbeat_alive()
                        self._last_alive_persist = now
                    except Exception:
                        pass

            for _ in range(15):
                if not self._running:
                    break
                time.sleep(1)

    def _safe_cycle(self, agent: AutonomousAgentState):
        """Run one cycle with error handling."""
        try:
            # Check if daemon was stopped or paused between submission and execution
            if not self._running or self._paused:
                logger.debug(f"[{agent.display_name or agent.name}] Cycle skipped — daemon {'paused' if self._paused else 'stopped'}")
                return
            logger.info(f"[{agent.display_name or agent.name}] Starting autonomous cycle #{agent.cycles_completed + 1}")
            self._run_agent_cycle(agent)
            logger.info(f"[{agent.display_name or agent.name}] Cycle complete "
                        f"(posts={agent.posts_created}, replies={agent.replies_made})")
        except Exception as e:
            agent.errors += 1
            logger.error(f"[{agent.display_name or agent.name}] Cycle failed: {e}", exc_info=True)
        finally:
            # Remove from active futures tracking
            with self._futures_lock:
                self._active_futures.pop(agent.agent_id, None)

    def _safe_jarvis_autonomous(self):
        """Run one Jarvis autonomous cycle with error handling."""
        if self._jarvis_heartbeat_running:
            logger.debug("[JARVIS] Heartbeat skipped — already running")
            return
        # Skip heartbeat while in a real-time voice conversation
        if self._conversational_awareness and self._conversational_awareness.is_conversing:
            logger.debug("[JARVIS] Heartbeat skipped — real-time conversation active")
            return
        self._jarvis_heartbeat_running = True
        try:
            if not self._running or self._paused:
                return
            # Suppress spontaneous conversations during active heartbeat work
            if self._conversational_awareness:
                self._conversational_awareness.suppress_spontaneous = True
            self._run_jarvis_autonomous_cycle()
        except Exception as e:
            logger.error(f"[JARVIS] Autonomous cycle failed: {e}", exc_info=True)
        finally:
            self._jarvis_heartbeat_running = False
            # Re-enable spontaneous conversations between heartbeats
            if self._conversational_awareness:
                self._conversational_awareness.suppress_spontaneous = False
            with self._futures_lock:
                self._active_futures.pop("jarvis_autonomous", None)

    # ── Trading functions removed ──────────────────────────────────────
    # _trading_cycle_tick, _build_trader_mode_prompt, _jarvis_trading_cold_call,
    # _portfolio_watchdog_tick, _whale_monitor_tick, _jarvis_portfolio_cold_call
    # Trading is delegated to the dedicated FT-001 (Memecoin Trader) agent.
    # The repryntt/trading/ module and tools remain available for FT-001.

    # ── Conversational awareness callbacks ─────────────────────────────
    # These bridge the ConversationalAwareness module to the daemon's
    # existing speak/listen/think/capture infrastructure.

    def _conversation_speak(self, text: str = "", **kw):
        """Speak text through physical speakers (Piper TTS).
        Uses blocking mode so mic doesn't pick up our own voice."""
        from repryntt.tools.media import speak as _media_speak
        return _media_speak(text=text, blocking=True)

    def _conversation_listen(self, duration: str = "5", **kw):
        """Listen through microphone (Faster-Whisper STT).
        Uses VAD-aware recording in conversation mode so it stops
        when the speaker goes quiet instead of a fixed timer."""
        from repryntt.tools.media import listen as _media_listen
        return _media_listen(duration=duration, conversation=True)

    def _conversation_think(self, messages: list) -> str:
        """Plain API call for real-time conversation turns — NO tools.

        Voice conversation needs fast, lightweight responses (<5s).
        Sending 93 tool definitions bloats the prompt and causes timeouts
        on free-tier LLM endpoints.  A plain chat completion with max 300
        tokens keeps latency low on NVIDIA/xAI free or low-cost tiers.
        """
        # ── Cortex voice pre-response: instant acknowledgment while API thinks ──
        if getattr(self, '_cortex', None) and len(messages) >= 1:
            try:
                from repryntt.cortex.dispatcher import get_dispatcher
                _user_text = ""
                for _m in reversed(messages):
                    if _m.get("role") == "user":
                        _user_text = _m.get("content", "")[:300]
                        break
                if _user_text:
                    _history = "\n".join(
                        f"{m.get('role', '?')}: {m.get('content', '')[:100]}"
                        for m in messages[-4:]
                    )
                    _vpr = get_dispatcher().request_voice_preresponse(_user_text, _history)
                    _ack = _vpr.get("result", {}).get("text", "")
                    if _ack and not _vpr.get("fallback"):
                        # Speak the quick acknowledgment immediately
                        try:
                            self._conversation_speak(text=_ack)
                        except Exception:
                            logger.debug("Suppressed exception", exc_info=True)
            except Exception as e:
                logger.debug("Voice pre-response failed (non-fatal): %s", e)

        _provider = self._default_provider()
        _settings = self.ai_config.get(_provider, {})
        _model = _settings.get("model", self._default_model())
        agent = AutonomousAgentState(
            agent_id="artemis_conversation",
            name="ARTEMIS_CONV",
            role="conversationalist",
            provider=_provider,
            model=_model,
            personality="Real-time conversationalist",
            department="executive",
            role_title="Conversationalist",
            focus_area="Real-time voice conversation",
            display_name="Artemis (conversation)",
            autonomous=False,
            cycle_interval=0,
        )

        # Plain API call — no tools, no agentic loop, just fast chat.
        # Retry once on failure to survive transient 429/timeout.
        response = self._call_api(agent, messages, max_tokens=300)
        if not response:
            # One retry after a brief pause (rate limit recovery)
            logger.debug("[ARTEMIS_CONV] First API call failed, retrying in 3s...")
            time.sleep(3)
            response = self._call_api(agent, messages, max_tokens=300)

        if not response:
            return None

        text = self._strip_think_blocks(response)

        # ── Cortex personality rewrite: reshape spoken output in Andrew's voice ──
        if getattr(self, '_cortex', None) and text:
            try:
                from repryntt.cortex.dispatcher import get_dispatcher
                _disp = get_dispatcher()
                if _disp.get_region("conscious"):
                    _rewrite = _disp.request_personality_rewrite(text, context="spoken")
                    _rewritten = _rewrite.get("result", {}).get("text", "")
                    if _rewritten and not _rewrite.get("fallback"):
                        text = _rewritten
            except Exception as e:
                logger.debug("Personality rewrite failed (non-fatal): %s", e)

        return text

    # ── Curated tools for voice conversation (fast, lightweight) ──
    # These are tools safe to execute mid-conversation without excessive latency.
    # Daemon-only tools (append_daily_memory, memory_search, task_queue_status,
    # update_pulse_working_state) are added separately in _build_native_tools_for_conversation.
    CONVERSATION_TOOLS = [
        # Communication
        "gmail_read_inbox", "gmail_send", "gmail_reply",
        # Web research
        "google_web_search", "web_search_results_only", "scrape_web_page",
        "knowledge_search", "grokipedia_search",
        # Files
        "read_file", "list_dir", "write_file",
        # Awareness / senses
        "capture_camera", "speak", "get_current_time",
        # Economy
        "get_economy_status", "sim_portfolio", "sim_price_check",
        # Navigation (physical body)
        "google_maps_search", "find_nearby_places", "get_directions",
        # Task management
        "add_task",
    ]

    def _conversation_think_with_tools(self, messages: list) -> Optional[str]:
        """API call for voice conversation WITH tool support.

        Uses a curated subset of ~18 fast tools. If the LLM decides to call
        a tool, we execute it, feed the result back, and get a natural
        spoken response — all within a single conversation turn.

        Supports two paths:
        - Cloud provider: native function calling via _call_api_with_tools
        - Local provider: text-based TOOL_CALL format via _parse_and_execute_tools

        Max 2 rounds of tool calls per turn to keep latency reasonable.
        """
        _provider = self._default_provider()
        _settings = self.ai_config.get(_provider, {})
        _model = _settings.get("model", self._default_model())
        agent = AutonomousAgentState(
            agent_id="artemis_conversation",
            name="ARTEMIS_CONV",
            role="conversationalist",
            provider=_provider,
            model=_model,
            personality="Real-time conversationalist with tool access",
            department="executive",
            role_title="Conversationalist",
            focus_area="Real-time voice conversation",
            display_name="Andrew (conversation)",
            autonomous=False,
            cycle_interval=0,
        )

        # Build curated tool definitions
        conv_tools = self._build_native_tools_for_conversation()
        if not conv_tools:
            return None

        # ── Local provider path: text-based tool calling ──
        if _provider == "local":
            return self._conversation_think_local_tools(agent, messages, conv_tools)

        # ── Cloud provider path: native function calling ──
        # Round 1: API call with tools
        msg = self._call_api_with_tools(agent, messages, tools=conv_tools,
                                         max_tokens=500, tool_choice="auto")
        if not msg:
            return None

        # If LLM responded with text (no tool calls), return it
        tool_calls = msg.get("tool_calls")
        if not tool_calls:
            content = msg.get("content", "")
            return self._strip_think_blocks(content) if content else None

        # Execute tool calls
        logger.info(f"🔧💬 Voice conversation tool call: "
                     f"{[tc.get('function', {}).get('name', '?') for tc in tool_calls]}")
        tool_results = self._execute_native_tool_calls(agent, tool_calls)

        # Round 2: Feed tool results back to get spoken response
        messages_with_tools = list(messages)
        messages_with_tools.append(msg)  # assistant message with tool_calls
        messages_with_tools.extend(tool_results)  # tool result messages
        messages_with_tools.append({
            "role": "system",
            "content": ("Now respond to the human naturally based on the tool results above. "
                        "Keep it SHORT — 1-3 sentences. Speak conversationally, "
                        "don't narrate the tool call or say 'I used a tool'. "
                        "Just give them the answer.")
        })

        response = self._call_api(agent, messages_with_tools, max_tokens=400)
        if response:
            return self._strip_think_blocks(response)

        # If the followup fails, try to extract useful text from the tool results
        for tr in tool_results:
            content = tr.get("content", "")
            if content and len(content) > 20:
                return f"I found something — {content[:200]}"

        return None

    def _conversation_think_local_tools(self, agent: 'AutonomousAgentState',
                                         messages: list,
                                         conv_tools: List[Dict]) -> Optional[str]:
        """Local LLM conversation path with text-based tool calling.

        Injects a compact tool description block into the system prompt so
        the local model can emit TOOL_CALL: {...} patterns, then parses and
        executes them using the same machinery as the heartbeat local path.
        """
        # Build compact tool description text for the curated conversation tools
        tool_lines = [
            "\n## AVAILABLE TOOLS (voice conversation)",
            "To use a tool, output on its own line:",
            'TOOL_CALL: {"tool_name": "<name>", "parameters": {"param": "value"}}',
            "Only use a tool if it helps answer the human's question. "
            "If no tool is needed, just respond normally.",
            ""
        ]
        for tdef in conv_tools:
            fn = tdef.get("function", {})
            name = fn.get("name", "")
            desc = fn.get("description", "")
            params = fn.get("parameters", {}).get("properties", {})
            required = set(fn.get("parameters", {}).get("required", []))
            param_parts = []
            for pname, pschema in params.items():
                ptype = pschema.get("type", "string")
                if pname in required:
                    param_parts.append(f"{pname}: {ptype}")
                else:
                    param_parts.append(f"{pname}?: {ptype}")
            param_str = ", ".join(param_parts)
            if desc:
                tool_lines.append(f"  - {name}({param_str}) — {desc}")
            else:
                tool_lines.append(f"  - {name}({param_str})")
        tool_lines.append("")

        tool_block = "\n".join(tool_lines)

        # Inject tool block into the system message
        augmented_messages = []
        injected = False
        for m in messages:
            if m.get("role") == "system" and not injected:
                augmented_messages.append({
                    "role": "system",
                    "content": m.get("content", "") + "\n" + tool_block,
                })
                injected = True
            else:
                augmented_messages.append(m)
        if not injected:
            augmented_messages.insert(0, {"role": "system", "content": tool_block})

        # Round 1: plain API call (local LLM sees tools in the prompt text)
        response = self._call_api(agent, augmented_messages, max_tokens=500)
        if not response:
            return None

        # Parse text-based tool calls
        tool_results_text = self._parse_and_execute_tools(agent, response)
        if not tool_results_text:
            return self._strip_think_blocks(response)

        logger.info(f"🔧💬 Voice conversation (local) tool executed")

        # Round 2: feed results back for a natural spoken response
        augmented_messages.append({"role": "assistant", "content": response})
        augmented_messages.append({"role": "user", "content": (
            f"Tool results:\n{tool_results_text}\n\n"
            "Now respond naturally to the human based on these results. "
            "Keep it SHORT — 1-3 sentences. Don't mention the tool call."
        )})

        followup = self._call_api(agent, augmented_messages, max_tokens=300)
        if followup:
            return self._strip_think_blocks(followup)

        # Fallback: summarize the raw tool results
        return f"Here's what I found — {tool_results_text[:200]}"

    def _build_native_tools_for_conversation(self) -> List[Dict]:
        """Build a small curated set of tool definitions for voice conversation.

        Combines registry tools (intersection of CONVERSATION_TOOLS with
        registered names) and daemon-only tools (defined as JSON schemas in
        _build_native_tools, not in the registry).
        """
        brain = self._get_brain_system()
        if not brain or not self._tool_registry:
            return []

        import inspect

        allowed_set = set(self.CONVERSATION_TOOLS) & set(self._tool_registry.names)

        tools = []
        for tname in self._tool_registry.names:
            if tname not in allowed_set:
                continue
            func = self._tool_registry.get(tname)

            description = ""
            parameters = {"type": "object", "properties": {}, "required": []}

            mcp_info = getattr(func, '_mcp_tool_info', None)
            if mcp_info and hasattr(mcp_info, 'input_schema') and mcp_info.input_schema:
                schema = mcp_info.input_schema
                parameters = {
                    "type": "object",
                    "properties": schema.get("properties", {}),
                    "required": schema.get("required", []),
                }
                description = (mcp_info.description or "").split('\n')[0].strip()[:200]
            else:
                doc = getattr(func, '__doc__', '') or ''
                try:
                    sig = inspect.signature(func)
                except Exception:
                    logger.debug("Suppressed exception", exc_info=True)
                    sig = None

                if sig:
                    for pname, param in sig.parameters.items():
                        if pname in ('self', 'kwargs', 'args', 'kw', 'brain_path'):
                            continue
                        if param.kind in (inspect.Parameter.VAR_KEYWORD, inspect.Parameter.VAR_POSITIONAL):
                            continue
                        ptype = "string"
                        if param.annotation == int:
                            ptype = "integer"
                        elif param.annotation == bool:
                            ptype = "boolean"
                        elif param.annotation == float:
                            ptype = "number"
                        elif param.default is not None and not isinstance(param.default, inspect.Parameter.empty.__class__):
                            if isinstance(param.default, bool):
                                ptype = "boolean"
                            elif isinstance(param.default, int):
                                ptype = "integer"
                            elif isinstance(param.default, float):
                                ptype = "number"
                        parameters["properties"][pname] = {"type": ptype}
                        if param.default is inspect.Parameter.empty:
                            parameters["required"].append(pname)

                first_line = doc.split('\n')[0].strip() if doc else f"Tool: {tname}"
                description = first_line[:200]

            tools.append({
                "type": "function",
                "function": {
                    "name": tname,
                    "description": description,
                    "parameters": parameters,
                },
            })

        # Include daemon-only tools relevant to conversation (not in registry)
        daemon_conversation_tools = [
            {
                "type": "function",
                "function": {
                    "name": "append_daily_memory",
                    "description": "Save a note to today's memory file for future reference.",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "note": {"type": "string", "description": "The note to save"},
                            "heading": {"type": "string", "description": "Section heading"},
                        },
                        "required": ["note"],
                    },
                },
            },
            {
                "type": "function",
                "function": {
                    "name": "memory_search",
                    "description": "Search past daily memory notes for relevant findings.",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "query": {"type": "string", "description": "What to search for"},
                            "limit": {"type": "integer", "description": "Max results (default 5)"},
                        },
                        "required": ["query"],
                    },
                },
            },
            {
                "type": "function",
                "function": {
                    "name": "task_queue_status",
                    "description": "Show current task queue — pending tasks and priorities.",
                    "parameters": {"type": "object", "properties": {}},
                },
            },
            {
                "type": "function",
                "function": {
                    "name": "update_pulse_working_state",
                    "description": "Update your working state (current focus, next actions).",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "current_focus": {"type": "string", "description": "What you're working on"},
                            "last_completed": {"type": "string", "description": "What you just finished"},
                            "next_actions": {"type": "string", "description": "What to do next"},
                        },
                        "required": ["current_focus", "last_completed", "next_actions"],
                    },
                },
            },
        ]
        # Only add daemon tools that aren't already in the list from the registry
        existing_names = {t["function"]["name"] for t in tools}
        for dt in daemon_conversation_tools:
            if dt["function"]["name"] not in existing_names:
                tools.append(dt)

        logger.debug(f"🔧💬 Voice conversation tools: {len(tools)} available "
                     f"({len(tools) - len(daemon_conversation_tools)} registry + daemon)")
        return tools

    def _conversation_capture(self, analyze: bool = True, question: str = "", **kw):
        """Capture camera for presence detection."""
        from repryntt.tools.media import capture_camera as _media_capture
        brain_path = str(BRAIN_DIR)
        return _media_capture(brain_path, camera_id=0, analyze=analyze, question=question, **kw)

    def _conversation_identity_context(self) -> str:
        """Return identity context + current state for conversation prompt."""
        parts = []
        bootstrap_dir = os.path.join(str(BRAIN_DIR), "bootstrap")
        # IDENTITY.md first — immutable config anchor
        id_path = _safe_bootstrap_path(bootstrap_dir, "IDENTITY.md")
        if id_path:
            id_content = _bootstrap_cache.read(id_path, max_chars=800)
            if id_content:
                parts.append(id_content)
        # SPIRIT.md — values/philosophy (abbreviated for conversation)
        spirit_path = _safe_bootstrap_path(bootstrap_dir, "SPIRIT.md")
        if spirit_path:
            spirit_content = _bootstrap_cache.read(spirit_path, max_chars=1000)
            if spirit_content:
                parts.append(spirit_content)
        # PROFILE.md — system architecture (abbreviated)
        profile_path = _safe_bootstrap_path(bootstrap_dir, "PROFILE.md")
        if profile_path:
            profile_content = _bootstrap_cache.read(profile_path, max_chars=500)
            if profile_content:
                parts.append(profile_content)

        # ── Current working state (what Andrew has been doing) ──
        try:
            pulse_path = os.path.join(str(BRAIN_DIR), "bootstrap", "PULSE.md")
            if os.path.exists(pulse_path):
                with open(pulse_path, 'r') as f:
                    pulse = f.read()
                # Extract working state section
                if "## Working State" in pulse:
                    ws_section = pulse.split("## Working State", 1)[1]
                    # Take up to next ## or end
                    if "\n## " in ws_section:
                        ws_section = ws_section.split("\n## ", 1)[0]
                    ws_text = ws_section.strip()[:600]
                    if ws_text:
                        parts.append(f"\nYOUR CURRENT WORKING STATE:\n{ws_text}")
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

        # ── Recent daily memory (last few entries for conversational context) ──
        try:
            import datetime as _dt
            today = _dt.date.today().isoformat()
            mem_path = os.path.join(_jarvis_workspace(), "memory", f"{today}.md")
            if os.path.exists(mem_path):
                with open(mem_path, 'r') as f:
                    mem_text = f.read()
                # Take last 800 chars of today's memory
                if len(mem_text) > 100:
                    recent = mem_text[-800:].strip()
                    parts.append(f"\nYOUR RECENT ACTIVITY TODAY:\n{recent}")
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

        # ── Active reasoning chain (what you're working on) ──
        try:
            chain_path = os.path.join(_jarvis_workspace(), "reasoning_chain.json")
            if os.path.exists(chain_path):
                with open(chain_path, 'r') as f:
                    chain = json.load(f)
                if chain.get("status") == "active":
                    goal = chain.get("goal", "")
                    step = len(chain.get("steps_completed", []))
                    if goal:
                        parts.append(f"\nYOUR CURRENT TASK: {goal[:200]} (step {step})")
        except Exception:
            logger.debug("Suppressed exception", exc_info=True)

        return "\n".join(parts) if parts else ""

